-- Poems batch 17
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('3b0035e7-490b-42ff-ad61-0927a2ed7573','折楊柳','盧照鄰','唐','唐诗','tang','','[]','倡樓啓曙扉，楊柳正依依。',48,'全唐诗/poet.tang.2000.json','["倡樓啓曙扉，楊柳正依依。", "鶯啼知歲隔，條變識春歸。", "露葉凝愁黛，風花亂舞衣。", "攀折聊將寄，軍中音信稀。"]'),
('77c3a980-2231-4b34-bc2e-5af8d2406b6d','十五夜觀燈','盧照鄰','唐','唐诗','tang','','["\u8282\u65e5", "\u5143\u5bb5\u8282", "\u5143\u5bb5"]','錦里開芳宴，蘭缸豔早年。',48,'全唐诗/poet.tang.2000.json','["錦里開芳宴，蘭缸豔早年。", "縟彩遙分地，繁光遠綴天。", "接漢疑星落，依樓似月懸。", "別有千金笑，來映九枝前。"]'),
('fce5f0f4-4c34-4d14-9bee-fed38b21efab','入秦川界','盧照鄰','唐','唐诗','tang','','[]','隴阪長無極，蒼山望不窮。',48,'全唐诗/poet.tang.2000.json','["隴阪長無極，蒼山望不窮。", "石徑縈疑斷，回流映似空。", "花開綠野霧，鶯囀紫巖風。", "春芳勿遽盡，留賞故人同。"]'),
('e58176d9-b4b1-48e7-a190-3ff988aecf3b','文翁講堂','盧照鄰','唐','唐诗','tang','','[]','錦里淹中館，岷山稷下亭。',48,'全唐诗/poet.tang.2000.json','["錦里淹中館，岷山稷下亭。", "空梁無燕雀，古壁有丹青。", "槐落猶疑市，苔深不辨銘。", "良哉二千石，江漢表遺靈。"]'),
('a0ecc4f3-31c2-4ad4-baee-fdecaf8a31fd','相如琴臺','盧照鄰','唐','唐诗','tang','','[]','聞有雍容地，千年無四鄰。',48,'全唐诗/poet.tang.2000.json','["聞有雍容地，千年無四鄰。", "園院風煙古，池臺松檟春。", "雲疑作賦客，月似聽琴人。", "寂寂啼鶯處，空傷遊子神。"]'),
('5513f618-8c28-45d0-82ec-78abbd3ae8d5','石鏡寺','盧照鄰','唐','唐诗','tang','','[]','古墓芙蓉塔，神銘松柏煙。',48,'全唐诗/poet.tang.2000.json','["古墓芙蓉塔，神銘松柏煙。", "鸞沈仙鏡底，花沒梵輪前。", "銖衣千古佛，寶月兩重圓。", "隱隱香臺夜，鐘聲徹九天。"]'),
('26f2fd7c-70a5-4489-bda1-392ee6d638f1','辛法司宅觀妓','盧照鄰','唐','唐诗','tang','','[]','南國佳人至，北棠羅薦開。',48,'全唐诗/poet.tang.2000.json','["南國佳人至，北棠羅薦開。", "長帬隨鳳管，促柱送鸞杯。", "雲光身後落，雪態掌中回。", "到愁金谷晚，不怪玉山頹。"]'),
('0d92eb7e-a7d9-4cb5-96d9-b998639424c6','春晚山莊率題二首 一','盧照鄰','唐','唐诗','tang','','[]','顧步三春晚，田園四望通。',48,'全唐诗/poet.tang.2000.json','["顧步三春晚，田園四望通。", "遊絲橫惹樹，戲蝶亂依藂。", "竹懶偏宜水，花狂不待風。", "唯餘詩酒意，當了一生中。"]'),
('01c26c32-dad7-4abd-ad71-b00d221b2975','春晚山莊率題二首 二','盧照鄰','唐','唐诗','tang','','[]','田家無四鄰，獨坐一園春。',48,'全唐诗/poet.tang.2000.json','["田家無四鄰，獨坐一園春。", "鶯啼非選樹，魚戲不驚綸。", "山水彈琴盡，風花酌酒頻。", "年華已可樂，高興復留人。"]'),
('88d2ec1d-9d99-4720-a891-b4ba23537b8f','江中望月','盧照鄰','唐','唐诗','tang','','[]','江水向涔陽，澄澄寫月光。',48,'全唐诗/poet.tang.2000.json','["江水向涔陽，澄澄寫月光。", "鏡圓珠留徹，弦滿箭波長。", "沈鉤搖兔影，浮桂動丹芳。", "延照相思夕，千里共霑裳。"]'),
('e0997b1d-d026-4ea1-b3a9-fef2234b6338','元日述懷','盧照鄰','唐','唐诗','tang','','[]','筮仕無中秩，歸耕有外臣。',48,'全唐诗/poet.tang.2000.json','["筮仕無中秩，歸耕有外臣。", "人歌小歲酒，花舞大唐春。", "草色迷三徑，風光動四鄰。", "願得長如此，年年物候新。"]'),
('da0a9e6d-a04b-41f8-833a-3415dd531eed','益州城西張超亭觀妓','盧照鄰','唐','唐诗','tang','','[]','落日明歌席，行雲逐舞人。',48,'全唐诗/poet.tang.2000.json','["落日明歌席，行雲逐舞人。", "江前飛暮雨，梁上下輕塵。", "冶服看疑畫，粧樓望似春。", "高車勿遽返，長袖欲相親。"]'),
('b25d8508-d48a-40b0-8aaa-11edad3a9783','還京贈別','盧照鄰','唐','唐诗','tang','','[]','風月清江夜，山水白雲朝。',48,'全唐诗/poet.tang.2000.json','["風月清江夜，山水白雲朝。", "萬里同爲客，三秋契不凋。", "戲鳧分斷岸，歸騎別高標。", "一去仙橋道，還望錦城遙。"]'),
('f647af7a-5f34-4622-a308-1539377f083a','至陳倉曉晴望京邑','盧照鄰','唐','唐诗','tang','','[]','拂曙驅飛傳，初晴帶曉涼。',48,'全唐诗/poet.tang.2000.json','["拂曙驅飛傳，初晴帶曉涼。", "霧歛長安樹，雲歸仙帝鄉。", "澗流漂素沫，巖景靄朱光。", "今朝好風色，延瞰極天莊。"]'),
('406125ce-3514-4912-9677-b66df15d8eac','晚渡滹沱敬贈魏大','盧照鄰','唐','唐诗','tang','','[]','津谷朝行遠，冰川夕望曛。',48,'全唐诗/poet.tang.2000.json','["津谷朝行遠，冰川夕望曛。", "霞明深淺浪，風卷去來雲。", "澄波泛月影，激浪聚沙文。", "誰忍仙舟上，攜手獨思君。"]'),
('d446bc5b-152e-411a-9028-e7289a43e20c','和吳侍御被使燕然','盧照鄰','唐','唐诗','tang','','[]','春歸龍塞北，騎指雁門垂。',48,'全唐诗/poet.tang.2000.json','["春歸龍塞北，騎指雁門垂。", "胡笳折楊柳，漢使採燕支。", "戍城聊一望，花雪幾參差。", "關山有新曲，應向笛中吹。"]'),
('9d34ac42-aab9-4db1-bb9a-20a0e732a481','七夕泛舟二首 一','盧照鄰','唐','唐诗','tang','','[]','汀葭肅徂暑，江樹起初涼。',48,'全唐诗/poet.tang.2000.json','["汀葭肅徂暑，江樹起初涼。", "水疑通織室，舟似泛仙潢。", "連橈渡急響，鳴櫂下浮光。", "日晚菱歌唱，風煙滿夕陽。"]'),
('183d219f-5901-43a4-ac3a-12ef4bedd6c4','七夕泛舟二首 二','盧照鄰','唐','唐诗','tang','','[]','鳳杼秋期至，鳧舟野望開。',48,'全唐诗/poet.tang.2000.json','["鳳杼秋期至，鳧舟野望開。", "微吟翠塘側，延想白雲隈。", "石似支機罷，槎疑犯宿來。", "天潢殊漫漫，日暮獨悠哉。"]'),
('ee8f79ea-36e2-4175-8575-f62818b98204','西使兼送孟學士南遊','盧照鄰','唐','唐诗','tang','','["\u79bb\u522b"]','地道巴陵北，天山弱水東。',72,'全唐诗/poet.tang.2000.json','["地道巴陵北，天山弱水東。", "相看萬餘里，共倚一征蓬。", "零雨悲王粲，清尊別孔融。", "裴回聞夜鶴，悵望待秋鴻。", "骨肉胡秦外，風塵關塞中。", "唯餘劍鋒在，耿耿氣成虹。"]'),
('6afd914e-0c61-40bc-acd8-f5bb9476e9b7','送鄭司倉入蜀','盧照鄰','唐','唐诗','tang','','[]','離人丹水北，遊客錦城東。',72,'全唐诗/poet.tang.2000.json','["離人丹水北，遊客錦城東。", "別意還無已，離憂自不窮。", "隴雲朝結陣，江月夜臨空。", "關塞疲征馬，霜氛落早鴻。", "潘年三十外，蜀道五千中。", "送君秋水曲，酌酒對清風。"]'),
('2dcbca94-4176-4e40-b656-4a0f102177e6','綿州官池贈別同賦灣字','盧照鄰','唐','唐诗','tang','','[]','輶軒遵上國，仙佩下靈關。',72,'全唐诗/poet.tang.2000.json','["輶軒遵上國，仙佩下靈關。", "尊酒方無地，聯綣喜暫攀。", "離言欲贈策，高辨正連環。", "野逕浮雲斷，荒池春草斑。", "殘花落古樹，度鳥入澄灣。", "欲敍他鄉別，幽谷有綿蠻。"]'),
('8a068fb5-6efa-4d5d-887e-a0a9441d3d25','還赴蜀中貽示京邑遊好','盧照鄰','唐','唐诗','tang','','[]','籞宿花初滿，章臺柳向飛。',72,'全唐诗/poet.tang.2000.json','["籞宿花初滿，章臺柳向飛。", "如何正此日，還望昔多違。", "悵別風期阻，將乖雲會稀。", "歛衽辭丹闕，懸旗陟翠微。", "野禽喧戍鼓，春草變征衣。", "回顧長安道，關山起夕霏。"]'),
('bd4a26c0-ca35-4280-b6ec-36900df5c9ef','初夏日幽莊','盧照鄰','唐','唐诗','tang','','[]','聞有高蹤客，耿介坐幽莊。',72,'全唐诗/poet.tang.2000.json','["聞有高蹤客，耿介坐幽莊。", "林壑人事少，風煙鳥路長。", "瀑水含秋氣，垂藤引夏涼。", "苗深全覆隴，荷上半侵塘。", "釣渚青鳧沒，村田白鷺翔。", "知君振奇藻，還嗣海隅芳。"]'),
('31ccc940-33ab-45d5-9ee7-4c32092a3001','山莊休沐','盧照鄰','唐','唐诗','tang','','[]','蘭署乘閑日，蓬扉狎遁棲。',72,'全唐诗/poet.tang.2000.json','["蘭署乘閑日，蓬扉狎遁棲。", "龍柯疎玉井，鳳葉下金堤。", "川光搖水箭，山氣上雲梯。", "亭幽聞唳鶴，窗曉聽鳴雞。", "玉軫臨風奏，瓊漿映月攜。", "田家自有樂，誰肯謝青溪。"]'),
('4bb5d9f5-9691-48ed-8cae-86453e48e22d','山林休日田家','盧照鄰','唐','唐诗','tang','','[]','歸休乘暇日，饁稼返秋場。',72,'全唐诗/poet.tang.2000.json','["歸休乘暇日，饁稼返秋場。", "徑草疏王篲，巖枝落帝桑。", "耕田虞訟寢，鑿井漢機忘。", "戎葵朝委露，齊棗夜含霜。", "南澗泉初冽，東籬菊正芳。", "還思北窗下，高臥偃羲皇。"]'),
('3d2b0b52-172e-4e69-bdbc-4a6b057037df','宴梓州南亭得池字','盧照鄰','唐','唐诗','tang','','[]','二條開勝迹，大隱叶沖規。',72,'全唐诗/poet.tang.2000.json','["二條開勝迹，大隱叶沖規。", "亭閣分危岫，樓臺遶曲池。", "長薄秋煙起，飛梁古蔓垂。", "水鳥翻荷葉，山蟲咬桂枝。", "遊人惜將晚，公子愛忘疲。", "願得回三舍，琴尊長若斯。"]'),
('14c66721-876b-4492-b9c9-4b6937b1952f','山行寄劉李二參軍','盧照鄰','唐','唐诗','tang','','[]','萬里煙塵客，三春桃李時。',72,'全唐诗/poet.tang.2000.json','["萬里煙塵客，三春桃李時。", "事去紛無限，愁來不自持。", "狂歌欲嘆鳳，失路反占龜。", "草礙人行緩，花繁鳥度遲。", "彼美參卿事，留連求友詩。", "安知倦遊子，兩鬢漸如絲。"]'),
('84f9b347-9993-4dfd-8fb6-39bfd6c7dc24','首春貽京邑文士','盧照鄰','唐','唐诗','tang','','[]','寂寂罷將迎，門無車馬聲。',84,'全唐诗/poet.tang.2000.json','["寂寂罷將迎，門無車馬聲。", "橫琴荅山水，披卷閱公卿。", "忽聞歲云晏，倚杖出簷楹。", "寒辭楊柳陌，春滿鳳皇城。", "梅花扶院吐，蘭葉遶階生。", "覽鏡改容色，藏書留姓名。", "時來不假問，生死任交情。"]'),
('8cedbc79-1480-4f03-bcd3-91c04c9cf805','贈許左丞從駕萬年宮','盧照鄰','唐','唐诗','tang','','["\u9ec4\u5c71"]','聞道上之回，詔蹕下蓬萊。',84,'全唐诗/poet.tang.2000.json','["聞道上之回，詔蹕下蓬萊。", "中樞移北斗，左轄去南臺。", "黃山聞鳳笛，清蹕侍龍媒。", "曳日朱旗卷，參雲金障開。", "朝參五城柳，夕宴柏梁杯。", "漢畤光如月，秦祠聽似雷。", "寂寂芸香閣，離思獨悠哉。"]'),
('2065dc7a-5ac9-406f-b7cd-285c5b5293df','晚渡渭橋寄示京邑遊好','盧照鄰','唐','唐诗','tang','','["\u9ec4\u5c71"]','我行背城闕，驅馬獨悠悠。',96,'全唐诗/poet.tang.2000.json','["我行背城闕，驅馬獨悠悠。", "寥落百年事，裴回萬里憂。", "途遙日向夕，時晚鬢將秋。", "滔滔俯東逝，耿耿泣西浮。", "長虹掩釣浦，落雁下星洲。", "草變黃山曲，花飛清渭流。", "迸水驚愁鷺，騰沙起狎鷗。", "一赴清泥道，空思玄灞遊。"]'),
('ac59c260-320d-4909-adc9-841b7af88f6d','羈臥山中','盧照鄰','唐','唐诗','tang','','[]','臥壑迷時代，行歌任死生。',120,'全唐诗/poet.tang.2000.json','["臥壑迷時代，行歌任死生。", "紅顏意氣盡，白璧故交輕。", "澗戶無人跡，山窗聽鳥聲。", "春色緣巖上，寒光入溜平。", "雪盡松帷暗，雲開石路明。", "夜伴飢鼯宿，朝隨馴雉行。", "度溪猶憶處，尋洞不知名。", "紫書常日閱，丹藥幾年成。", "扣鐘鳴天鼓，燒香厭地精。", "倘遇浮丘鶴，飄颻凌太清。"]'),
('dd4e8883-5eb6-423e-9854-8e6b0f0bbfa2','酬張少府柬之','盧照鄰','唐','唐诗','tang','','[]','昔余與夫子，相遇漢川陰。',120,'全唐诗/poet.tang.2000.json','["昔余與夫子，相遇漢川陰。", "珠浦龍猶臥，檀溪馬正沈。", "價重瑤山曲，詞驚丹鳳林。", "十年暌賞慰，萬里隔招尋。", "毫翰風期阻，荆衡雲路深。", "鵬飛俱望昔，蠖屈共悲今。", "誰謂青衣道，還嘆白頭吟。", "地接神仙磵，江連雲雨岑。", "飛泉如散玉，落日似懸金。", "重以瑤華贈，空懷舞詠心。"]'),
('b889c22b-1949-4327-9f2f-ad9804991c35','過東山谷口','盧照鄰','唐','唐诗','tang','','[]','不知名利險，辛苦滯皇州。',120,'全唐诗/poet.tang.2000.json','["不知名利險，辛苦滯皇州。", "始覺飛塵倦，歸來事綠疇。", "桃源迷處所，桂樹可淹留。", "跡異人間俗，禽同海上鷗。", "古苔依井被，新乳傍崖流。", "野老堪成鶴，山神或化鳩。", "泉鳴碧澗底，花落紫巖幽。", "日暮飡龜殼，天寒御鹿裘。", "不辨秦將漢，寧知春與秋。", "多謝青溪客，去去赤松遊。"]'),
('8e4f53da-0190-413d-9c18-f8043d90e2be','送幽州陳參軍赴任寄呈鄉曲父老','盧照鄰','唐','唐诗','tang','','[]','薊北三千里，關西二十年。',120,'全唐诗/poet.tang.2000.json','["薊北三千里，關西二十年。", "馮唐猶在漢，樂毅不歸燕。", "人同黃鶴遠，鄉共白雲連。", "郭隗池臺處，昭王尊酒前。", "故人當已老，舊壑幾成田。", "紅顏如昨日，衰鬢似秋天。", "西蜀橋應毀，東周石尚全。", "灞池水猶綠，榆關月早圓。", "塞雲初上雁，庭樹欲銷蟬。", "送君之舊國，揮淚獨澘然。"]'),
('cc29cf49-34db-4291-8795-cea0661afcb2','哭金部韋郎中','盧照鄰','唐','唐诗','tang','','[]','金曹初受拜，玉地始含香。',84,'全唐诗/poet.tang.2000.json','["金曹初受拜，玉地始含香。", "翻同五日尹，遽見一星亡。", "賀客猶扶路，哀人遂上堂。", "歌筵長寂寂，哭位自蒼蒼。", "歲時賓徑斷，朝暮雀羅張。", "書留魏主闕，魂掩漢家牀。", "徒令永平帝，千載罷撞郎。"]'),
('7f3d1c20-b12f-4ffe-9b34-a5c7c951c469','哭明堂裴主簿','盧照鄰','唐','唐诗','tang','','[]','締歡三十載，通家數百年。',120,'全唐诗/poet.tang.2000.json','["締歡三十載，通家數百年。", "潘楊稱代穆，秦晉忝姻連。", "風雲洛陽道，花月茂陵田。", "相悲共相樂，交騎復交筵。", "始謂調金鼎，如何掩玉泉。", "黃公酒鑪處，青眼竹林前。", "故琴無復雪，新樹但生煙。", "遽痛蘭襟斷，徒令寶劍懸。", "客散同秋葉，人亡似夜川。", "送君一長慟，松臺路幾千。"]'),
('669a1229-04ef-4957-81a7-043b871316ac','同崔錄事哭鄭員外','盧照鄰','唐','唐诗','tang','','["\u6cf0\u5c71"]','文學秋天遠，郎官星位尊。',144,'全唐诗/poet.tang.2000.json','["文學秋天遠，郎官星位尊。", "伊人表時彥，飛譽滿司存。", "楚席光文雅，瑤山侍討論。", "鳳詞凌漢閣，龜辯罩周園。", "已陪東嶽駕，將逝北溟鯤。", "如何萬化盡，空嘆九飛魂。", "白馬西京驛，青松北海門。", "夜臺無曉箭，朝奠有虛尊。", "一代儒風沒，千年隴霧昏。", "梁山送夫子，湘水弔王孫。", "僕本多悲淚，沾裳不待猿。", "聞君絕弦曲，吞恨更無言。"]'),
('a64c785b-0a0f-4392-af9c-47926d1dac90','登玉清','盧照鄰','唐','唐诗','tang','','[]','絕頂橫臨日，孤峰半倚天。',24,'全唐诗/poet.tang.2000.json','["絕頂橫臨日，孤峰半倚天。", "裴回拜真老，萬里見風煙。"]'),
('15a37290-0aef-4c6b-92c9-97cff61aafa6','曲池荷','盧照鄰','唐','唐诗','tang','','["\u548f\u7269", "\u6292\u60c5", "\u8377\u82b1", "\u548f\u7269\u8bd7"]','浮香繞曲岸，圓影覆華池。',24,'全唐诗/poet.tang.2000.json','["浮香繞曲岸，圓影覆華池。", "常恐秋風早，飄零君不知。"]'),
('3285c49f-f375-45da-9af5-aaac7b50fefb','浴浪鳥','盧照鄰','唐','唐诗','tang','','[]','獨舞依磐石，羣飛動輕浪。',24,'全唐诗/poet.tang.2000.json','["獨舞依磐石，羣飛動輕浪。", "奮迅碧沙前，長懷白雲上。"]'),
('249420f3-fc9d-4123-a073-595cb15e3e48','臨階竹','盧照鄰','唐','唐诗','tang','','[]','封霜連錦砌，防露拂瑤階。',24,'全唐诗/poet.tang.2000.json','["封霜連錦砌，防露拂瑤階。", "聊將儀鳳質，暫與俗人諧。"]'),
('b0b758f8-94eb-401a-981a-939f5b0ac9e1','含風蟬','盧照鄰','唐','唐诗','tang','','[]','高情臨爽月，急響送秋風。',24,'全唐诗/poet.tang.2000.json','["高情臨爽月，急響送秋風。", "獨有危冠意，還將衰鬢同。"]'),
('9586bbe6-2570-4388-abef-bef340dca01a','葮川獨泛','盧照鄰','唐','唐诗','tang','','[]','倚櫂春江上，橫舟石岸前。',24,'全唐诗/poet.tang.2000.json','["倚櫂春江上，橫舟石岸前。", "山瞑行人斷，迢迢獨泛仙。"]'),
('870a55a5-8d37-4903-810c-6bf02874c7f5','送二兄入蜀','盧照鄰','唐','唐诗','tang','','["\u4eb2\u60c5", "\u9001\u522b"]','關山客子路，花柳帝王城。',24,'全唐诗/poet.tang.2000.json','["關山客子路，花柳帝王城。", "此中一分手，相顧憐無聲。"]'),
('bdae66c6-9f86-45c8-8a5f-d1181052f25b','宿玄武二首 一','盧照鄰','唐','唐诗','tang','','[]','方池開曉色，圓月下秋陰。',24,'全唐诗/poet.tang.2000.json','["方池開曉色，圓月下秋陰。", "已乘千里興，還撫一弦琴。"]'),
('5e763161-1f93-4d8f-bec1-c0d0a9d636c0','宿玄武二首 二','盧照鄰','唐','唐诗','tang','','[]','庭搖北風柳，院繞南溟禽。',24,'全唐诗/poet.tang.2000.json','["庭搖北風柳，院繞南溟禽。", "累宿恩方重，窮秋嘆不深。"]'),
('bee511bd-1104-475f-8254-c914e3f70f10','九隴津集','盧照鄰','唐','唐诗','tang','','[]','落落樹陰紫，澄澄水華碧。',24,'全唐诗/poet.tang.2000.json','["落落樹陰紫，澄澄水華碧。", "復有翻飛禽，裴回疑曳舃。"]'),
('7ebaccc6-ae72-4010-98ac-5de8cd9b105c','遊昌化山精舍','盧照鄰','唐','唐诗','tang','','[]','寶地乘峰出，香臺接漢高。',24,'全唐诗/poet.tang.2000.json','["寶地乘峰出，香臺接漢高。", "稍覺真途近，方知人事勞。"]'),
('fe1644ee-ec63-43b5-b0df-80496869af64','登封大酺歌四首 一','盧照鄰','唐','唐诗','tang','','[]','明君封禪日重光，天子垂衣曆數長。',32,'全唐诗/poet.tang.2000.json','["明君封禪日重光，天子垂衣曆數長。", "九州四海常無事，萬歲千秋樂未央。"]'),
('a3f2198c-a49f-4f80-9f0b-84f0d10b912a','登封大酺歌四首 二','盧照鄰','唐','唐诗','tang','','[]','日觀仙雲隨鳳輦，天門瑞雪照龍衣。',32,'全唐诗/poet.tang.2000.json','["日觀仙雲隨鳳輦，天門瑞雪照龍衣。", "繁弦綺席方終夜，妙舞清歌歡未歸。"]'),
('1d0e830f-8269-444d-8a86-c5f679ed3b61','登封大酺歌四首 三','盧照鄰','唐','唐诗','tang','','[]','翠鳳逶迤登介丘，仙鶴裴回天上遊。',32,'全唐诗/poet.tang.2000.json','["翠鳳逶迤登介丘，仙鶴裴回天上遊。", "借問乾封何所樂，人皆壽命得千秋。"]'),
('9768f5e7-0e92-4e82-a2c2-0a53f4df5f64','登封大酺歌四首 四','盧照鄰','唐','唐诗','tang','','[]','千年聖主應昌期，萬國淳風王化基。',32,'全唐诗/poet.tang.2000.json','["千年聖主應昌期，萬國淳風王化基。", "請比上古無爲代，何如今日太平時。"]'),
('fc1a56cb-8746-4218-84f8-04a685e8c9c3','九月九日登玄武山','盧照鄰','唐','唐诗','tang','','["\u6052\u5c71", "\u91cd\u9633\u8282", "\u601d\u4e61", "\u91cd\u9633", "\u996e\u9152"]','九月九日眺山川，歸心歸望積風煙。',32,'全唐诗/poet.tang.2000.json','["九月九日眺山川，歸心歸望積風煙。", "他鄉共酌金花酒，萬里同悲鴻雁天。"]'),
('3aa932be-bef9-4847-ab6e-57880e14c166','句','盧照鄰','唐','唐诗','tang','','[]','城狐尾獨束，山鬼面參覃。',12,'全唐诗/poet.tang.2000.json','["城狐尾獨束，山鬼面參覃。"]'),
('b7519153-94de-4167-8be6-166f13fa0264','少年行','李百藥','唐','唐诗','tang','','[]','少年飛翠蓋，上路勒金鑣。',72,'全唐诗/poet.tang.2000.json','["少年飛翠蓋，上路勒金鑣。", "始酌文君酒，新吹弄玉簫。", "少年不歡樂，何以盡芳朝。", "千金笑裏面，一搦掌中腰。", "挂纓豈憚宿，落珥不勝嬌。", "寄語少年子，無辭歸路遙。"]'),
('94eecb16-1c55-4e84-a824-a885267389d5','渡漢江','李百藥','唐','唐诗','tang','','[]','東流既瀰瀰，南紀信滔滔。',72,'全唐诗/poet.tang.2000.json','["東流既瀰瀰，南紀信滔滔。", "水激沈碑岸，波駭弄珠皐。", "含星映淺石，浮蓋下奔濤。", "溜闊霞光近，川長曉氣高。", "檣烏轉輕翼，戲鳥落風毛。", "客心既多緒，長歌且代勞。"]'),
('4542edb4-128e-4216-840a-8503ae4fe03b','秋晚登古城','李百藥','唐','唐诗','tang','','["\u79cb\u5929", "\u767b\u9ad8", "\u5199\u666f", "\u6000\u53e4"]','日落征途遠，悵然臨古城。',60,'全唐诗/poet.tang.2000.json','["日落征途遠，悵然臨古城。", "頹墉寒雀集，荒堞晚烏驚。", "蕭森灌木上，迢遰孤煙生。", "霞景煥餘照，露氣澄晚清。", "秋風轉搖落，此志安可平。"]'),
('38dbe298-cd2a-4f2f-b5ed-67b6e481b064','途中述懷','李百藥','唐','唐诗','tang','','[]','伯喈遷塞北，亭伯之遼東。',84,'全唐诗/poet.tang.2000.json','["伯喈遷塞北，亭伯之遼東。", "伊余何爲客，獨守雲臺中。", "途遙已日暮，時泰道斯窮。", "拔心悲岸草，半死落巖桐。", "目送衡陽雁，情傷江上楓。", "福兮良所伏，今也信難通。", "丈夫自有志，寧傷官不公。"]'),
('84560524-af19-4281-b978-2ab24a4ef50b','郢城懷古','李百藥','唐','唐诗','tang','','[]','客心悲暮序，登墉瞰平陸。',216,'全唐诗/poet.tang.2000.json','["客心悲暮序，登墉瞰平陸。", "林澤窅芊緜，山川鬱重複。", "王公資設險，名都拒江隩。", "方城次北門，溟海窮南服。", "長策挫吳豕，雄圖競周鹿。", "萬乘重沮漳，九鼎輕伊穀。", "大蒐雲夢掩，壯觀章華築。", "人世更盛衰，吉凶良倚伏。", "遽見鄰交斷，仍覩賢臣逐。", "南風忽不競，西師日侵蹙。", "運圯屬馳驅，時屯恣敲朴。", "莫救夷陵火，無復秦庭哭。", "鄢郢遂丘墟，風塵俄慘黷。", "狐兔時遊踐，霜露日霑沐。", "釣渚故池平，神臺層宇覆。", "陣雲埋夏首，窮陰慘荒谷。", "悵矣舟壑遷，悲哉年祀倏。", "雖異三春望，終傷千里目。"]'),
('6b235ba9-ee6b-4670-9ca5-bb522b52a43e','晚渡江津','李百藥','唐','唐诗','tang','','[]','寂寂江山晚，蒼蒼原野暮。',60,'全唐诗/poet.tang.2000.json','["寂寂江山晚，蒼蒼原野暮。", "秋氣懷易悲，長波淼難泝。", "索索風葉下，離離早鴻度。", "丘壑列夕陰，葭菼凝寒霧。", "日落亭皐遠，獨此懷歸慕。"]'),
('a057cb3f-9d7a-44ab-8172-cdb3ebfd049a','王師渡漢水經襄陽','李百藥','唐','唐诗','tang','','[]','導漾疏源遠，歸海會流長。',96,'全唐诗/poet.tang.2000.json','["導漾疏源遠，歸海會流長。", "延波接荆夢，通望邇沮漳。", "高岸沈碑影，曲漵麗珠光。", "雲昏翠島沒，水廣素濤揚。", "閱川已多歎，遐睇幾增傷。", "臨谿猶駐馬，望峴欲霑裳。", "喬木下寒葉，亭林落曉霜。", "山公不可遇，誰與訪高陽。"]'),
('887b73ab-b767-4327-8f4b-bce906981116','謁漢高廟','李百藥','唐','唐诗','tang','','[]','纂堯靈命啓，滅楚餘閏終。',144,'全唐诗/poet.tang.2000.json','["纂堯靈命啓，滅楚餘閏終。", "飛名膺帝籙，沈迹韞神功。", "瑞氣朝浮碭，祥符夜告豐。", "抑揚駕人傑，叱咤掩時雄。", "締構三靈改，經綸五緯同。", "干戈革宇內，聲教盡寰中。", "運謝年逾遠，魂歸道未窮。", "樹碑留故邑，抗殿表祠宮。", "沐蘭祈泗上，謁帝動深衷。", "英威肅如在，文物杳成空。", "竹皮聚寒徑，枌社落霜叢。", "蕭索陰雲晚，長川起大風。"]'),
('e82ca232-9a56-4a68-acaa-b6e622fe2777','登葉縣故城謁沈諸梁廟','李百藥','唐','唐诗','tang','','[]','總轡臨秋原，登城望寒日。',84,'全唐诗/poet.tang.2000.json','["總轡臨秋原，登城望寒日。", "煙霞共掩映，林野俱蕭瑟。", "楚塞鬱不窮，吳山高漸出。", "客行殊未已，沐澡期終吉。", "椒桂奠芳樽，風雲下虛室。", "館宇肅而靜，神心康且逸。", "伊我非真龍，勿驚疲朽質。"]'),
('409125e2-cc6b-41d3-95c2-8a8522724c16','安德山池宴集','李百藥','唐','唐诗','tang','','[]','朝宰論思暇，高宴臨方塘。',72,'全唐诗/poet.tang.2000.json','["朝宰論思暇，高宴臨方塘。", "雲飛鳳臺管，風動令君香。", "細草開金埒，流霞泛羽觴。", "虹橋分水態，鏡石引菱光。", "上才同振藻，小技謬連章。", "懷音自蘭室，徐步返山莊。"]'),
('ae1dbbdd-01aa-4492-9c49-d64235c4c9ec','和許侍郎遊昆明池','李百藥','唐','唐诗','tang','','[]','神池望不極，滄波接遠天。',120,'全唐诗/poet.tang.2000.json','["神池望不極，滄波接遠天。", "儀星似河漢，落景類虞泉。", "年深平館宇，道泰偃戈船。", "差池下鳧雁，掩映生雲煙。", "浪花開已合，風文直且連。", "稅馬金堤外，橫舟石岸前。", "羽觴傾綠蟻，飛日落紅鮮。", "積水浮深智，明珠曜雅篇。", "大鯨方遠擊，沈灰獨未然。", "知君嘯儔侶，短翮徒聯翩。"]'),
('490cf518-c296-44a6-b651-41e12e243ce6','賦得魏都','李百藥','唐','唐诗','tang','','[]','炎運精華歇，清都寶命開。',72,'全唐诗/poet.tang.2000.json','["炎運精華歇，清都寶命開。", "帝里三方盛，王庭萬國來。", "玄武疏遙磴，金鳳上層臺。", "乍進仙童藥，時傾避暑杯。", "南館招奇士，西園引上才。", "還惜劉公幹，疲病清漳隈。"]'),
('35ec6317-7b10-493a-8ef1-6e30d096e624','賦禮記','李百藥','唐','唐诗','tang','','[]','玉帛資王會，郊丘叶聖情。',48,'全唐诗/poet.tang.2000.json','["玉帛資王會，郊丘叶聖情。", "重廣開環堵，至道軼金籝。", "盤薄依厚地，遙裔騰太清。", "方悅升中禮，足以慰餘生。"]'),
('509191f0-423b-44b6-b067-176c951d0f10','奉和正日臨朝應詔','李百藥','唐','唐诗','tang','','[]','化曆昭唐典，承天順夏正。',48,'全唐诗/poet.tang.2000.json','["化曆昭唐典，承天順夏正。", "百靈警朝禁，三辰揚斾旌。", "充庭富禮樂，高讌齒簪纓。", "獻壽符萬歲，移風韻九成。"]'),
('63f091c8-9253-4604-8f58-3cb055332d77','妾薄命','李百藥','唐','唐诗','tang','','[]','團扇秋風起，長門夜月明。',48,'全唐诗/poet.tang.2000.json','["團扇秋風起，長門夜月明。", "羞聞拊背入，恨說舞腰輕。", "太常先已醉，劉君恆帶酲。", "橫陳每虛設，吉夢竟何成。"]'),
('9f9f2087-9511-454f-b199-d3b367b29eaf','火鳳詞二首 一','李百藥','唐','唐诗','tang','','[]','歌聲扇後出，妝影鏡中輕。',48,'全唐诗/poet.tang.2000.json','["歌聲扇後出，妝影鏡中輕。", "未能令掩笑，何處欲障聲。", "知音自不惑，得念是分明。", "莫見雙嚬歛，疑人含笑情。"]'),
('508aa87e-4cf7-4a4a-903d-07ea38b4c51c','火鳳詞二首 二','李百藥','唐','唐诗','tang','','[]','佳人靚晚妝，清唱動蘭房。',48,'全唐诗/poet.tang.2000.json','["佳人靚晚妝，清唱動蘭房。", "影出含風扇，聲飛照日梁。", "嬌嚬眉際歛，逸韻口中香。", "自有橫陳會，應憐秋夜長。"]'),
('e53765b3-84fe-4028-bd32-1c46d7ed7052','奉和初春出遊應令','李百藥','唐','唐诗','tang','','[]','鳴笳出望苑，飛蓋下芝田。',48,'全唐诗/poet.tang.2000.json','["鳴笳出望苑，飛蓋下芝田。", "水光浮落照，霞彩淡輕煙。", "柳色迎三月，梅花隔二年。", "日斜歸騎動，餘興滿山川。"]'),
('1b37522f-73a2-48a1-b6c3-43f771353756','寄楊公','李百藥','唐','唐诗','tang','','[]','公子盛西京，光華早著名。',48,'全唐诗/poet.tang.2000.json','["公子盛西京，光華早著名。", "分庭接遊士，虛館待時英。", "高閣浮香出，長廊寶釧鳴。", "面花無隔笑，歌扇不障聲。"]'),
('b935dc2f-43b5-4f83-9ee3-4ec5211c588e','戲贈潘徐城門迎兩新婦','李百藥','唐','唐诗','tang','','[]','秦晉稱舊匹，潘徐有世親。',48,'全唐诗/poet.tang.2000.json','["秦晉稱舊匹，潘徐有世親。", "三星宿已會，四德婉而嬪。", "霞光鬢裏薄，月影扇中新。", "年華與妝面，共作一芳春。"]'),
('0519561c-3d1e-45c7-b4b2-98441aebe8a2','送別','李百藥','唐','唐诗','tang','','[]','眷言一杯酒，悽愴起離憂。',48,'全唐诗/poet.tang.2000.json','["眷言一杯酒，悽愴起離憂。", "夜花飄露氣，暗水急還流。", "雁行遙上月，蟲聲迥映秋。", "明日河梁上，誰與論仙舟。"]'),
('127c095a-7497-4325-a7c5-f1f6e3407af2','雨後','李百藥','唐','唐诗','tang','','[]','晚來風景麗，晴初物色華。',48,'全唐诗/poet.tang.2000.json','["晚來風景麗，晴初物色華。", "薄雲向空盡，輕虹逐望斜。", "後窗臨岸竹，前階枕浦沙。", "寂寥無與晤，尊酒論風花。"]'),
('16d5478a-d7b1-427b-8e6b-28f2d47d8fc7','文德皇后挽歌','李百藥','唐','唐诗','tang','','[]','裴回兩儀殿，悵望九成臺。',48,'全唐诗/poet.tang.2000.json','["裴回兩儀殿，悵望九成臺。", "玉輦終辭宴，瑤筐遂不開。", "野曠陰風積，川長思鳥來。", "寒山寂已暮，虞殯有餘哀。"]'),
('1f291438-5f13-449c-a049-b9e02cfe50b8','詠蟬','李百藥','唐','唐诗','tang','','[]','清心自飲露，哀響乍吟風。',24,'全唐诗/poet.tang.2000.json','["清心自飲露，哀響乍吟風。", "未上華冠側，先驚翳葉中。"]'),
('96c16098-4513-4a47-99f4-477de55b5244','詠螢火示情人','李百藥','唐','唐诗','tang','','[]','窗裏憐燈暗，階前畏月明。',24,'全唐诗/poet.tang.2000.json','["窗裏憐燈暗，階前畏月明。", "不辭逢露溼，祗爲重宵行。"]'),
('68342232-1a39-4c2b-979a-8d7dda75bff3','春眺','李百藥','唐','唐诗','tang','','[]','疲痾荷拙患，淪躓合幽襟。',24,'全唐诗/poet.tang.2000.json','["疲痾荷拙患，淪躓合幽襟。", "栖息在何處？丘中鳴素琴。"]'),
('e32e21ed-d6c6-4512-a45f-8dc1ef05f415','句','李百藥','唐','唐诗','tang','','[]','今日持團扇，非是爲秋風。',12,'全唐诗/poet.tang.2000.json','["今日持團扇，非是爲秋風。"]'),
('272e70ae-7357-4c26-bfed-6e16de2d59fe','奉和太子納妃太平公主出降','劉禕之','唐','唐诗','tang','','[]','夢梓光青陛，穠桃藹紫宮。',48,'全唐诗/poet.tang.2000.json','["夢梓光青陛，穠桃藹紫宮。", "德優宸念遠，禮備國姻崇。", "萬戶聲明發，三條騎吹通。", "香輪送重景，綵斾引仙虹。"]'),
('dd8ddf29-7238-467a-a4fd-f7dad1520b24','奉和別越王','劉禕之','唐','唐诗','tang','','[]','周屏辭金殿，梁驂整玉珂。',48,'全唐诗/poet.tang.2000.json','["周屏辭金殿，梁驂整玉珂。", "管聲依折柳，琴韻動流波。", "鶴蓋分陰促，龍軒別念多。", "延襟小山路，還起大風歌。"]'),
('c5fe28f5-9e56-472f-aef4-1bb7f6ff27d9','酬鄭沁州','劉禕之','唐','唐诗','tang','','[]','麒閣一代良，熊軒千里躅。',120,'全唐诗/poet.tang.2000.json','["麒閣一代良，熊軒千里躅。", "緝圖昭國典，按部留宸矚。", "匪厭承明廬，佇兼司隸局。", "芸書暫輟載，竹使方臨俗。", "節變風緒高，秋深露華溽。", "寒山斂輕靄，霽野澄初旭。", "已切長年悲，誰堪岐路促。", "遙林征馬迅，別館嘶驂跼。", "雅贈響摐金，索居暌倚玉。", "悽斷離鴻引，勞歌思足曲。"]'),
('9004484b-473f-48dd-862d-0c56bbffa8d3','孝敬皇帝挽歌','劉禕之','唐','唐诗','tang','','[]','戒奢虛蜃輅，錫號紀鴻名。',48,'全唐诗/poet.tang.2000.json','["戒奢虛蜃輅，錫號紀鴻名。", "地叶蒼梧野，途經紫聚城。", "重照掩寒色，晨飆斷曙聲。", "一隨仙驥遠，霜雪愁陰生。"]'),
('3a4f65f1-a96e-4257-9c0f-7e048aee3ac9','九成宮秋初應詔','劉禕之','唐','唐诗','tang','','[]','帝圃疏金闕，仙臺駐玉鑾。',72,'全唐诗/poet.tang.2000.json','["帝圃疏金闕，仙臺駐玉鑾。", "野分鳴鸑岫，路接寶雞壇。", "林樹千霜積，山宮四序寒。", "蟬急知秋早，鶯疎覺夏闌。", "怡神紫氣外，凝睇白雲端。", "舜海詞波發，空驚遊聖難。"]'),
('e9555fe3-1f41-4015-bade-c616a78e1079','奉和別魯王','李敬玄','唐','唐诗','tang','','[]','綠車旋楚服，丹蹕佇秦川。',84,'全唐诗/poet.tang.2000.json','["綠車旋楚服，丹蹕佇秦川。", "珠皐轉歸騎，金岸引行旃。", "一朝限原隰，千里間風煙。", "鶯喧上林谷，鳧響御溝泉。", "斷雲移魯蓋，離歌動舜弦。", "別念凝神扆，崇恩洽玳筵。", "顧惟慙叩寂，徒自仰鈞天。"]'),
('c9e86ab3-fe2e-4fc7-a063-ae784d77948e','奉和別越王','李敬玄','唐','唐诗','tang','','[]','飛蓋迴蘭坂，宸襟佇柏梁。',48,'全唐诗/poet.tang.2000.json','["飛蓋迴蘭坂，宸襟佇柏梁。", "別館分涇渭，歸路指衡漳。", "關山通曙色，林籞徧春光。", "帝念紆千里，詞波照五潢。"]'),
('ed717515-0b8b-44ba-a5c7-491867608b51','奉和別越王','張大安','唐','唐诗','tang','','[]','盛藩資右戚，連蕚重皇情。',48,'全唐诗/poet.tang.2000.json','["盛藩資右戚，連蕚重皇情。", "離襟愴睢苑，分途指鄴城。", "麗日開芳甸，佳氣積神京。", "何時驂駕入，還見謁承明。"]'),
('ef1b7dde-5d9c-49fb-8689-472d965c7ee2','奉和太子納妃太平公主出降','元萬頃','唐','唐诗','tang','','[]','象輅初乘鴈，璇宮早結褵。',48,'全唐诗/poet.tang.2000.json','["象輅初乘鴈，璇宮早結褵。", "離元應春夕，帝子降秋期。", "鳴瑜合清響，冠玉麗穠姿。", "和聲躋鳳掖，交影步鸞墀。"]'),
('5b760a75-8c4a-41c5-be5b-6e686b4b8c75','奉和春日池臺','元萬頃','唐','唐诗','tang','','[]','日影飛花殿，風文積草池。',24,'全唐诗/poet.tang.2000.json','["日影飛花殿，風文積草池。", "鳳樓通夜敞，虬輦望春移。"]'),
('d693186e-aedb-4ff9-b542-930f0411d3fb','奉和春日二首 一','元萬頃','唐','唐诗','tang','','[]','花輕蘂亂仙人杏，葉密鶯喧帝女桑。',32,'全唐诗/poet.tang.2000.json','["花輕蘂亂仙人杏，葉密鶯喧帝女桑。", "飛雲閣上春應至，明月樓中夜未央。"]'),
('c76de463-4f2f-4fb9-bd49-87679461a7d0','奉和春日二首 二','元萬頃','唐','唐诗','tang','','[]','鳳輦迎風乘紫閣，鸞車避日轉彤闈。',32,'全唐诗/poet.tang.2000.json','["鳳輦迎風乘紫閣，鸞車避日轉彤闈。", "中堂促管淹春望，後殿清歌開夜扉。"]'),
('e1af0e0c-8e7a-411b-a2f3-9b22858ccb77','奉和太子納妃太平公主出降','郭正一','唐','唐诗','tang','','[]','桂宮初服冕，蘭掖早升筓。',48,'全唐诗/poet.tang.2000.json','["桂宮初服冕，蘭掖早升筓。", "禮盛親迎晉，聲芬出降齊。", "金龜開瑞鈕，寶翟上仙袿。", "轉扇承宵月，揚旌照夕蜺。"]'),
('f9381d96-cea0-40cc-a3f0-99582b2323d3','奉和太子納妃太平公主出降三首 一','胡元範','唐','唐诗','tang','','[]','帝子威儀絕，儲妃禮度優。',48,'全唐诗/poet.tang.2000.json','["帝子威儀絕，儲妃禮度優。", "疊鼓陪仙觀，凝笳翼畫輈。", "鬱鬱神香滿，奕奕彩雲浮。", "排空列錦罽，騰歡溢皇州。"]'),
('4388e401-f0ac-441b-aa30-6d15ef6ff41c','奉和太子納妃太平公主出降三首 二','胡元範','唐','唐诗','tang','','[]','金閨未息火，玉樹鍾天愛。',48,'全唐诗/poet.tang.2000.json','["金閨未息火，玉樹鍾天愛。", "月路飾還裝，星津動歸佩。", "紫極流宸渥，清規佇慈誨。", "恩波洽九流，光輝軼千載。"]'),
('7b18b21c-9fe3-47e6-ab69-858602883e56','奉和太子納妃太平公主出降三首 三','胡元範','唐','唐诗','tang','','[]','列席詔親賢，式宴坐神仙。',48,'全唐诗/poet.tang.2000.json','["列席詔親賢，式宴坐神仙。", "聖文飛聖筆，天樂奏鈞天。", "曲池涵瑞景，文宇孕祥煙。", "小臣同百獸，率舞悅堯年。"]'),
('ff9bd7ac-738b-429b-ab14-95a38f0f585c','奉和太子納妃太平公主出降','任希古','唐','唐诗','tang','','[]','帝子陞青陛，王姬降紫宸。',48,'全唐诗/poet.tang.2000.json','["帝子陞青陛，王姬降紫宸。", "星光移雜珮，月彩薦重輪。", "龍旌翻地杪，鳳管颺天濱。", "槐陰浮淺瀨，葆吹翼輕塵。"]'),
('939e0995-4c5d-4af7-9f47-3c1ae9875797','和東觀羣賢七夕臨泛昆明池','任希古','唐','唐诗','tang','','[]','秋風始搖落，秋水正澄鮮。',120,'全唐诗/poet.tang.2000.json','["秋風始搖落，秋水正澄鮮。", "飛眺牽牛渚，激賞鏤鯨川。", "岸珠淪曉魄，池灰斂曙煙。", "泛查分寫漢，儀星別搆天。", "雲光波處動，日影浪中懸。", "驚鴻絓蒲弋，遊鯉入莊筌。", "萍葉疑江上，菱花似鏡前。", "長林代輕幄，細草即芳筵。", "文峰開翠瀲，筆海控清漣。", "不挹蘭樽聖，空仰桂舟仙。"]'),
('150c11df-3192-4d8e-84af-4aec7dd77da7','和左僕射燕公春日端居述懷','任希古','唐','唐诗','tang','','[]','豐野光三傑，嬀庭贊五臣。',144,'全唐诗/poet.tang.2000.json','["豐野光三傑，嬀庭贊五臣。", "綈緗歌美譽，絲竹詠芳塵。", "聖曆開環象，昌年降甫申。", "高門非捨築，華構豈垂綸。", "鳳邸摶霄翰，龍池躍海鱗。", "玉鼎昇黃閣，金章謁紫宸。", "禮闈通政本，文昌總國均。", "調風振薄俗，清教敘彝倫。", "星迴應緹管，日御警寅賓。", "葉上曾槐變，花發小堂春。", "思挂五都冕，言訪北山巾。", "赫赫容臺上，千祀耀平津。"]'),
('d46997eb-d100-4f71-94dc-3701e22d91c8','和長孫祕監伏日苦熱','任希古','唐','唐诗','tang','','[]','玉署三時曉，金羈五日歸。',62,'全唐诗/poet.tang.2000.json','["玉署三時曉，金羈五日歸。", "北林開逸徑，東閣敞閑扉。", "池鏡分天色，雲峰減日輝。", "游鱗映荷聚，驚翰遶林飛。", "披襟[揚]子宅，舒嘯仰重闈。"]'),
('cdc8c314-14e2-4e5d-a692-70986b3a2a25','和李公七夕','任希古','唐','唐诗','tang','','[]','落日照高牖，涼風起庭樹。',144,'全唐诗/poet.tang.2000.json','["落日照高牖，涼風起庭樹。", "悠悠天宇平，昭昭月華度。", "開軒卷綃幕，延首晞雲路。", "層漢有靈妃，仙居無與晤。", "履化悲流易，臨川怨遲暮。", "昔從九春徂，方此三秋遇。", "瑤駕越星河，羽蓋凝珠露。", "便妍耀井色，窈窕凌波步。", "始閱故人新，俄見新人故。", "掩淚收機石，銜啼襞紈素。", "惆悵何傷已，裴回勞永慕。", "無由西北歸，空自東南顧。"]'),
('98e0ab67-bf26-46e0-a938-9eada686fa37','和長孫祕監七夕','任希古','唐','唐诗','tang','','["\u4e03\u5915\u60c5\u4eba\u8282", "\u4e03\u5915\u8282", "\u79cb\u5929"]','二秋叶神媛，七夕望仙妃。',72,'全唐诗/poet.tang.2000.json','["二秋叶神媛，七夕望仙妃。", "影照河陽妓，色麗平津闈。", "鵲橋波裏出，龍車霄外飛。", "露泫低珠佩，雲移薦錦衣。", "更深黃月落，夜久靨星稀。", "空接靈臺下，方恧辨支機。"]'),
('61851d55-bb5e-45f0-8d07-4de1987575f7','奉和太子納妃太平公主出降三首 一','裴守真','唐','唐诗','tang','','[]','瑜珮升青殿，穠華降紫微。',50,'全唐诗/poet.tang.2000.json','["瑜珮升青殿，穠華降紫微。", "還如桃李發，更似鳳皇飛。", "金屋真離象，瑤臺起婺徽。", "綵纓紛碧坐，[繢]羽泛褕衣。"]'),
('f0364f72-dc5b-4561-8822-dcbe5dc310f1','奉和太子納妃太平公主出降三首 二','裴守真','唐','唐诗','tang','','[]','雲路移彤輦，天津轉明鏡。',48,'全唐诗/poet.tang.2000.json','["雲路移彤輦，天津轉明鏡。", "仙珠照乘歸，寶月重輪映。", "望園嘉宴洽，主第歡娛盛。", "絲竹揚帝熏，簪裾奉宸慶。"]'),
('d10771e6-f816-4f50-b4f6-249d338e3178','奉和太子納妃太平公主出降三首 三','裴守真','唐','唐诗','tang','','[]','藂雲靄曉光，湛露晞朝陽。',48,'全唐诗/poet.tang.2000.json','["藂雲靄曉光，湛露晞朝陽。", "天文天景麗，睿藻睿詞芳。", "玉庭散秋色，銀宮生夕涼。", "太平超邃古，萬壽樂無疆。"]'),
('10a7a237-cb33-495a-bf95-170cde661530','奉和聖製過溫湯','楊思玄','唐','唐诗','tang','','[]','豐城觀漢迹，溫谷幸秦餘。',60,'全唐诗/poet.tang.2000.json','["豐城觀漢迹，溫谷幸秦餘。", "地接幽王壘，塗分鄭國渠。", "風威肅文衛，日彩鏡雕輿。", "遠岫凝氛重，寒叢對影疎。", "迴瞻漢章闕，佳氣滿宸居。"]'),
('dcd6160c-5b84-4899-bebd-e43cd91ea49b','奉和別魯王','楊思玄','唐','唐诗','tang','','[]','元王詩傳博，文后寵靈優。',84,'全唐诗/poet.tang.2000.json','["元王詩傳博，文后寵靈優。", "鶴蓋動宸眷，龍章送遠遊。", "函關疏別道，灞岸引行舟。", "北林分苑樹，東流溢御溝。", "鳥聲含羽碎，騎影曳花浮。", "聖澤九垓普，天文七曜周。", "方圖獻雅樂，簪帶奉鳴球。"]'),
('cfdd75c5-3693-4edb-8f69-9894020e1de4','奉和聖製過溫湯','王德真','唐','唐诗','tang','','[]','握圖開萬宇，屬聖啓千年。',60,'全唐诗/poet.tang.2000.json','["握圖開萬宇，屬聖啓千年。", "驪阜疏緹騎，驚鴻映綵旃。", "玉霜鳴鳳野，金陣藻龍川。", "祥煙聚危岫，德水溢飛泉。", "停輿興睿覽，還舉大風篇。"]'),
('5ded1b93-1e2e-4f09-a407-cbf6edbd64aa','奉和聖製過溫湯','鄭義真','唐','唐诗','tang','','[]','洛川方駐蹕，豐野暫停鑾。',60,'全唐诗/poet.tang.2000.json','["洛川方駐蹕，豐野暫停鑾。", "湯泉恆獨涌，溫谷豈知寒。", "漏鼓依巖畔，相風出樹端。", "嶺煙遙聚草，山月迥臨鞍。", "日用誠多幸，天文遂仰觀。"]'),
('92681379-cbf2-4c6a-bc7c-b7e807cdccac','奉和展禮岱宗塗經濮濟','蕭楚材','唐','唐诗','tang','','["\u6cf0\u5c71"]','拂漢星旗轉，分霄日羽明。',60,'全唐诗/poet.tang.2000.json','["拂漢星旗轉，分霄日羽明。", "將追會阜跡，更勒岱宗銘。", "林戈咽濟岸，獸鼓震河庭。", "葉箭凌寒矯，鳥弓望曉驚。", "已降汾水作，仍深迎渭情。"]'),
('b96312f4-ef5f-41aa-86fa-488e23c8f5ce','奉和展禮岱宗塗經濮濟','薛克構','唐','唐诗','tang','','["\u6cf0\u5c71"]','龍圖冠胥陸，鳳駕指云亭。',60,'全唐诗/poet.tang.2000.json','["龍圖冠胥陸，鳳駕指云亭。", "非煙泛濟浦，綠字啓河汀。", "畫裳晨應月，文戟曙分星。", "四田巡揖禮，三驅道契經。", "行欣奉萬歲，竊抃偶千齡。"]'),
('13841a18-9cc4-4482-9aee-64c944898e64','日暮望涇水','徐珩','唐','唐诗','tang','','[]','導源徑隴阪，屬汭貫嬴都。',48,'全唐诗/poet.tang.2000.json','["導源徑隴阪，屬汭貫嬴都。", "下瀨波常急，迴圻溜亦紆。", "毒流秦卒斃，泥糞漢田腴。", "獨有迷津客，懷歸軫暮途。"]'),
('c4e13367-9756-4efa-8c1f-fc3b2231aad2','贈韓思彥','賀遂亮','唐','唐诗','tang','','[]','意氣百年內，平生一寸心。',72,'全唐诗/poet.tang.2000.json','["意氣百年內，平生一寸心。", "欲交天下士，未面已虛襟。", "君子重名義，直道冠衣簪。", "風雲行可託，懷抱自然深。", "落霞靜霜景，墜葉下風林。", "若上南登岸，希訪北山岑。"]'),
('c0b9d1cc-80ba-4807-a6c2-27836a34ed63','酬賀遂亮','韓思彥','唐','唐诗','tang','','[]','古人一言重，嘗謂百年輕。',72,'全唐诗/poet.tang.2000.json','["古人一言重，嘗謂百年輕。", "今投歡會面，顧盼盡平生。", "簪裾非所託，琴酒冀相倂。", "累日同游處，通宵欵素誠。", "霜飄知柳脆，雪冒覺松貞。", "願言何所道，幸得歲寒名。"]'),
('84794959-5249-4c3d-9cda-18ae875322b2','自御史左授山陽丞','魏求己','唐','唐诗','tang','','[]','朝昇照日檻，夕次下烏臺。',48,'全唐诗/poet.tang.2000.json','["朝昇照日檻，夕次下烏臺。", "風竿一眇邈，月樹幾裴回。", "翼向高標斂，聲隨下調哀。", "懷燕首自白，非是爲年催。"]'),
('e18429f0-43d1-4097-9f91-faf926c4a647','贈右臺監察鄧茂遷左臺殿中','劉懷一','唐','唐诗','tang','','[]','惟昔參多士，無雙仰異才。',72,'全唐诗/poet.tang.2000.json','["惟昔參多士，無雙仰異才。", "鷹鸇同效逐，鵷鷺忝游陪。", "入仕光三命，遷榮歷二臺。", "隔牆欽素躅，對問限清埃。", "紫署春光早，蘭闈曙色催。", "誰言夕鳥至，空想鄧林隈。"]'),
('bc80ffc7-f17e-446a-85d9-56aed2155a49','湘川新曲二首 一','杜易簡','唐','唐诗','tang','','[]','昭潭深無底，橘洲淺而浮。',36,'全唐诗/poet.tang.2000.json','["昭潭深無底，橘洲淺而浮。", "本欲凌波去，翻爲目成留。", "願君稍弭檝，無令賤妾羞。"]'),
('d2801b9b-c753-467c-8ef3-6de9a96d6705','湘川新曲二首 二','杜易簡','唐','唐诗','tang','','[]','二八相招攜，采菱渡前谿。',36,'全唐诗/poet.tang.2000.json','["二八相招攜，采菱渡前谿。", "弱腕隨橈起，纖腰向舸低。", "自解看花笑，憎聞染竹啼。"]'),
('3faf3410-28f6-457f-abf4-d16336cce25e','落成會詠一首','陳元光','唐','唐诗','tang','','[]','泉潮天萬里，一鎮屹天中。',108,'全唐诗/poet.tang.2000.json','["泉潮天萬里，一鎮屹天中。", "筮宅龍鍾地，承恩燕翼宮。", "環堂巍嶽秀，帶礪大江雄。", "輪奐雲霄望，晶華日月通。", "凌煙喬木茂，獻寶介圭崇。", "昆俊歌常棣，民和教即戎。", "盤庚遷美士，陶侃效兼庸。", "設醴延張老，開軒禮呂蒙。", "無孤南國仰，庶補聖皇功。"]'),
('041f5266-023d-424a-852c-9e92f3b4061d','示珦','陳元光','唐','唐诗','tang','','[]','恩銜楓陛渥，策向桂淵弘。',84,'全唐诗/poet.tang.2000.json','["恩銜楓陛渥，策向桂淵弘。", "載筆沿儒習，持弓纘祖風。", "祛災勦猛虎，溥德翊飛龍。", "日閱書開士，星言駕勸農。", "勤勞思命重，戲謔逐時空。", "百粵霧紛滿，諸戎澤普通。", "願言加壯努，勿坐鬢霜蓬。"]'),
('a2cdd49e-e29f-4f4e-b1ca-cbf2165b2ccd','太母魏氏半徑題石','陳元光','唐','唐诗','tang','','[]','喬岳標仙蹟，玄扃妥壽姬。',144,'全唐诗/poet.tang.2000.json','["喬岳標仙蹟，玄扃妥壽姬。", "烏號非嶺海，鶴仰向京師。", "繫牒公侯裔，懸弧將相兒。", "清貞蜚簡籍，規範肅門楣。", "萬里提兵路，三年報母慈。", "劒埋龍守壤，石臥虎司碑。", "憂闋情猶結，祥回禫屆期。", "竹符忠介凜，桐杖孝思淒。", "許史峋嶙篆，曹侯感舊詩。", "鴻濛山暝啓，駿彩德昭垂。", "華表瑤池冥，清漳玉樹枝。", "昭題盟岳瀆，展墓慶重熙。"]'),
('42f3a3f0-9d0d-467e-848c-8a0fe4f255bc','和陳元光平潮寇詩','許天正','唐','唐诗','tang','','[]','抱磴從天上，驅車返嶺東。',84,'全唐诗/poet.tang.2000.json','["抱磴從天上，驅車返嶺東。", "氣昂無醜虜，策妙詘羣雄。", "飛絮隨風散，餘氛響日鎔。", "長戈收百甲，聚騎破千重。", "落劒惟戎首，游繩繫脅從。", "四野無堅壁，羣生未化融。", "龍湖膏澤下，早晚徧枯窮。"]'),
('ab366c63-b6ce-4210-82f4-6f4c2621135e','詠牛應制','許圉師','唐','唐诗','tang','','[]','逸足還同驥，奇毛自偶麟。',24,'全唐诗/poet.tang.2000.json','["逸足還同驥，奇毛自偶麟。", "欲知花跡遠，雲影入天津。"]'),
('f82a580d-d750-49c9-99dd-309b71bc64a7','荅戶部員外賀遂涉戲贈','趙謙光','唐','唐诗','tang','','[]','錦帳隨情設，金鑪任意熏。',24,'全唐诗/poet.tang.2000.json','["錦帳隨情設，金鑪任意熏。", "惟愁員外署，不應列星文。"]'),
('e81b9c98-b5ed-47fa-824a-ebc4cff04eeb','送蘇尚書赴益州','鄭惟忠','唐','唐诗','tang','','[]','離憂將歲盡，歸望逐春來。',24,'全唐诗/poet.tang.2000.json','["離憂將歲盡，歸望逐春來。", "庭花如有意，留豔待人開。"]'),
('fa0fb4d9-c6e2-445f-aa45-66048025619b','詠燕','張鷟','唐','唐诗','tang','','[]','變石身猶重，銜泥力尚微。',24,'全唐诗/poet.tang.2000.json','["變石身猶重，銜泥力尚微。", "從來赴甲第，兩起一雙飛。"]'),
('2e58959d-fe91-4129-a956-36b42abd366a','嶺外守歲','李福業','唐','唐诗','tang','','[]','冬去更籌盡，春隨斗柄迴。',24,'全唐诗/poet.tang.2000.json','["冬去更籌盡，春隨斗柄迴。", "寒暄一夜隔，客鬢兩年催。"]'),
('d03a192f-7940-41a6-8c81-71c18169a3c6','奉和進船洛水應制','薛眘惑','唐','唐诗','tang','','[]','禁園紆睿覽，仙櫂叶宸遊。',48,'全唐诗/poet.tang.2000.json','["禁園紆睿覽，仙櫂叶宸遊。", "洛北風花樹，江南彩畫舟。", "榮生蘭蕙草，春入鳳皇樓。", "興盡離宮暮，煙光起夕流。"]'),
('3148b2e5-e3c2-4e8d-8d31-966c9adea836','奉和九月九日應制','賀敱','唐','唐诗','tang','','[]','商飆凝素籥，玄覽賁黃圖。',108,'全唐诗/poet.tang.2000.json','["商飆凝素籥，玄覽賁黃圖。", "曉霜驚斷雁，晨吹結栖烏。", "寒花低岸菊，涼葉下庭梧。", "澤宮申舊典，相圃叶前模。", "玉砌分雕戟，金溝轉鏤衢。", "帶星飛夏箭，映月上軒弧。", "慶展簪裾洽，恩融雨露濡。", "天文發丹篆，寶思掩玄珠。", "承歡徒抃舞，負弛竊忘軀。"]'),
('5d4e1930-659a-45dc-9c5d-6295f8ec33c4','奉和聖製夏日遊石淙山','狄仁傑','唐','唐诗','tang','','[]','宸暉降望金輿轉，仙路崢嶸碧澗幽。',64,'全唐诗/poet.tang.2000.json','["宸暉降望金輿轉，仙路崢嶸碧澗幽。", "羽杖遙臨鸞鶴駕，帷宮直坐鳳麟洲。", "飛泉灑液恆疑雨，密樹含涼鎮似秋。", "老臣預陪懸圃宴，餘年方共赤松遊。"]'),
('537ea290-9bc8-4ca1-85ef-333283704a98','修書院學士奉勅宴梁王宅','魏元忠','唐','唐诗','tang','','[]','大君敦宴賞，萬乘下梁園。',48,'全唐诗/poet.tang.2000.json','["大君敦宴賞，萬乘下梁園。", "酒助閑平樂，人霑雨露恩。", "榮光開帳殿，佳氣滿旌門。", "願陪南岳壽，長奉北宸樽。"]'),
('ec46607d-ef03-4008-b82e-e8b7a6a6db2d','銀潢宮侍宴應制','魏元忠','唐','唐诗','tang','','[]','別殿秋雲上，離宮夏景移。',48,'全唐诗/poet.tang.2000.json','["別殿秋雲上，離宮夏景移。", "寒風生玉樹，涼氣下瑤池。", "塹花仍吐葉，巖木尚抽枝。", "願奉南山壽，千秋長若斯。"]'),
('6c9c2b52-edc9-465d-bda7-ef8d4aa38756','折楊柳','韋承慶','唐','唐诗','tang','','[]','萬里邊城地，三春楊柳節。',48,'全唐诗/poet.tang.2000.json','["萬里邊城地，三春楊柳節。", "葉似鏡中眉，花如關外雪。", "征人遠鄉思，倡婦高樓別。", "不忍擲年華，含情寄攀折。"]'),
('f9722f9a-5865-4638-9961-96cad7cbab00','寒食應制','韋承慶','唐','唐诗','tang','','[]','鳳城春色晚，龍禁早暉通。',48,'全唐诗/poet.tang.2000.json','["鳳城春色晚，龍禁早暉通。", "舊火收槐燧，餘寒入桂宮。", "鶯啼正隱葉，雞鬬始開籠。", "藹藹瑤山滿，仙歌始樂風。"]'),
('d5c6ca0b-e8c8-4ab9-9b65-0f6298f9708c','凌朝浮江旅思','韋承慶','唐','唐诗','tang','','["\u6292\u60c5", "\u7f81\u65c5", "\u5199\u666f"]','天晴上初日，春水送孤舟。',48,'全唐诗/poet.tang.2000.json','["天晴上初日，春水送孤舟。", "山遠疑無樹，潮平似不流。", "岸花開且落，江鳥沒還浮。", "羈望傷千里，長歌遣四愁。"]'),
('0382cbde-c1d8-49da-ae39-540e0c1f8aca','直中書省','韋承慶','唐','唐诗','tang','','[]','清切鳳皇池，扶疎雞樹枝。',156,'全唐诗/poet.tang.2000.json','["清切鳳皇池，扶疎雞樹枝。", "唯應集鸞鷺，何爲宿羈雌。", "大造乾坤闢，深恩雨露垂。", "昆蚑皆含養，駑駘亦驅馳。", "木偶翻爲用，芝泥忽濫窺。", "九思空自勉，五字本無施。", "徒喜逢千載，何階荅二儀。", "螢光向日盡，蚊力負山疲。", "禁宇庭除闊，閑宵鐘箭移。", "暗花臨戶發，殘月下簾欹。", "白髮隨年改，丹心爲主披。", "命將時共泰，言與行俱危。", "寄謝巢由客，堯年正在斯。"]'),
('71ac5280-9b58-4381-ac21-23a62f486092','南行別弟','韋承慶','唐','唐诗','tang','','["\u957f\u6c5f"]','澹澹長江水，悠悠遠客情。',24,'全唐诗/poet.tang.2000.json','["澹澹長江水，悠悠遠客情。", "落花相與恨，到地一無聲。"]'),
('9cb8ce3e-dbe3-4e67-af00-a804071e351c','南中詠雁','韋承慶','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u601d\u4e61", "\u548f\u7269"]','萬里人南去，三春雁北飛。',24,'全唐诗/poet.tang.2000.json','["萬里人南去，三春雁北飛。", "不知何歲月？得與爾同歸。"]'),
('cb14448f-b5b5-4e78-811b-fd105d3e771c','江樓','韋承慶','唐','唐诗','tang','','[]','獨酌芳春酒，登樓已半曛。',24,'全唐诗/poet.tang.2000.json','["獨酌芳春酒，登樓已半曛。", "誰驚一行雁，衝斷過江雲。"]'),
('37ed7598-c25c-4394-95fc-36ba2fbd9e41','凝碧池侍宴看競渡應制','李懷遠','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','上苑清鑾路，高居重豫遊。',84,'全唐诗/poet.tang.2000.json','["上苑清鑾路，高居重豫遊。", "前對芙蓉沼，傍臨杜若洲。", "地如玄扈望，波似洞庭秋。", "列筵飛翠斝，分曹戲鷁舟。", "湍高櫂影沒，岸近榜歌遒。", "舞曲依鸞殿，簫聲下鳳樓。", "忽聞天上樂，疑逐海查流。"]'),
('ac1d8c07-f1ea-43c3-9a6c-5baee29578a4','奉和九月九日登慈恩寺浮圖應制','崔日用','唐','唐诗','tang','','[]','紫宸歡每洽，紺殿法初隆。',48,'全唐诗/poet.tang.2000.json','["紫宸歡每洽，紺殿法初隆。", "菊泛延齡酒，蘭吹解慍風。", "咸英調正樂，香梵徧秋空。", "臨幸浮天瑞，重陽日再中。"]'),
('d37add31-d4aa-40c6-8195-f44d72a66b8e','奉和聖製送張說巡邊','崔日用','唐','唐诗','tang','','[]','軒相推風后，周官重夏卿。',120,'全唐诗/poet.tang.2000.json','["軒相推風后，周官重夏卿。", "廟謀能允迪，韜略又縱橫。", "吉日四黃馬，宣王六月兵。", "擬清雞鹿塞，先指朔方城。", "列將懷威撫，匈奴畏盛名。", "去當推轂送，來佇出郊迎。", "絕漠蓬將斷，華筵槿正榮。", "壯心看舞劒，別緒應懸旌。", "睿錫承優旨，乾文復寵行。", "暫勞期永逸，赫矣振天聲。"]'),
('6102da34-bbc0-46b8-aecd-4d118e80c07c','奉和立春遊苑迎春應制','崔日用','唐','唐诗','tang','','[]','乘時迎氣正璿衡，灞滻煙氛向晚清。',64,'全唐诗/poet.tang.2000.json','["乘時迎氣正璿衡，灞滻煙氛向晚清。", "剪綺裁紅妙春色，宮梅殿柳識天情。", "瑤筐綵燕先呈端，金縷晨雞未學鳴。", "聖澤陽和宜宴樂，年年捧日向東城。"]'),
('e7f2d7f8-a6e2-4eb2-8c20-99db92f4dc7f','奉和聖製春日幸望春宮應制','崔日用','唐','唐诗','tang','','[]','東郊風物正熏馨，素滻鳧鷖戲綠汀。',64,'全唐诗/poet.tang.2000.json','["東郊風物正熏馨，素滻鳧鷖戲綠汀。", "鳳閣斜通平樂觀，龍旂直逼望春亭。", "光風搖動蘭英紫，淑氣依遲柳色青。", "渭浦明晨修禊事，羣公傾賀水心銘。"]'),
('ab913da7-fe1d-42d5-9afb-97d6c3224570','奉和人日重宴大明宮恩賜綵縷人勝應制','崔日用','唐','唐诗','tang','','[]','新年宴樂坐東朝，鐘鼓鏗鍠大樂調。',64,'全唐诗/poet.tang.2000.json','["新年宴樂坐東朝，鐘鼓鏗鍠大樂調。", "金屋瑤筐開寶勝，花箋綵筆頌春椒。", "曲池苔色冰前液，上苑梅香雪裏嬌。", "宸極此時飛聖藻，微臣竊抃預聞韶。"]'),
('5ea0b4eb-d6ef-4199-9b25-60f80722bb52','奉和聖製龍池篇','崔日用','唐','唐诗','tang','','[]','龍興白水漢興符，聖主時乘運斗樞。',64,'全唐诗/poet.tang.2000.json','["龍興白水漢興符，聖主時乘運斗樞。", "岸上䒠茸五花樹，波中的皪千金珠。", "操環昔聞迎夏啓，發匣先來瑞有虞。", "風色雲光隨隱見，赤雲神化象江湖。"]'),
('f80c6962-9af7-49db-830d-17412e18ea2a','夜宴安樂公主宅','崔日用','唐','唐诗','tang','','[]','銀燭金屏坐碧堂，只言河漢動神光。',32,'全唐诗/poet.tang.2000.json','["銀燭金屏坐碧堂，只言河漢動神光。", "主家盛時歡不極，才子能歌夜未央。"]'),
('f26fe1c9-3a67-417f-a738-6d0a919dad93','餞唐永昌','崔日用','唐','唐诗','tang','','[]','洛陽桴鼓今不鳴，朝野咸推重太平。',32,'全唐诗/poet.tang.2000.json','["洛陽桴鼓今不鳴，朝野咸推重太平。", "冬至冰霜俱怨別，春來花鳥若爲情。"]'),
('39390e9e-7226-46ff-b955-60a0bb460bca','奉和送金城公主適西蕃','崔日用','唐','唐诗','tang','','[]','聖后經綸遠，謀臣計畫多。',48,'全唐诗/poet.tang.2000.json','["聖后經綸遠，謀臣計畫多。", "受降追漢策，築館計戎和。", "俗化烏孫壘，春生積石河。", "六龍今出餞，雙鶴願爲歌。"]'),
('5646354e-0082-4b48-88b3-ff31b8ecabf6','句','崔日用','唐','唐诗','tang','','[]','彼名流兮左氏癖，意玄遠兮冠今夕。',16,'全唐诗/poet.tang.2000.json','["彼名流兮左氏癖，意玄遠兮冠今夕。"]'),
('429e15be-738b-416b-8e51-1d600e08ac10','奉和人日清暉閣宴羣臣遇雪應制','宗楚客','唐','唐诗','tang','','[]','窈窕神仙閣，參差雲漢間。',48,'全唐诗/poet.tang.2000.json','["窈窕神仙閣，參差雲漢間。", "九重中葉啓，七日早春還。", "太液天爲水，蓬萊雪作山。", "今朝上林樹，無處不堪攀。"]'),
('25dfc95b-7088-4eb3-b967-03820bc78859','安樂公主移入新宅侍宴應制','宗楚客','唐','唐诗','tang','','[]','星橋他日創，仙牓此時開。',48,'全唐诗/poet.tang.2000.json','["星橋他日創，仙牓此時開。", "馬向鋪錢埒，簫聞弄玉臺。", "人同衛叔美，客似長卿才。", "借問遊天漢，誰能取石回。"]'),
('b1c3aaca-f15c-47df-b5dc-16ac2d5464f8','正月晦日侍宴滻水應制賦得長字','宗楚客','唐','唐诗','tang','','[]','御輦出明光，乘流泛羽觴。',48,'全唐诗/poet.tang.2000.json','["御輦出明光，乘流泛羽觴。", "珠胎隨月減，玉漏與年長。", "寒盡梅猶白，風遲柳未黃。", "日斜旌騎轉，休氣滿林塘。"]'),
('5102dcfb-8520-471e-a5fc-7bf36b48ff74','奉和幸上陽宮侍宴應制','宗楚客','唐','唐诗','tang','','[]','紫庭金鳳闕，丹禁玉雞川。',72,'全唐诗/poet.tang.2000.json','["紫庭金鳳闕，丹禁玉雞川。", "似立蓬瀛上，疑遊崑閬前。", "鳥將歌合轉，花共錦爭鮮。", "湛露飛堯酒，熏風入舜弦。", "水光搖落日，樹色帶晴煙。", "向夕迴琱輦，佳氣滿巖泉。"]'),
('a68d3c9d-dad7-4f39-804c-5295b85101f9','奉和幸安樂公主山莊應制','宗楚客','唐','唐诗','tang','','[]','玉樓銀牓枕嚴城，翠蓋紅旂列禁營。',64,'全唐诗/poet.tang.2000.json','["玉樓銀牓枕嚴城，翠蓋紅旂列禁營。", "日映層巖圖畫色，風搖雜樹管弦聲。", "水邊重閣含飛動，雲裏孤峰類削成。", "幸覩八龍遊閬苑，無勞萬里訪蓬瀛。"]'),
('c30e4c1c-e83d-49fb-8bc9-35ec57d98bbb','奉和聖製喜雪應制','宗楚客','唐','唐诗','tang','','[]','飄飄瑞雪下山川，散漫輕飛集九埏。',64,'全唐诗/poet.tang.2000.json','["飄飄瑞雪下山川，散漫輕飛集九埏。", "似絮還飛垂柳陌，如花更繞落梅前。", "影隨明月團紈扇，聲將流水雜鳴弦。", "共荷神功萬庾積，終朝聖壽百千年。"]'),
('0277e0ca-9ba4-4748-98a8-663a5e1b27a0','句','宗楚客','唐','唐诗','tang','','[]','竹町羅千衛，蘭莛降兩宮。',36,'全唐诗/poet.tang.2000.json','["竹町羅千衛，蘭莛降兩宮。", "七萃鑾輿動，千年瑞檢開。", "綵旗臨鳳闕，翠幕遶龜津。"]'),
('83a2178a-099b-4e39-9c39-b0a022f8c229','奉和九日幸臨渭亭登高應制得暉字','蘇瓌','唐','唐诗','tang','','[]','重陽早露晞，睿賞瞰秋磯。',48,'全唐诗/poet.tang.2000.json','["重陽早露晞，睿賞瞰秋磯。", "菊氣先熏酒，萸香更襲衣。", "清切絲桐會，縱橫文雅飛。", "恩深荅效淺，留醉奉宸暉。"]'),
('2541506b-27b1-483c-952b-beb08f2bfe75','興慶池侍宴應制','蘇瓌','唐','唐诗','tang','','[]','金闕平明宿霧收，瑤池式宴俯清流。',64,'全唐诗/poet.tang.2000.json','["金闕平明宿霧收，瑤池式宴俯清流。", "瑞鳳飛來隨帝輦，祥魚出戲躍王舟。", "帷齊綠樹當筵密，蓋轉緗荷接岸浮。", "如臨竊比微臣懼，若濟叨陪聖主遊。"]'),
('d9566e5b-ddb3-4e5d-91c2-8c8efe97a2ae','奉和聖製燭龍齋祭','張九齡','唐','唐诗','tang','','[]','上帝臨下，鑒亦有光。',100,'全唐诗/poet.tang.2000.json','["上帝臨下，鑒亦有光。", "孰云陰隲，惟聖克彰。", "六月徂暑，四郊愆陽。", "我后其勤，告于壇場。", "精意允溢，羣靈鼓舞。", "蔚兮朝雲，沛然時雨。", "雨我原田，亦既有年。", "燭龍煌煌，明宗報祀。", "于以助之，天人帝子。", "聞詩有訓，國風茲始。"]'),
('9cbbc945-d6eb-4ada-8511-a45d7b8518c1','奉和聖製喜雨','張九齡','唐','唐诗','tang','','[]','艱我稼穡，載育載亭。',130,'全唐诗/poet.tang.2000.json','["艱我稼穡，載育載亭。", "隨物應之，曷聖與靈。", "謂我何憑，惟德之馨。", "誰云天遠，以誠必至。", "太清無雲，羲和頓轡。", "于斯烝人，瞻彼非覬。", "陰冥倏忽，沛澤咸洎。", "何以致之，我后之感。", "無皐無隰，黍稷黯黯。", "無卉無木，敷芬黮黤。", "黃龍勿來，鳴鳥不思。", "人和年豐，皇心則怡。", "豈與周宣，雲漢徒詩。"]'),
('a5f2288a-1511-4498-859c-4c588a8d4391','南郊文武出入舒和之樂','張九齡','唐','唐诗','tang','','[]','祝史辭正，人神慶叶。',40,'全唐诗/poet.tang.2000.json','["祝史辭正，人神慶叶。", "福以德昭，享以誠接。", "六變云備，百禮斯浹。", "祀事孔明，祚流萬葉。"]'),
('71bada30-9afa-49ec-b815-968c5306e107','奉和聖製幸晉陽宮','張九齡','唐','唐诗','tang','','[]','隋季失天策，萬方罹凶殘。',144,'全唐诗/poet.tang.2000.json','["隋季失天策，萬方罹凶殘。", "皇祖稱義旗，三靈皆獲安。", "聖期將申錫，王業成艱難。", "盜移未改命，曆在終履端。", "彼汾惟帝鄉，雄都信鬱盤。", "一月朔巡狩，羣后陪清鑾。", "霸跡在沛庭，舊儀覩漢官。", "唐風思何深？舜典敷更寬。", "戶蒙枌榆復，邑爭牛酒歡。", "緬惟翦商後，豈獨微禹歎。", "三后既在天，萬年斯不刊。", "尊祖實我皇，天文皆仰觀。"]'),
('a19b5bfa-bb35-4d92-80c1-13f1a7b02234','奉和聖製次成皐先聖擒建德之所','張九齡','唐','唐诗','tang','','[]','天命誠有集，王業初惟艱。',72,'全唐诗/poet.tang.2000.json','["天命誠有集，王業初惟艱。", "翦商自文祖，夷項在茲山。", "地識斬蛇處，河臨飲馬間。", "威加昔運往，澤流今聖還。", "尊祖頌先烈，賡歌安用攀。", "紹成即我后，封岱出天關。"]'),
('80bd6628-261d-41a9-852a-67f80285c53f','奉和聖製賜諸州刺史以題座右','張九齡','唐','唐诗','tang','','[]','聖人合天德，洪覆在元元。',120,'全唐诗/poet.tang.2000.json','["聖人合天德，洪覆在元元。", "每勞蒼生念，不以黃屋尊。", "興化俟羣辟，擇賢守列藩。", "得人此爲盛，咨岳今復存。", "降鑒引君道，殷勤啓政門。", "容光無不照，有象必爲言。", "成憲知所奉，致理歸其根。", "肅肅稟玄猷，煌煌戒朱軒。", "豈徒任遇重，兼爾宴錫繁。", "載聞勵臣節，持答明主恩。"]'),
('44ac8705-4526-4dcb-be9d-039279cd1178','奉和聖製送十道採訪使及朝集使','張九齡','唐','唐诗','tang','','[]','三年一上計，萬國趨河洛。',96,'全唐诗/poet.tang.2000.json','["三年一上計，萬國趨河洛。", "課最力已陳，賞延恩復博。", "垂衣深共理，改瑟其咸若。", "首路迴竹符，分鑣揚木鐸。", "戒程有攸往，詔餞無淹泊。", "昭晰動天文，殷勤在人瘼。", "持久望茲念，克終期所託。", "行矣當自強，春耕庶秋獲。"]'),
('0584ae56-f5a7-44c6-9af7-1b768459d7b1','奉和聖製謁玄元皇帝廟齋','張九齡','唐','唐诗','tang','','[]','興運昔有感，建祠北山巔。',120,'全唐诗/poet.tang.2000.json','["興運昔有感，建祠北山巔。", "雲雷初締構，日月今悠然。", "紫氣尚蓊鬱，玄元如在焉。", "迨茲事追遠，輪奐復增鮮。", "洞府香林處，齋壇清漢邊。", "吾君乃尊祖，夙駕此留連。", "樂動人神會，鐘成律度圓。", "笙歌下鸞鶴，芝朮萃靈仙。", "曾是福黎庶，豈唯味虛玄。", "賡歌徒有作，微薄謝昭宣。"]'),
('4406edea-27bd-40ec-9340-e33c43bfa149','巫山高','張九齡','唐','唐诗','tang','','[]','巫山與天近，煙景長青熒。',48,'全唐诗/poet.tang.2000.json','["巫山與天近，煙景長青熒。", "此中楚王夢，夢得神女靈。", "神女去已久，雲雨空冥冥。", "唯有巴猿嘯，哀音不可聽。"]'),
('6c1a8add-764b-466a-b14b-c329f00d7ef0','和黃門盧監望秦始皇陵','張九齡','唐','唐诗','tang','','[]','秦帝始求仙，驪山何遽卜。',120,'全唐诗/poet.tang.2000.json','["秦帝始求仙，驪山何遽卜。", "中年既無效，茲地所宜復。", "徒役如雷奔，珍怪亦雲蓄。", "黔首無寄命，赭衣相追逐。", "人怨神亦怒，身死宗遂覆。", "土崩失天下，龍鬬入函谷。", "國爲項籍屠，君同華元戮。", "始掘既由楚，終焚乃因牧。", "上宰議揚賢，中阿感桓速。", "一聞過秦論，載懷空杼軸。"]'),
('fdad555d-a566-4950-8508-2437c9359415','酬周判官巡至始興會改秘書少監見貽之作兼呈耿廣州','張九齡','唐','唐诗','tang','','[]','惟昔遷樂土，迨今已重世。',288,'全唐诗/poet.tang.2000.json','["惟昔遷樂土，迨今已重世。", "陰慶荷先德，素風慙後裔。", "唯益梓桑恭，豈稟山川麗。", "于時初自勉，揆己無兼濟。", "瘠土資勞力，良書啓蒙蔽。", "一探石室文，再擢金門第。", "既起南宮草，復掌西掖制。", "過舉及小人，便蕃在中歲。", "亞司河海秩，轉牧江湖澨。", "勿謂符竹輕，但覺涓塵細。", "一麾尚云忝，十駕宜求稅。", "心息已如灰，跡牽且爲贅。", "忽捧天書委，將革海隅弊。", "朝聞循誠節，夕飲蒙瘴癘。", "義疾恥無勇，盜憎攻亦銳。", "葵藿是傾心，豺狼何反噬。", "履險甘所受，勞賢恧相曳。", "攬轡但荒服，循陔便私第。", "嘉慶始獲申，恩華復相繼。", "無庸我先舉，同事君猶滯。", "當推奉使績，且結拜親契。", "更延懷安旨，曾是慮危際。", "善謀雖若茲，至理焉可替。", "所杖有神道，況承明主惠。"]'),
('cd14f44a-0c60-49ed-a8fd-4310a28f8823','和吏部李侍郎見示秋夜望月憶諸侍郎之什其卒章有前後行之戲因命僕繼作','張九齡','唐','唐诗','tang','','[]','清秋發高興，涼月復閑宵。',96,'全唐诗/poet.tang.2000.json','["清秋發高興，涼月復閑宵。", "光逐露華滿，情因水鏡搖。", "同時亦所見，異路無相招。", "美景向空盡，歡言隨事銷。", "忽聽金華作，誠如玉律調。", "南宮尚爲後，東觀何其遼。", "名數雖云隔，風期幸未遙。", "今來重餘論，懷此更終朝。"]'),
('c404b3a0-8660-43f2-9ad2-36b70d01c77b','登南嶽事畢謁司馬道士','張九齡','唐','唐诗','tang','','["\u8861\u5c71"]','將命祈靈嶽，迴策詣真士。',96,'全唐诗/poet.tang.2000.json','["將命祈靈嶽，迴策詣真士。", "絕跡尋一徑，異香聞數里。", "分庭八桂樹，肅容兩童子。", "入室希把袖，登牀願啓齒。", "誘我棄智訣，迨茲長生理。", "吸精反自然，鍊藥求不死。", "斯言眇霄漢，顧余嬰紛滓。", "相去九牛毛，慙歎知何已。"]'),
('3344d843-6e7e-423f-9ae6-d6c96689d34c','九月九日登龍山','張九齡','唐','唐诗','tang','','[]','郡庭常窘束，涼野求昭曠。',156,'全唐诗/poet.tang.2000.json','["郡庭常窘束，涼野求昭曠。", "楚客凜秋時，桓公舊臺上。", "清明風日好，歷落江山望。", "極遠何蕭條，中留坐惆悵。", "東彌夏首闊，西拒荆門壯。", "夷險雖異時，古今豈殊狀。", "先賢杳不接，故老猶可訪。", "投弔傷昔人，揮斤感前匠。", "自爲本疎散，未始忘幽尚。", "際會非有欲，往來是无妄。", "爲邦復多幸，去國殊遷放。", "且汎籬下菊，還聆郢中唱。", "灌園亦何爲，於陵乃逃相。"]'),
('d986c471-a075-481d-a7f2-952fa8e2c409','登郡城南樓','張九齡','唐','唐诗','tang','','[]','閉閣幸無事，登樓聊永日。',120,'全唐诗/poet.tang.2000.json','["閉閣幸無事，登樓聊永日。", "雲霞千里開，洲渚萬形出。", "澹澹澄江漫，飛飛度鳥疾。", "邑人半艫艦，津樹多楓橘。", "感別時已屢，憑眺情非一。", "遠懷不我同，孤興與誰悉。", "平生本單緒，邂逅承優秩。", "謬忝爲邦寄，多慙理人術。", "駑鉛雖自勉，倉廩素非實。", "陳力倘無効，謝病從芝朮。"]'),
('7d6c2871-a934-4de6-bd8c-bd1e892ec141','歲初巡屬縣登高安南樓言懷','張九齡','唐','唐诗','tang','','[]','山城本孤峻，憑高結層軒。',156,'全唐诗/poet.tang.2000.json','["山城本孤峻，憑高結層軒。", "江氣偏宜早，林英粲已繁。", "餘滋含宿霽，衆妍在朝暾。", "拂衣釋簿領，伏檻遺紛喧。", "深俯東溪澳，遠延南山樊。", "歸雲納前嶺，去鳥投遙村。", "目盡有餘意，心惻不可諼。", "朅來彭蠡澤，載經敷淺原。", "春及但生思，時哉無與言。", "不才叨過舉，唯力酬明恩。", "美化猶寂蔑，迅節徒飛奔。", "雖無成立効，庶以去思論。", "行復徇孤迹，亦云吾道存。"]'),
('a0f7f1e4-7cbb-43d4-9517-b795ca94fff8','秋晚登樓望南江入始興郡路','張九齡','唐','唐诗','tang','','["\u79cb\u5929", "\u4f24\u6000"]','潦收沙衍出，霜降天宇晶。',108,'全唐诗/poet.tang.2000.json','["潦收沙衍出，霜降天宇晶。", "伏檻一長眺，津途多遠情。", "思來江山外，望盡煙雲生。", "滔滔不自辨，役役且何成。", "我來颯衰鬢，孰云飄華纓。", "櫪馬苦踡跼，籠禽念遐征。", "歲陰向晼晚，日夕空屏營。", "物生貴得性，身累由近名。", "內顧覺今是，追歎何時平。"]'),
('c0cd2108-f068-4b92-ada5-5bfb7c5a7782','登古陽雲臺','張九齡','唐','唐诗','tang','','[]','庭樹日衰颯，風霜未云已。',84,'全唐诗/poet.tang.2000.json','["庭樹日衰颯，風霜未云已。", "駕言遣憂思，乘興求相似。", "楚國茲故都，蘭臺有餘址。", "傳聞襄王世，仍立巫山祀。", "方此全盛時，豈無嬋娟子。", "色荒神女至，魂蕩宮觀啓。", "蔓草今如積，朝雲爲誰起。"]'),
('6fefc21d-970a-40ba-aee7-6b831130b2af','與生公尋幽居處','張九齡','唐','唐诗','tang','','[]','同方久厭俗，相與事遐討。',132,'全唐诗/poet.tang.2000.json','["同方久厭俗，相與事遐討。", "及此雲山去，窅然巖徑好。", "疑入武陵源，如逢漢陰老。", "清諧欣有得，幽閑歘盈抱。", "我本玉階侍，偶訪金仙道。", "茲焉求卜築，所過皆神造。", "歲晚林始敷，日晏崖方杲。", "不種緣嶺竹，豈植臨潭草。", "即途可淹留，隨日成黼藻。", "期爲靜者說，曾是終焉保。", "今爲簡書畏，秖令歸思浩。"]'),
('72f55764-164d-48cc-a2a2-165be4a3c681','與生公遊石窟山','張九齡','唐','唐诗','tang','','[]','探秘孰云遠，忘懷復爾同。',96,'全唐诗/poet.tang.2000.json','["探秘孰云遠，忘懷復爾同。", "日尋高深意，宛是神仙中。", "躋險搆靈室，詭制非人功。", "潛洞黝無底，殊庭忽似夢。", "豈如武安鑿，自若茅山通。", "造物良有寄，嬉遊迺愜衷。", "猶希咽玉液，從此昇雲空。", "咄咄共攜手，泠然且馭風。"]'),
('5a71a229-d884-46dd-bf6a-089e69ee9278','郡舍南有園畦雜樹聊以永日','張九齡','唐','唐诗','tang','','[]','爲郡久無補，越鄉空復深。',120,'全唐诗/poet.tang.2000.json','["爲郡久無補，越鄉空復深。", "苟能秉素節，安用叨華簪。", "却步園畦裏，追吾野逸心。", "形骸拘俗吏，光景賴閑林。", "內訟誠知止，外言猶匪忱。", "成蹊謝李徑，衞足感葵陰。", "榮達豈不偉，孤生非所任。", "江城何寂歷，秋樹亦蕭森。", "下有北流水，上有南飛禽。", "我願從歸翼，無然坐自沈。"]'),
('0249981e-ab46-4b02-822d-97779f1c1b59','臨泛東湖','張九齡','唐','唐诗','tang','','[]','郡庭日休暇，湖曲邀勝踐。',156,'全唐诗/poet.tang.2000.json','["郡庭日休暇，湖曲邀勝踐。", "樂職在中和，靈心挹上善。", "乘流坐清曠，舉目眺悠緬。", "林與西山重，雲因北風卷。", "晶明畫不逮，陰影鏡無辨。", "晚秀復芬敷，秋光更遙衍。", "萬族紛可佳，一遊豈能展。", "羇孤忝邦牧，顧己非時選。", "梁公世不容，長孺心亦褊。", "永念出籠縶，常思退疲蹇。", "歲徂風露嚴，日恐蘭苕剪。", "佳辰不可得，良會何其鮮。", "罷興還江城，閉關聊自遣。"]'),
('f06c180b-3753-4b25-b5e4-6a809ed32b69','始興南山下有林泉嘗卜居焉荆州臥病有懷此地','張九齡','唐','唐诗','tang','','[]','出處各有在，何者爲陸沈。',156,'全唐诗/poet.tang.2000.json','["出處各有在，何者爲陸沈。", "幸無迫賤事，聊可祛迷襟。", "世路少夷坦，孟門未嶇嶔。", "多慙入火術，常惕履冰心。", "一跌不自保，萬全焉可尋。", "行行念歸路，眇眇惜光陰。", "浮生如過隙，先達已吾箴。", "敢忘丘山施，亦云年病侵。", "力衰在所養，時謝良不任。", "但憶舊棲息，願言遂窺臨。", "雲間日孤秀，山下面清深。", "蘿蔦自爲幄，風泉何必琴。", "歸此老吾老，還當日千金。"]'),
('c8e942b0-0407-45cc-92d9-1d6b27d868b8','晨坐齋中偶而成詠','張九齡','唐','唐诗','tang','','[]','寒露潔秋空，遙山紛在矚。',84,'全唐诗/poet.tang.2000.json','["寒露潔秋空，遙山紛在矚。", "孤頂乍修聳，微雲復相續。", "人茲賞地偏，鳥亦愛林旭。", "結念憑幽遠，撫躬曷羈束。", "仰霄謝逸翰，臨路嗟疲足。", "徂歲方暌攜，歸心亟躑躅。", "休閑倘有素，豈負南山曲。"]'),
('0aa91a05-c4ce-4593-8537-d89bda495082','詠史','張九齡','唐','唐诗','tang','','[]','大德始無頗，中智是所是。',120,'全唐诗/poet.tang.2000.json','["大德始無頗，中智是所是。", "居然已不一，況乃務相詭。", "小道致泥難，巧言因萋毀。", "穰侯或見遲，蘇生得陰揣。", "輕既長沙傅，重亦邊郡徙。", "勢傾不幸然，跡在胡寧爾。", "滄溟所爲大，江漢日來委。", "灃水雖復清，魚鼈豈游此。", "賢哉有小白，讎中有管氏。", "若人不世生，悠悠多如彼。"]'),
('8fe6b67d-539d-43e6-a172-19abd72c9434','龍門旬宴得月字韻','張九齡','唐','唐诗','tang','','[]','恩華逐芳歲，形勝兼韶月。',48,'全唐诗/poet.tang.2000.json','["恩華逐芳歲，形勝兼韶月。", "中席傍魚潭，前山倚龍闕。", "花迎妙妓至，鳥避仙舟發。", "宴賞良在茲，再來情不歇。"]'),
('5b6a0985-bf67-4083-8371-f0c415d20313','驪山下逍遙公舊居游集','張九齡','唐','唐诗','tang','','[]','君子體清尚，歸處有兼資。',168,'全唐诗/poet.tang.2000.json','["君子體清尚，歸處有兼資。", "雖然經濟日，無忘幽棲時。", "卜居舊何所，休澣嘗來茲。", "岑寂罕人至，幽深獲我思。", "松澗聆遺風，蘭林覽餘滋。", "往事誠已矣，道存猶可追。", "遺子後黃金，作歌先紫芝。", "明德有自來，奕世皆秉彝。", "豈與磻溪老，崛起周太師。", "我心希碩人，逮此問元龜。", "怊悵既懷遠，沈吟亦省私。", "已云寵祿過，況在華髮衰。", "軒蓋有迷復，丘壑無磷緇。", "感物重所懷，何但止足斯。"]'),
('3f30083f-23c2-4787-b60c-cfbb7567bf17','雜詩五首 一','張九齡','唐','唐诗','tang','','[]','孤桐亦胡爲，百尺傍無枝。',48,'全唐诗/poet.tang.2000.json','["孤桐亦胡爲，百尺傍無枝。", "疎陰不自覆，修幹欲何施。", "高岡地復迥，弱植風屢吹。", "凡鳥已相噪，鳳皇安得知。"]'),
('262d50a6-0dec-4cc8-af7d-5a65c39aa684','雜詩五首 二','張九齡','唐','唐诗','tang','','[]','蘿蔦必有託，風霜不能落。',48,'全唐诗/poet.tang.2000.json','["蘿蔦必有託，風霜不能落。", "酷在蘭將蕙，甘從葵與藿。", "運命雖爲宰，寒暑自回薄。", "悠悠天地間，委順無不樂。"]'),
('712be3c6-45f2-4948-b956-4c38335e5564','雜詩五首 三','張九齡','唐','唐诗','tang','','[]','良辰不可遇，心賞更蹉跎。',48,'全唐诗/poet.tang.2000.json','["良辰不可遇，心賞更蹉跎。", "終日塊然坐，有時勞者歌。", "庭前攬芳蕙，江上託微波。", "路遠無能達，憂情空復多。"]'),
('d00cec61-36f7-4af9-a4e3-4e731624cd7b','雜詩五首 四','張九齡','唐','唐诗','tang','','[]','湘水弔靈妃，斑竹爲情緒。',72,'全唐诗/poet.tang.2000.json','["湘水弔靈妃，斑竹爲情緒。", "漢水訪遊女，解佩欲誰與。", "同心不可見，異路空延佇。", "浦上青楓林，津傍白沙渚。", "行吟至落日，坐望秖愁予。", "神物亦豈孤，佳期竟何許。"]'),
('1398ae96-a9ff-43a3-90b6-62c92bc1fdb9','雜詩五首 五','張九齡','唐','唐诗','tang','','[]','木直幾自寇，石堅亦他攻。',96,'全唐诗/poet.tang.2000.json','["木直幾自寇，石堅亦他攻。", "何言爲用薄，而與火膏同。", "物類有固然，誰能取徑通。", "纖纖良田草，靡靡唯從風。", "日夜沐甘澤，春秋等芳叢。", "生性苟不夭，香臭誰爲中。", "道家貴至柔，儒生何固窮。", "終始行一意，無乃過愚公。"]'),
('9b4f2d56-6df4-4999-a82c-11283529dd51','感遇十二首 一','張九齡','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u54f2\u7406", "\u6292\u5fd7", "\u751f\u6d3b", "\u4e94\u8a00\u53e4\u8bd7", "\u690d\u7269"]','蘭葉春葳蕤，桂華秋皎潔。',48,'全唐诗/poet.tang.2000.json','["蘭葉春葳蕤，桂華秋皎潔。", "欣欣此生意，自爾爲佳節。", "誰知林棲者，聞風坐相悅。", "草木有本心，何求美人折。"]'),
('6df38a77-6e5d-43ae-a115-7de36475f53e','感遇十二首 二','張九齡','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5bd3\u4eba", "\u4e94\u8a00\u53e4\u8bd7", "\u54f2\u7406", "\u5199\u9e1f", "\u5bd3\u8a00"]','幽林歸獨臥，滯慮洗孤清。',48,'全唐诗/poet.tang.2000.json','["幽林歸獨臥，滯慮洗孤清。", "持此謝高鳥，因之傳遠情。", "日夕懷空意，人誰感至精。", "飛沈理自隔，何所慰吾誠。"]'),
('9d89b9e8-8deb-4969-ac17-4ea6ce0d299a','感遇十二首 三','張九齡','唐','唐诗','tang','','[]','魚游樂深池，鳥棲欲高枝。',60,'全唐诗/poet.tang.2000.json','["魚游樂深池，鳥棲欲高枝。", "嗟爾蜉蝣羽，薨薨亦何爲。", "有生豈不化，所感奚若斯。", "神理日微滅，吾心安得知。", "浩歎楊朱子，徒然泣路岐。"]'),
('f9798830-48c1-45e3-be90-4028d93954dc','感遇十二首 四','張九齡','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5bd3\u4eba", "\u4e94\u8a00\u53e4\u8bd7", "\u751f\u6d3b", "\u54f2\u7406", "\u6292\u6000"]','孤鴻海上來，池潢不敢顧。',60,'全唐诗/poet.tang.2000.json','["孤鴻海上來，池潢不敢顧。", "側見雙翠鳥，巢在三珠樹。", "矯矯珍木巔，得無金丸懼。", "美服患人指，高明逼神惡。", "今我遊冥冥，弋者何所慕。"]'),
('b3aa30ff-3a42-47ef-a176-c25d8536a261','感遇十二首 五','張九齡','唐','唐诗','tang','','[]','吳越數千里，夢寐今夕見。',48,'全唐诗/poet.tang.2000.json','["吳越數千里，夢寐今夕見。", "形骸非我親，衾枕即鄉縣。", "化蝶猶不識，川魚安可羨。", "海上有仙山，歸期覺神變。"]'),
('81a1887d-9a38-4135-ae3a-6e5f26698e4d','感遇十二首 六','張九齡','唐','唐诗','tang','','[]','西日下山隱，北風乘夕流。',72,'全唐诗/poet.tang.2000.json','["西日下山隱，北風乘夕流。", "燕雀感昏旦，簷楹呼匹儔。", "鴻鵠雖自遠，哀音非所求。", "貴人棄疵賤，下士嘗殷憂。", "衆情累外物，恕己忘內修。", "感歎長如此，使我心悠悠。"]'),
('11b013f9-aa6a-4e55-8e68-195dc62f161f','感遇十二首 七','張九齡','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5bd3\u4eba", "\u4e94\u8a00\u53e4\u8bd7", "\u548f\u7269", "\u4eba\u683c", "\u548f\u7269\u8bd7"]','江南有丹橘，經冬猶綠林。',60,'全唐诗/poet.tang.2000.json','["江南有丹橘，經冬猶綠林。", "豈伊地氣暖，自有歲寒心。", "可以薦嘉客，奈何阻重深。", "運命唯所遇，循環不可尋。", "徒言樹桃李，此木豈無陰。"]'),
('152e5db5-1760-4f47-aa39-494f47c256ef','感遇十二首 八','張九齡','唐','唐诗','tang','','[]','永日徒離憂，臨風懷蹇修。',48,'全唐诗/poet.tang.2000.json','["永日徒離憂，臨風懷蹇修。", "美人何處所？孤客空悠悠。", "青鳥跂不至，朱鱉誰云浮。", "夜分起躑躅，時逝曷淹留。"]'),
('0777f88b-b3c4-4efb-98cc-52711af60d10','感遇十二首 九','張九齡','唐','唐诗','tang','','[]','抱影吟中夜，誰聞此歎息。',48,'全唐诗/poet.tang.2000.json','["抱影吟中夜，誰聞此歎息。", "美人適異方，庭樹含幽色。", "白雲愁不見，滄海飛無翼。", "鳳皇一朝來，竹花斯可食。"]'),
('468d30a8-978e-49a0-aa3f-6390b0440b1f','感遇十二首 十','張九齡','唐','唐诗','tang','','[]','漢上有游女，求思安可得。',72,'全唐诗/poet.tang.2000.json','["漢上有游女，求思安可得。", "袖中一札書，欲寄雙飛翼。", "冥冥愁不見，耿耿徒緘憶。", "紫蘭秀空蹊，皓露奪幽色。", "馨香歲欲晚，感歎情何極。", "白雲在南山，日暮長太息。"]'),
('cbf565de-5d46-42a6-92ea-8593a6bc2229','感遇十二首 十一','張九齡','唐','唐诗','tang','','[]','我有異鄉憶，宛在雲溶溶。',60,'全唐诗/poet.tang.2000.json','["我有異鄉憶，宛在雲溶溶。", "憑此目不覯，要之心所鍾。", "但欲附高鳥，安敢攀飛龍。", "至精無感遇，悲惋填心胸。", "歸來扣寂寞，人願天豈從。"]'),
('9445cb2e-feca-4e06-9523-e98f6e9d22f3','感遇十二首 十二','張九齡','唐','唐诗','tang','','[]','閉門跡羣化，憑林結所思。',96,'全唐诗/poet.tang.2000.json','["閉門跡羣化，憑林結所思。", "嘯歎此寒木，疇昔乃芳蕤。", "朝陽鳳安在，日暮蟬獨悲。", "浩思極中夜，深嗟欲待誰。", "所懷誠已矣，既往不可追。", "鼎食非吾事，雲仙嘗我期。", "胡越方杳杳，車馬何遲遲。", "天壤一何異，幽嘿臥簾帷。"]'),
('015fb1b1-38b5-4343-85fd-8c05dce895cb','江上遇疾風','張九齡','唐','唐诗','tang','','[]','疾風江上起，鼓怒揚煙埃。',60,'全唐诗/poet.tang.2000.json','["疾風江上起，鼓怒揚煙埃。", "白晝晦如夕，洪濤聲若雷。", "投林鳥鎩羽，入浦魚曝鰓。", "瓦飛屋且發，帆快檣已摧。", "不知天地氣，何爲此喧豗。"]'),
('15007e5d-15e8-4ebb-9dc3-e35af867b9a3','自商行謁復州盧使君虔','孟郊','唐','唐诗','tang','','[]','一身遶千山，遠作行路人。',96,'全唐诗/poet.tang.20000.json','["一身遶千山，遠作行路人。", "未遂東吳歸，暫出西京塵。", "仲宣荆州客，今余竟陵賓。", "往蹟雖不同，託意皆有因。", "商嶺莓苔滑，石坂上下頻。", "江漢沙泥潔，永日光景新。", "獨淚起殘夜，孤吟望初晨。", "驅馳竟何事，章句依深仁。"]'),
('d9ac40a0-4639-4fcb-9520-7aecd5d4c9e6','夢澤中行','孟郊','唐','唐诗','tang','','[]','楚山爭蔽虧，日月無全輝。',48,'全唐诗/poet.tang.20000.json','["楚山爭蔽虧，日月無全輝。", "楚路饒迴惑，旅人有迷歸。", "騏驥思北首，鷓鴣願南飛。", "我懷京洛遊，未厭風塵衣。"]'),
('c956cd69-5f68-45a2-bf67-ac8ff591f77c','京山行','孟郊','唐','唐诗','tang','','[]','衆䖟聚病馬，流血不得行。',36,'全唐诗/poet.tang.20000.json','["衆䖟聚病馬，流血不得行。", "後路起夜色，前山聞虎聲。", "此時遊子心，百尺風中旌。"]'),
('bb5825af-7fba-4c01-bf48-c3bb17c9617f','旅次湘沅有懷靈均','孟郊','唐','唐诗','tang','','[]','分拙多感激，久遊遵長途。',240,'全唐诗/poet.tang.20000.json','["分拙多感激，久遊遵長途。", "經過湘水源，懷古方踟躕。", "舊稱楚靈均，此處殞忠軀。", "側聆故老言，遂得旌賢愚。", "名參君子場，行爲小人儒。", "騷文衒貞亮，體物情崎嶇。", "三黜有慍色，即非賢哲模。", "五十爵高秩，謬膺從大夫。", "胸襟積憂愁，容鬢復彫枯。", "死爲不弔鬼，生作猜謗徒。", "吟澤潔其身，忠節寧見輸。", "懷沙滅其性，孝行焉能俱。", "且聞善稱君，一何善自殊。", "且聞過稱己，一何過不渝。", "悠哉風土人，角黍投川隅。", "相傳歷千祀，哀悼延八區。", "如今聖明朝，養育無羈孤。", "君臣逸雍熙，德化盈紛敷。", "巾車徇前侶，白日猶昆吾。", "寄君臣子心，戒此真良圖。"]'),
('3d5b5fec-ba90-4b43-b1d4-7b0103cdfecd','過彭澤','孟郊','唐','唐诗','tang','','[]','揚帆過彭澤，舟人訝歎息。',24,'全唐诗/poet.tang.20000.json','["揚帆過彭澤，舟人訝歎息。", "不見種柳人，霜風空寂歷。"]'),
('81558696-7b82-4a2d-a6f6-40b6abeb8b83','過分水嶺','孟郊','唐','唐诗','tang','','[]','山壯馬力短，馬行石齒中。',60,'全唐诗/poet.tang.20000.json','["山壯馬力短，馬行石齒中。", "十步九舉轡，迴環失西東。", "溪水變爲雨，懸崖陰濛濛。", "客衣飄颻秋，葛花零落風。", "白日捨我沒，征途忽然窮。"]'),
('5c1944d5-903c-487e-86bd-c253d36f874b','分水嶺別夜示從弟寂','孟郊','唐','唐诗','tang','','[]','南中少平地，山水重疊生。',96,'全唐诗/poet.tang.20000.json','["南中少平地，山水重疊生。", "別泉萬餘曲，迷舟獨難行。", "四際亂峰合，一眺千慮幷。", "潺湲冬夏冷，光彩晝夜明。", "賞心難久勝，離腸忽自驚。", "古木搖霽色，高風動秋聲。", "飲爾一樽酒，慰我百憂輕。", "嘉期何處定，此晨堪寄情。"]'),
('12bda257-d0ec-425b-ae82-044bc5bd5252','連州吟 一','孟郊','唐','唐诗','tang','','[]','春風朝夕起，吹綠日日深。',72,'全唐诗/poet.tang.20000.json','["春風朝夕起，吹綠日日深。", "試爲連州吟，淚下不可禁。", "連山何連連，連天碧岑岑。", "哀猿哭花死，子規裂客心。", "蘭芷結新佩，瀟湘遺舊音。", "怨聲能翦弦，坐撫零落琴。"]'),
('36b6f467-dc98-4ac0-9b1b-316b4a65db43','連州吟 二','孟郊','唐','唐诗','tang','','[]','羽翼不自有，相追力難任。',96,'全唐诗/poet.tang.20000.json','["羽翼不自有，相追力難任。", "唯憑方寸靈，獨夜萬里尋。", "方尋魂飄颻，南夢山嶇嶔。", "髣髴驚魍魎，悉窣聞楓林。", "正直被放者，鬼魅無所侵。", "賢人多安排，俗士多虛欽。", "孤懷吐明月，衆毀鑠黃金。", "願君保玄曜，壯志無自沉。"]'),
('b6c96e59-7b85-441f-9dd6-eccdf167757c','連州吟 三','孟郊','唐','唐诗','tang','','[]','朝亦連州吟，暮亦連州吟。',96,'全唐诗/poet.tang.20000.json','["朝亦連州吟，暮亦連州吟。", "連州果有信，一紙萬里心。", "開緘白雲斷，明月墮衣襟。", "南風嘶舜琯，苦竹動猿音。", "萬里愁一色，瀟湘雨淫淫。", "兩劒忽相觸，雙蛟恣浮沈。", "鬬水正迴斡，倒流安可禁。", "空愁江海信，驚浪隔相尋。"]'),
('38745ddb-3c6b-429d-b0d4-d89824c3d6a4','旅行','孟郊','唐','唐诗','tang','','[]','楚水結冰薄，楚雲爲雨微。',24,'全唐诗/poet.tang.20000.json','["楚水結冰薄，楚雲爲雨微。", "野梅參差發，旅榜逍遙歸。"]'),
('18be44ca-4432-4648-9db6-c3b9bc5a8e3a','上河陽李大夫','孟郊','唐','唐诗','tang','','[]','上將秉神略，至兵無猛威。',108,'全唐诗/poet.tang.20000.json','["上將秉神略，至兵無猛威。", "三軍當嚴冬，一撫勝重衣。", "霜劒奪衆景，夜星失長輝。", "蒼鷹獨立時，惡鳥不敢飛。", "武牢鎖天關，河橋紐地機。", "大將奚以安，守此稱者稀。", "貧士少顏色，貴門多輕肥。", "試登山嶽高，方見草木微。", "山嶽恩既廣，草木心皆歸。"]'),
('3f954ce2-044e-45a3-9c6c-2f90a64718c8','投贈張端公','孟郊','唐','唐诗','tang','','[]','君子量不極，胸吞百川流。',72,'全唐诗/poet.tang.20000.json','["君子量不極，胸吞百川流。", "嫉邪霜氣直，問俗春辭柔。", "日戶晝輝靜，月杯夜景幽。", "詠驚芙蓉發，笑激風飆秋。", "鸞步獨無侶，鶴音仍寡儔。", "幸霑分寸顧，散此千萬憂。"]'),
('d5175448-bb74-43b5-9610-475dd2f92b7f','贈蘇州韋郎中使君','孟郊','唐','唐诗','tang','','[]','謝客吟一聲，霜落羣聽清。',96,'全唐诗/poet.tang.20000.json','["謝客吟一聲，霜落羣聽清。", "文含元氣柔，鼓動萬物輕。", "嘉木依性植，曲枝亦不生。", "塵埃徐庾詞，金玉曹劉名。", "章句作雅正，江山益鮮明。", "萍蘋一浪草，菰蒲片池榮。", "曾是康樂詠，如今搴其英。", "顧惟菲薄質，亦願將此幷。"]'),
('cd7e9429-04bb-4f9e-98f5-ba6ff5c4380c','上張徐州','孟郊','唐','唐诗','tang','','[]','爲水不入海，安得浮天波。',144,'全唐诗/poet.tang.20000.json','["爲水不入海，安得浮天波。", "爲木不在山，安得橫日柯。", "再來君子傍，始覺精義多。", "大德唯一施，衆情自偏頗。", "至樂無宮徵，至聲遺謳謌。", "願鼓空桑弦，永使萬物和。", "顧己誠拙訥，干名已蹉跎。", "獻詞惟在口，所欲無餘佗。", "乍作支泉石，乍作翳松蘿。", "一不改方圓，破質爲琢磨。", "賤子本如此，大賢心若何。", "豈是無異途，異途難經過。"]'),
('2bbe57c4-65b2-4f16-8039-2e2a70c1316a','上包祭酒','孟郊','唐','唐诗','tang','','[]','嶽嶽冠蓋彥，英英文字雄。',72,'全唐诗/poet.tang.20000.json','["嶽嶽冠蓋彥，英英文字雄。", "瓊音獨聽時，塵韻固不同。", "春雲生紙上，秋濤起胸中。", "時吟五君詠，再舉七子風。", "何幸松桂侶，見知勤苦功。", "願將黃鶴翅，一借飛雲空。"]'),
('b8edbaec-abd4-4508-96b5-5b99d41cdf2a','贈別崔純亮','孟郊','唐','唐诗','tang','','[]','食薺腸亦苦，強歌聲無歡。',192,'全唐诗/poet.tang.20000.json','["食薺腸亦苦，強歌聲無歡。", "出門即有礙，誰謂天地寬。", "有礙非遐方，長安大道傍。", "小人智慮險，平地生太行。", "鏡破不改光，蘭死不改香。", "始知君子心，交久道益彰。", "君心與我懷，離別俱迴遑。", "譬如浸蘖泉，流苦已日長。", "忍泣目易衰，忍憂形易傷。", "項籍豈不壯，賈生豈不良。", "當其失意時，涕泗各沾裳。", "古人勸加餐，此餐難自強。", "一飯九祝噎，一嗟十斷腸。", "況是兒女怨，怨氣凌彼蒼。", "彼蒼若有知，白日下清霜。", "今朝始驚歎，碧落空茫茫。"]'),
('722122cd-6919-4b44-938d-9ce698f0dfb0','贈文應上人','孟郊','唐','唐诗','tang','','[]','棲遲青山巔，高靜身所便。',60,'全唐诗/poet.tang.20000.json','["棲遲青山巔，高靜身所便。", "不踐有命草，但飲無聲泉。", "齋性空轉寂，學情深更專。", "經文開貝葉，衣製垂秋蓮。", "厭此俗人羣，暫來還却旋。"]'),
('2b326233-1546-4645-8931-5bc81bcec480','嚴河南','孟郊','唐','唐诗','tang','','[]','赤令風骨峭，語言清霜寒。',156,'全唐诗/poet.tang.20000.json','["赤令風骨峭，語言清霜寒。", "不必用雄威，見者毛髮攢。", "我有赤令心，未得赤令官。", "終朝衡門下，忍志將筑彈。", "君從西省郎，正有東洛觀。", "洛民蕭條久，威恩憫撫難。", "苦竹聲嘯雪，夜齋聞千竿。", "詩人偶寄耳，聽苦心多端。", "多端落杯酒，酒中方得歡。", "隱士多飲酒，此言信難刊。", "取次令坊沽，舉止務在寬。", "何必紅燭嬌，始言清宴闌。", "丈夫莫矜莊，矜莊不中看。"]'),
('97a3737c-dafe-4fbf-9cef-d59793fa827b','贈李觀','孟郊','唐','唐诗','tang','','[]','誰言形影親，燈滅影去身。',96,'全唐诗/poet.tang.20000.json','["誰言形影親，燈滅影去身。", "誰言魚水歡，水竭魚枯鱗。", "昔爲同恨客，今爲獨笑人。", "捨予在泥轍，飄跡上雲津。", "臥木易成蠹，棄花難再春。", "何言對芳景，愁望極蕭晨。", "埋劒誰識氣，匣弦日生塵。", "願君語高風，爲余問蒼旻。"]'),
('c5e26004-8a53-4cd3-bc7f-105c85b67b09','吳安西館贈從弟楚客','孟郊','唐','唐诗','tang','','[]','蒙籠楊柳館，中有南風生。',60,'全唐诗/poet.tang.20000.json','["蒙籠楊柳館，中有南風生。", "風生今爲誰，湘客多遠情。", "孤枕楚水夢，獨帆楚江程。", "覺來殘恨深，尚與歸路幷。", "玉匣五弦在，請君時一鳴。"]'),
('d751d09e-5305-4a2c-ab02-3a6beac7ebae','贈章仇將軍','孟郊','唐','唐诗','tang','','[]','將軍不誇劒，才氣爲英雄。',48,'全唐诗/poet.tang.20000.json','["將軍不誇劒，才氣爲英雄。", "五嶽拽力內，百川傾意中。", "本立誰敢拔，飛文自難窮。", "前時天地翻，已有扶正功。"]'),
('caed2f58-c96d-4d76-b27d-025989ec7125','贈道月上人','孟郊','唐','唐诗','tang','','[]','僧貌淨無點，僧衣寧綴華。',48,'全唐诗/poet.tang.20000.json','["僧貌淨無點，僧衣寧綴華。", "尋常晝日行，不使身影斜。", "飯朮煮松柏，坐山敷雲霞。", "欲知禪隱高，緝薜爲袈裟。"]'),
('5a9e3e53-cd89-43f4-a90f-f9f21e52899a','抒情因上郎中二十二叔監察十五叔兼呈李益端公柳縝評事','孟郊','唐','唐诗','tang','','[]','方憑指下弦，寫出心中言。',108,'全唐诗/poet.tang.20000.json','["方憑指下弦，寫出心中言。", "寸草賤子命，高山主人恩。", "遊邊風沙意，夢楚波濤魂。", "一日引別袂，九迴沾淚痕。", "自悲何以然，在禮闕晨昏。", "名利時轉甚，是非宵亦喧。", "浮情少定主，百慮隨世翻。", "舉此胸臆恨，幸從賢哲論。", "明明三飛鸞，照物如朝暾。"]'),
('a4a41811-d96e-4c66-bd18-54f4a135d638','贈城郭道士','孟郊','唐','唐诗','tang','','[]','望裏失却山，聽中遺却泉。',48,'全唐诗/poet.tang.20000.json','["望裏失却山，聽中遺却泉。", "松枝休策雲，藥囊翻貯錢。", "曾依青桂隣，學得白雪弦。", "別來意未迴，世上爲隱仙。"]'),
('bc0652a6-84c4-49e7-9f68-acdbe9e4de73','桐廬山中贈李明府','孟郊','唐','唐诗','tang','','["\u5e90\u5c71"]','靜境無濁氛，清雨零碧雲。',48,'全唐诗/poet.tang.20000.json','["靜境無濁氛，清雨零碧雲。", "千山不隱響，一葉動亦聞。", "即此佳志士，精微誰相羣。", "欲識楚章句，袖中蘭茝薰。"]'),
('d23cf818-caff-4858-b6f8-d7f178987574','獻漢南樊尚書','孟郊','唐','唐诗','tang','','[]','天下昔崩亂，大君識賢臣。',120,'全唐诗/poet.tang.20000.json','["天下昔崩亂，大君識賢臣。", "衆木盡搖落，始見竹色真。", "兵勢走山嶽，陽光潛埃塵。", "心開玄女符，面縛清波人。", "異俗既從化，澆風亦歸淳。", "自公理斯郡，寒谷皆變春。", "旗影卷赤電，劒鋒匣青鱗。", "如何嵩高氣，作鎮楚水濱。", "雲鏡忽開霽，孤光射無垠。", "乃知尋常鑒，照影不照神。"]'),
('c89c328c-c196-4212-a4e1-fde7e2798b61','贈轉運陸中丞','孟郊','唐','唐诗','tang','','[]','掌運職既大，摧邪名更雄。',120,'全唐诗/poet.tang.20000.json','["掌運職既大，摧邪名更雄。", "鵬飛簸曲雲，鶚怒生直風。", "投彼霜雪令，翦除荆棘叢。", "楚倉傾向西，吳米發自東。", "帆影咽河口，車聲聾關中。", "堯知才策高，人喜道路通。", "皆經內史力，繼得酇侯功。", "萊子真爲少，相如未免窮。", "衣花野菡萏，書葉山梧桐。", "不是宗匠心，誰憐久棲蓬。"]'),
('0dce990f-7981-4f47-93fb-69ee9ba11688','贈萬年陸郎中','孟郊','唐','唐诗','tang','','[]','天子憂劇縣，寄深華省郎。',72,'全唐诗/poet.tang.20000.json','["天子憂劇縣，寄深華省郎。", "紛紛風響珮，蟄蟄劒開霜。", "舊事笑堆案，新聲唯雅章。", "誰言百里才，終作橫天梁。", "江鴻恥承眷，雲津未能翔。", "徘徊塵俗中，短毳無輝光。"]'),
('5a27558b-ebcb-4073-a6fa-fe619881a570','擢第後東歸書懷獻座主呂侍御','孟郊','唐','唐诗','tang','','[]','昔歲辭親淚，今爲戀主泣。',180,'全唐诗/poet.tang.20000.json','["昔歲辭親淚，今爲戀主泣。", "去住情難竝，別離景易戢。", "夭矯大空鱗，曾爲小泉蟄。", "幽意獨沈時，震雷忽相及。", "神行既不宰，直致非所執。", "至運本遺功，輕生各自立。", "大君思此化，良佐自然集。", "寶鏡無私光，時文有新習。", "慈親誡志就，賤子歸情急。", "擢第謝靈臺，牽衣出皇邑。", "行襟海日曙，逸抱江風入。", "蒹葭得波浪，芙蓉紅岸濕。", "雲寺勢動搖，山鐘韻噓吸。", "舊遊期再踐，懸水得重挹。", "松蘿雖可居，青紫終當拾。"]'),
('fe123ad6-7f8b-4bc9-a03d-16c07efc1358','古意贈梁肅補闕','孟郊','唐','唐诗','tang','','[]','曲木忌日影，讒人畏賢明。',48,'全唐诗/poet.tang.20000.json','["曲木忌日影，讒人畏賢明。", "自然照燭間，不受邪佞輕。", "不有百煉火，孰知寸金精。", "金鉛正同鑪，願分精與麤。"]'),
('586b9736-995d-4a92-b4c5-a65e70432e96','贈黔府王中丞楚','孟郊','唐','唐诗','tang','','[]','舊說天下山，半在黔中青。',132,'全唐诗/poet.tang.20000.json','["舊說天下山，半在黔中青。", "又聞天下泉，半落黔中鳴。", "山水千萬遶，中有君子行。", "儒風一以扇，汙俗心皆平。", "我願中國春，化從異方生。", "昔爲陰草毒，今爲陽華英。", "嘉實綴綠蔓，涼湍瀉清聲。", "逍遙物景勝，視聽空曠幷。", "困驥猶在轅，沉珠尚隱精。", "路遐莫及眄，泥汙日已盈。", "歲晏將何從，落葉甘自輕。"]'),
('d975de03-a422-47c9-b4a1-30768576d816','上達奚舍人','孟郊','唐','唐诗','tang','','[]','北山少日月，草木苦風霜。',72,'全唐诗/poet.tang.20000.json','["北山少日月，草木苦風霜。", "貧士在重坎，食梅有酸腸。", "萬俗皆走圓，一身猶學方。", "常恐衆毀至，春葉成秋黃。", "大賢秉高鑒，公燭無私光。", "暗室曉未及，幽行涕空行。"]'),
('01413869-a26e-4025-af70-eea03a58cbfe','贈主人','孟郊','唐','唐诗','tang','','[]','斗水瀉大海，不如瀉枯池。',84,'全唐诗/poet.tang.20000.json','["斗水瀉大海，不如瀉枯池。", "分明賢達交，豈顧豪華兒。", "海有不足流，豪有不足資。", "枯鱗易爲水，貧士易爲施。", "幸覩君子席，會將幽賤期。", "側聞清風議，飫如黃金巵。", "此道與日月，同光無盡時。"]'),
('508a04f0-aed1-4158-aefe-be0ff41797ae','贈建業契公','孟郊','唐','唐诗','tang','','[]','師住青山寺，清華常繞身。',24,'全唐诗/poet.tang.20000.json','["師住青山寺，清華常繞身。", "雖然到城郭，衣不上棲塵。"]'),
('4bd8ab64-ee6d-4ba5-938c-85650dace115','獻襄陽于大夫','孟郊','唐','唐诗','tang','','[]','襄陽青山郭，漢江白銅堤。',132,'全唐诗/poet.tang.20000.json','["襄陽青山郭，漢江白銅堤。", "謝公領茲郡，山水無塵泥。", "鐵馬萬霜雪，絳旗千虹霓。", "風漪參差泛，石板重疊躋。", "舊淚不復墮，新歡居然齊。", "還畊竟原野，歸老相扶攜。", "物色增曖曖，寒芳更萋萋。", "淵清有遐略，高躅無近蹊。", "即此富蒼翠，自然引翔棲。", "曩遊常抱憶，夙好今尚暌。", "願言從逸轡，暇日凌清溪。"]'),
('c6bcc594-fe63-4aa7-8d76-3a15d7fba078','贈鄭夫子魴','孟郊','唐','唐诗','tang','','[]','天地入胸臆，吁嗟生風雷。',60,'全唐诗/poet.tang.20000.json','["天地入胸臆，吁嗟生風雷。", "文章得其微，物象由我裁。", "宋玉逞大句，李白飛狂才。", "苟非聖賢心，孰與造化該。", "勉矣鄭夫子，驪珠今始胎。"]'),
('ec94c0a3-ef97-4d8c-b008-3fd1764cd335','大隱坊 崔從事鄖以直隳職','孟郊','唐','唐诗','tang','','[]','古人留清風，千載遙贈君。',72,'全唐诗/poet.tang.20000.json','["古人留清風，千載遙贈君。", "破松見貞心，裂竹見直文。", "殘月色不改，高賢德常新。", "家懷詩書富，宅抱草木貧。", "安得一蹄泉，來化千尺鱗。", "含意永不語，釣璜幽水濱。"]'),
('b88f75dc-df70-45f9-87c9-11713eed0137','大隱坊 章仇將軍良棄功守貧','孟郊','唐','唐诗','tang','','["\u534e\u5c71"]','飲君江海心，詎能辨淺深。',72,'全唐诗/poet.tang.20000.json','["飲君江海心，詎能辨淺深。", "挹君山嶽德，誰能齊嶔岑。", "東海精爲月，西嶽氣凝金。", "進則萬景晝，退則羣物陰。", "我欲薦此言，天門峻沈沈。", "風飆亦感激，爲我颼飀吟。"]'),
('e2dd3fa6-35ad-47a2-bc87-9f4ce44faf33','大隱坊 趙記室俶在職無事','孟郊','唐','唐诗','tang','','[]','卑靜身後老，高動物先摧。',72,'全唐诗/poet.tang.20000.json','["卑靜身後老，高動物先摧。", "方圓水任器，剛勁木成灰。", "大道母羣物，達人腹衆才。", "時吟堯舜篇，心向無爲開。", "彼隱山萬曲，我隱酒一杯。", "公庭何所有，日日清風來。"]'),
('35e85885-54bb-4a99-ac17-260899034522','贈韓郎中愈 一','孟郊','唐','唐诗','tang','','[]','何以定交契，贈君高山石。',48,'全唐诗/poet.tang.20000.json','["何以定交契，贈君高山石。", "何以保貞堅，贈君青松色。", "貧居過此外，無可相彩飾。", "聞君碩鼠詩，吟之淚空滴。"]'),
('2c718f5d-5eee-4d05-bdd8-08ad87cd204c','贈韓郎中愈 二','孟郊','唐','唐诗','tang','','[]','碩鼠既穿墉，又嚙機上絲。',72,'全唐诗/poet.tang.20000.json','["碩鼠既穿墉，又嚙機上絲。", "穿墉有閑土，嚙絲無餘衣。", "朝吟枯桑柘，暮泣空杼機。", "豈是無巧妙，絲斷將何施。", "衆人尚肥華，志士多飢羸。", "願君保此節，天意當察微。"]'),
('691d3e81-f1d2-43ed-a8ce-181569c03d05','贈韓郎中愈 三','孟郊','唐','唐诗','tang','','[]','前日遠別離，今日生白髮。',36,'全唐诗/poet.tang.20000.json','["前日遠別離，今日生白髮。", "欲知萬里情，曉臥半牀月。", "常恐百蟲秋，使我芳草歇。"]'),
('22107002-3bdc-478c-a488-2aa99acc3f8b','戲贈無本 一','孟郊','唐','唐诗','tang','','[]','長安秋聲乾，木葉相號悲。',72,'全唐诗/poet.tang.20000.json','["長安秋聲乾，木葉相號悲。", "瘦僧臥冰凌，嘲詠含金痍。", "金痍非戰痕，峭病方在茲。", "詩骨聳東野，詩濤湧退之。", "有時踉蹌行，人驚鶴阿師。", "可惜李杜死，不見此狂癡。"]'),
('8b4c36ff-cac2-4e3d-97e2-9bcff5c4e3b8','戲贈無本 二','孟郊','唐','唐诗','tang','','[]','燕僧聳聽詞，袈裟喜新翻。',168,'全唐诗/poet.tang.20000.json','["燕僧聳聽詞，袈裟喜新翻。", "北岳厭利殺，玄功生微言。", "天高亦可飛，海廣亦可源。", "文章杳無底，劚掘誰能根。", "夢靈髣髴到，對我方與論。", "拾月鯨口邊，何人免爲吞。", "燕僧擺造化，萬有隨手犇。", "補綴雜霞衣，笑傲諸貴門。", "將明文在身，亦爾道所存。", "朔雪凝別句，朔風飄征魂。", "再期嵩少遊，一訪蓬蘿村。", "春草步步綠，春山日日暄。", "遙鶯相應吟，晚聽恐不繁。", "相思塞心胸，高逸難攀援。"]'),
('a8e9ed33-399c-4995-aae0-e0209c3eff2e','寄張籍','孟郊','唐','唐诗','tang','','[]','夜鏡不照物，朝光何時升。',108,'全唐诗/poet.tang.20000.json','["夜鏡不照物，朝光何時升。", "黯然秋思來，走入志士膺。", "志士惜時逝，一宵三四興。", "清漢徒自朗，濁河終無澄。", "舊愛忽已遠，新愁坐相凌。", "君其隱壯懷，我亦逃名稱。", "古人貴從晦，君子忌黨朋。", "傾敗生所競，保全歸懵懵。", "浮雲何當來，潛虯會飛騰。"]'),
('e7b782c4-dbcf-497a-b9ef-63ceacc60522','憶周秀才素上人時聞各在一方','孟郊','唐','唐诗','tang','','[]','東西分我情，魂夢安能定。',72,'全唐诗/poet.tang.20000.json','["東西分我情，魂夢安能定。", "野客雲作心，高僧月爲性。", "浮雲自高閑，明月常空淨。", "衣敝得古風，居山無俗病。", "吟聽碧雲語，手把青松柄。", "羨爾欲寄書，飛禽杳難倩。"]'),
('469ea863-7b08-4a83-824c-82ccf185f177','舟中喜遇從叔簡別後寄上時從叔初擢第歸江南郊不從行','孟郊','唐','唐诗','tang','','[]','一意兩片雲，暫合還却分。',36,'全唐诗/poet.tang.20000.json','["一意兩片雲，暫合還却分。", "南雲乘慶歸，北雲與誰羣。", "寄聲千里風，相喚聞不聞。"]'),
('151122cb-9900-416d-8b06-bafacb4e5549','懷南岳隱士 一','孟郊','唐','唐诗','tang','','[]','見說祝融峰，擎天勢似騰。',48,'全唐诗/poet.tang.20000.json','["見說祝融峰，擎天勢似騰。", "藏千尋布水，出十八高僧。", "古路無人跡，新霞吐石稜。", "終居將爾叟，一一共余登。"]'),
('370aba20-4559-4d44-99f4-c63a73126e38','懷南岳隱士 二','孟郊','唐','唐诗','tang','','[]','千峰映碧湘，真叟此中藏。',48,'全唐诗/poet.tang.20000.json','["千峰映碧湘，真叟此中藏。", "飯不煮石喫，眉應似髮長。", "楓梩搘酒甕，鶴蝨落琴牀。", "強效忘機者，斯人尚未忘。"]'),
('fecd42d7-482f-4022-8ca7-e7adcdf1169c','春夜憶蕭子真','孟郊','唐','唐诗','tang','','[]','半夜不成寐，燈盡又無月。',48,'全唐诗/poet.tang.20000.json','["半夜不成寐，燈盡又無月。", "獨向堦前立，子規啼不歇。", "況我有金蘭，忽爾爲胡越。", "爭得明鏡中，久長無白髮。"]'),
('661df0b5-7ae6-4190-bdf7-70a639fad61d','寄院中諸公','孟郊','唐','唐诗','tang','','[]','奕奕秋水傍，駸駸綠雲蹄。',96,'全唐诗/poet.tang.20000.json','["奕奕秋水傍，駸駸綠雲蹄。", "月仙有高曜，靈鳳無卑棲。", "翠色遶雲谷，碧華凝月溪。", "竹林遞歷覽，雲寺行攀躋。", "冠豸獨屈蠖，匣龍期剸犀。", "千山驚月曉，百里聞霜鼙。", "戎府多秀異，謝公期相攜。", "因之仰羣彥，養拙固難齊。"]'),
('eb282e80-c8c0-427b-a0f0-5f86341bb962','寄洺州李大夫','孟郊','唐','唐诗','tang','','[]','自從薊師反，中國事紛紛。',108,'全唐诗/poet.tang.20000.json','["自從薊師反，中國事紛紛。", "儒道一失所，賢人多在軍。", "鳥巢憂迸射，鹿耳駭驚聞。", "劍折唯恐匣，弓貪不讓勳。", "方知省事將，動必謝前羣。", "鸛陣常先罷，魚符最晚分。", "步閑洺水曲，笑激太行雲。", "詩叟未相識，竹兒爭見君。", "殷勤越談說，記盡古風文。"]'),
('b9c03668-409b-4290-b7cb-22c8b1ecdbd5','寄盧虔使君','孟郊','唐','唐诗','tang','','[]','霜露再相換，遊人猶未歸。',60,'全唐诗/poet.tang.20000.json','["霜露再相換，遊人猶未歸。", "歲新月改色，客久線斷衣。", "有鶴冰在翅，竟久力難飛。", "千家舊素沼，昨日生綠輝。", "春色若可借，爲君步芳菲。"]'),
('4dd4e413-e9fd-4afc-9c55-fff3ee1a86d3','寄崔純亮','孟郊','唐','唐诗','tang','','[]','百川有餘水，大海無滿波。',60,'全唐诗/poet.tang.20000.json','["百川有餘水，大海無滿波。", "器量各相懸，賢愚不同科。", "羣辯有姿語，衆歡無行歌。", "唯餘洛陽子，鬱鬱恨常多。", "時讀過秦篇，爲君涕滂沱。"]'),
('ddd8f318-28d9-45fe-9660-fac93b8210f4','汴州離亂後憶韓愈李翱','孟郊','唐','唐诗','tang','','[]','會合一時哭，別離三斷腸。',108,'全唐诗/poet.tang.20000.json','["會合一時哭，別離三斷腸。", "殘花不待風，春盡各飛揚。", "歡去收不得，悲來難自防。", "孤門清館夜，獨臥明月牀。", "忠直血白刃，道路聲蒼黃。", "食恩三千士，一旦爲豺狼。", "海島士皆直，夷門士非良。", "人心既不類，天道亦反常。", "自殺與彼殺，未知何者臧。"]'),
('037daca3-070f-4844-b52b-53ea28fbe276','寄張籍','孟郊','唐','唐诗','tang','','[]','未見天子面，不如雙盲人。',142,'全唐诗/poet.tang.20000.json','["未見天子面，不如雙盲人。", "賈生對文帝，終日猶悲辛。", "夫子亦如盲，所以空泣麟。", "有時獨齋心，髣髴夢稱臣。", "夢中稱臣言，覺後真埃塵。", "東京有眼富不如，西京無眼貧西京。", "無眼猶有耳隔牆，時聞天子車轔轔。", "轔轔車聲輾冰玉，南郊壇上禮百神。", "西明寺後窮瞎張太祝，縱爾有眼誰爾珍。", "天子咫尺不得見，不如閉眼且養真。"]'),
('c72ab4e6-6649-40e9-8c7a-f3e5bf6f3fe8','寄義興小女子','孟郊','唐','唐诗','tang','','[]','江南莊宅淺，所固唯疎籬。',108,'全唐诗/poet.tang.20000.json','["江南莊宅淺，所固唯疎籬。", "小女未解行，酒弟老更癡。", "家中多吳語，教爾遙可知。", "山怪夜動門，水妖時弄池。", "所憂癡酒腸，不解委曲辭。", "漁妾性崛強，耕童手皴釐。", "想茲爲襁褓，如鳥拾柴枝。", "我詠元魯山，胸臆流甘滋。", "終當學自乳，起坐常相隨。"]'),
('dddb79fa-7c1c-4854-9738-3d4de5dbfcce','憶江南弟','孟郊','唐','唐诗','tang','','[]','白首眼垂血，望爾唯夢中。',144,'全唐诗/poet.tang.20000.json','["白首眼垂血，望爾唯夢中。", "筋力強起時，魂魄猶在東。", "眼光寄明星，起來東望空。", "望空不見人，江海波無窮。", "衰老無氣力，呼叫不成風。", "孑然憶憶言，落地何由通。", "常師共被教，竟作生離翁。", "生離不可訴，上天何曾聰。", "未忍對松栢，自鞭殘朽躬。", "自鞭亦何益，知教非所崇。", "努力拄杖來，餘活與爾同。", "不然死後恥，遺死亦有終。"]'),
('18150e75-3efd-4f7d-a525-89761eb9b260','宿空姪院寄澹公','孟郊','唐','唐诗','tang','','[]','夜坐冷竹聲，二三高人語。',72,'全唐诗/poet.tang.20000.json','["夜坐冷竹聲，二三高人語。", "燈窗看律鈔，小師別爲侶。", "雪簷晴滴滴，茗椀華舉舉。", "磬音多風飆，聲韻聞江楚。", "官街不相隔，詩思空愁予。", "明日策杖歸，去住兩延佇。"]'),
('f7aab388-f346-40c3-809f-ca48fefe588c','寄陝府鄧給事','孟郊','唐','唐诗','tang','','[]','陝城臨大道，館宇屹幾鮮。',228,'全唐诗/poet.tang.20000.json','["陝城臨大道，館宇屹幾鮮。", "候謁隨芳語，鏗詞芬蜀牋。", "從來鏡目下，見盡道心前。", "自謂古詩量，異將新學偏。", "戇人年六十，每月請三千。", "不敢等閑用，願爲長壽錢。", "非關亦潔爾，將以救羸然。", "孤省癡皎皎，默吟寫綿綿。", "病書憑晝日，驛信寄宵鞭。", "疾訴將何諭，肆鱗今倒懸。", "塵鯉見枯浪，土鬣思乾泉。", "感感無緒蕩，愁愁作□邊。", "貞元文祭酒，比謹學韋玄。", "滿坐風無雜，當朝雅獨全。", "見知囑徐孺，賞句類陶淵。", "一顧生鴻羽，再言將鶴翩。", "宣揚隘車馬，君子湊駢闐。", "曾是此同睠，至今應賜憐。", "磨墨零落淚，楷字貢仁賢。"]'),
('2e6bfc9a-9e1a-42e6-bf59-89566c0b1932','送諫議十六叔至孝義渡後奉寄','孟郊','唐','唐诗','tang','','[]','曉渡明鏡中，霞衣相飄颻。',84,'全唐诗/poet.tang.20000.json','["曉渡明鏡中，霞衣相飄颻。", "浪鳧驚亦雙，蓬客將誰僚。", "別飲孤易醒，離憂壯難銷。", "文清雖無敵，儒貴不敢驕。", "江吏捧紫泥，海旗剪紅蕉。", "分明太守禮，跨躡毗陵橋。", "伊洛去未迴，遐矚空寂寥。"]'),
('c7029a7d-14d4-4ef3-a1fd-3924e4f1cc8d','至孝義渡寄鄭軍事唐二十五','孟郊','唐','唐诗','tang','','[]','咫尺不得見，心中空嗟嗟。',72,'全唐诗/poet.tang.20000.json','["咫尺不得見，心中空嗟嗟。", "官街泥水深，下脚道路斜。", "嵩少玉峻峻，伊雒碧華華。", "岸亭當四迥，詩老獨一家。", "洧叟何所如，鄭石唯有些。", "何當來說事，爲君開流霞。"]'),
('c2247f55-4e93-48ad-9ee3-3c65e0e55725','答友人','孟郊','唐','唐诗','tang','','[]','白日照清水，淺深無隱姿。',120,'全唐诗/poet.tang.20000.json','["白日照清水，淺深無隱姿。", "君子業高文，懷抱多正思。", "砥行碧山石，結交青松枝。", "碧山無轉易，青松難傾移。", "落落出俗韻，琅琅大雅詞。", "自非隨氏掌，明月安能持。", "千里不可倒，一返無近期。", "如何非意中，良覿忽在茲。", "道語必疎淡，儒風易凌遲。", "願存堅貞節，勿爲霜霰欺。"]'),
('e8842219-6716-4e7c-89e9-b92d58d8d654','酬友人見寄新文','孟郊','唐','唐诗','tang','','[]','爲客棲未定，況當玄月中。',96,'全唐诗/poet.tang.20000.json','["爲客棲未定，況當玄月中。", "繁雲翳碧霄，落雪和清風。", "郊陌絕行人，原隰多飛蓬。", "耕牛返村巷，野鳥依房櫳。", "我無饑凍憂，身託蓮花宮。", "安閑賴禪伯，復得疏塵蒙。", "覽君郢曲文，詞彩何沖融。", "謳吟不能已，頓覺形神空。"]'),
('33ca206a-03ef-462f-a1ad-beec2ba07560','答韓愈李觀別因獻張徐州','孟郊','唐','唐诗','tang','','[]','富別愁在顏，貧別愁銷骨。',180,'全唐诗/poet.tang.20000.json','["富別愁在顏，貧別愁銷骨。", "懶磨舊銅鏡，畏見新白髮。", "古樹春無花，子規啼有血。", "離弦不堪聽，一聽四五絕。", "世途非一險，俗慮有千結。", "有客步大方，驅車獨迷轍。", "故人韓與李，逸翰雙皎潔。", "哀我摧折歸，贈詞縱橫設。", "徐方國東樞，元戎天下傑。", "禰生投刺遊，王粲吟詩謁。", "高情無遺照，朗抱開曉月。", "有土不埋冤，有讎皆爲雪。", "願爲直草木，永向君地列。", "願爲古琴瑟，永向君聽發。", "欲識丈夫心，會將孤劍說。"]'),
('63a9811c-86f6-45ec-a071-c45f8463d5f7','答晝上人止讒作','孟郊','唐','唐诗','tang','','[]','烈烈鸑鷟吟，鏗鏗琅玕音。',60,'全唐诗/poet.tang.20000.json','["烈烈鸑鷟吟，鏗鏗琅玕音。", "梟摧明月嘯，鶴起清風心。", "渭水不可渾，涇流徒相侵。", "俗侶唱桃葉，隱士鳴桂琴。", "子野真遺却，浮淺藏淵深。"]'),
('813bcd01-9d71-4337-bb3b-615d83e9c631','答姚怤見寄','孟郊','唐','唐诗','tang','','[]','日月不同光，晝夜各有宜。',84,'全唐诗/poet.tang.20000.json','["日月不同光，晝夜各有宜。", "賢哲不苟合，出處亦待時。", "而我獨迷見，意求異士知。", "如將舞鶴管，誤向驚鳧吹。", "大雅難具陳，正聲易漂淪。", "君有丈夫淚，泣人不泣身。", "行吟楚山玉，義淚沾衣巾。"]'),
('4dfff14e-59b0-47fd-94a3-4dcb0dd5292a','答郭郎中','孟郊','唐','唐诗','tang','','[]','松栢死不變，千年色青青。',60,'全唐诗/poet.tang.20000.json','["松栢死不變，千年色青青。", "志士貧更堅，守道無異營。", "每彈瀟湘瑟，獨抱風波聲。", "中有失意吟，知者淚滿纓。", "何以報知者，永存堅與貞。"]'),
('cff74d90-de40-4e9a-a1b8-f3885700f76d','答盧虔故園見寄','孟郊','唐','唐诗','tang','','[]','訪舊無一人，獨歸清雒春。',48,'全唐诗/poet.tang.20000.json','["訪舊無一人，獨歸清雒春。", "花聞哭聲死，水見別容新。", "亂後故鄉宅，多爲行路塵。", "因悲楚左右，謗玉不知珉。"]'),
('e7dc3547-262e-46d9-8dc5-65e59847b438','汝墳蒙從弟楚材見贈時郊將入秦楚材適楚','孟郊','唐','唐诗','tang','','[]','朝爲主人心，暮爲行客吟。',60,'全唐诗/poet.tang.20000.json','["朝爲主人心，暮爲行客吟。", "汝水忽淒咽，汝風流苦音。", "北闕秦門高，南路楚石深。", "分淚灑白日，離腸繞青岑。", "何以寄遠懷，黃鶴能相尋。"]'),
('ebea1a6d-f894-4fbd-a4d7-71310b0b8ac5','同從叔簡酬盧殷少府','孟郊','唐','唐诗','tang','','[]','梅尉吟楚聲，竹風爲淒清。',48,'全唐诗/poet.tang.20000.json','["梅尉吟楚聲，竹風爲淒清。", "深虛冰在性，高潔雲入情。", "借水洗閑貌，寄蕉書逸名。", "羞將片石文，鬬此雙瓊英。"]'),
('e27ad4d3-aca5-4d2b-947f-3f3875c3e4a0','酬李侍御書記秋夕雨中病假見寄','孟郊','唐','唐诗','tang','','[]','秋風遶衰柳，遠客聞雨聲。',72,'全唐诗/poet.tang.20000.json','["秋風遶衰柳，遠客聞雨聲。", "重茲阻良夕，孤坐唯積誠。", "果枉移疾詠，中含嘉慮明。", "洗滌煩濁盡，視聽昭曠生。", "未覺衾枕倦，久爲章奏嬰。", "達人不寶藥，所保在閑情。"]'),
('65bd4ccd-a4b5-489f-9cc9-d575d5ef735c','答盧仝','孟郊','唐','唐诗','tang','','[]','楚屈入水死，詩孟踏雪僵。',204,'全唐诗/poet.tang.20000.json','["楚屈入水死，詩孟踏雪僵。", "直氣苟有存，死亦何所妨。", "日劈高查牙，清稜含冰漿。", "前古後古冰，與山氣勢強。", "閃怪千石形，異狀安可量。", "有時春鏡破，百道聲飛揚。", "潛仙不足言，朗客無隱腸。", "爲君傾海宇，日夕多文章。", "天下豈無緣，此山雪昂藏。", "煩君前致詞，哀我老更狂。", "狂歌不及狂，歌聲緣鳳皇。", "鳳兮何當來，消我孤直瘡。", "君文真鳳聲，宣隘滿鏗鏘。", "洛友零落盡，逮茲悲重傷。", "獨自奮異骨，將騎白角翔。", "再三勸莫行，寒氣有刀槍。", "仰慙君子多，慎勿作芬芳。"]'),
('788bf024-af98-4350-b910-fd112900b023','奉報翰林張舍人見遺之詩','孟郊','唐','唐诗','tang','','[]','百蟲笑秋律，清削月夜聞。',264,'全唐诗/poet.tang.20000.json','["百蟲笑秋律，清削月夜聞。", "曉稜視聽微，風剪葉已紛。", "君子鑒大雅，老人非俊羣。", "收拾古所棄，俛仰補空文。", "孤韻恥春俗，餘響逸零雰。", "自然蹈終南，滌暑凌寒氛。", "巖霰不知午，磵澌鎮含曛。", "曾是醒古醉，所以多隱淪。", "江調樂之遠，溪謠生徒新。", "衆蘊有餘采，寒泉空哀呻。", "南謝竟莫至，北宋當時珍。", "賾靈各自異，酌酒誰能均。", "昔詠多寫諷，今詞詎無因。", "品松何高翠，宮殿沒荒榛。", "苔趾識宏製，沙潨游崩津。", "忽吟陶淵明，此即羲皇人。", "心放出天地，形拘在風塵。", "前賢素行階，夙嗜青山勤。", "達士立明鏡，朗言爲近臣。", "將期律萬有，傾倒甄無垠。", "鸑鷟應蟋蟀，絲毫意皆申。", "況於三千章，哀叩不爲神。"]'),
('5a1659cf-edde-4a0a-b285-90e483003c2c','送從弟郢東歸','孟郊','唐','唐诗','tang','','[]','爾去東南夜，我無西北夢。',48,'全唐诗/poet.tang.20000.json','["爾去東南夜，我無西北夢。", "誰言貧別易，貧別愁更重。", "曉色奪明月，征人逐羣動。", "秋風楚濤高，旅榜將誰共。"]'),
('63c31a5c-2392-49c5-a0dc-b387ca65b716','山中送從叔簡赴舉','孟郊','唐','唐诗','tang','','[]','石根百尺杉，山眼一片泉。',48,'全唐诗/poet.tang.20000.json','["石根百尺杉，山眼一片泉。", "倚之道氣高，飲之詩思鮮。", "於此逍遙場，忽奏別離弦。", "却笑薜蘿子，不同鳴躍年。"]'),
('c3eb6869-21ba-4981-938c-0da0a127e375','送別崔寅亮下第','孟郊','唐','唐诗','tang','','[]','天地唯一氣，用之自偏頗。',84,'全唐诗/poet.tang.20000.json','["天地唯一氣，用之自偏頗。", "憂人成苦吟，達士爲高歌。", "君子識不淺，桂枝憂更多。", "歲晏期攀折，時歸且婆娑。", "素質如削玉，清詞若傾河。", "虯龍未化時，魚鱉同一波。", "去矣當自適，故鄉饒薜蘿。"]'),
('064df4f4-45b7-48c9-83ac-648bc4efc695','大梁送柳淳先入關','孟郊','唐','唐诗','tang','','[]','青山輾爲塵，白日無閑人。',48,'全唐诗/poet.tang.20000.json','["青山輾爲塵，白日無閑人。", "自古推高車，爭利西入秦。", "王門與侯門，待富不待貧。", "空攜一束書，去去誰相親。"]'),
('fbff6412-2ead-4d22-830c-084cb4941c74','送無懷道士遊富春山水','孟郊','唐','唐诗','tang','','[]','造化絕高處，富春獨多觀。',96,'全唐诗/poet.tang.20000.json','["造化絕高處，富春獨多觀。", "山濃翠滴灑，水折珠摧殘。", "溪鏡不隱髮，樹衣長遇寒。", "風猿虛空飛，月狖叫嘯酸。", "信此神僊路，豈爲時俗安。", "煮金陰陽火，囚怪星宿壇。", "花發我未識，玉生忽藂攢。", "蓬萊浮蕩漾，非道相從難。"]'),
('d7be84a2-5ba3-47f7-8305-00b604fcc052','送溫初下第','孟郊','唐','唐诗','tang','','[]','日落濁水中，夜光誰能分。',48,'全唐诗/poet.tang.20000.json','["日落濁水中，夜光誰能分。", "高懷無近趣，清抱多遠聞。", "欲識丈夫志，心藏孤岳雲。", "長安風塵別，咫尺不見君。"]'),
('9494d6f3-87a2-43e8-aa96-099f9f6c2f39','送盧虔端公守復州','孟郊','唐','唐诗','tang','','[]','師曠聽羣木，自然識孤桐。',96,'全唐诗/poet.tang.20000.json','["師曠聽羣木，自然識孤桐。", "正聲逢知音，願出大朴中。", "知音不韻俗，獨立占古風。", "忽挂觸邪冠，逮逐南飛鴻。", "肅肅太守章，明明華轂熊。", "商山無平路，楚水有驚潨。", "日月千里外，光陰難載同。", "新愁徒自積，良會何由通。"]'),
('687f2bd0-0bc8-4707-b619-e8b8b6d33549','送任載齊古二秀才自洞庭遊宣城','孟郊','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭非人境，道路行虛空。',108,'全唐诗/poet.tang.20000.json','["洞庭非人境，道路行虛空。", "二客月中下，一帆天外風。", "魚龍波五色，金碧樹千叢。", "閃怪如可懼，在誠無不通。", "扣奇知浩淼，采異訪穹崇。", "物表即高韻，人間訪仙公。", "宣城文雅地，謝守聲聞融。", "證玉易爲力，辨珉誰不同。", "從茲阮籍淚，且免泣途窮。"]'),
('62768965-b8e2-44ba-8bc0-d25a7c9a5919','送曉公歸庭山','孟郊','唐','唐诗','tang','','[]','庭山何崎嶇，寺路緣翠微。',60,'全唐诗/poet.tang.20000.json','["庭山何崎嶇，寺路緣翠微。", "秋霽山盡出，日落人獨歸。", "雲生高高步，泉灑田田衣。", "枯巢無還羽，新木有爭飛。", "茲焉不可繼，夢寐空清輝。"]'),
('7f7f9ddf-5c2d-4d93-ac43-d2e1ca1c3e2e','送豆盧策歸別墅','孟郊','唐','唐诗','tang','','[]','短松鶴不巢，高石雲不棲。',60,'全唐诗/poet.tang.20000.json','["短松鶴不巢，高石雲不棲。", "君今瀟湘去，意與雲鶴齊。", "力買奇險地，手開清淺溪。", "身披薜荔衣，山陟莓苔梯。", "一卷冰雪文，避俗常自攜。"]'),
('f403902a-a2a0-4547-8ba3-80a85a00be04','送清遠上人歸楚山舊寺','孟郊','唐','唐诗','tang','','[]','波中出吳境，霞際登楚岑。',48,'全唐诗/poet.tang.20000.json','["波中出吳境，霞際登楚岑。", "山寺一別來，雲蘿三改陰。", "詩誇碧雲句，道證青蓮心。", "應笑泛萍者，不知松隱深。"]'),
('4d84abcd-8cb0-4a3c-8450-cc42e408523b','山中送從叔簡','孟郊','唐','唐诗','tang','','[]','莫以手中瓊，言邀世上名。',48,'全唐诗/poet.tang.20000.json','["莫以手中瓊，言邀世上名。", "莫以山中迹，久向人間行。", "松栢有霜操，風泉無俗聲。", "應憐枯朽質，驚此別離情。"]'),
('189a38ce-6ebf-44f1-a12f-f8cbb8e5d34e','送蕭鍊師入四明山','孟郊','唐','唐诗','tang','','[]','閑於獨鶴心，大於高松年。',60,'全唐诗/poet.tang.20000.json','["閑於獨鶴心，大於高松年。", "迥出萬物表，高棲四明巔。", "千尋直裂峰，百尺倒瀉泉。", "絳雪爲我飯，白雲爲我田。", "靜言不語俗，靈蹤時步天。"]'),
('45e7589b-be3a-46bf-9399-5347bacfd8fd','感別送從叔校書簡再登科東歸','孟郊','唐','唐诗','tang','','[]','長安車馬道，高槐結浮陰。',84,'全唐诗/poet.tang.20000.json','["長安車馬道，高槐結浮陰。", "下有名利人，一人千萬心。", "黃鵠多遠勢，滄溟無近潯。", "怡怡靜退姿，泠泠思歸吟。", "菱唱忽生聽，芸書迴望深。", "清風散言笑，餘花綴衣襟。", "獨恨魚鳥別，一飛將一沈。"]'),
('d960fbb2-9162-4ed1-b8e7-7970b7fac129','送玄亮師','孟郊','唐','唐诗','tang','','[]','蘭泉滌我襟，杉月棲我心。',36,'全唐诗/poet.tang.20000.json','["蘭泉滌我襟，杉月棲我心。", "茗啜綠淨花，經誦清柔音。", "何處笑爲別，淡情愁不侵。"]'),
('0b75d681-74aa-4fc7-ad3c-8cda5d361266','送李尊師玄','孟郊','唐','唐诗','tang','','[]','口誦碧簡文，身是青霞君。',36,'全唐诗/poet.tang.20000.json','["口誦碧簡文，身是青霞君。", "頭冠兩片月，肩披一條雲。", "松骨輕自飛，鶴心高不羣。"]'),
('05979c1c-21bf-46ea-809e-ad7d6707eeff','同晝上人送郭秀才江南尋兄弟','孟郊','唐','唐诗','tang','','[]','地上春色生，眼前詩彩明。',48,'全唐诗/poet.tang.20000.json','["地上春色生，眼前詩彩明。", "手攜片寶月，言是高僧名。", "溪轉萬曲心，水流千里聲。", "飛鳴向誰去，江鴻弟與兄。"]'),
('a8a116dc-b0f6-47d8-b765-69ce805473a0','春日同韋郎中使君送鄒儒立少府扶侍赴雲陽','孟郊','唐','唐诗','tang','','[]','離思著百草，綿綿生無窮。',120,'全唐诗/poet.tang.20000.json','["離思著百草，綿綿生無窮。", "側聞畿甸秀，三振詞策雄。", "太守不韻俗，諸生皆變風。", "郡齋敞西清，楚瑟驚南鴻。", "海畔帝城望，雲陽天色中。", "酒酣正芳景，詩綴新碧叢。", "服綵老萊並，侍車江革同。", "過隋柳顦顇，入洛花蒙籠。", "高步詎留足，前程在層空。", "獨慙病鶴羽，飛送力難崇。"]'),
('ed947732-ca9c-4b2b-b96a-6c917796caba','送從叔校書簡南歸','孟郊','唐','唐诗','tang','','[]','長安別離道，宛在東南隅。',72,'全唐诗/poet.tang.20000.json','["長安別離道，宛在東南隅。", "寒草根未死，愁人心已枯。", "促促水上景，遙遙天際途。", "生隨昏曉中，皆被日月驅。", "北騎達山岳，南帆指江湖。", "高蹤一超越，千里在須臾。"]'),
('37972b94-000b-468a-9075-dbf997309066','送韓愈從軍','孟郊','唐','唐诗','tang','','[]','志士感恩起，變衣非變性。',120,'全唐诗/poet.tang.20000.json','["志士感恩起，變衣非變性。", "親賓改舊觀，僮僕生新敬。", "坐作羣書吟，行爲孤劍詠。", "始知出處心，不失平生正。", "淒淒天地秋，凜凜軍馬令。", "驛塵時一飛，物色極四靜。", "王師既不戰，廟略在無競。", "王粲有所依，元瑜初應命。", "一章喻檄明，百萬心氣定。", "今朝旌鼓前，笑別丈夫盛。"]'),
('310c962f-32b2-4f23-b973-59235cdf6fec','同茅郎中使君送河南裴文學','孟郊','唐','唐诗','tang','','[]','河南有歸客，江風繞行襟。',48,'全唐诗/poet.tang.20000.json','["河南有歸客，江風繞行襟。", "送君無塵聽，舞鶴清瑟音。", "菱蔓綴楚棹，日華正嵩岑。", "如何謝文學，還起會雲吟。"]'),
('8399a509-3f09-4027-a389-f5c4ba9e5dfe','送李翺習之','孟郊','唐','唐诗','tang','','[]','習之勢翩翩，東南去遙遙。',144,'全唐诗/poet.tang.20000.json','["習之勢翩翩，東南去遙遙。", "贈君雙履足，一爲上臯橋。", "臯橋路逶迤，碧水清風飄。", "新秋折藕花，應對吳語嬌。", "千巷分淥波，四門生早潮。", "湖榜輕褭褭，酒旗高寥寥。", "小時屐齒痕，有處應未銷。", "舊憶如霧星，怳見於夢消。", "言之燒人心，事去不可招。", "獨孤宅前曲，箜篌醉中謠。", "壯年俱悠悠，逮茲各焦焦。", "執手復執手，唯道無枯凋。"]'),
('18893e95-e3ef-4d84-a099-6a797a91df59','送丹霞子阮芳顏上人歸山','孟郊','唐','唐诗','tang','','[]','松色不肯秋，玉性不可柔。',48,'全唐诗/poet.tang.20000.json','["松色不肯秋，玉性不可柔。", "登山須正路，飲水須直流。", "倩鶴附書信，索雲作衣裘。", "仙村莫道遠，枉策招交游。"]'),
('57bf2a58-a86f-4365-8a37-2028e89e7a43','送從舅端適楚地','孟郊','唐','唐诗','tang','','[]','歸情似泛空，飄蕩楚波中。',48,'全唐诗/poet.tang.20000.json','["歸情似泛空，飄蕩楚波中。", "羽扇掃輕汗，布帆篩細風。", "江花折菡萏，岸影泊梧桐。", "元舅唱離別，賤生愁不窮。"]'),
('dc767945-04bd-42e2-ba0d-01d4b64ab5fb','送盧汀侍御歸天德幕','孟郊','唐','唐诗','tang','','["\u9ec4\u6cb3"]','仲宣領騎射，結束皆少年。',72,'全唐诗/poet.tang.20000.json','["仲宣領騎射，結束皆少年。", "匹馬黃河岸，射鵰清霜天。", "旌旗防日北，道路上雲巔。", "古雪無銷鑠，新冰有堆填。", "清溪徒聳誚，白璧自招賢。", "豈比重恩者，閉門方獨全。"]'),
('c49fefcb-a297-4850-a778-267e6f583e6b','送草書獻上人歸廬山','孟郊','唐','唐诗','tang','','["\u5e90\u5c71"]','狂僧不爲酒，狂筆自通天。',84,'全唐诗/poet.tang.20000.json','["狂僧不爲酒，狂筆自通天。", "將書雲霞片，直至清明巔。", "手中飛黑電，象外瀉玄泉。", "萬物隨指顧，三光爲迴旋。", "聚書雲霮䨴，洗硯山晴鮮。", "忽怒畫虵虺，噴然生風煙。", "江人願停筆，驚浪恐傾船。"]'),
('621cacb3-1e6d-4ad5-af43-f7dba7502681','和薛先輩送獨孤秀才上都赴嘉會得青字','孟郊','唐','唐诗','tang','','[]','秦雲攀窈窕，楚桂搴芳馨。',48,'全唐诗/poet.tang.20000.json','["秦雲攀窈窕，楚桂搴芳馨。", "五色豈徒爾，萬枝皆有靈。", "仙謠天上貴，林詠雪中青。", "持此一爲贈，送君翔杳冥。"]'),
('cad5b8e8-da6b-43a0-ae0d-c402495943c4','送崔爽之湖南','孟郊','唐','唐诗','tang','','[]','江與湖相通，二水洗高空。',48,'全唐诗/poet.tang.20000.json','["江與湖相通，二水洗高空。", "定知一日帆，使得千里風。", "雪唱與誰和，俗情多不通。", "何當逸翮縱，飛起泥沙中。"]'),
('f3d3999c-8bf8-48e3-9014-7fca647e2f8f','送超上人歸天台','孟郊','唐','唐诗','tang','','[]','天台山最高，動躡赤城霞。',84,'全唐诗/poet.tang.20000.json','["天台山最高，動躡赤城霞。", "何以靜雙目，掃山除妄花。", "何以潔其性，濾泉去泥沙。", "靈境物皆直，萬松無一斜。", "月中見心近，雲外將俗賒。", "山獸護方丈，山猿捧袈裟。", "遺身獨得身，笑我牽名華。"]'),
('b221fc00-ff01-48a4-8a62-a0e5f07ddba9','同李益崔放送王鍊師還樓觀兼爲羣公先營山居','孟郊','唐','唐诗','tang','','[]','十年白雲士，一卷紫芝書。',48,'全唐诗/poet.tang.20000.json','["十年白雲士，一卷紫芝書。", "來結崆峒侶，還期縹緲居。", "霞冠遺彩翠，月帔上空虛。", "寄謝泉根水，清泠閑有餘。"]'),
('82b7ccd3-cab7-479b-8308-b990601db6b7','張徐州席送岑秀才','孟郊','唐','唐诗','tang','','[]','振振芝蘭步，升自君子堂。',84,'全唐诗/poet.tang.20000.json','["振振芝蘭步，升自君子堂。", "泠泠松桂吟，生自楚客腸。", "羇鳥無定棲，驚蓬在他鄉。", "去茲門館閑，即彼道路長。", "雨餘山川淨，麥熟草木涼。", "楚淚滴章句，京塵染衣裳。", "贈君無餘佗，久要不可忘。"]'),
('46adb3aa-63a6-4481-b0f9-842f35cb1edb','送黃構擢第後歸江南','孟郊','唐','唐诗','tang','','[]','澹澹滄海氣，結成黃香才。',108,'全唐诗/poet.tang.20000.json','["澹澹滄海氣，結成黃香才。", "幼齡思奮飛，弱冠遊靈臺。", "一鶚顧喬木，衆禽不敢猜。", "一驥騁長衢，衆獸不敢陪。", "遂得會風雨，感通如雲雷。", "至矣小宗伯，確乎心不回。", "能令幽靜人，聲實喧九垓。", "却憶江南道，祖筵花裏開。", "春風不能別，別罷空徘徊。"]'),
('17cf9768-34e4-4556-ba50-990284295cd8','送道士','孟郊','唐','唐诗','tang','','[]','千年山上行，山上無遺蹤。',36,'全唐诗/poet.tang.20000.json','["千年山上行，山上無遺蹤。", "一日人間游，六合人皆逢。", "自有意中侶，白寒徒相從。"]'),
('a5149be2-c4a5-481a-a7fe-45cf35f6986a','送孟寂赴舉','孟郊','唐','唐诗','tang','','[]','烈士不憂身，爲君吟苦辛。',72,'全唐诗/poet.tang.20000.json','["烈士不憂身，爲君吟苦辛。", "男兒久失意，寶劍亦生塵。", "浮俗官是貴，君子道所珍。", "況當聖明主，豈乏證玉臣。", "濁水無白日，清流鑒蒼旻。", "賢愚皎然別，結交當有因。"]'),
('f4059c1d-f2c1-435f-89b1-f002888bc682','同溧陽宰送孫秀才','孟郊','唐','唐诗','tang','','[]','廢瑟難爲弦，南風難爲歌。',60,'全唐诗/poet.tang.20000.json','["廢瑟難爲弦，南風難爲歌。", "幽幽拙疾中，忽忽浮夢多。", "清韻始嘯侶，雅言相與和。", "訟閑每往招，祖送奈若何。", "牽苦強爲贈，邦邑光峨峨。"]'),
('9cbe556f-8306-4645-88eb-361b09a7d979','溧陽唐興寺觀薔薇花同諸公餞陳明府','孟郊','唐','唐诗','tang','','[]','忽驚紅琉璃，千豔萬豔開。',48,'全唐诗/poet.tang.20000.json','["忽驚紅琉璃，千豔萬豔開。", "佛火不燒物，淨香空徘徊。", "花下印文字，林間詠觴杯。", "羣官餞宰官，此地車馬來。"]'),
('baff4e4c-909c-4e66-a2ea-fd3e22ca827c','送柳淳','孟郊','唐','唐诗','tang','','["\u9ec4\u6cb3"]','青山臨黃河，下有長安道。',24,'全唐诗/poet.tang.20000.json','["青山臨黃河，下有長安道。", "世上名利人，相逢不知老。"]'),
('f655033f-c2a8-4698-928e-1fbfada5043e','送殷秀才南遊','孟郊','唐','唐诗','tang','','[]','詩句臨離袂，酒花薰別顏。',48,'全唐诗/poet.tang.20000.json','["詩句臨離袂，酒花薰別顏。", "水程千里外，岸泊幾宵間。", "風葉亂辭木，雪猿清叫山。", "南中多古事，詠遍始應還。"]'),
('6396f1dc-ee8a-4de1-a0b6-27790160e4ad','送青陽上人遊越','孟郊','唐','唐诗','tang','','[]','秋風吹白髮，微官自蕭索。',60,'全唐诗/poet.tang.20000.json','["秋風吹白髮，微官自蕭索。", "江僧何用歎，溪縣饒寂寞。", "楚思物皆清，越山勝非薄。", "時看鏡中月，獨向衣上落。", "多謝入冥鴻，笑予在籠鶴。"]'),
('125c7c19-81d4-49af-9ea9-46464546e7ba','奉同朝賢送新羅使','孟郊','唐','唐诗','tang','','[]','淼淼望遠國，一萍秋海中。',108,'全唐诗/poet.tang.20000.json','["淼淼望遠國，一萍秋海中。", "恩傳日月外，夢在波濤東。", "浪興豁胸臆，泛程舟虛空。", "既茲吟仗信，亦以難私躬。", "實怪賞不足，異鮮悅多叢。", "安危所繫重，征役誰能窮。", "彼俗媚文史，聖朝富才雄。", "送行數百首，各以鏗奇工。", "宂隸竊抽韻，孤屬思將同。"]'),
('0997f50b-783b-4efc-a4ec-f2b949a06808','留弟郢不得送之江南','孟郊','唐','唐诗','tang','','[]','剛有下水船，白日留不得。',24,'全唐诗/poet.tang.20000.json','["剛有下水船，白日留不得。", "老人獨自歸，苦淚滿眼黑。"]'),
('fd692f85-49ad-4f35-a8f2-a7977ab14dc1','送陸暢歸湖州因憑題故人皎然塔陸羽墳','孟郊','唐','唐诗','tang','','[]','淼淼霅寺前，白蘋多清風。',156,'全唐诗/poet.tang.20000.json','["淼淼霅寺前，白蘋多清風。", "昔游詩會滿，今游詩會空。", "孤吟玉淒惻，遠思景蒙籠。", "杼山塼塔禪，竟陵廣宵翁。", "饒彼草木聲，髣髴聞餘聰。", "因君寄數句，遍爲書其藂。", "追吟當時說，來者實不窮。", "江調難再得，京塵徒滿躬。", "送君溪鴛鴦，彩色雙飛東。", "東多高靜鄉，芳宅冬亦崇。", "手自擷甘旨，供養歡沖融。", "待我遂前心，收拾使有終。", "不然洛岸亭，歸死爲大同。"]'),
('0582cfee-1ad6-484c-8ceb-e9e33d21b4ec','送淡公 一','孟郊','唐','唐诗','tang','','[]','燕本冰雪骨，越淡蓮花風。',107,'全唐诗/poet.tang.20000.json','["燕本冰雪骨，越淡蓮花風。", "五言雙寶刀，聯響高飛鴻。", "翰苑錢舍人，詩韻鏗雷公。", "識本未識淡，仰詠嗟無窮。", "清恨生物表，朗玉傾夢中。", "常於冷竹坐，相語道意沖。", "嵩洛興不薄，稽江事難同。", "明年若不來，我作黃蒿翁。", "何以兀其心爲君學虛空。"]'),
('36d5b37a-fcc1-4f31-9234-0ff7fba0036b','送淡公 二','孟郊','唐','唐诗','tang','','[]','坐愛青草上，意含滄海濱。',60,'全唐诗/poet.tang.20000.json','["坐愛青草上，意含滄海濱。", "渺渺獨見水，悠悠不問人。", "鏡浪洗手綠，剡花入心春。", "雖然防外觸，無奈饒衣新。", "行當譯文字，慰此吟殷勤。"]'),
('b187c5fa-984c-4de9-ac1b-101ca446dbd9','送淡公 三','孟郊','唐','唐诗','tang','','[]','銅斗飲江酒，手拍銅斗歌。',60,'全唐诗/poet.tang.20000.json','["銅斗飲江酒，手拍銅斗歌。", "儂是拍浪兒，飲則拜浪婆。", "脚踏小船頭，獨速舞短蓑。", "笑伊漁陽操，空恃文章多。", "閑倚青竹竿，白日奈我何。"]'),
('b288ca67-9ebe-4b4d-98dd-42bd8a7661a9','送淡公 四','孟郊','唐','唐诗','tang','','[]','短蓑不怕雨，白鷺相爭飛。',48,'全唐诗/poet.tang.20000.json','["短蓑不怕雨，白鷺相爭飛。", "短楫畫菰蒲，鬬作豪橫歸。", "笑伊水健兒，浪戰求光輝。", "不如竹枝弓，射鴨無是非。"]'),
('bc7ce201-5142-4de2-8f8b-cb9931e3c7eb','送淡公 五','孟郊','唐','唐诗','tang','','[]','射鴨復射鴨，鴨驚菰蒲頭。',60,'全唐诗/poet.tang.20000.json','["射鴨復射鴨，鴨驚菰蒲頭。", "鴛鴦亦零落，彩色難相求。", "儂是清浪兒，每踏清浪游。", "笑伊鄉貢郎，踏土稱風流。", "如何丱角翁，至死不裹頭。"]'),
('b750cdf2-57bc-4261-a573-dc315ba11cee','送淡公 六','孟郊','唐','唐诗','tang','','[]','師得天文章，所以相知懷。',72,'全唐诗/poet.tang.20000.json','["師得天文章，所以相知懷。", "數年伊雒同，一旦江湖乖。", "江湖有故莊，小女啼喈喈。", "我憂未相識，乳養難和諧。", "幸以片佛衣，誘之令看齋。", "齋中百福言，催促西歸來。"]'),
('1f3d0a17-9e7d-448b-8be2-a68e77f01b7c','送淡公 七','孟郊','唐','唐诗','tang','','[]','伊洛氣味薄，江湖文章多。',96,'全唐诗/poet.tang.20000.json','["伊洛氣味薄，江湖文章多。", "坐緣江湖岸，意識鮮明波。", "銅斗短蓑行，新章其奈何。", "茲焉激切句，非是等閑歌。", "製之附驛迴，勿使餘風訛。", "都城第一寺，昭成屹嵯峨。", "爲師書廣壁，仰詠時經過。", "徘徊相思心，老淚雙滂沱。"]'),
('db947156-32bf-406f-8c75-bb649de3ddd1','送淡公 八','孟郊','唐','唐诗','tang','','[]','江南邑中寺，平地生勝山。',60,'全唐诗/poet.tang.20000.json','["江南邑中寺，平地生勝山。", "開元吳語僧，律韻高且閑。", "妙藥溪岸平，桂榜往復還。", "樹石相鬬生，紅綠各異顏。", "風味我遙憶，新奇師獨攀。"]'),
('3b7aa17e-5f9f-428e-adc6-b8f4c8643ab6','送淡公 九','孟郊','唐','唐诗','tang','','[]','報恩兼報德，寺與山爭鮮。',60,'全唐诗/poet.tang.20000.json','["報恩兼報德，寺與山爭鮮。", "橙橘金蓋檻，竹蕉綠凝禪。", "經章音韻細，風磬清泠翩。", "離腸繞師足，舊憶隨路延。", "不知幾千尺，至死方綿綿。"]'),
('1de9b856-9107-4c02-a7f2-529a838032b2','送淡公 十','孟郊','唐','唐诗','tang','','[]','鄉在越鏡中，分明見歸心。',72,'全唐诗/poet.tang.20000.json','["鄉在越鏡中，分明見歸心。", "鏡芳步步綠，鏡水日日深。", "異剎碧天上，古香清桂岑。", "朗約徒在昔，章句忽盈今。", "幸因西飛葉，書作東風吟。", "落我病枕上，慰此浮恨侵。"]'),
('a5da13b9-e54d-4b4f-a1e7-cb1723cd2edf','送淡公 十一','孟郊','唐','唐诗','tang','','[]','牽師袈裟別，師斷袈裟歸。',60,'全唐诗/poet.tang.20000.json','["牽師袈裟別，師斷袈裟歸。", "問師何苦去，感吃言語稀。", "意恐被詩餓，欲住將底依。", "盧殷劉言史，餓死君已噫。", "不忍見別君，哭君他是非。"]'),
('f8c98c12-b0a8-40e5-ba7f-df92345024d5','送淡公 十二','孟郊','唐','唐诗','tang','','[]','詩人苦爲詩，不如脫空飛。',72,'全唐诗/poet.tang.20000.json','["詩人苦爲詩，不如脫空飛。", "一生空鷕氣，非諫復非譏。", "脫枯挂寒枝，棄如一唾微。", "一步一步乞，半片半片衣。", "倚詩爲活計，從古多無肥。", "詩饑老不怨，勞師淚霏霏。"]'),
('ac0730d6-7a27-4321-83bd-f10fb7eda52c','送魏端公入朝','孟郊','唐','唐诗','tang','','[]','東洛尚淹翫，西京足芳妍。',72,'全唐诗/poet.tang.20000.json','["東洛尚淹翫，西京足芳妍。", "大賓威儀肅，上客冠劒鮮。", "豈惟空戀闕，亦以將朝天。", "局促塵末吏，幽老病中弦。", "徒懷青雲價，忽至白髮年。", "何當補風教，爲薦三百篇。"]'),
('2c24e27a-86a3-4556-be9f-06d67d646501','送盧郎中汀','孟郊','唐','唐诗','tang','','[]','洛水春渡闊，別離心悠悠。',108,'全唐诗/poet.tang.20000.json','["洛水春渡闊，別離心悠悠。", "一生空吟詩，不覺成白頭。", "向事每計較，與山實綢繆。", "太華天上開，其下車轍流。", "縣街無塵土，過客多淹留。", "坐飲孤驛酒，行思獨山遊。", "逸關嵐氣明，照渭空漪浮。", "玉珂擺新歡，聲與鸞鳳儔。", "朝謁大家事，唯余去無由。"]'),
('9ca3f4cf-327b-4bd2-80d9-799436f906fb','送鄭僕射出節山南','孟郊','唐','唐诗','tang','','[]','國老出爲將，紅旗入青山。',96,'全唐诗/poet.tang.20000.json','["國老出爲將，紅旗入青山。", "再招門下生，結束餘病孱。", "自笑騎馬醜，強從驅馳間。", "顧顧磨天路，褭褭鏡下顏。", "文魄既飛越，宦情唯等閑。", "羨他白面少，多是清朝班。", "惜命非所報，慎行誠獨艱。", "悠悠去住心，兩說何能刪。"]'),
('c1af8b69-d249-451a-9635-cddfc113929b','別妻家','孟郊','唐','唐诗','tang','','[]','芙蓉濕曉露，秋別南浦中。',72,'全唐诗/poet.tang.20000.json','["芙蓉濕曉露，秋別南浦中。", "鴛鴦卷新贈，遙戀東牀空。", "碧水不息浪，清溪易生風。", "參差坐成阻，飄颻去無窮。", "孤雲目雖斷，明月心相通。", "私情詎銷鑠，積芳在春藂。"]'),
('afc850df-124d-4fe7-97c1-b141eeee219c','贈姚怤別','孟郊','唐','唐诗','tang','','[]','美人廢琴瑟，不是無巧彈。',60,'全唐诗/poet.tang.20000.json','["美人廢琴瑟，不是無巧彈。", "聞君郢中唱，始覺知音難。", "驚蓬無還根，馳水多分瀾。", "倦客厭出門，疲馬思解鞍。", "何以寫此心，贈君握中丹。"]'),
('9620d374-59b6-46ea-b49b-1984fd2bf41c','贈竟陵盧使君虔別','孟郊','唐','唐诗','tang','','[]','赤日千里火，火中行子心。',72,'全唐诗/poet.tang.20000.json','["赤日千里火，火中行子心。", "孰不苦焦灼，所行爲貧侵。", "山木豈無涼，猛獸蹲清陰。", "歸人憶平坦，別路多嶇嶔。", "賴得竟陵守，時聞建安吟。", "贈別折楚芳，楚芳搖衣襟。"]'),
('7c52da8e-5d6b-48bf-baf3-6d0c5851907e','與韓愈李翺張籍話別','孟郊','唐','唐诗','tang','','[]','朱弦奏離別，華燈少光輝。',96,'全唐诗/poet.tang.20000.json','["朱弦奏離別，華燈少光輝。", "物色豈有異，人心顧將違。", "客程殊未已，歲華忽然微。", "秋桐故葉下，寒露新雁飛。", "遠遊起重恨，送人念先歸。", "夜集類飢鳥，晨光失相依。", "馬跡遶川水，雁書還閨闈。", "常恐親朋阻，獨行知慮非。"]'),
('a30db985-c13a-40e8-b1f6-da88559f78aa','監察十五叔東齋招李益端公會別','孟郊','唐','唐诗','tang','','[]','欲知惜別情，瀉水還清池。',48,'全唐诗/poet.tang.20000.json','["欲知惜別情，瀉水還清池。", "此地有君子，芳蘭步葳蕤。", "手掇雜英珮，意搖春夜思。", "莫作遶山雲，循環無定期。"]'),
('e87073d6-8089-481f-bc0b-32dde82eb4f8','汴州留別韓愈','孟郊','唐','唐诗','tang','','[]','不飲濁水瀾，空滯此汴河。',72,'全唐诗/poet.tang.20000.json','["不飲濁水瀾，空滯此汴河。", "坐見遶岸水，盡爲還海波。", "四時不在家，弊服斷線多。", "遠客獨顦顇，春英落婆娑。", "汴水饒曲流，野桑無直柯。", "但爲君子心，歎息終靡他。"]'),
('2a64e0de-e550-498b-af8c-5cd631190b69','贈別殷山人說易後歸幽墅','孟郊','唐','唐诗','tang','','[]','夫子說天地，若與靈龜言。',84,'全唐诗/poet.tang.20000.json','["夫子說天地，若與靈龜言。", "幽幽人不知，一一予所敦。", "秋月吐白夜，涼風韻清源。", "旁通忽已遠，神感寂不喧。", "一悟祛萬結，夕懷傾朝煩。", "旅輈無停波，別馬嘶去轅。", "殷勤荒草士，會有知己論。"]'),
('d99384d0-666c-44c7-b87f-775e35a606e4','壽安西渡奉別鄭相公 一','孟郊','唐','唐诗','tang','','[]','洛河向西道，石波橫磷磷。',120,'全唐诗/poet.tang.20000.json','["洛河向西道，石波橫磷磷。", "清風送君子，車遠無還塵。", "春別亦蕭索，況茲冰霜晨。", "零落景易入，鬱抑抱難申。", "百宵華燈宴，一旦星散人。", "歲去弦吐箭，憂來蠶抽綸。", "綿綿無窮事，各各馳遶身。", "徘徊黃縹緲，倏忽春霜賓。", "相爲物表物，永謝區中姻。", "日嗟來教士，仰望無由親。"]'),
('fda6f87b-62dd-4806-ad1e-857856352d36','壽安西渡奉別鄭相公 二','孟郊','唐','唐诗','tang','','[]','東都清風減，君子西歸朝。',168,'全唐诗/poet.tang.20000.json','["東都清風減，君子西歸朝。", "獨抱歲晏恨，泗吟不成謠。", "貴遊意多味，賤別情易消。", "迴鴈憶前叫，浪鳧念後漂。", "悠悠孤飛景，聳聳銜霜條。", "昧趣多滯澀，嬾朋寡新僚。", "病深理方悟，悔至心自燒。", "寂靜道何在，憂勤學空饒。", "乃知減聞見，始遂情逍遙。", "文字徒營織，聲華諒疑驕。", "顧慙耕稼士，朴略氣韻調。", "善士有餘食，佳畦冬生苗。", "養人在養身，此旨清如韶。", "願貢高古言，敢望錫類招。"]'),
('942d1b0c-771a-46c9-b66a-bf00da520b83','宇文秀才齋中海柳詠','孟郊','唐','唐诗','tang','','[]','玉縷青葳蕤，結爲芳樹姿。',60,'全唐诗/poet.tang.20000.json','["玉縷青葳蕤，結爲芳樹姿。", "忽驚明月鉤，鉤出珊瑚枝。", "灼灼不死花，蒙蒙長生絲。", "飲栢泛仙味，詠蘭擬古詞。", "霜風清颼颼，與君長相思。"]'),
('a00bc423-d9df-47a9-9ac1-cabcaeb5d5bb','搖柳','孟郊','唐','唐诗','tang','','[]','弱弱本易驚，看看勢難定。',36,'全唐诗/poet.tang.20000.json','["弱弱本易驚，看看勢難定。", "因風似醉舞，盡日不能正。", "時邀詠花女，笑輟春妝鏡。"]'),
('d367dabb-1d6d-4392-aa3a-a1d945cad8de','曉鶴','孟郊','唐','唐诗','tang','','[]','曉鶴彈古舌，婆羅門叫音。',72,'全唐诗/poet.tang.20000.json','["曉鶴彈古舌，婆羅門叫音。", "應吹天上律，不使塵中尋。", "虛空夢皆斷，歆唏安能禁。", "如開孤月口，似說明星心。", "既非人間韻，枉作人間禽。", "不如相將去，碧落窠巢深。"]'),
('e663ebd5-d2ce-4ef7-a278-1abca072f68c','和薔薇花歌','孟郊','唐','唐诗','tang','','[]','仙機札札織鳳皇，花開七十有二行。',72,'全唐诗/poet.tang.20000.json','["仙機札札織鳳皇，花開七十有二行。", "天霞落地攢紅光，風枝嫋嫋時一颺。", "飛散葩馥遶空王，忽驚錦浪洗新色。", "又似宮娃逞妝飾，終當一使移花根，還比蒲桃天上植。"]'),
('cbe6ccc7-beb7-4578-8203-4891f37e203b','邀人賞薔薇','孟郊','唐','唐诗','tang','','[]','蜀色庶可比，楚叢亦應無。',48,'全唐诗/poet.tang.20000.json','["蜀色庶可比，楚叢亦應無。", "醉紅不自力，狂豔如索扶。", "麗蘂惜未埽，宛枝長更紆。", "何人是花侯，詩老強相呼。"]'),
('e2be0d75-9a58-48a4-99d8-c73f3ea0e2ed','和宣州錢判官使院廳前石楠樹','孟郊','唐','唐诗','tang','','[]','大朴既一剖，衆材爭萬殊。',216,'全唐诗/poet.tang.20000.json','["大朴既一剖，衆材爭萬殊。", "懿茲南海華，來與北壤俱。", "生長如自惜，雪霜無凋渝。", "籠籠抱靈秀，簇簇抽芳膚。", "寒日吐丹豔，頳子流細珠。", "鴛鴦花數重，翡翠葉四鋪。", "雨洗新妝色，一枝如一姝。", "聳異敷庭際，傾妍來坐隅。", "散彩飾机案，餘輝盈盤盂。", "高意因造化，常情逐榮枯。", "主公方寸中，陶植在須臾。", "養此奉君子，賞覿日爲娛。", "始覺石楠詠，價傾賦兩都。", "棠頌庶可比，桂詞難以踰。", "因謝丘墟木，空采落泥塗。", "時來開佳姿，道去臥枯株。", "爭芳無由緣，受氣如鬱紆。", "抽肝在郢匠，歎息何踟躕。"]'),
('8e56dba0-eb4e-4785-9f20-7d5a290cc1c1','酬鄭毗躑躅詠','孟郊','唐','唐诗','tang','','[]','不似人手致，豈關地勢偏。',48,'全唐诗/poet.tang.20000.json','["不似人手致，豈關地勢偏。", "孤光褭餘翠，獨影舞多妍。", "迸火燒閑地，紅星墮青天。", "忽驚物表物，嘉客爲留連。"]'),
('f3b8f1f1-c715-48d9-8b16-31af8a4cb151','品松','孟郊','唐','唐诗','tang','','[]','追悲謝靈運，不得殊常封。',144,'全唐诗/poet.tang.20000.json','["追悲謝靈運，不得殊常封。", "縱然孔與顏，亦莫及此松。", "此松天格高，聳異千萬重。", "抓拏巨靈手，擘裂少室峰。", "擘裂風雨獰，抓拏指爪𦟛。", "道入難抱心，學生易墮蹤。", "時時數點仙，嫋嫋一線龍。", "霏微嵐浪際，遊戲顥興濃。", "品松徒高高，雌鳴詎噰噰。", "賞異尚可貴，賞潛誰能容。", "名華非典實，翦棄徒纖茸。", "刻削大雅文，所以不敢慵。"]'),
('71616d4c-bb23-433e-a28e-4c79b44441af','答李員外小榼味','孟郊','唐','唐诗','tang','','[]','一拳芙蓉水，傾玉何泠泠。',48,'全唐诗/poet.tang.20000.json','["一拳芙蓉水，傾玉何泠泠。", "仙情夙已高，詩味今更馨。", "試啜月入骨，再銜愁盡醒。", "荷君道古誠，使我善飛翎。"]'),
('3216fdc8-9d92-43d6-ad09-7c0f6c46bb45','井上枸杞架','孟郊','唐','唐诗','tang','','[]','深鎖銀泉甃，高葉架雲空。',60,'全唐诗/poet.tang.20000.json','["深鎖銀泉甃，高葉架雲空。", "不與凡木並，自將仙蓋同。", "影疎千點月，聲細萬條風。", "迸子鄰溝外，飄香客位中。", "花杯承此飲，椿歲小無窮。"]'),
('9a2c04d4-88ec-4029-ac1b-96a2c4d41a42','蜘蛛諷','孟郊','唐','唐诗','tang','','[]','萬類皆有性，各各稟天和。',72,'全唐诗/poet.tang.20000.json','["萬類皆有性，各各稟天和。", "蠶身與汝身，汝身何太訛。", "蠶身不爲己，汝身不爲佗。", "蠶絲爲衣裳，汝絲爲網羅。", "濟物幾無功，害物日已多。", "百蟲雖切恨，其將奈爾何。"]'),
('e938786e-9471-4c27-856a-07df08b4128b','蚊','孟郊','唐','唐诗','tang','','[]','五月中夜息，飢蚊尚營營。',48,'全唐诗/poet.tang.20000.json','["五月中夜息，飢蚊尚營營。", "但將膏血求，豈覺性命輕。", "顧己寧自愧，飲人以偷生。", "願爲天下幮，一使夜景清。"]'),
('45f7a43e-f6f9-453f-87ab-8d0be976440b','燭蛾','孟郊','唐','唐诗','tang','','[]','燈前雙舞蛾，厭生何太切。',36,'全唐诗/poet.tang.20000.json','["燈前雙舞蛾，厭生何太切。", "想爾飛來心，惡明不惡滅。", "天若百尺高，應去掩明月。"]'),
('2563d416-de47-440e-a4ae-30ffaa438e29','和錢侍郎甘露','孟郊','唐','唐诗','tang','','[]','玄天何以言，瑞露青松繁。',108,'全唐诗/poet.tang.20000.json','["玄天何以言，瑞露青松繁。", "忽見垂書跡，還驚涌澧源。", "春枝晨嫋嫋，香味曉翻翻。", "子禮忽來獻，臣心固易敦。", "清風惜不動，薄霧肯蒙昏。", "嘉晝色更晶，仁慈久乃存。", "一方難獨占，天下恐爭論。", "側聽飛中使，重榮華德門。", "從公樂萬壽，餘慶及兒孫。"]'),
('92c87b6b-ce3d-4207-9182-c8b60acae2f6','和令狐侍郎郭郎中題項羽廟','孟郊','唐','唐诗','tang','','[]','碧草凌古廟，清塵鎖秋窗。',48,'全唐诗/poet.tang.20000.json','["碧草凌古廟，清塵鎖秋窗。", "當時獨宰割，猛志誰能降。", "鼓氣雷作敵，劒光電爲雙。", "新悲徒自起，舊恨空浮江。"]'),
('47f7971f-e137-402d-9450-2b6f366ee035','讀張碧集','孟郊','唐','唐诗','tang','','[]','天寶太白歿，六藝已消歇。',72,'全唐诗/poet.tang.20000.json','["天寶太白歿，六藝已消歇。", "大哉國風本，喪而王澤竭。", "先生今復生，斯文信難缺。", "下筆證興亡，陳詞備風骨。", "高秋數奏琴，澄潭一輪月。", "誰作采詩官，忍之不揮發。"]'),
('3549a7b4-8816-47cc-ada9-a6472ac82265','聽琴','孟郊','唐','唐诗','tang','','[]','颯颯微雨收，翻翻橡葉鳴。',108,'全唐诗/poet.tang.20000.json','["颯颯微雨收，翻翻橡葉鳴。", "月沈亂峰西，寥落三四星。", "前溪忽調琴，隔林寒琤琤。", "聞彈正弄聲，不敢枕上聽。", "迴燭整頭簪，漱泉立中庭。", "定步屐齒深，貌禪目冥冥。", "微風吹衣襟，亦認宮徵聲。", "學道三十年，未免憂死生。", "聞彈一夜中，會盡天地情。"]'),
('0682ba7e-6308-42cc-87af-b17e138138cd','聞夜啼贈劉正元','孟郊','唐','唐诗','tang','','["\u9ec4\u6cb3"]','寄泣須寄黃河泉，此中怨聲流徹天。',32,'全唐诗/poet.tang.20000.json','["寄泣須寄黃河泉，此中怨聲流徹天。", "愁人獨有夜燈見，一紙鄉書淚滴穿。"]'),
('75292265-6590-4f1b-891b-4cd65dd63024','喜雨','孟郊','唐','唐诗','tang','','[]','朝見一片雲，暮成千里雨。',24,'全唐诗/poet.tang.20000.json','["朝見一片雲，暮成千里雨。", "淒清濕高枝，散漫沾荒土。"]'),
('ecba6e81-8714-4d86-bb31-62e040169ad9','終南山下作','孟郊','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','見此原野秀，始知造化偏。',48,'全唐诗/poet.tang.20000.json','["見此原野秀，始知造化偏。", "山村不假陰，流水自雨田。", "家家梯碧峰，門門鎖青煙。", "因思蛻骨人，化作飛桂仙。"]'),
('52a343e8-cf12-4e7a-ae94-dbb160eb6dc2','觀種樹','孟郊','唐','唐诗','tang','','[]','種樹皆待春，春至難久留。',48,'全唐诗/poet.tang.20000.json','["種樹皆待春，春至難久留。", "君看朝夕花，誰免離別愁。", "心意已零落，種之仍未休。", "胡爲好奇者，無事自買憂。"]'),
('f3d74201-40bc-4b6e-a5b2-dbcfdd1abda4','春雨後','孟郊','唐','唐诗','tang','','[]','昨夜一霎雨，天意蘇羣物。',24,'全唐诗/poet.tang.20000.json','["昨夜一霎雨，天意蘇羣物。", "何物最先知，虛庭草爭出。"]'),
('f910ce3e-e040-4e37-9b99-84f5f7e250d4','答友人贈炭','孟郊','唐','唐诗','tang','','[]','青山白屋有仁人，贈炭價重雙烏銀。',48,'全唐诗/poet.tang.20000.json','["青山白屋有仁人，贈炭價重雙烏銀。", "驅却坐上千重寒，燒出爐中一片春。", "吹霞弄日光不定，暖得曲身成直身。"]'),
('9f003b53-2c93-459b-85f9-01f80a427980','爛柯石','孟郊','唐','唐诗','tang','','[]','仙界一日內，人間千載窮。',48,'全唐诗/poet.tang.20000.json','["仙界一日內，人間千載窮。", "雙碁未徧局，萬物皆爲空。", "樵客返歸路，斧柯爛從風。", "唯餘石橋在，猶自凌丹虹。"]'),
('b6d1ccc7-7a37-4fec-99d6-a88b10300b25','尋言上人','孟郊','唐','唐诗','tang','','[]','萬里莓苔地，不見驅馳蹤。',48,'全唐诗/poet.tang.20000.json','["萬里莓苔地，不見驅馳蹤。", "唯開文字窗，時寫日月容。", "竹韻漫蕭屑，草花徒蒙茸。", "披霜入衆木，獨自識青松。"]'),
('a7cf6818-7ac0-4e54-abad-3ad2e4a9acf2','噴玉布','孟郊','唐','唐诗','tang','','[]','去塵咫尺步，山笑康樂巖。',108,'全唐诗/poet.tang.20000.json','["去塵咫尺步，山笑康樂巖。", "天開紫石屏，泉縷明月簾。", "仙凝刻削跡，靈綻雲霞纖。", "悅聞若有待，瞥見終無厭。", "俗玩詎能近，道嬉方可淹。", "踏着不死機，欲歸多浮嫌。", "古醉今忽醒，今求古仍潛。", "古今相共失，語默兩難恬。", "贈君噴玉布，一濯高嶄嶄。"]'),
('e2168ed2-e658-4ead-9711-b3f98026e41b','姑蔑城','孟郊','唐','唐诗','tang','','[]','勁越既成土，強吳亦爲墟。',48,'全唐诗/poet.tang.20000.json','["勁越既成土，強吳亦爲墟。", "皇風一已被，茲邑信平居。", "撫俗觀舊跡，行春布新書。", "興亡意何在，綿歎空躊躕。"]'),
('d3397817-5ef2-43e9-9b0f-cb96e8bab224','崢嶸嶺','孟郊','唐','唐诗','tang','','[]','疏鑿順高下，結構橫煙霞。',48,'全唐诗/poet.tang.20000.json','["疏鑿順高下，結構橫煙霞。", "坐嘯郡齋肅，玩奇石路斜。", "古樹浮綠氣，高門結朱華。", "始見崢嶸狀，仰止逾可嘉。"]'),
('e14f3acb-c22f-42cb-93ec-d2550512ecb7','尋裴處士','孟郊','唐','唐诗','tang','','[]','涉水更登陸，所向皆清真。',72,'全唐诗/poet.tang.20000.json','["涉水更登陸，所向皆清真。", "寒草不藏徑，靈峰知有人。", "悠哉鍊金客，獨與煙霞親。", "曾是欲輕舉，誰言空隱淪。", "遠心寄白月，華髮迴青春。", "對此欽勝事，胡爲勞我身。"]'),
('a6062777-a23a-4e6f-8362-843f251c4a0e','子慶詩','孟郊','唐','唐诗','tang','','[]','王家事已奇，孟氏慶無涯。',72,'全唐诗/poet.tang.20000.json','["王家事已奇，孟氏慶無涯。", "獻子還生子，羲之又有之。", "鳳兮且莫歎，鯉也會聞詩。", "小小豫章甲，纖纖玉樹姿。", "人來唯仰乳，母抱未知慈。", "我欲揀其養，放麛者是誰。"]'),
('9f54b64f-43c0-4016-a7b7-f880af34b8ce','憩淮上觀公法堂','孟郊','唐','唐诗','tang','','[]','動覺日月短，靜知時歲長。',108,'全唐诗/poet.tang.20000.json','["動覺日月短，靜知時歲長。", "自悲道路人，暫宿空閑堂。", "孤燭讓清晝，紗巾歛輝光。", "高僧積素行，事外無剛強。", "我有巖下桂，願爲爐中香。", "不惜青翠姿，爲君揚芬芳。", "淮水色不汙，汴流徒渾黃。", "且將琉璃意，淨綴芙蓉章。", "明日還獨行，羇愁來舊腸。"]'),
('d2c0bb64-7033-421a-8f30-069251c9b9fc','江邑春霖奉贈陳侍御','孟郊','唐','唐诗','tang','','[]','江上花木凍，雨中零落春。',120,'全唐诗/poet.tang.20000.json','["江上花木凍，雨中零落春。", "應由放忠直，在此成漂淪。", "嘉豔皆損汙，好音難殷勤。", "天涯多遠恨，雪涕盈芳辰。", "坐哭青草上，臥吟幽水濱。", "興言念風俗，得意唯波鱗。", "枕席病流濕，簷楹若飛津。", "始知吳楚水，不及京洛塵。", "風浦蕩歸棹，泥陂陷征輪。", "兩途日無遂，相贈唯沾巾。"]'),
('bf4a63aa-cc43-4428-98df-e59ef6392469','溧陽秋霽','孟郊','唐','唐诗','tang','','[]','晚雨曉猶在，蕭寥激前階。',72,'全唐诗/poet.tang.20000.json','["晚雨曉猶在，蕭寥激前階。", "星星滿衰鬢，耿耿入秋懷。", "舊識半零落，前心驟相乖。", "飽泉亦恐醉，惕宦肅如齋。", "上客處華池，下寮宅枯崖。", "叩高占生物，齟齬回難諧。"]'),
('5457764e-720b-4ab3-89ae-422fb9687a4a','列仙文 方諸青童君','孟郊','唐','唐诗','tang','','[]','大霞霏晨暉，元氣無常形。',60,'全唐诗/poet.tang.20000.json','["大霞霏晨暉，元氣無常形。", "玄轡飛霄外，八景乘高清。", "手把玉皇袂，攜我晨中生。", "玄庭自嘉會，金書拆華名。", "賢女密所妍，相期洛水軿。"]'),
('04dcf756-3aa4-4c24-a727-b262ba1ad46b','列仙文 清虛真人','孟郊','唐','唐诗','tang','','[]','歘駕空清虛，徘徊西華館。',84,'全唐诗/poet.tang.20000.json','["歘駕空清虛，徘徊西華館。", "瓊輪暨晨抄，虎騎逐煙散。", "惠風振丹旌，明燭朗八煥。", "解襟墉房內，神鈴鳴璀璨。", "棲景若林柯，九弦空中彈。", "遺我積世憂，釋此千載歎。", "怡眄無極已，終夜復待旦。"]'),
('4628c2c7-4349-42b8-92ab-e6a1bf0f6e7e','列仙文 金母飛空歌','孟郊','唐','唐诗','tang','','["\u8861\u5c71"]','駕我八景輿，歘然入玉清。',108,'全唐诗/poet.tang.20000.json','["駕我八景輿，歘然入玉清。", "龍羣拂霄上，虎旗攝朱兵。", "逍遙三弦際，萬流無暫停。", "哀此去留會，劫盡天地傾。", "當尋無中景，不死亦不生。", "體彼自然道，寂觀合大冥。", "南嶽挺直幹，玉英曜頴精。", "有任靡期事，無心自虛靈。", "嘉會絳河內，相與樂未英。"]'),
('a5bb5bbd-2637-48e7-bc03-c0a9766be04f','列仙文 安度明','孟郊','唐','唐诗','tang','','[]','丹霞煥上清，八風鼓太和。',84,'全唐诗/poet.tang.20000.json','["丹霞煥上清，八風鼓太和。", "迴我神霄輦，遂造嶺玉阿。", "咄嗟天地外，九圍皆我家。", "上采白日精，下飲黃月華。", "靈觀空無中，鵬路無間邪。", "顧見魏賢安，濁氣傷汝和。", "勤研玄中思，道成更相過。"]'),
('4bf72d4e-3c82-4c98-9966-321f5014d594','夏日謁智遠禪師','孟郊','唐','唐诗','tang','','[]','吾師當幾祖，說法云無空。',96,'全唐诗/poet.tang.20000.json','["吾師當幾祖，說法云無空。", "禪心三界外，宴坐天地中。", "院靜鬼神去，身與草木同。", "因知護王國，滿鉢盛毒龍。", "抖擻塵埃衣，謁師見真宗。", "何必千萬劫，瞬息去樊籠。", "盛夏火爲日，一堂十月風。", "不得爲弟子，名姓挂儒宮。"]'),
('f77593ab-6de7-4aea-b313-cd8ae8aa0799','訪嵩陽道士不遇','孟郊','唐','唐诗','tang','','[]','先生五兵遊，文焰藏金鼎。',48,'全唐诗/poet.tang.20000.json','["先生五兵遊，文焰藏金鼎。", "日下鶴過時，人間空落影。", "常言一粒藥，不墮生死境。", "何當列禦寇，去問仙人請。"]'),
('970ae8a8-5142-493f-9e67-40c8b12c577c','聽藍溪僧爲元居士說維摩經','孟郊','唐','唐诗','tang','','[]','古樹少枝葉，真僧亦相依。',60,'全唐诗/poet.tang.20000.json','["古樹少枝葉，真僧亦相依。", "山木自曲直，道人無是非。", "手持維摩偈，心向居士歸。", "空景忽開霽，雪花猶在衣。", "洗然水溪晝，寒物生光輝。"]'),
('638d5260-6bc2-4256-9d58-725fa76e2576','借車','孟郊','唐','唐诗','tang','','[]','借車載家具，家具少於車。',36,'全唐诗/poet.tang.20000.json','["借車載家具，家具少於車。", "借者莫彈指，貧窮何足嗟。", "百年徒役走，萬事盡隨花。"]'),
('4d6ea2ab-68b3-4172-ac6c-a13c375067c6','喜符郎詩有天縱','孟郊','唐','唐诗','tang','','[]','念符不由級，屹得文章階。',72,'全唐诗/poet.tang.20000.json','["念符不由級，屹得文章階。", "白玉抽一毫，綠珉已難排。", "偷筆作文章，乞墨潛磨揩。", "海鯨始生尾，試擺蓬壺渦。", "幸當禁止之，勿使恣狂懷。", "自悲無子嗟，喜妬雙喈喈。"]'),
('95c9711d-cc5d-46f6-9d05-f0e27cd337b5','憑周況先輩於朝賢乞茶','孟郊','唐','唐诗','tang','','[]','道意勿乏味，心緒病無悰。',72,'全唐诗/poet.tang.20000.json','["道意勿乏味，心緒病無悰。", "蒙茗玉花盡，越甌荷葉空。", "錦水有鮮色，蜀山饒芳藂。", "雲根纔翦綠，印縫已霏紅。", "曾向貴人得，最將詩叟同。", "幸爲乞寄來，救此病劣躬。"]'),
('d3066753-cfc3-4aea-a36e-6d3fec1f3ab0','上昭成閣不得於從姪僧悟空院歎嗟','孟郊','唐','唐诗','tang','','[]','欲上千級閣，問天三四言。',132,'全唐诗/poet.tang.20000.json','["欲上千級閣，問天三四言。", "未盡數十登，心目風浪翻。", "手手把驚魄，脚脚踏墜魂。", "却流至舊手，傍掣猶欲奔。", "老病但自悲，古蠹木萬痕。", "老力安可誇，秋海萍一根。", "孤叟何所歸，晝眼如黃昏。", "常恐失好步，入彼市井門。", "結僧爲親情，策竹爲子孫。", "此誠徒切切，此意空存存。", "一寸地上語，高天何由聞。"]'),
('4fd71b2c-69b7-43db-84aa-7b9b95f067e3','魏博田興尚書聽嫂命不立非夫人詩','孟郊','唐','唐诗','tang','','[]','君子躭古禮，如饞魚吞鉤。',48,'全唐诗/poet.tang.20000.json','["君子躭古禮，如饞魚吞鉤。", "昨聞敬嫂言，掣心東北流。", "魏博田尚書，與禮相綢繆。", "善詞聞天下，一日一再周。"]'),
('ba1c1ea7-01bf-40cb-b6a1-78b8188df5b3','讀經','孟郊','唐','唐诗','tang','','[]','垂老抱佛脚，教妻讀黃經。',192,'全唐诗/poet.tang.20000.json','["垂老抱佛脚，教妻讀黃經。", "經黃名小品，一紙千明星。", "曾讀大般若，細感肸蠁聽。", "當時把齋中，方寸抱萬靈。", "忽復入長安，蹴踏日月寧。", "老方却歸來，收拾可丁丁。", "拂拭塵几案，開函就孤亭。", "儒書難借索，僧籤饒芳馨。", "驛驛不開手，鏗鏗聞異鈴。", "得善如焚香，去惡如脫腥。", "安得顏子耳，曾未如此聽。", "聽之何有言，德教貴有形。", "何言中國外，有國如海萍。", "海萍國教異，天聲各泠泠。", "安排未定時，心火競熒熒。", "將如庶幾者，聲盡形元冥。"]'),
('17678211-6bd8-4c2c-9ed9-cec4de707be0','謝李輈再到','孟郊','唐','唐诗','tang','','[]','等閑拜日晚，夫妻獨相瘡。',108,'全唐诗/poet.tang.20000.json','["等閑拜日晚，夫妻獨相瘡。", "況是賢人冤，何必哭飛楊。", "昨夜夢得劒，爲君藏中腸。", "會將當風烹，血染布衣裳。", "勞君又扣門，詞句失尋常。", "我不忍出廳，血字濕土牆。", "血字耿不滅，我心懼惶惶。", "會有鏗鏘夫，見之目生光。", "生光非等閑，君其且安祥。"]'),
('dd77b4e7-0f9f-478f-a2cc-7da99c6b9827','忽不貧喜盧仝書船歸洛','孟郊','唐','唐诗','tang','','[]','貧孟忽不貧，請問孟何如。',192,'全唐诗/poet.tang.20000.json','["貧孟忽不貧，請問孟何如。", "盧仝歸洛船，崔嵬但載書。", "江潮清翻翻，淮潮碧徐徐。", "夜信爲朝信，朝信良卷舒。", "江淮君子水，相送仁有餘。", "我去官色衫，肩經入君廬。", "喃喃肩經郎，言語傾琪琚。", "琪琚鏗好詞，鳥鵲躍庭除。", "書船平安歸，喜報鄉里閭。", "我願拾遺柴，巢經於空虛。", "下免塵土侵，上爲雲霞居。", "日月更相鎖，道義分明儲。", "不願空岧嶢，但願實工夫。", "實空二理微，分別相起予。", "經書荒蕪多，爲君勉勉鋤。", "勉勉不敢專，傳之方在諸。"]'),
('e6e3083b-091c-4cb1-9a2a-170b869f0e31','弔國殤','孟郊','唐','唐诗','tang','','[]','徒言人最靈，白骨亂縱橫。',60,'全唐诗/poet.tang.20000.json','["徒言人最靈，白骨亂縱橫。", "如何當春死，不及羣草生。", "堯舜宰乾坤，器農不器兵。", "秦漢盜山岳，鑄殺不鑄畊。", "天地莫生金，生金人競爭。"]'),
('7e6a00ad-c167-4256-bfa3-a4b25d19b978','弔比干墓','孟郊','唐','唐诗','tang','','[]','殷辛帝天下，厭爲天下尊。',96,'全唐诗/poet.tang.20000.json','["殷辛帝天下，厭爲天下尊。", "乾剛既一斷，賢愚無二門。", "佞是福身本，忠是喪己源。", "餓虎不食子，人無骨肉恩。", "日影不入地，下埋冤死魂。", "有骨不爲土，應作直木根。", "今來過此鄉，下馬弔此墳。", "靜念君臣間，有道誰敢論。"]'),
('cff79683-5f8c-4939-97cd-5f98fdcd8fb6','弔元魯山 一','孟郊','唐','唐诗','tang','','[]','[搏]鷙有餘飽，魯山長飢空。',74,'全唐诗/poet.tang.20000.json','["[搏]鷙有餘飽，魯山長飢空。", "豪人飫鮮肥，魯山飯蒿蓬。", "食名皆霸官，食力乃堯農。", "君子恥新態，魯山與古終。", "天璞本平一，人巧生異同。", "魯山不自剖，全璞竟沒躬。"]'),
('6107697e-3474-46de-8e3e-7b5f9534a921','弔元魯山 二','孟郊','唐','唐诗','tang','','[]','自剖多是非，流濫將何歸。',48,'全唐诗/poet.tang.20000.json','["自剖多是非，流濫將何歸。", "奔競立詭節，凌侮爭怪輝。", "五常坐銷鑠，萬類隨衰微。", "以茲見魯山，道蹇無所依。"]'),
('e5639382-92ac-4d40-a3cd-2196c3843182','弔元魯山 三','孟郊','唐','唐诗','tang','','[]','君子不自蹇，魯山蹇有因。',60,'全唐诗/poet.tang.20000.json','["君子不自蹇，魯山蹇有因。", "苟含天地秀，皆是天地身。", "天地蹇既甚，魯山道莫伸。", "天地氣不足，魯山食更貧。", "始知補元化，竟須得賢人。"]'),
('995c073b-9f1b-4bc0-9f00-d2414159428a','弔元魯山 四','孟郊','唐','唐诗','tang','','[]','賢人多自霾，道理與俗乖。',60,'全唐诗/poet.tang.20000.json','["賢人多自霾，道理與俗乖。", "細功不敢言，遠韻方始諧。", "萬物飽爲飽，萬人懷爲懷。", "一聲苟失所，衆憾來相排。", "所以元魯山，飢衰難與偕。"]'),
('ab391671-fb2a-4d82-adee-1874536c85ee','弔元魯山 五','孟郊','唐','唐诗','tang','','[]','遠階無近級，造次不可升。',48,'全唐诗/poet.tang.20000.json','["遠階無近級，造次不可升。", "賢人潔腸胃，寒日空澄凝。", "血誓竟訛謬，膏明易煎蒸。", "以之驅魯山，疎迹去莫乘。"]'),
('31ccc74f-fcdc-4ff9-a842-3380efbaaab2','弔元魯山 六','孟郊','唐','唐诗','tang','','[]','言從魯山宦，盡化堯時心。',84,'全唐诗/poet.tang.20000.json','["言從魯山宦，盡化堯時心。", "豺狼恥狂噬，齒牙閉霜金。", "競來闢田土，相與畊嶔岑。", "當宵無關鎖，竟歲饒歌吟。", "善教復天術，美詞非俗箴。", "精微自然事，視聽不可尋。", "因書魯山績，庶合簫韶音。"]'),
('76b6053e-67dd-47eb-8bbd-057fb717e01d','弔元魯山 七','孟郊','唐','唐诗','tang','','[]','簫韶太平樂，魯山不虛作。',96,'全唐诗/poet.tang.20000.json','["簫韶太平樂，魯山不虛作。", "千古若有知，百年幸如昨。", "誰能嗣教化，以此洗浮薄。", "君臣貴深遇，天地有靈橐。", "力運既艱難，德符方合漠。", "名位苟虛曠，聲明自銷鑠。", "禮法雖相救，貞濃易糟粕。", "哀哀元魯山，畢竟誰能度。"]'),
('684108f3-6a6e-4052-a45f-12ad2f72b64c','弔元魯山 八','孟郊','唐','唐诗','tang','','[]','當今富教化，元后得賢相。',96,'全唐诗/poet.tang.20000.json','["當今富教化，元后得賢相。", "冰心鏡衰古，霜議清遐障。", "幽埋盡洸洗，滯旅免流浪。", "唯餘魯山名，未獲旌廉讓。", "二三貞苦士，刷視聳危望。", "髮秋青山夜，目斷丹闕亮。", "誘類幸從茲，嘉招固非妄。", "小生奏狂狷，感惕增萬狀。"]'),
('c2ac09ac-7ef7-4f31-b0a4-7a6732bd18e7','弔元魯山 九','孟郊','唐','唐诗','tang','','[]','黃犢不知孝，魯山自駕車。',48,'全唐诗/poet.tang.20000.json','["黃犢不知孝，魯山自駕車。", "非賢不可妻，魯山竟無家。", "供養恥佗力，言詞豈纖瑕。", "將謠魯山德，賾海誰能涯。"]'),
('390cd0ff-b216-4913-bb04-fa2efa555ba6','弔元魯山 十','孟郊','唐','唐诗','tang','','[]','遺嬰盡雛乳，何況骨肉枝。',48,'全唐诗/poet.tang.20000.json','["遺嬰盡雛乳，何況骨肉枝。", "心腸結苦誠，胸臆垂甘滋。", "事已出古表，誰言獨今奇。", "賢人母萬物，豈弟流前詩。"]'),
('7963fe91-fbbc-434e-b7f1-cdfef0af961c','哭李觀','孟郊','唐','唐诗','tang','','[]','志士不得老，多爲直氣傷。',204,'全唐诗/poet.tang.20000.json','["志士不得老，多爲直氣傷。", "阮公終日哭，壽命固難長。", "顏子既殂謝，孔門無輝光。", "文星落奇曜，寶劒摧修鋩。", "常作金應石，忽爲宮別商。", "爲爾弔琴瑟，斷弦難再張。", "偏轂不可轉，隻翼不可翔。", "清塵無吹噓，委地難飛揚。", "此義古所重，此風今則亡。", "自聞喪元賓，一日八九狂。", "沈痛此丈夫，驚呼彼穹蒼。", "我有出俗韻，勞君疾惡腸。", "知音既已矣，微言誰能彰。", "旅葬無高墳，栽松不成行。", "哀歌動寒日，贈淚沾晨霜。", "神理本窅窅，今來更茫茫。", "何以蕩悲懷，萬事付一觴。"]'),
('343c0edb-c884-4346-a767-d2e449c41915','李少府廳弔李元賓遺字','孟郊','唐','唐诗','tang','','[]','零落三四字，忽成千萬年。',72,'全唐诗/poet.tang.20000.json','["零落三四字，忽成千萬年。", "那知冥寞客，不有補亡篇。", "斜月弔空壁，旅人難獨眠。", "一生能幾時，百慮來相煎。", "戚戚故交淚，幽幽長夜泉。", "已矣難重言，一言一潸然。"]'),
('0506b846-9565-44ae-b41c-02e3c6879a8c','悼吳興湯衡評事','孟郊','唐','唐诗','tang','','[]','君生霅水清，君歿霅水渾。',72,'全唐诗/poet.tang.20000.json','["君生霅水清，君歿霅水渾。", "空令骨肉情，哭得白日昏。", "大夜不復曉，古松長閉門。", "琴弦綠水絕，詩句青山存。", "昔爲芳春顏，今爲荒草根。", "獨問冥冥理，先儒未曾言。"]'),
('fe15afa3-dd50-4092-bfef-475f0e97d78c','哀孟雲卿嵩陽荒居','孟郊','唐','唐诗','tang','','[]','戚戚抱幽獨，宴宴沈荒居。',108,'全唐诗/poet.tang.20000.json','["戚戚抱幽獨，宴宴沈荒居。", "不聞新歡笑，但覩舊詩書。", "藝蘗意彌苦，耕山食無餘。", "定交昔何在，至戚今或疎。", "薄俗易銷歇，淳風難久舒。", "秋蕪上空堂，寒槿落枯渠。", "薙草恐傷蕙，攝衣自理鋤。", "殘芳亦可餌，遺秀誰忍除。", "徘徊未能去，爲爾涕漣如。"]'),
('9fb51888-5d7c-4ee0-8284-a9e8b1adab5f','哭盧貞國','孟郊','唐','唐诗','tang','','[]','一別難與期，存亡易寒燠。',60,'全唐诗/poet.tang.20000.json','["一別難與期，存亡易寒燠。", "下馬入君門，聲悲不成哭。", "自能富才藝，當冀深榮祿。", "皇天負我賢，遺恨至兩目。", "平生嘆無子，家家親相囑。"]'),
('f8fbc419-4322-4e87-9cf1-362b17c194c0','傷舊遊','孟郊','唐','唐诗','tang','','[]','去春會處今春歸，花數不減人數稀。',32,'全唐诗/poet.tang.20000.json','["去春會處今春歸，花數不減人數稀。", "朝笑片時暮成泣，東風一向還西輝。"]'),
('93f7cf37-7d72-4951-a0d8-1b74a478727b','弔房十五次卿少府','孟郊','唐','唐诗','tang','','[]','日高方得起，獨賞些些春。',96,'全唐诗/poet.tang.20000.json','["日高方得起，獨賞些些春。", "可惜宛轉鸎，好音與佗人。", "昔年此氣味，還走曲江濱。", "逢著韓退之，結交方殷勤。", "蜀客骨目高，聰辯劒戟新。", "如何昨日歡，今日見無因。", "英奇一謝世，視聽一爲塵。", "誰言老淚短，淚短沾衣巾。"]'),
('7815179b-c4d1-4365-a169-b4dabe1caaf3','逢江南故晝上人會中鄭方回','孟郊','唐','唐诗','tang','','[]','相逢失意中，萬感因語至。',84,'全唐诗/poet.tang.20000.json','["相逢失意中，萬感因語至。", "追思東林日，掩抑北邙淚。", "筐篋有遺文，江山舊清氣。", "塵生逍遙注，墨故飛動字。", "荒毀碧澗居，虛無青松位。", "珠沈百泉暗，月死羣象閉。", "永謝平生言，知音豈容易。"]'),
('983d12ef-7554-4fcc-8bdb-3a5f18e57932','哭祕書包大監','孟郊','唐','唐诗','tang','','[]','哲人臥病日，賤子泣玉年。',60,'全唐诗/poet.tang.20000.json','["哲人臥病日，賤子泣玉年。", "常恐寶鏡破，明月難再圓。", "文字未改素，聲容忽歸玄。", "始知知音稀，千載一絕弦。", "舊館有遺琴，清風那復傳。"]'),
('2262e5e7-f10e-47f6-a85e-b769ef289beb','悼幼子','孟郊','唐','唐诗','tang','','[]','一閉黃蒿門，不聞白日事。',48,'全唐诗/poet.tang.20000.json','["一閉黃蒿門，不聞白日事。", "生氣散成風，枯骸化爲地。", "負我十年恩，欠爾千行淚。", "灑之北原上，不待秋風至。"]'),
('21985c1e-ae70-4e0c-8218-e934d407bb93','悼亡','孟郊','唐','唐诗','tang','','[]','山頭明月夜增輝，增輝不照重泉下。',48,'全唐诗/poet.tang.20000.json','["山頭明月夜增輝，增輝不照重泉下。", "泉下雙龍無再期，金蠶玉燕空銷化。", "朝雲暮雨成古墟，蕭蕭野竹風吹亞。"]'),
('f07e39fe-5dd8-4940-a589-07af5f2db4ec','弔李元賓墳','孟郊','唐','唐诗','tang','','[]','曉上荒涼原，弔彼寂寥魂。',36,'全唐诗/poet.tang.20000.json','["曉上荒涼原，弔彼寂寥魂。", "眼咽此時淚，耳悽在日言。", "冥冥千萬年，墳鎖孤松根。"]'),
('3c68201f-53b9-471b-9cf0-824b23481fb5','覽崔爽遺文因紓幽懷','孟郊','唐','唐诗','tang','','[]','墮淚數首文，悲結千里墳。',72,'全唐诗/poet.tang.20000.json','["墮淚數首文，悲結千里墳。", "蒼旻且留我，白日空遺君。", "仙鶴未巢月，衰鳳先墜雲。", "清風獨起時，舊語如再聞。", "瑤草罷葳蕤，桂花休氛氳。", "萬物與我心，相感吳江濆。"]'),
('31d023e0-e562-452d-8812-e3b7e88e73c5','峽哀 一','孟郊','唐','唐诗','tang','','[]','昔多相與笑，今誰相與哀。',156,'全唐诗/poet.tang.20000.json','["昔多相與笑，今誰相與哀。", "峽哀哭幽魂，噭噭風吹來。", "墮魄抱空月，出沒難自裁。", "齏粉一閃間，春濤百丈雷。", "峽水聲不平，碧沲牽清洄。", "沙稜箭箭急，波齒齗齗開。", "呀彼無底吮，待此不測災。", "谷號相噴激，石怒爭旋迴。", "古醉有復鄉，今縲多爲能。", "字孤徒髣髴，銜雪猶驚猜。", "薄俗少直腸，交結須橫財。", "黃金買相弔，幽泣無餘漼。", "我有古心意，爲君空摧頹。"]'),
('6c740e0f-b75f-4d19-abee-2c5a51e7f96f','峽哀 二','孟郊','唐','唐诗','tang','','[]','上天下天水，出地入地舟。',60,'全唐诗/poet.tang.20000.json','["上天下天水，出地入地舟。", "石劒相劈斫，石波怒蛟虯。", "花木疊宿春，風飆凝古秋。", "幽怪窟穴語，飛聞肸蠁流。", "沈哀日已深，銜訴將何求。"]'),
('ae57e200-b1b8-4773-8779-96766948a8e8','峽哀 三','孟郊','唐','唐诗','tang','','[]','三峽一線天，三峽萬繩泉。',108,'全唐诗/poet.tang.20000.json','["三峽一線天，三峽萬繩泉。", "上仄碎日月，下掣狂漪漣。", "破魂一兩點，凝幽數百年。", "峽暉不停午，峽險多飢涎。", "樹根鎖枯棺，孤骨褭褭懸。", "樹枝哭霜棲，哀韻杳杳鮮。", "逐客零落腸，到此湯火煎。", "性命如紡績，道路隨索緣。", "奠淚弔波靈，波靈將閃然。"]'),
('1ed92763-9ec1-4a40-a4fc-13fd46f584c4','峽哀 四','孟郊','唐','唐诗','tang','','[]','峽亂鳴清磬，產石爲鮮鱗。',60,'全唐诗/poet.tang.20000.json','["峽亂鳴清磬，產石爲鮮鱗。", "噴爲腥雨涎，吹作黑井身。", "怪光閃衆異，餓劒唯待人。", "老腸未曾飽，古齒嶄巖嗔。", "嚼齒三峽泉，三峽聲齗齗。"]'),
('0d66406d-4f78-418f-8338-c541eb127321','峽哀 五','孟郊','唐','唐诗','tang','','[]','峽螭老解語，百丈潭底聞。',84,'全唐诗/poet.tang.20000.json','["峽螭老解語，百丈潭底聞。", "毒波爲計校，飲血養子孫。", "既非臯陶吏，空食沈獄魂。", "潛怪何幽幽，魄說徒云云。", "峽聽哀哭泉，峽弔鰥寡猿。", "峽聲非人聲，劒水相劈翻。", "斯誰士諸謝，奏此沉苦言。"]'),
('06de6be3-0257-4ee5-9fde-2e2fef90ad9b','峽哀 六','孟郊','唐','唐诗','tang','','[]','讒人峽虯心，渴罪呀然潯。',84,'全唐诗/poet.tang.20000.json','["讒人峽虯心，渴罪呀然潯。", "所食無直腸，所語饒梟音。", "石齒嚼百泉，石風號千琴。", "幽哀莫能遠，分雪何由尋。", "月魄高卓卓，峽窟清沉沉。", "銜訴何時明，抱痛已不禁。", "犀飛空波濤，裂石千嶔岑。"]'),
('637d8858-d5ab-4ba0-b687-a72be1f55bec','峽哀 七','孟郊','唐','唐诗','tang','','[]','峽稜剸日月，日月多摧輝。',72,'全唐诗/poet.tang.20000.json','["峽稜剸日月，日月多摧輝。", "物皆斜仄生，鳥亦斜仄飛。", "潛石齒相鎖，沉魂招莫歸。", "恍惚清泉甲，斑斕碧石衣。", "餓嚥潺湲號，涎似泓浤肥。", "峽青不可遊，腥草生微微。"]'),
('e8d89175-a6e3-493b-84f7-86eb548a0ce6','峽哀 八','孟郊','唐','唐诗','tang','','[]','峽景滑易墮，峽花怪非春。',84,'全唐诗/poet.tang.20000.json','["峽景滑易墮，峽花怪非春。", "紅光根潛涎，碧雨飛沃津。", "巴谷蛟螭心，巴鄉魍魎親。", "噉生不問賢，至死獨養身。", "腥語信者誰，拗歌歡非真。", "仄田無異稼，毒水多獰鱗。", "異類不可友，峽哀哀難伸。"]'),
('3be29063-1b83-4ae7-a589-32a9d3182fcb','峽哀 九','孟郊','唐','唐诗','tang','','[]','峽水劒戟獰，峽舟霹靂翔。',72,'全唐诗/poet.tang.20000.json','["峽水劒戟獰，峽舟霹靂翔。", "因依虺蜴手，起坐風雨忙。", "峽旅多竄官，峽氓多非良。", "滑心不可求，滑習積已長。", "漠漠涎霧起，齗齗涎水光。", "渴賢如之何，忽在水中央。"]'),
('a3f69401-d5ea-4775-a07d-453ba5d27816','峽哀 十','孟郊','唐','唐诗','tang','','[]','梟鴟作人語，蛟虯吸水波。',72,'全唐诗/poet.tang.20000.json','["梟鴟作人語，蛟虯吸水波。", "能于白日間，諂欲晴風和。", "駭智蹶衆命，蘊腥布深蘿。", "齒泉無底貧，鋸涎在處多。", "仄樹鳥不巢，踔𨃚猿相過。", "峽哀不可聽，峽怨其奈何。"]'),
('b7fe7bae-cf4a-484f-a5c3-726e217a15ce','杏殤 一','孟郊','唐','唐诗','tang','','[]','凍手莫弄珠，弄珠珠易飛。',48,'全唐诗/poet.tang.20000.json','["凍手莫弄珠，弄珠珠易飛。", "驚霜莫翦春，翦春無光輝。", "零落小花乳，斕斑昔嬰衣。", "拾之不盈把，日暮空悲歸。"]'),
('cd91cd6c-166f-4f90-bcab-d71b2f6d48bc','杏殤 二','孟郊','唐','唐诗','tang','','[]','地上空拾星，枝上不見花。',60,'全唐诗/poet.tang.20000.json','["地上空拾星，枝上不見花。", "哀哀孤老人，戚戚無子家。", "豈若沒水鳧，不如拾巢鴉。", "浪鷇破便飛，風雛褭相誇。", "芳嬰不復生，向物空悲嗟。"]'),
('3cd29e60-6971-4072-8a0e-8d96adefe284','杏殤 三','孟郊','唐','唐诗','tang','','[]','應是一線淚，入此春木心。',48,'全唐诗/poet.tang.20000.json','["應是一線淚，入此春木心。", "枝枝不成花，片片落翦金。", "春壽何可長，霜哀亦已深。", "常時洗芳泉，此日洗淚襟。"]'),
('2988fec5-a58f-4310-ae02-d8357b44da0f','杏殤 四','孟郊','唐','唐诗','tang','','[]','兒生月不明，兒死月始光。',48,'全唐诗/poet.tang.20000.json','["兒生月不明，兒死月始光。", "兒月兩相奪，兒命果不長。", "如何此英英，亦爲弔蒼蒼。", "甘爲墮地塵，不爲末世芳。"]'),
('e9b9a39b-c5ed-45d1-9641-dec4175814fb','杏殤 五','孟郊','唐','唐诗','tang','','[]','踏地恐土痛，損彼芳樹根。',48,'全唐诗/poet.tang.20000.json','["踏地恐土痛，損彼芳樹根。", "此誠天不知，翦棄我子孫。", "垂枝有千落，芳命無一存。", "誰謂生人家，春色不入門。"]'),
('e3fb12bb-2b1b-4177-8d50-4864bacc7673','杏殤 六','孟郊','唐','唐诗','tang','','[]','冽冽霜殺春，枝枝疑纖刀。',48,'全唐诗/poet.tang.20000.json','["冽冽霜殺春，枝枝疑纖刀。", "木心既零落，山竅空呼號。", "班班落地英，點點如明膏。", "始知天地間，萬物皆不牢。"]'),
('22024e09-ca03-4c28-a9c9-9cc3f7a12281','杏殤 七','孟郊','唐','唐诗','tang','','[]','哭此不成春，淚痕三四斑。',48,'全唐诗/poet.tang.20000.json','["哭此不成春，淚痕三四斑。", "失芳蝶既狂，失子老亦孱。", "且無生生力，自有死死顏。", "靈鳳不銜訴，誰爲扣天關。"]'),
('c6765273-c5ad-43fd-9756-f61ab31cfdb1','杏殤 八','孟郊','唐','唐诗','tang','','[]','此兒自見災，花發多不諧。',48,'全唐诗/poet.tang.20000.json','["此兒自見災，花發多不諧。", "窮老收碎心，永夜抱破懷。", "聲死更何言，意死不必喈。", "病叟無子孫，獨立猶束柴。"]'),
('38055e54-5940-46f8-a5f5-5b0e1980fa41','杏殤 九','孟郊','唐','唐诗','tang','','[]','霜似敗紅芳，剪啄十數雙。',48,'全唐诗/poet.tang.20000.json','["霜似敗紅芳，剪啄十數雙。", "參差呻細風，噞喁沸淺江。", "泣凝不可消，恨壯難自降。", "空遺舊日影，怨彼小書窗。"]'),
('b4ab0057-6846-46fc-afce-1d641980509f','弔江南老家人春梅','孟郊','唐','唐诗','tang','','[]','念爾筋力盡，違我衣食恩。',48,'全唐诗/poet.tang.20000.json','["念爾筋力盡，違我衣食恩。", "奈何粗獷兒，生鞭見死痕。", "舊使常以禮，新怨將誰吞。", "胡爲乎泥中，消歇教義源。"]'),
('6db50b2a-0236-411d-b939-15ff10357a64','哭李丹員外幷寄杜中丞','孟郊','唐','唐诗','tang','','[]','生死方知交態存，忍將齚齖報幽魂。',32,'全唐诗/poet.tang.20000.json','["生死方知交態存，忍將齚齖報幽魂。", "十年同在平原客，更遣何人哭寢門。"]'),
('346f34e0-5943-44bb-b4ec-3370c166a187','哭劉言史','孟郊','唐','唐诗','tang','','[]','詩人業孤峭，餓死良已多。',98,'全唐诗/poet.tang.20000.json','["詩人業孤峭，餓死良已多。", "相悲與相笑，累累其奈何。", "精異劉言史，詩腸傾珠河。", "取次抱置之，飛過東溟波。", "可惜大國謠，飄爲四夷歌。", "常於衆中會，顏色兩切[磋]。", "今日果成死，葬襄之洛河。", "洛岸遠相弔，灑淚雙滂沱。"]'),
('de14bb60-1d94-446e-afff-0c7d17b454d4','弔盧殷 一','孟郊','唐','唐诗','tang','','[]','詩人多清峭，餓死抱空山。',84,'全唐诗/poet.tang.20000.json','["詩人多清峭，餓死抱空山。", "白雲既無主，飛出意等閑。", "久病牀席尸，護喪童僕孱。", "故書窮鼠嚙，狼藉一室間。", "君歸新鬼鄉，我面古玉顏。", "羞見入地時，無人叫追攀。", "百泉空相吊，日久哀潺潺。"]'),
('008fdabf-1891-4fe5-8851-36318b19224e','弔盧殷 二','孟郊','唐','唐诗','tang','','[]','唧唧復唧唧，千古一月色。',96,'全唐诗/poet.tang.20000.json','["唧唧復唧唧，千古一月色。", "新新復新新，千古一花春。", "邙風噫孟郊，嵩秋葬盧殷。", "北邙前後客，相弔爲埃塵。", "北邙棘針草，淚根生苦辛。", "煙火不自煖，筋力早已貧。", "幽薦一盃泣，瀉之清洛濱。", "添爲斷腸聲，愁殺長別人。"]'),
('4ccb9aec-0dc4-4b49-96c3-1c5b720297a0','弔盧殷 三','孟郊','唐','唐诗','tang','','[]','棘針風相號，破碎諸苦哀。',72,'全唐诗/poet.tang.20000.json','["棘針風相號，破碎諸苦哀。", "苦哀不可聞，掩耳亦入來。", "哭弦多煎聲，恨涕有餘摧。", "噫貧氣已焚，噫死心更灰。", "夢世浮閃閃，淚波深洄洄。", "薤歌一以去，蒿閉不復開。"]'),
('5b282752-b9a3-49c7-b975-1f65993ea72a','弔盧殷 四','孟郊','唐','唐诗','tang','','[]','登封草木深，登封道路微。',96,'全唐诗/poet.tang.20000.json','["登封草木深，登封道路微。", "日月不與光，莓苔空生衣。", "可憐無子翁，蚍蜉緣病肌。", "攣臥歲時長，漣漣但幽噫。", "幽噫虎豹聞，此外相訪稀。", "至親唯有詩，抱心死有歸。", "河南韓先生，後君作因依。", "磨一片嵌巖，書千古光輝。"]'),
('2370c769-c3fb-4154-a5d4-93b5e50c098a','弔盧殷 五','孟郊','唐','唐诗','tang','','[]','賢人無計較，生苦死徒誇。',48,'全唐诗/poet.tang.20000.json','["賢人無計較，生苦死徒誇。", "佗名潤子孫，君名潤泥沙。", "可惜千首文，閃如一朝花。", "零落難苦言，起坐空驚嗟。"]'),
('2238859b-ade4-47fc-8684-502f8143f88b','弔盧殷 六','孟郊','唐','唐诗','tang','','[]','耳聞陋巷生，眼見魯山君。',60,'全唐诗/poet.tang.20000.json','["耳聞陋巷生，眼見魯山君。", "餓死始有名，餓名高氛氳。", "戇叟老壯氣，感之爲憂雲。", "所憂唯一泣，古今相紛紛。", "平生與君說，逮此俱云云。"]'),
('bef6b664-d115-43f8-929d-97bec1b95af4','弔盧殷 七','孟郊','唐','唐诗','tang','','[]','初識漆鬢髮，爭爲新文章。',96,'全唐诗/poet.tang.20000.json','["初識漆鬢髮，爭爲新文章。", "夜踏明月橋，店飲吾曹床。", "醉啜二盃釀，名郁一縣香。", "寺中摘梅花，園裏翦浮芳。", "高嗜綠蔬羹，意輕肥膩羊。", "吟哦無滓韻，言語多古腸。", "白首忽然至，盛年如偷將。", "清濁俱莫追，何須駡滄浪。"]'),
('2b738b26-0060-4418-8025-38a133c90064','弔盧殷 八','孟郊','唐','唐诗','tang','','[]','前賢多哭酒，哭酒免哭心。',72,'全唐诗/poet.tang.20000.json','["前賢多哭酒，哭酒免哭心。", "後賢試銜之，哀至無不深。", "少年哭酒時，白髮亦已侵。", "老年哭酒時，聲韻隨生沈。", "寄言哭酒賓，勿作登封音。", "登封徒放聲，天地竟難尋。"]'),
('2815a0de-0d56-4a9b-bba9-b0e349b8cad9','弔盧殷 九','孟郊','唐','唐诗','tang','','[]','同人少相哭，異類多相號。',84,'全唐诗/poet.tang.20000.json','["同人少相哭，異類多相號。", "始知禽獸癡，却至天然高。", "非子病無淚，非父念莫勞。", "如何裁親疎，用禮如用刀。", "孤喪鮮匍匐，閉哀抱鬱陶。", "煩他手中葬，誠信焉能褒。", "嗟嗟無子翁，死棄如脫毛。"]'),
('22f231c5-5f6c-4328-baa0-c9426d921a37','弔盧殷 十','孟郊','唐','唐诗','tang','','[]','聖人哭賢人，骨化氣爲星。',72,'全唐诗/poet.tang.20000.json','["聖人哭賢人，骨化氣爲星。", "文章飛上天，列宿增晶熒。", "前古文可數，今人文亦靈。", "高名稱謫仙，昇降曾莫停。", "有文死更香，無文生亦腥。", "爲君鏗好辭，永傳作謐寧。"]'),
('cadff3b7-673c-4865-ae08-07142e12c523','寄遠曲','張籍','唐','唐诗','tang','','[]','美人來去春江暖，江頭無人湘水滿。',48,'全唐诗/poet.tang.20000.json','["美人來去春江暖，江頭無人湘水滿。", "浣沙石上水禽栖，江南路長春日短。", "蘭舟桂楫常渡江，無因重寄雙瓊璫。"]'),
('d82512d0-4837-4c31-9a00-ba54632af283','行路難','張籍','唐','唐诗','tang','','[]','湘東行人長歎息，十年離家歸未得。',63,'全唐诗/poet.tang.20000.json','["湘東行人長歎息，十年離家歸未得。", "弊裘羸馬苦難行，僮僕饑寒少筋力。", "君不見牀頭黃金盡，壯士無顏色。", "龍蟠泥中未有雲，不能生彼升天翼。"]'),
('16f31f24-e417-47b2-8fd8-478d9e10cd23','征婦怨','張籍','唐','唐诗','tang','','["\u54c0\u6028", "\u5987\u5973", "\u4e50\u5e9c", "\u65b0\u4e50\u5e9c\u8f9e"]','九月匈奴殺邊將，漢軍全沒遼水上。',64,'全唐诗/poet.tang.20000.json','["九月匈奴殺邊將，漢軍全沒遼水上。", "萬里無人收白骨，家家城下招魂葬。", "婦人依倚子與夫，同居貧賤心亦舒。", "夫死戰場子在腹，妾身雖存如晝燭。"]'),
('926829c8-5343-499f-ae07-833e3b238f0a','白紵歌','張籍','唐','唐诗','tang','','[]','皎皎白紵白且鮮，將作春衣稱少年。',64,'全唐诗/poet.tang.20000.json','["皎皎白紵白且鮮，將作春衣稱少年。", "裁縫長短不能定，自持刀尺向姑前。", "復恐蘭膏汙纖指，常遣傍人收墮珥。", "衣裳著時寒食下，還把玉鞭鞭白馬。"]'),
('b0b8c9b0-e68f-444e-b99c-c8733efe43b2','野老歌','張籍','唐','唐诗','tang','','["\u751f\u6d3b", "\u7530\u56ed", "\u519c\u6c11", "\u6292\u60c5", "\u4e50\u5e9c"]','老農家貧在山住，耕種山田三四畝。',64,'全唐诗/poet.tang.20000.json','["老農家貧在山住，耕種山田三四畝。", "苗疎稅多不得食，輸入官倉化爲土。", "歲暮鋤犂傍空室，呼兒登山收橡實。", "西江賈客珠百斛，船中養犬長食肉。"]'),
('c97e43dc-51d8-4d66-b3ff-78e71a23bc51','寄衣曲','張籍','唐','唐诗','tang','','[]','織素縫衣獨苦辛，遠因回使寄征人。',64,'全唐诗/poet.tang.20000.json','["織素縫衣獨苦辛，遠因回使寄征人。", "官家亦自寄衣去，貴從妾手著君身。", "高堂姑老無侍子，不得自到邊城裏。", "殷勤爲看初著時，征夫身上宜不宜。"]'),
('6a91a995-8301-4000-a129-d93c9224852e','送遠曲','張籍','唐','唐诗','tang','','["\u9001\u522b", "\u53cb\u60c5"]','戲馬臺南山簇簇，山邊飲酒歌別曲。',64,'全唐诗/poet.tang.20000.json','["戲馬臺南山簇簇，山邊飲酒歌別曲。", "行人醉後起登車，席上回尊勸僮僕。", "青天漫漫覆長路，遠遊無家安得住。", "願君到處自題名，他日知君從此去。"]'),
('0bcb1dcc-33d6-4983-a3e1-d2a0db8416a4','築城詞','張籍','唐','唐诗','tang','','[]','築城處，千人萬人齊把杵。',76,'全唐诗/poet.tang.20000.json','["築城處，千人萬人齊把杵。", "重重土堅試行錐，軍吏執鞭催作遲。", "來時一年深磧裏，盡著短衣渴無水。", "力盡不得拋杵聲，杵聲未盡人皆死。", "家家養男當門戶，今日作君城下土。"]'),
('7fec9452-4066-4bce-a4b6-18f0fcbd4a78','猛虎行','張籍','唐','唐诗','tang','','[]','南山北山樹冥冥，猛虎白日繞林行。',80,'全唐诗/poet.tang.20000.json','["南山北山樹冥冥，猛虎白日繞林行。", "向晚一身當道食，山中麋鹿盡無聲。", "年年養子在空谷，雌雄上山不相逐。", "谷中近窟有山村，長向村家取黃犢。", "五陵年少不敢射，空來林下看行迹。"]'),
('e746df5e-8161-458b-8bbf-4ca3f3c90b91','別離曲','張籍','唐','唐诗','tang','','[]','行人結束出門去，幾時更踏門前路。',80,'全唐诗/poet.tang.20000.json','["行人結束出門去，幾時更踏門前路。", "憶昔君初納采時，不言身屬遼陽戍。", "早知今日當別離，成君家計良爲誰。", "男兒生身自有役，那得誤我少年時。", "不如逐君征戰死，誰能獨老空閨裏。"]'),
('0a89bd17-bf77-4229-aed9-1418f67081e4','牧童詞','張籍','唐','唐诗','tang','','[]','遠牧牛，遶村四面禾黍稠。',76,'全唐诗/poet.tang.20000.json','["遠牧牛，遶村四面禾黍稠。", "陂中飢烏啄牛背，令我不得戲壠頭。", "入陂草多牛散行，白犢時向蘆中鳴。", "隔堤吹葉應同伴，還鼓長鞭三四聲。", "牛牛食草莫相觸，官家截爾頭上角。"]'),
('d59506ee-5231-4bc1-bdbc-478c7a7074b8','沙堤行呈裴相公','張籍','唐','唐诗','tang','','["\u6292\u60c5", "\u53d9\u4e8b"]','長安大道沙爲堤，早風無塵雨無泥。',80,'全唐诗/poet.tang.20000.json','["長安大道沙爲堤，早風無塵雨無泥。", "宮中玉漏下三刻，朱衣導騎丞相來。", "路傍高樓息歌吹，千車不行行者避。", "街官閭吏相傳呼，當前十里惟空衢。", "白麻詔下移相印，新堤未成舊堤盡。"]'),
('49522bf6-df30-4a45-a34f-68ed4c97bcc9','求仙行','張籍','唐','唐诗','tang','','[]','漢皇欲作飛仙子，年年採藥東海裏。',80,'全唐诗/poet.tang.20000.json','["漢皇欲作飛仙子，年年採藥東海裏。", "蓬萊無路海無邊，方士舟中相枕死。", "招搖在天迴白日，甘泉玉樹無仙實。", "九皇真人終不下，空向離宮祠太乙。", "丹田有氣凝素華，君能保之昇絳霞。"]'),
('a5466d66-fe78-40d7-a3e6-3bbb2cf58405','古釵歎','張籍','唐','唐诗','tang','','[]','古釵墮井無顏色，百尺泥中今復得。',80,'全唐诗/poet.tang.20000.json','["古釵墮井無顏色，百尺泥中今復得。", "鳳凰宛轉有古儀，欲爲首飾不稱時。", "女伴傳看不知主，羅袖拂拭生光輝。", "蘭膏已盡股半折，雕文刻樣無年月。", "雖離井底入匣中，不用還與墜時同。"]'),
('b27631db-b481-41c5-94a8-e876dfebd693','各東西','張籍','唐','唐诗','tang','','[]','遊人別，一東復一西。',90,'全唐诗/poet.tang.20000.json','["遊人別，一東復一西。", "出門相背兩不返，惟信車輪與馬蹄。", "道路悠悠不知處，山高海闊誰辛苦。", "遠遊不定難寄書，日日空尋別時語。", "浮雲上天雨墮地，暫時會合終離異。", "我今與子非一身，安得死生不相棄。"]'),
('7f57cb22-3bda-45c2-b5cb-aeaa10a3376d','節婦吟寄東平李司空師道','張籍','唐','唐诗','tang','','["\u575a\u8d1e", "\u5973\u5b50", "\u4e50\u5e9c", "\u65b0\u4e50\u5e9c\u8f9e"]','君知妾有夫，贈妾雙明珠。',56,'全唐诗/poet.tang.20000.json','["君知妾有夫，贈妾雙明珠。", "感君纏綿意，繫在紅羅襦。", "妾家高樓連苑起，良人執戟明光裏。", "知君用心如日月，事夫誓擬同生死。"]'),
('87ea2b40-5293-4d9d-97ef-aea11337a8cb','讌客詞','張籍','唐','唐诗','tang','','[]','上客不用顧金羈，主人有酒君莫違。',80,'全唐诗/poet.tang.20000.json','["上客不用顧金羈，主人有酒君莫違。", "請君看取園中花，地上漸多枝上稀。", "山頭樹影不見石，溪水無風應更碧。", "人人齊醉起舞時，誰覺翻衣與倒幘。", "明朝花盡人已去，此地獨來空繞樹。"]'),
('2e203343-f5ca-44ee-9f86-6b7d806726a8','永嘉行','張籍','唐','唐诗','tang','','[]','黃頭鮮卑入洛陽，胡兒執戟升明堂。',96,'全唐诗/poet.tang.20000.json','["黃頭鮮卑入洛陽，胡兒執戟升明堂。", "晉家天子作降虜，公卿奔走如牛羊。", "紫陌旌幡暗相觸，家家雞犬驚上屋。", "婦人出門隨亂兵，夫死眼前不敢哭。", "九州諸侯自顧土，無人領兵來護主。", "北人避胡多在南，南人至今能晉語。"]'),
('23ab2f0e-060c-40b8-b711-024666849c7f','採蓮曲','張籍','唐','唐诗','tang','','["\u5730\u65b9", "\u5199\u83b2", "\u5199\u4eba", "\u5199\u4eba\u8bd7"]','秋江岸邊蓮子多，採蓮女兒凭船歌。',96,'全唐诗/poet.tang.20000.json','["秋江岸邊蓮子多，採蓮女兒凭船歌。", "青房圓實齊戢戢，爭前競折漾微波。", "試牽綠莖下尋藕，斷處絲多刺傷手。", "白練束腰袖半卷，不插玉釵妝梳淺。", "船中未滿度前洲，借問阿誰家住遠。", "歸時共待暮潮上，自弄芙蓉還蕩槳。"]'),
('c8cc1a6e-077f-41c5-9ad3-2f8af41a9a18','傷歌行','張籍','唐','唐诗','tang','','[]','黃門詔下促收捕，京兆尹繫御史府。',112,'全唐诗/poet.tang.20000.json','["黃門詔下促收捕，京兆尹繫御史府。", "出門無復部曲隨，親戚相逢不容語。", "辭成謫尉南海州，受命不得須臾留。", "身着青衫騎惡馬，中門之外無送者。", "郵夫防吏急諠驅，往往驚墮馬蹄下。", "長安里中荒大宅，朱門已除十二戟。", "高堂舞榭鎖管絃，美人遙望西南天。"]'),
('0209bc51-5bf0-4413-af8a-a31388e1d542','吳宮怨','張籍','唐','唐诗','tang','','[]','吳宮四面秋江水，江清露白芙蓉死。',112,'全唐诗/poet.tang.20000.json','["吳宮四面秋江水，江清露白芙蓉死。", "吳王醉後欲更衣，座上美人嬌不起。", "宮中千門復萬戶，君恩反覆誰能數。", "君心與妾既不同，徒向君前作歌舞。", "茱萸滿宮紅實垂，秋風嫋嫋生繁枝。", "姑蘇臺上夕燕罷，佗人侍寢還獨歸。", "白日在天光在地，君今那得長相棄。"]'),
('3f1aa35f-ea49-46f3-9a38-cd901e54bd88','北邙行','張籍','唐','唐诗','tang','','[]','洛陽北門北邙道，喪車轔轔入秋草。',112,'全唐诗/poet.tang.20000.json','["洛陽北門北邙道，喪車轔轔入秋草。", "車前齊唱薤露歌，高墳新起白峨峨。", "朝朝暮暮人送葬，洛陽城中人更多。", "千金立碑高百尺，終作誰家柱下石。", "山頭松柏半無主，地下白骨多於土。", "寒食家家送紙錢，烏鳶作窠銜上樹。", "人居朝市未解愁，請君暫向北邙遊。"]'),
('203fcabb-90e3-433f-b578-f73c204c7059','關山月','張籍','唐','唐诗','tang','','[]','秋月朗朗關山上，山中行人馬蹄響。',112,'全唐诗/poet.tang.20000.json','["秋月朗朗關山上，山中行人馬蹄響。", "關山秋來雨雪多，行人見月唱邊歌。", "海邊茫茫天氣白，胡兒夜度黃龍磧。", "軍中探騎暮出城，伏兵暗處低旌戟。", "溪水連天霜草平，野駝尋水磧中鳴。", "隴頭風急雁不下，沙場苦戰多流星。", "可憐萬國關山道，年年戰骨多秋草。"]'),
('d5f74a11-92b2-42b3-b360-0caab73939b3','隴頭行','張籍','唐','唐诗','tang','','[]','隴頭路斷人不行，胡騎夜入涼州城。',80,'全唐诗/poet.tang.20000.json','["隴頭路斷人不行，胡騎夜入涼州城。", "漢兵處處格鬬死，一朝盡沒隴西地。", "驅我邊人胡中去，散放牛羊食禾黍。", "去年中國養子孫，今著氈裘學胡語。", "誰能更使李輕車，收取涼州入漢家。"]'),
('e884efcb-d9c0-48b5-95b3-e644dba54b9b','楚妃歎','張籍','唐','唐诗','tang','','[]','湘雲初起江沉沉，君王遙在雲夢林。',80,'全唐诗/poet.tang.20000.json','["湘雲初起江沉沉，君王遙在雲夢林。", "江南雨多旌旗暗，臺下朝朝春水深。", "章華殿前朝萬國，君心獨自無終極。", "楚兵滿地能逐禽，誰用一身騁筋力。", "西江若飜雲夢中，麋鹿死盡應還宮。"]'),
('37c902a0-b08c-4226-81d1-c6600bec4220','春日行','張籍','唐','唐诗','tang','','[]','春日融融池上暖，竹牙出土蘭心短。',96,'全唐诗/poet.tang.20000.json','["春日融融池上暖，竹牙出土蘭心短。", "草堂晨起酒半醒，家僮報我園花滿。", "頭上皮冠未曾整，直入花間不尋徑。", "樹樹殷勤盡遶行，攀枝未徧春日暝。", "不用積金著青天，不用服藥求神仙。", "但願園裏花長好，一生飲酒花前老。"]'),
('ad0f966c-f139-4667-8533-dc2e49657492','秋夜長','張籍','唐','唐诗','tang','','[]','秋天如水夜未央，天漢東西月色光。',64,'全唐诗/poet.tang.20000.json','["秋天如水夜未央，天漢東西月色光。", "愁人不寐畏枕席，暗蟲唧唧遶我傍。", "荒城爲村無更聲，起看北斗天未明。", "白露滿田風嫋嫋，千聲萬聲鶡鳥鳴。"]'),
('eaf535f0-d599-4356-b69d-2ad5622e018f','白鼉鳴','張籍','唐','唐诗','tang','','[]','天欲雨，有東風，南谿白鼉鳴窟中。',32,'全唐诗/poet.tang.20000.json','["天欲雨，有東風，南谿白鼉鳴窟中。", "六月人家井無水，夜聞鼉聲人盡起。"]'),
('cd8604be-3ce1-4a4e-891b-c30857a16fa0','洛陽行','張籍','唐','唐诗','tang','','[]','洛陽宮闕當中州，城上峨峨十二樓。',112,'全唐诗/poet.tang.20000.json','["洛陽宮闕當中州，城上峨峨十二樓。", "翠華西去幾時返，梟巢乳鳥藏蟄燕。", "御門空鎖五十年，稅彼農夫修玉殿。", "六街朝暮鼓鼕鼕，禁兵持戟守空宮。", "百官月月拜章表，驛使相續長安道。", "上陽宮樹黃復綠，野豺入苑食麋鹿。", "陌上老翁雙淚垂，共說武皇巡幸時。"]'),
('6d276f70-5659-4c8b-ae55-32fad946ad9e','春江曲','張籍','唐','唐诗','tang','','[]','春江無雲潮水平，蒲心出水鳧雛鳴。',80,'全唐诗/poet.tang.20000.json','["春江無雲潮水平，蒲心出水鳧雛鳴。", "長干夫壻愛遠行，自染春衣縫已成。", "妾身生長金陵側，去年隨夫住江北。", "春來未到父母家，舟小風多渡不得。", "欲辭舅姑先問人，私向江頭祭水神。"]'),
('5639c076-ff59-4271-bfff-731b0ab3b719','送遠曲','張籍','唐','唐诗','tang','','[]','吳門向西流水長，水長柳暗煙茫茫。',112,'全唐诗/poet.tang.20000.json','["吳門向西流水長，水長柳暗煙茫茫。", "行人送客各惆悵，話離敘別傾清觴。", "吟絲竹，鳴笙簧，酒酣性逸歌猖狂。", "行人告我挂帆去，此去何時返故鄉。", "殷勤振衣兩相囑，世事近來還淺促。", "願君看取吳門山，帶雪經春依舊綠。", "行人行處求知親，送君去去徒酸辛。"]'),
('1ab92554-c207-49bf-a3d3-edb6b7f6b0bb','塞下曲','張籍','唐','唐诗','tang','','[]','邊州八月修城堡，候騎先燒磧中草。',96,'全唐诗/poet.tang.20000.json','["邊州八月修城堡，候騎先燒磧中草。", "胡風吹沙度隴飛，隴頭林木無北枝。", "將軍閱兵青塞下，鳴鼓逢逢促獵圍。", "天寒山路石斷裂，白日不銷帳上雪。", "烏孫國亂多降胡，詔使名王持漢節。", "年年征戰不得閑，邊人殺盡唯空山。"]'),
('593f42d7-3b06-4409-bd98-00513a326392','董逃行','張籍','唐','唐诗','tang','','[]','洛陽城頭火曈曈，亂兵燒我天子宮。',76,'全唐诗/poet.tang.20000.json','["洛陽城頭火曈曈，亂兵燒我天子宮。", "宮城南面有深山，盡將老幼藏其間。", "重巖爲屋橡爲食，丁男夜行候消息。", "聞道官軍猶掠人，舊里如今歸未得。", "董逃行，漢家幾時重太平。"]'),
('bc5bbf65-131f-496a-bb4d-656e68f06918','少年行','張籍','唐','唐诗','tang','','[]','少年從獵出長楊，禁中新拜羽林郎。',112,'全唐诗/poet.tang.20000.json','["少年從獵出長楊，禁中新拜羽林郎。", "獨對輦前射雙虎，君王手賜黃金璫。", "日日鬬雞都市裏，贏得寶刀重刻字。", "百里報仇夜出城，平明還在娼樓醉。", "遙聞虜到平陵下，不待詔書行上馬。", "斬得名王獻桂宮，封侯起第一日中。", "不爲六郡良家子，百戰始取邊城功。"]'),
('fef3b512-d4e0-473b-9b3a-b1d87831dfdd','白頭吟','張籍','唐','唐诗','tang','','[]','請君漆上琴，彈我白頭吟。',124,'全唐诗/poet.tang.20000.json','["請君漆上琴，彈我白頭吟。", "憶昔君前嬌笑語，兩情宛轉如縈素。", "宮中爲我起高樓，更開花池種芳樹。", "春天百草秋始衰，棄我不待白頭時。", "羅襦玉珥色未暗，今朝已道不相宜。", "揚州青銅作明鏡，暗中持照不見影。", "人心回互自無窮，眼前好惡那能定。", "君恩已去若再返，菖蒲花開月長滿。"]'),
('a90fd6d4-03a9-408e-afd2-4c0246edabc3','將軍行','張籍','唐','唐诗','tang','','[]','彈箏峽東有胡塵，天子擇日拜將軍。',128,'全唐诗/poet.tang.20000.json','["彈箏峽東有胡塵，天子擇日拜將軍。", "蓬萊殿前賜六纛，還領禁兵爲部曲。", "當朝受詔不辭家，夜向咸陽原上宿。", "戰車彭彭旌旗動，三十六軍齊上隴。", "隴頭戰勝夜亦行，分兵處處收舊城。", "胡兒殺盡陰磧暮，擾擾唯有牛羊聲。", "邊人親戚曾戰沒，今逐官軍收舊骨。", "磧西行見萬里空，幕府獨奏將軍功。"]'),
('fd94f220-36a3-4e1d-9ee9-cde5f2b95b56','賈客樂','張籍','唐','唐诗','tang','','[]','金陵向西賈客多，船中生長樂風波。',128,'全唐诗/poet.tang.20000.json','["金陵向西賈客多，船中生長樂風波。", "欲發移船近江口，船頭祭神各澆酒。", "停杯共說遠行期，入蜀經蠻誰別離。", "金多衆中爲上客，夜夜算緡眠獨遲。", "秋江初月猩猩語，孤帆夜發瀟湘渚。", "水工持檝防暗灘，直過山邊及前侶。", "年年逐利西復東，姓名不在縣籍中。", "農夫稅多長辛苦，棄業長爲販寶翁。"]'),
('bd210732-06c5-4b11-9db7-6a813d71ac4c','羈旅行','張籍','唐','唐诗','tang','','[]','遠客出門行路難，停車斂策在門端。',144,'全唐诗/poet.tang.20000.json','["遠客出門行路難，停車斂策在門端。", "荒城無人霜滿路，野火燒橋不得度。", "寒蟲入窟鳥歸巢，僮僕問我誰家去。", "行尋田頭暝未息，雙轂長轅礙荆棘。", "緣岡入澗投田家，主人舂米爲夜食。", "晨雞喔喔茅屋傍，行人起掃車上霜。", "舊山已別行已遠，身計未成難復返。", "長安陌上相識稀，遙望天山白日晚。", "誰能聽我辛苦行，爲向君前歌一聲。"]'),
('2c3dbfc3-e271-4454-93b0-2abb419ac45c','車遙遙','張籍','唐','唐诗','tang','','[]','征人遙遙出古城，雙輪齊動駟馬鳴。',112,'全唐诗/poet.tang.20000.json','["征人遙遙出古城，雙輪齊動駟馬鳴。", "山川無處不歸路，念君長作萬里行。", "野田人稀秋草綠，日暮放馬車中宿。", "驚麏游兔在我傍，獨唱鄉歌對僮僕。", "君家大宅鳳城隅，年年道上隨行車。", "願爲玉鑾繫華軾，終日有聲在君側。", "門前舊轍久已平，無由復得君消息。"]'),
('fa247c16-f33d-427b-ba30-20a1cd152f54','妾薄命','張籍','唐','唐诗','tang','','[]','薄命婦，良家子，無事從軍去萬里。',96,'全唐诗/poet.tang.20000.json','["薄命婦，良家子，無事從軍去萬里。", "漢家天子平四夷，護羌都尉裹尸歸。", "念君此行爲死別，對君裁縫泉下衣。", "與君一日爲夫婦，千年萬歲亦相守。", "君愛龍城征戰功，妾願青樓歌樂同。", "人生各各有所欲，詎得將心入君腹。"]'),
('1f8f39f3-51ea-40e5-89b5-d0f7575d7055','朱鷺','張籍','唐','唐诗','tang','','[]','翩翩兮朱鷺，來汎春塘栖綠樹。',62,'全唐诗/poet.tang.20000.json','["翩翩兮朱鷺，來汎春塘栖綠樹。", "羽毛如翦色如染，遠飛欲下雙翅斂。", "避人引子入深壍，動處水紋開灩灩。", "誰知豪家網爾軀，不如飲啄江海隅。"]'),
('f8df321b-96ae-4faa-8e6e-c1cce6bd3e07','遠別離','張籍','唐','唐诗','tang','','["\u957f\u6c5f"]','蓮葉團團杏花拆，長江鯉魚鬐鬣赤。',64,'全唐诗/poet.tang.20000.json','["蓮葉團團杏花拆，長江鯉魚鬐鬣赤。", "念君少年棄親戚，千里萬里獨爲客。", "誰言遠別心不易，天星墜地能爲石。", "幾時斷得城南陌，勿使居人有行役。"]'),
('4c612716-883d-459c-bc5a-ed043128792f','楚宮行','張籍','唐','唐诗','tang','','[]','章華宮中九月時，桂花半落紅橘垂。',144,'全唐诗/poet.tang.20000.json','["章華宮中九月時，桂花半落紅橘垂。", "江頭騎火照輦道，君王夜從雲夢歸。", "霓旌鳳蓋到雙闕，臺上重重歌吹發。", "千門萬戶開相當，燭籠左右列成行。", "下輦更衣入洞房，洞房侍女盡焚香。", "玉階羅幕微有霜，齊言此夕樂未央。", "玉酒湛湛盈華觴，絲竹次第鳴中堂。", "巴姬起舞向君王，迴身垂手結明璫。", "願君千年萬年壽，朝出射麋夜飲酒。"]'),
('a10fe79c-f316-4f75-8ea0-8f5fe5f239aa','江南行','張籍','唐','唐诗','tang','','[]','江南人家多橘樹，吳姬舟上織白苧。',112,'全唐诗/poet.tang.20000.json','["江南人家多橘樹，吳姬舟上織白苧。", "土地卑濕饒蟲蛇，連木爲牌入江住。", "江村亥日長爲市，落帆度橋來蒲裏。", "清莎覆城竹爲屋，無井家家飲潮水。", "長干午日沽春酒，高高酒旗懸江口。", "娼樓兩岸臨水柵，夜唱竹枝留北客。", "江南風土歡樂多，悠悠處處盡經過。"]'),
('14e2e1e8-85c4-4b6b-92a8-e0d3501f1899','烏夜啼引','張籍','唐','唐诗','tang','','[]','秦烏啼啞啞，夜啼長安吏人家。',90,'全唐诗/poet.tang.20000.json','["秦烏啼啞啞，夜啼長安吏人家。", "吏人得罪囚在獄，傾家賣產將自贖。", "少婦起聽夜啼烏，知是官家有赦書。", "下牀心喜不重寐，未明上堂賀舅姑。", "少婦語啼烏，汝啼慎勿虛。", "借汝庭樹作高巢，年年不令傷爾雛。"]'),
('f6234488-2cb9-426a-92fa-7bbf5c1d7811','促促詞','張籍','唐','唐诗','tang','','[]','促促復促促，家貧夫婦歡不足。',80,'全唐诗/poet.tang.20000.json','["促促復促促，家貧夫婦歡不足。", "今年爲人送租船，去年捕魚在江邊。", "家中姑老子復小，自執吳綃輸稅錢。", "家家桑麻滿地黑，念君一身空努力。", "願教牛蹄團團羊角直，君身常在應不得。"]'),
('a002dfd5-85f1-451e-aff2-9971432d0a23','宛轉行','張籍','唐','唐诗','tang','','[]','華屋重翠幄，綺席雕象牀。',60,'全唐诗/poet.tang.20000.json','["華屋重翠幄，綺席雕象牀。", "遠漏微更疎，薄衾中夜涼。", "爐氣暗裴徊，寒燈背斜光。", "妍姿結宵態，寢臂幽夢長。", "宛轉復宛轉，憶君更未央。"]'),
('81bc9fa6-fd47-4437-a3fc-6a92a7ee4ded','短歌行','張籍','唐','唐诗','tang','','[]','青天蕩蕩高且虛，上有白日無根株。',64,'全唐诗/poet.tang.20000.json','["青天蕩蕩高且虛，上有白日無根株。", "流光暫出還入地，使我年少不須臾。", "與君相逢勿寂寞，衰老不復如今樂。", "玉巵盛酒置君前，再拜願君千萬年。"]'),
('cc737538-d2f9-44e0-b663-09d41410e9e8','山頭鹿','張籍','唐','唐诗','tang','','[]','山頭鹿，角芟芟，尾促促。',60,'全唐诗/poet.tang.20000.json','["山頭鹿，角芟芟，尾促促。", "貧兒多租輸不足，夫死未葬兒在獄。", "早日熬熬蒸野岡，禾黍不收無獄糧。", "縣家唯憂少軍食，誰能令爾無死傷。"]'),
('9b3d3cc0-6c4d-4c4b-a987-81ae9ac321f1','湘江曲','張籍','唐','唐诗','tang','','[]','湘水無潮秋水闊，湘中月落行人發。',32,'全唐诗/poet.tang.20000.json','["湘水無潮秋水闊，湘中月落行人發。", "送人發，送人歸，白蘋茫茫鷓鴣飛。"]'),
('35ef0bea-62c9-40f6-b20e-d5c6b94e9383','楚妃怨','張籍','唐','唐诗','tang','','[]','梧桐葉下黃金井，橫架轆轤牽素綆。',32,'全唐诗/poet.tang.20000.json','["梧桐葉下黃金井，橫架轆轤牽素綆。", "美人初起天未明，手拂銀缾秋水冷。"]'),
('58380015-6707-4e90-994d-c9aa635f835b','離宮怨','張籍','唐','唐诗','tang','','[]','高堂別館連湘渚，長向春光開萬戶。',32,'全唐诗/poet.tang.20000.json','["高堂別館連湘渚，長向春光開萬戶。", "荆王去去不復來，宮中美人自歌舞。"]'),
('651987af-2600-4410-a813-0d0f8ae28b66','成都曲','張籍','唐','唐诗','tang','','["\u5e26\u6709\u5730\u540d", "\u5199\u666f", "\u5730\u540d"]','錦江近西煙水綠，新雨山頭荔枝熟。',32,'全唐诗/poet.tang.20000.json','["錦江近西煙水綠，新雨山頭荔枝熟。", "萬里橋邊多酒家，遊人愛向誰家宿。"]'),
('c605ce03-b734-46c5-ad73-7e8ddf072cf0','寒塘曲','張籍','唐','唐诗','tang','','[]','寒塘沉沉柳葉疎，水暗人語驚棲鳧。',32,'全唐诗/poet.tang.20000.json','["寒塘沉沉柳葉疎，水暗人語驚棲鳧。", "舟中少年醉不起，持燭照水射遊魚。"]'),
('e283aa1c-56bb-490b-89dc-54e0a33465d4','春別曲','張籍','唐','唐诗','tang','','["\u957f\u6c5f", "\u6625\u5929"]','長江春水綠堪染，蓮葉出水大如錢。',32,'全唐诗/poet.tang.20000.json','["長江春水綠堪染，蓮葉出水大如錢。", "江頭橘樹君自種，那不長繫木蘭船。"]'),
('0e878fb0-293f-4513-8624-4c57000921ff','春堤曲','張籍','唐','唐诗','tang','','[]','野塘鵁鶄飛樹頭，綠蒲紫菱蓋碧流。',32,'全唐诗/poet.tang.20000.json','["野塘鵁鶄飛樹頭，綠蒲紫菱蓋碧流。", "狂客誰家愛雲水，日日獨來城下遊。"]'),
('0fe2eef5-dd56-4343-9f7f-a9c12499e22e','烏棲曲','張籍','唐','唐诗','tang','','[]','西山作宮潮滿池，宮鳥曉鳴茱萸枝。',32,'全唐诗/poet.tang.20000.json','["西山作宮潮滿池，宮鳥曉鳴茱萸枝。", "吳姬採蓮自唱曲，君王昨夜舟中宿。"]'),
('c8892f5b-777e-4221-be4b-65e43a230725','雀飛多','張籍','唐','唐诗','tang','','[]','雀飛多，觸網羅，網羅高樹顛。',46,'全唐诗/poet.tang.20000.json','["雀飛多，觸網羅，網羅高樹顛。", "汝飛蓬蒿下，勿復投身網羅間。", "粟積倉，禾在田。", "巢之雛，望其母來還。"]'),
('4453d037-74ce-434d-8db0-1c63b6cc62b8','泗水行','張籍','唐','唐诗','tang','','[]','泗水流急石纂纂，鯉魚上下紅尾短。',48,'全唐诗/poet.tang.20000.json','["泗水流急石纂纂，鯉魚上下紅尾短。", "春冰銷散日華滿，行舟往來浮橋斷。", "城邊魚市人早行，水煙漠漠多棹聲。"]'),
('5ce0a98f-2b5f-4cfe-bfc5-6967bfeb87a6','廢居行','張籍','唐','唐诗','tang','','[]','胡馬崩騰滿阡陌，都人避亂唯空宅。',96,'全唐诗/poet.tang.20000.json','["胡馬崩騰滿阡陌，都人避亂唯空宅。", "宅邊青桑垂宛宛，野蠶食葉還成繭。", "黃雀銜草入燕窠，嘖嘖啾啾白日晚。", "去時禾黍埋地中，飢兵掘土翻重重。", "鴟梟養子庭樹上，曲牆空屋多旋風。", "亂定幾人還本土，唯有官家重作主。"]'),
('08a57734-3ccb-4ba5-bfe5-a33ac611c1af','寄菖蒲','張籍','唐','唐诗','tang','','[]','石上生菖蒲，一寸十二節。',58,'全唐诗/poet.tang.20000.json','["石上生菖蒲，一寸十二節。", "仙人勸我食，令我頭青面如雪。", "逢人寄君一絳囊，書中不得傳此方。", "君能來作棲霞侶，與君同入丹玄鄉。"]'),
('667d82a0-09a4-4191-966a-ab32956894f5','江村行','張籍','唐','唐诗','tang','','[]','南塘水深蘆笋齊，下田種稻不作畦。',112,'全唐诗/poet.tang.20000.json','["南塘水深蘆笋齊，下田種稻不作畦。", "耕場磷磷在水底，短衣半染蘆中泥。", "田頭刈莎結爲屋，歸來繫牛還獨宿。", "水淹手足盡有瘡，山蝱遶身飛颺颺。", "桑林椹黑蠶再眠，婦姑採桑不向田。", "江南熱旱天氣毒，雨中移秧顏色鮮。", "一年耕種長苦辛，田熟家家將賽神。"]'),
('d9565e5d-ab7e-4293-88d0-ea04ad751c7b','樵客吟','張籍','唐','唐诗','tang','','[]','上山採樵選枯樹，深處樵多出辛苦。',122,'全唐诗/poet.tang.20000.json','["上山採樵選枯樹，深處樵多出辛苦。", "秋來野火燒櫟林，枝柯已枯堪採取。", "斧聲坎坎在幽谷，採得齊梢青葛束。", "日西待伴同下山，竹擔彎彎向身曲。", "共知路傍多虎窟，未出深林不敢歇。", "村西地暗狐兔行，稚子呌時相應聲。", "採樵客，莫採松與栢。", "松栢生枝直且堅，與君作屋成家宅。"]'),
('b89c7d43-a354-4903-bb84-b0e3fb1caba8','湖南曲','張籍','唐','唐诗','tang','','[]','瀟湘多別離，風起芙蓉洲。',36,'全唐诗/poet.tang.20000.json','["瀟湘多別離，風起芙蓉洲。", "江上人已遠，夕陽滿中流。", "鴛鴦東南飛，飛上青山頭。"]'),
('f9f520a9-13e6-4379-b6fd-f86904c219d6','春水曲','張籍','唐','唐诗','tang','','[]','鴨鴨，觜唼唼。',35,'全唐诗/poet.tang.20000.json','["鴨鴨，觜唼唼。", "青蒲生，春水狹。", "蕩漾木蘭船，中有雙少年。", "少年醉，鴨不起。"]'),
('f4a58042-0cb6-4881-83cf-6dbc6efda309','雲童行','張籍','唐','唐诗','tang','','[]','雲童童，白龍之尾垂江中。',28,'全唐诗/poet.tang.20000.json','["雲童童，白龍之尾垂江中。", "今年天旱不作雨，水足牆上有禾黍。"]'),
('029ff16c-6562-4d06-95d9-765045b30c69','新桃行','張籍','唐','唐诗','tang','','[]','桃生葉婆娑，枝葉四向多。',96,'全唐诗/poet.tang.20000.json','["桃生葉婆娑，枝葉四向多。", "高未出牆顛，蒿莧相凌摩。", "植之三年餘，今年初試花。", "秋來已成實，其陰良已嘉。", "青蟬不來鳴，安得迅羽過。", "常惡牽絲蟲，蒙冪成網羅。", "顧託戲兒童，勿折吾柔柯。", "明年結其實，磊磊充汝家。"]'),
('a3743cb0-1b04-48da-b200-539bed84707f','憶遠曲','張籍','唐','唐诗','tang','','[]','水上山沈沈，征途復繞林。',48,'全唐诗/poet.tang.20000.json','["水上山沈沈，征途復繞林。", "途荒人行少，馬跡猶可尋。", "雪中獨立樹，海口失侶禽。", "離憂如長線，千里縈我心。"]'),
('06510f1b-fb30-43ee-a941-b013f96f6601','長塘湖','張籍','唐','唐诗','tang','','[]','長塘湖，一斛水中半斛魚。',32,'全唐诗/poet.tang.20000.json','["長塘湖，一斛水中半斛魚。", "大魚如柳葉，小魚如針鋒，水濁誰能辨真龍。"]'),
('1fa1686d-4d76-4113-9758-3dd042a3c36a','廢瑟詞','張籍','唐','唐诗','tang','','[]','古瑟在匣誰復識，玉柱顛倒朱絲黑。',64,'全唐诗/poet.tang.20000.json','["古瑟在匣誰復識，玉柱顛倒朱絲黑。", "千年曲譜不分明，樂府無人傳正聲。", "秋蟲暗穿塵作色，腹中不辨工人名。", "幾時天下復古樂，此瑟還奏雲門曲。"]'),
('7a45c880-aded-459f-a5a5-a67fab2f7665','野居','張籍','唐','唐诗','tang','','[]','貧賤易爲適，荒郊亦安居。',96,'全唐诗/poet.tang.20000.json','["貧賤易爲適，荒郊亦安居。", "端坐無餘思，彌樂古人書。", "秋田多良苗，野水多遊魚。", "我無耒與網，安得充廩廚。", "寒天白日短，簷下煖我軀。", "四肢暫寬柔，中腸鬱不舒。", "多病減志氣，爲客足憂虞。", "況復苦時節，覽景獨踟躕。"]'),
('eb2087c2-631e-4425-b387-f262110567a2','西州','張籍','唐','唐诗','tang','','[]','羌胡據西州，近甸無邊城。',108,'全唐诗/poet.tang.20000.json','["羌胡據西州，近甸無邊城。", "山東收稅租，養我防塞兵。", "胡騎來無時，居人常震驚。", "嗟我五陵間，農者罷耘耕。", "邊頭多殺傷，士卒難全形。", "郡縣發丁役，丈夫各征行。", "生男不能養，懼身有姓名。", "良馬不念秣，烈士不苟營。", "所願除國難，再逢天下平。"]'),
('6d166ac5-5466-46a8-943d-1d7df991eeee','雜怨','張籍','唐','唐诗','tang','','[]','切切重切切，秋風桂枝折。',60,'全唐诗/poet.tang.20000.json','["切切重切切，秋風桂枝折。", "人當少年嫁，我當少年別。", "念君非征行，年年長遠途。", "妾身甘獨歿，高堂有舅姑。", "山川豈遙遠，行人自不返。"]'),
('0665115d-dc5d-4bd0-9130-05dd7dc03d75','惜花','張籍','唐','唐诗','tang','','[]','春潭足芳樹，水清不如素。',48,'全唐诗/poet.tang.20000.json','["春潭足芳樹，水清不如素。", "幽人愛華景，一一空山暮。", "月出潭氣白，游魚暗衝石。", "夜深春思多，酒醒山寂寂。"]'),
('2ffd2a7f-75c9-44e9-b3a9-2ea43014554c','三原李氏園宴集','張籍','唐','唐诗','tang','','[]','暮春天早熱，邑居苦囂煩。',120,'全唐诗/poet.tang.20000.json','["暮春天早熱，邑居苦囂煩。", "言從君子樂，樂彼李氏園。", "園中有草堂，池引涇水泉。", "開戶西北望，遠見嵯峨山。", "借問主人翁，北州佐戎軒。", "僕夫守舊宅，爲客侍華筵。", "高懷有餘興，竹樹芳且鮮。", "傾我所持觴，盡日共留連。", "疎拙不偶俗，常喜形體閑。", "況來幽棲地，能不重歎言。"]'),
('c490a58a-f973-4f3b-842c-472aeb3f660e','沈千運舊居','張籍','唐','唐诗','tang','','[]','汝北君子宅，我來見頹墉。',132,'全唐诗/poet.tang.20000.json','["汝北君子宅，我來見頹墉。", "亂離子孫盡，地屬鄰里翁。", "土木被丘墟，谿路不連通。", "舊井蔓草合，牛羊墜其中。", "君辭天下書，放意任體躬。", "一生不自力，家與逆旅同。", "高議切星辰，餘聲激瘖聾。", "方將旌舊閭，百世可封崇。", "嗟其未積年，已爲荒林叢。", "時豈無知音，不能崇此風。", "浩蕩竟無覩，我將安所從。"]'),
('a888e890-ca60-47f3-a750-3df66492fb8c','贈別孟郊','張籍','唐','唐诗','tang','','[]','歷歷天上星，沉沉水中萍。',120,'全唐诗/poet.tang.20000.json','["歷歷天上星，沉沉水中萍。", "幸當清秋夜，流影及微形。", "君生衰俗間，立身如禮經。", "純誠發新文，獨有金石聲。", "才名振京國，歸省東南行。", "停車楚城下，顧我不念程。", "寶鏡曾墜水，不磨豈自明。", "苦節居貧賤，所知賴友生。", "歡會方別離，戚戚憂慮幷。", "安得在一方，終老無送迎。"]'),
('1451f8f4-ea3c-444d-8a2d-cb370fcad7d5','臥疾','張籍','唐','唐诗','tang','','[]','身病多思慮，亦讀神農經。',120,'全唐诗/poet.tang.20000.json','["身病多思慮，亦讀神農經。", "空堂留燈燭，四壁青熒熒。", "羈旅隨人歡，貧賤還自輕。", "今來問良醫，乃知病所生。", "僮僕各憂愁，杵臼無停聲。", "見我形顦顇，勸藥語丁寧。", "春雨枕席冷，窗前新禽鳴。", "開門起無力，遙愛雞犬行。", "服藥察耳目，漸如醉者醒。", "顧非達性命，猶爲憂患生。"]'),
('e482fbfb-c53a-4202-bde6-410b0cccc84f','臥疾','張籍','唐','唐诗','tang','','[]','身病始知道，卧讀神農經。',120,'全唐诗/poet.tang.20000.json','["身病始知道，卧讀神農經。", "空房夜留燈，四壁青熒熒。", "羇旅逐人歡，貧賤還自輕。", "今來問良醫，乃知病所生。", "僮僕各相憂，杵臼無停聲。", "見我形憔悴，勸藥語丁寧。", "春雨枕席冷，窗前新禽鳴。", "開門起無力，遥愛鷄犬行。", "服藥察耳目，漸覺如酒醒。", "方悟養生者，不為憂患并。"]'),
('738d2629-b1b5-4688-bca6-bee1805a13fb','別段生','張籍','唐','唐诗','tang','','[]','與子骨肉親，願言長相隨。',144,'全唐诗/poet.tang.20000.json','["與子骨肉親，願言長相隨。", "況離父母傍，從我學書詩。", "同在道路間，講論亦未虧。", "爲文於我前，日夕生光儀。", "行役多疾疚，賴此相扶持。", "貧賤事難拘，今日有別離。", "我去秦城中，子留汴水湄。", "離情兩飄斷，不異風中絲。", "幼年獨爲客，舉動難得宜。", "努力自修勵，常如見我時。", "送我登山岡，再拜問還期。", "還期在新年，勿怨歡會遲。"]'),
('41070caa-7d85-4393-99c5-06abbda8eb37','哭于鵠','張籍','唐','唐诗','tang','','[]','青山無逸人，忽覺大國貧。',120,'全唐诗/poet.tang.20000.json','["青山無逸人，忽覺大國貧。", "良玉沈幽泉，名爲天下珍。", "野性疎時俗，再拜乃從軍。", "氣高終不合，去如鏡上塵。", "我初有章句，相合者唯君。", "今來弔嗣子，對隴燒新文。", "耕者廢其耜，爨者絕其薪。", "苟無新衣裳，曷用光我身。", "奠酒徒拜手，哀懷安能陳。", "徒保金石韻，千載人所聞。"]'),
('3b5d6e14-a07e-422c-8a6d-c8e343ac8fc6','南歸','張籍','唐','唐诗','tang','','[]','促促念道路，四支不常寧。',120,'全唐诗/poet.tang.20000.json','["促促念道路，四支不常寧。", "行車未及家，天外非盡程。", "骨肉待我歡，鄉里望我榮。", "豈知東與西，顦顇竟無成。", "人言苦夜長，窮者不念明。", "懼離其寢寐，百憂傷性靈。", "世道多險薄，相勸畢中誠。", "遠遊無知音，不如商賈行。", "達人有常志，愚夫勞所營。", "舊山行去遠，言歸樂此生。"]'),
('d8e69d3f-323e-4e7b-a49f-86254e40c644','惜花','張籍','唐','唐诗','tang','','[]','濛濛庭樹花，墜地無顏色。',48,'全唐诗/poet.tang.20000.json','["濛濛庭樹花，墜地無顏色。", "日暮東風起，飄揚玉階側。", "殘蘂在猶稀，青條聳復直。", "爲君結芳實，令君勿歎息。"]'),
('d462022f-de0f-450b-9410-3dacca1f1d4d','奉和舍人叔直省時思琴','張籍','唐','唐诗','tang','','[]','藹藹紫薇直，秋意深無窮。',72,'全唐诗/poet.tang.20000.json','["藹藹紫薇直，秋意深無窮。", "滴瀝仙閣漏，肅穆禁池風。", "竹月泛涼影，萱露澹幽叢。", "地清物態勝，宵閑琴思通。", "時屬雅音際，逈凝虛抱中。", "達人掌樞近，常與隱默同。"]'),
('8ea07b6e-b3fc-4f30-a95d-b2eb178f6193','離婦','張籍','唐','唐诗','tang','','[]','十載來夫家，閨門無瑕疵。',204,'全唐诗/poet.tang.20000.json','["十載來夫家，閨門無瑕疵。", "薄命不生子，古制有分離。", "託身言同穴，今日事乖違。", "念君終棄捐，誰能強在茲。", "堂上謝姑嫜，長跪請離辭。", "姑嫜見我往，將決復沉疑。", "與我古時釧，留我嫁時衣。", "高堂拊我身，哭我於路陲。", "昔日初爲婦，當君貧賤時。", "晝夜常紡績，不得事蛾眉。", "辛勤積黃金，濟君寒與飢。", "洛陽買大宅，邯鄲買侍兒。", "夫壻乘龍馬，出入有光儀。", "將爲富家婦，永爲子孫資。", "誰謂出君門，一身上車歸。", "有子未必榮，無子坐生悲。", "爲人莫作女，作女實難爲。"]'),
('7e43da74-cffe-4a4c-9b54-5781fe17153b','懷別','張籍','唐','唐诗','tang','','[]','僕人驅行軒，低昂出我門。',96,'全唐诗/poet.tang.20000.json','["僕人驅行軒，低昂出我門。", "離堂無留客，席上唯琴樽。", "古道隨水曲，悠悠繞荒村。", "遠程未奄息，別念在朝昏。", "端居愁歲永，獨此留清景。", "豈無經過人，尋歎門巷靜。", "君如天上雨，我如屋下井。", "無因同波流，願作形與影。"]'),
('06cb49fe-1ae7-464b-8b6c-00fa521adf16','學仙','張籍','唐','唐诗','tang','','[]','樓觀開朱門，樹木連房廊。',228,'全唐诗/poet.tang.20000.json','["樓觀開朱門，樹木連房廊。", "中有學仙人，少年休穀糧。", "高冠如芙蓉，霞月披衣裳。", "六時朝上清，佩玉紛鏗鏘。", "自言天老書，祕覆雲錦囊。", "百年度一人，妄泄有災殃。", "每占有仙相，然後傳此方。", "先生坐中堂，弟子跪四廂。", "金刀截身髮，結誓焚靈香。", "弟子得其訣，清齋入空房。", "守神保元氣，動息隨天罡。", "爐燒丹砂盡，晝夜候火光。", "藥成既服食，計日乘鸞凰。", "虛空無靈應，終歲安所望。", "勤勞不能成，疑慮積心腸。", "虛羸生疾疹，壽命多夭傷。", "身歿懼人見，夜埋山谷傍。", "求道慕靈異，不如守尋常。", "先王知其非，戒之在國章。"]'),
('b3d7be3d-60a0-4af9-bafe-5ee50b68cd96','夜懷','張籍','唐','唐诗','tang','','[]','窮居積遠念，轉轉迷所歸。',48,'全唐诗/poet.tang.20000.json','["窮居積遠念，轉轉迷所歸。", "幽蕙零落色，暗螢參差飛。", "病生秋風簟，淚墮月明衣。", "無愁坐寂寞，重使奏清徽。"]'),
('3f962772-6ebf-4d81-bd74-2eb3e3736b85','城南','張籍','唐','唐诗','tang','','[]','漾漾南澗水，來作曲池流。',144,'全唐诗/poet.tang.20000.json','["漾漾南澗水，來作曲池流。", "言尋參差島，曉榜輕盈舟。", "萬繞不再止，千尋盡孤幽。", "藻澀訝人重，萍分指魚游。", "繁苗毯下垂，密箭翻迴輈。", "曝鼈亂自墜，陰藤斜相鉤。", "臥蔣黑米吐，翻芰紫角稠。", "橋低競俯僂，亭近閑夷猶。", "目爲逐勝朗，手因掇芳柔。", "漸喜游來極，忽疑歸無由。", "氣狀雖可覽，纖微諒難搜。", "未聽主人賞，徒愛清華秋。"]'),
('afdc3f8f-8c56-42d8-a074-102b1811c2f9','懷友','張籍','唐','唐诗','tang','','[]','人生有行役，誰能如草木。',120,'全唐诗/poet.tang.20000.json','["人生有行役，誰能如草木。", "別離感中懷，乃爲我桎梏。", "百年受命短，光景良不足。", "念我別離者，願懷日月促。", "平地施道路，車馬往不復。", "空知爲良田，秋望禾黍熟。", "端居無儔侶，日夜禱耳目。", "立身難自覺，常恐憂與辱。", "窮賤無閑暇，疾痛多嗜欲。", "我思攜手人，逍遙任心腹。"]'),
('a3b26734-32e3-4c56-a6d2-fa8a2a206fc0','寄別者','張籍','唐','唐诗','tang','','[]','寒天正飛雪，行人心切切。',84,'全唐诗/poet.tang.20000.json','["寒天正飛雪，行人心切切。", "同爲萬里客，中路忽離別。", "別君汾水東，望君汾水西。", "積雪無平岡，空山無人蹊。", "羸馬時倚轅，行行未遑食。", "下車勸僮僕，相顧莫歎息。", "詎知佳期隔，離念終無極。"]'),
('c31c213f-6a36-4e49-b027-ba2f54bdb95e','獻從兄','張籍','唐','唐诗','tang','','[]','悠悠旱天雲，不遠如飛塵。',120,'全唐诗/poet.tang.20000.json','["悠悠旱天雲，不遠如飛塵。", "賢達失其所，沉飄同衆人。", "擢秀登王畿，出爲良使賓。", "名高滿朝野，幼賤誰不聞。", "一朝遇讒邪，流竄八九春。", "詔書近遷移，組綬未及身。", "冬井無寒冰，玉潤難爲焚。", "虛懷日迢遙，榮辱常保純。", "我念出游時，勿吟康樂文。", "願言靈溪期，聊欲相依因。"]'),
('8b5cfd73-3877-4401-953e-d8cdf7510a91','寄韓愈','張籍','唐','唐诗','tang','','[]','野館非我室，新居未能安。',132,'全唐诗/poet.tang.20000.json','["野館非我室，新居未能安。", "讀書避塵雜，方覺此地閑。", "過郭多園墟，桑果相接連。", "獨游竟寂寞，如寄空雲山。", "夏景常晝毒，密林無鳴蟬。", "臨溪一盥濯，清去肢體煩。", "出林望曾城，君子在其間。", "戎府草章記，阻我此遊盤。", "憶昔西潭時，並持釣魚竿。", "共忻得魴鯉，烹鱠于我前。", "幾朝還復來，歎息時獨言。"]'),
('cb5eb77b-ff07-4b2b-87f7-40bf9ed03ca4','贈姚怤','張籍','唐','唐诗','tang','','[]','漏天日無光，澤土松不長。',120,'全唐诗/poet.tang.20000.json','["漏天日無光，澤土松不長。", "君今職下位，志氣安得揚。", "白髮文思壯，才爲國賢良。", "無人識高韻，薦于天子傍。", "況我愚朴姿，強趨利名場。", "遠同干貴人，身舉固難彰。", "昔逢汴水濱，今會習池陽。", "豈無再來期，顧恐非此方。", "願爲石中泉，不爲瓦上霜。", "離別勿復道，所貴不相忘。"]'),
('42bd551f-6de1-4328-bac7-ca0a6e0c8d0e','病中寄白學士拾遺','張籍','唐','唐诗','tang','','[]','秋亭病客眠，庭樹滿枝蟬。',96,'全唐诗/poet.tang.20000.json','["秋亭病客眠，庭樹滿枝蟬。", "涼風繞砌起，斜影入牀前。", "梨晚漸紅墜，菊寒無黃鮮。", "倦遊寂寞日，感歎蹉跎年。", "塵歡久消委，華念獨迎延。", "自寓城闕下，識君弟事焉。", "君爲天子識，我方沉病纏。", "無因會同語，悄悄中懷煎。"]'),
('29d665f0-6078-43cd-9d39-53ce82a28dc5','雨中寄元宗簡','張籍','唐','唐诗','tang','','[]','秋堂羸病起，盥漱風雨朝。',60,'全唐诗/poet.tang.20000.json','["秋堂羸病起，盥漱風雨朝。", "竹影冷疎澀，榆葉暗飄蕭。", "街徑多墜果，牆隅有蛻蜩。", "延瞻游步阻，獨坐閑思饒。", "君居應如此，恨言相去遙。"]'),
('96785bef-3908-4cb6-b354-c8168b1aed44','野寺後池寄友','張籍','唐','唐诗','tang','','[]','佛寺連野水，池幽夏景清。',72,'全唐诗/poet.tang.20000.json','["佛寺連野水，池幽夏景清。", "繁木蔭芙蕖，時有水禽鳴。", "通溪岸蹔斷，分渚流復縈。", "伴僧鐘磬罷，月來池上明。", "友人竟不至，東北見高城。", "獨遊自寂寞，況此恨盈盈。"]'),
('d88638c4-bbd6-42d4-a9fa-6ae172966ddd','董公詩','張籍','唐','唐诗','tang','','[]','誰主東諸侯，元臣隴西公。',288,'全唐诗/poet.tang.20000.json','["誰主東諸侯，元臣隴西公。", "旌節居汴水，四方皆承風。", "在朝四十年，天下誦其功。", "相我明天子，政成如太宗。", "東方有艱難，公乃出臨戎。", "單車入危城，慈惠安羣兇。", "公謂其黨言，汝材甚驍雄。", "爲我帳下士，出入衛我躬。", "汝息爲我子，汝親我爲翁。", "衆皆相顧泣，無不和且恭。", "其父教子義，其妻勉夫忠。", "不自以爲資，奉上但顒顒。", "公衣無文采，公食少肥濃。", "所憂在萬人，人實我寧空。", "輕刑寬其政，薄賦弛租庸。", "四郡三十城，不知歲饑凶。", "天子臨朝喜，元老留在東。", "今聞揚盛德，就安我大邦。", "百辟賀明主，皇風恩賜重。", "朝廷有大事，就決其所從。", "海內既無虞，君臣方肅雍。", "端居任僚屬，宴語常從容。", "翩翩者蒼烏，來巢於林叢。", "甘瓜生場圃，一蔕實連中。"]'),
('7798a85b-ae35-4abc-bfb7-1c43940b2de2','祭退之','張籍','唐','唐诗','tang','','[]','嗚呼吏部公，其道誠巍昂。',288,'全唐诗/poet.tang.20000.json','["嗚呼吏部公，其道誠巍昂。", "生爲大賢姿，天使光我唐。", "德義動鬼神，鑒用不可詳。", "獨得雄直氣，發爲古文章。", "學無不該貫，吏治得其方。", "三次論諍退，其志亦剛強。", "再使平山東，不言所謀臧。", "薦待皆寒羸，但取其才良。", "親朋有孤稚，婚姻有辦營。", "如彼天有斗，人可爲信常。", "如彼歲有春，物宜得華昌。", "哀哉未申施，中年遽殂喪。", "朝野良共哀，矧於知舊腸。", "籍在江湖間，獨以道自將。", "學詩爲衆體，久乃溢笈囊。", "略無相知人，黯如霧中行。", "北遊偶逢公，盛語相稱明。", "名因天下聞，傳者入歌聲。", "公領試士司，首薦到上京。", "一來遂登科，不見苦貢場。", "觀我性朴直，乃言及平生。", "由茲類朋黨，骨肉無以當。", "坐令其子拜，常呼幼時名。", "追招不隔日，繼踐公之堂。"]'),
('3920da1c-459c-4452-9d92-fd40d5ed5520','薊北旅思','張籍','唐','唐诗','tang','','["\u67f3\u6811", "\u601d\u4e61"]','日日望鄉國，空謌白苧詞。',48,'全唐诗/poet.tang.20000.json','["日日望鄉國，空謌白苧詞。", "長因送人處，憶得別家時。", "失意還獨語，多愁祗自知。", "客亭門外柳，折盡向南枝。"]'),
('07d2eddf-6b2a-4262-beeb-be35780550c8','江南春','張籍','唐','唐诗','tang','','[]','江南楊柳春，日暖地無塵。',48,'全唐诗/poet.tang.20000.json','["江南楊柳春，日暖地無塵。", "渡口過新雨，夜來生白蘋。", "晴沙鳴乳燕，芳樹醉遊人。", "向晚青山下，誰家祭水神。"]'),
('6001b891-e317-4a8e-aa59-891d271b95a9','西樓望月','張籍','唐','唐诗','tang','','[]','城西樓上月，復是雪晴時。',48,'全唐诗/poet.tang.20000.json','["城西樓上月，復是雪晴時。", "寒夜共來望，思鄉獨下遲。", "幽光落水塹，淨色在霜枝。", "明日千里去，此中還別離。"]'),
('edffb141-5b6c-4193-b6d2-a74bc02c0c11','別鶴','張籍','唐','唐诗','tang','','[]','雙鶴出雲谿，分飛各自迷。',48,'全唐诗/poet.tang.20000.json','["雙鶴出雲谿，分飛各自迷。", "空巢在松頂，折羽落紅泥。", "尋水終不飲，逢林亦未棲。", "別離應易老，萬里雨淒淒。"]'),
('febead0e-6183-478c-88a5-bf9ef073d3ac','江陵孝女','張籍','唐','唐诗','tang','','[]','孝女獨垂髮，少年唯一身。',48,'全唐诗/poet.tang.20000.json','["孝女獨垂髮，少年唯一身。", "無家空托墓，主祭不從人。", "相弔有行客，起廬無舊鄰。", "江頭聞哭處，寂寂楚花春。"]'),
('e8aa4fd9-43ba-49ea-a4df-985b01c050a4','山中古祠','張籍','唐','唐诗','tang','','[]','春草空祠墓，荒林唯鳥飛。',48,'全唐诗/poet.tang.20000.json','["春草空祠墓，荒林唯鳥飛。", "記年碑石在，經亂祭人稀。", "野鼠緣朱帳，陰塵蓋畫衣。", "近門潭水黑，時見宿龍歸。"]'),
('027a565a-ada3-4e75-a195-e2322d952375','漁陽將','張籍','唐','唐诗','tang','','[]','塞深沙草白，都護領燕兵。',48,'全唐诗/poet.tang.20000.json','["塞深沙草白，都護領燕兵。", "放火燒奚帳，分旗築漢城。", "下營看嶺勢，尋雪覺人行。", "更向桑乾北，擒生問磧名。"]'),
('92ea24f9-4780-4d8e-857a-3fd7b3778b39','聽夜泉','張籍','唐','唐诗','tang','','[]','細泉深處落，夜久漸聞聲。',48,'全唐诗/poet.tang.20000.json','["細泉深處落，夜久漸聞聲。", "獨起出門聽，欲尋當澗行。", "還疑隔林遠，復畏有風生。", "月下長來此，無人亦到明。"]'),
('33fac8f1-e14d-4392-8357-a3f64ad78e09','送南遷客','張籍','唐','唐诗','tang','','[]','去去遠遷客，瘴中衰病身。',48,'全唐诗/poet.tang.20000.json','["去去遠遷客，瘴中衰病身。", "青山無限路，白首不歸人。", "海國戰騎象，蠻州市用銀。", "一家分幾處，誰見日南春。"]'),
('737fcd5c-9ed6-4009-acc6-c279c05d3b55','薊北春懷','張籍','唐','唐诗','tang','','[]','渺渺水雲外，別來音信稀。',48,'全唐诗/poet.tang.20000.json','["渺渺水雲外，別來音信稀。", "因逢過江使，却寄在家衣。", "問路更愁遠，逢人空說歸。", "今朝薊城北，又見塞鴻飛。"]'),
('c7002464-6e6b-4de1-b31c-0ec2612b4757','思遠人','張籍','唐','唐诗','tang','','[]','野橋春水清，橋上送君行。',48,'全唐诗/poet.tang.20000.json','["野橋春水清，橋上送君行。", "去去人應老，年年草自生。", "出門看遠道，無信向邊城。", "楊柳別離處，秋蟬今復鳴。"]'),
('718d4e6b-5a8e-4b47-9c24-6fea9c3b6ab8','贈同溪客','張籍','唐','唐诗','tang','','[]','幽居得相近，煙景每寥寥。',48,'全唐诗/poet.tang.20000.json','["幽居得相近，煙景每寥寥。", "共伐臨谿樹，因爲過水橋。", "自教青鶴舞，分採紫芝苗。", "更愛南峰住，尋君路恐遙。"]'),
('ef5c91ad-be60-4308-aa07-5d89717c9908','望行人','張籍','唐','唐诗','tang','','[]','秋風窗下起，旅雁向南飛。',48,'全唐诗/poet.tang.20000.json','["秋風窗下起，旅雁向南飛。", "日日出門望，家家行客歸。", "無因見邊使，空待寄寒衣。", "獨倚青樓暮，煙深鳥雀稀。"]'),
('a9015c97-d2fe-4fdb-af24-1ce00e084986','送宮人入道','張籍','唐','唐诗','tang','','[]','舊寵昭陽裏，尋仙此最稀。',48,'全唐诗/poet.tang.20000.json','["舊寵昭陽裏，尋仙此最稀。", "名初出宮籍，身未稱霞衣。", "已別歌舞貴，長隨鸞鶴飛。", "中官看入洞，空駕玉輪歸。"]'),
('35f681d8-2999-41d7-ab86-4594e93e64e1','送越客','張籍','唐','唐诗','tang','','[]','見說孤帆去，東南到會稽。',48,'全唐诗/poet.tang.20000.json','["見說孤帆去，東南到會稽。", "春雲剡溪口，殘月鏡湖西。", "水鶴沙邊立，山鼯竹裏啼。", "謝家曾住處，煙洞入應迷。"]'),
('b688d659-e36a-4c0d-85d5-a17054131575','贈辟穀者','張籍','唐','唐诗','tang','','[]','學得餐霞法，逢人與小還。',48,'全唐诗/poet.tang.20000.json','["學得餐霞法，逢人與小還。", "身輕曾試鶴，力弱未離山。", "無食犬猶在，不耕牛自閑。", "朝朝空漱水，叩齒草堂間。"]'),
('932a8566-a2ee-48a7-878d-f051ca6fae15','思江南舊遊','張籍','唐','唐诗','tang','','[]','江臯三月時，花發石楠枝。',48,'全唐诗/poet.tang.20000.json','["江臯三月時，花發石楠枝。", "歸客應無數，春山自不知。", "獨行愁道遠，迴信畏家移。", "楊柳東西渡，茫茫欲問誰。"]'),
('f3df89b4-1a24-40b5-b668-1348f73d22c6','夜到漁家','張籍','唐','唐诗','tang','','["\u6292\u60c5", "\u6e38\u5b50", "\u5199\u4eba"]','漁家在江口，潮水入柴扉。',48,'全唐诗/poet.tang.20000.json','["漁家在江口，潮水入柴扉。", "行客欲投宿，主人猶未歸。", "竹深村路遠，月出釣船稀。", "遙見尋沙岸，春風動草衣。"]'),
('9c8e7368-a276-45e8-99ea-c23474cf39ef','送遠使','張籍','唐','唐诗','tang','','[]','揚旌過隴頭，隴水向西流。',48,'全唐诗/poet.tang.20000.json','["揚旌過隴頭，隴水向西流。", "塞路依山遠，戍城逢笛秋。", "寒沙陰漫漫，疲馬去悠悠。", "爲問征行將，誰封定遠侯。"]'),
('4ecad10d-5ac7-423f-b2bd-bb86f0e21b39','不食姑','張籍','唐','唐诗','tang','','[]','幾年山裏住，已作綠毛身。',48,'全唐诗/poet.tang.20000.json','["幾年山裏住，已作綠毛身。", "護氣常稀語，存思自見神。", "養龜同不食，留藥任生塵。", "要問西王母，仙中第幾人。"]'),
('0872f854-66eb-44bb-b652-da68abad8429','古苑杏花','張籍','唐','唐诗','tang','','[]','廢苑杏花在，行人愁到時。',48,'全唐诗/poet.tang.20000.json','["廢苑杏花在，行人愁到時。", "獨開新塹底，半露舊燒枝。", "晚色連荒轍，低陰覆折碑。", "茫茫古陵下，春盡又誰知。"]'),
('bf8dca5e-f104-4fd7-a5ed-1820014b96d8','送流人','張籍','唐','唐诗','tang','','[]','獨向長城北，黃雲暗塞天。',48,'全唐诗/poet.tang.20000.json','["獨向長城北，黃雲暗塞天。", "流名屬邊將，舊業作公田。", "擁雪添軍壘，收冰當井泉。", "知君住應老，須記別鄉年。"]'),
('1fa47ded-6d42-4689-a632-a5b472e3449e','宿臨江驛','張籍','唐','唐诗','tang','','[]','楚驛南渡口，夜深來客稀。',48,'全唐诗/poet.tang.20000.json','["楚驛南渡口，夜深來客稀。", "月明見潮上，江靜覺鷗飛。", "旅宿今已遠，此行殊未歸。", "離家久無信，又聽擣寒衣。"]'),
('a6af3fae-9f7c-44a7-8e8e-dda896fb8497','送蠻客','張籍','唐','唐诗','tang','','[]','借問炎州客，天南幾日行。',48,'全唐诗/poet.tang.20000.json','["借問炎州客，天南幾日行。", "江連惡谿路，山遶夜郎城。", "柳葉瘴雲濕，桂叢蠻鳥聲。", "知君却迴日，記得海花名。"]'),
('d9422679-c159-4bf1-8351-083069848194','襄國別友','張籍','唐','唐诗','tang','','[]','曉色荒城下，相看秋草時。',48,'全唐诗/poet.tang.20000.json','["曉色荒城下，相看秋草時。", "獨遊無定計，不欲道來期。", "別處去家遠，愁中驅馬遲。", "歸人渡煙水，遙暎野棠枝。"]'),
('8a772176-3c27-442a-9fe6-5b44ed42423a','送遠客','張籍','唐','唐诗','tang','','[]','南原相送處，秋水草還生。',48,'全唐诗/poet.tang.20000.json','["南原相送處，秋水草還生。", "同作憶鄉客，如今分路行。", "因誰寄歸信，漸遠問前程。", "明日重陽節，無人上古城。"]'),
('2bd9b340-a9b3-4979-9c8e-fc36a559aa5d','山中贈日南僧','張籍','唐','唐诗','tang','','[]','獨向雙峰老，松門閉兩崖。',48,'全唐诗/poet.tang.20000.json','["獨向雙峰老，松門閉兩崖。", "翻經上蕉葉，挂衲落藤花。", "甃石新開井，穿林自種茶。", "時逢海南客，蠻語問誰家。"]'),
('99c50768-61db-4ca5-9f28-810d9ce6fa72','征西將','張籍','唐','唐诗','tang','','[]','黃沙北風起，半夜又翻營。',48,'全唐诗/poet.tang.20000.json','["黃沙北風起，半夜又翻營。", "戰馬雪中宿，探人冰上行。", "深山旗未展，陰磧鼓無聲。", "幾道征西將，同收碎葉城。"]'),
('a9c7c5b0-202f-42be-876d-62737b4daab0','寄友人','張籍','唐','唐诗','tang','','[]','憶在江南日，同遊三月時。',48,'全唐诗/poet.tang.20000.json','["憶在江南日，同遊三月時。", "採茶尋遠澗，鬬鴨向春池。", "送客沙頭宿，招僧竹裏碁。", "如今各千里，無計得相隨。"]'),
('b0173008-7777-4799-afe3-7e1b4bd1ce89','送防秋將','張籍','唐','唐诗','tang','','[]','白首征西將，猶能射戟支。',48,'全唐诗/poet.tang.20000.json','["白首征西將，猶能射戟支。", "元戎選部曲，軍吏換旌旗。", "逐虜招降遠，開邊舊壘移。", "重收隴外地，應似漢家時。"]'),
('5e511964-25aa-42b4-8e37-c92c84246060','律僧','張籍','唐','唐诗','tang','','[]','苦行長不出，清羸最少年。',48,'全唐诗/poet.tang.20000.json','["苦行長不出，清羸最少年。", "持齋唯一食，講律豈曾眠。", "避草每移徑，濾蟲還入泉。", "從來天竺法，到此幾人傳。"]'),
('037532de-b69a-4032-ae4b-63d8b28c101a','山中秋夜','張籍','唐','唐诗','tang','','[]','寂寂山景靜，幽人歸去遲。',48,'全唐诗/poet.tang.20000.json','["寂寂山景靜，幽人歸去遲。", "橫琴當月下，壓酒及花時。", "冷露濕茆屋，暗泉衝竹籬。", "西峰採藥伴，此夕恨無期。"]'),
('ad33bfc2-7b45-48ee-b3ca-3891ab32a9f5','送南客','張籍','唐','唐诗','tang','','[]','行路雨脩脩，青山盡海頭。',48,'全唐诗/poet.tang.20000.json','["行路雨脩脩，青山盡海頭。", "天涯人去遠，嶺北水空流。", "夜市連銅柱，巢居屬象州。", "來時舊相識，誰向日南遊。"]'),
('89c302eb-ba2e-41eb-ba00-12993d2db718','宿江店','張籍','唐','唐诗','tang','','[]','野店臨西浦，門前有橘花。',48,'全唐诗/poet.tang.20000.json','["野店臨西浦，門前有橘花。", "停燈待賈客，賣酒與漁家。", "夜靜江水白，路迴山月斜。", "閑尋泊船處，潮落見平沙。"]'),
('adbd2eab-c9ed-4cdc-955d-8da6e2c6a143','嶺表逢故人','張籍','唐','唐诗','tang','','[]','過嶺萬餘里，旅遊經此稀。',48,'全唐诗/poet.tang.20000.json','["過嶺萬餘里，旅遊經此稀。", "相逢去家遠，共說幾時歸。", "海上見花發，瘴中唯鳥飛。", "炎州望鄉伴，自識北人衣。"]'),
('6082d88e-bb2c-4f44-aa55-1c9e3d526d87','出塞','張籍','唐','唐诗','tang','','[]','秋塞雪初下，將軍遠出師。',48,'全唐诗/poet.tang.20000.json','["秋塞雪初下，將軍遠出師。", "分營長記火，放馬不收旗。", "月冷邊帳濕，沙昏夜探遲。", "征人皆白首，誰見滅胡時。"]'),
('61242ff9-7965-47a3-9301-a882f67aa3b1','寄紫閣隱者','張籍','唐','唐诗','tang','','[]','紫閣氣沉沉，先生住處深。',48,'全唐诗/poet.tang.20000.json','["紫閣氣沉沉，先生住處深。", "有人時得見，無路可相尋。", "夜鹿伴茅屋，秋猿守栗林。", "唯應採靈藥，更不別營心。"]'),
('720e3d90-14ad-4393-9163-e063ab3e6783','夜宿黑竈溪','張籍','唐','唐诗','tang','','[]','夜到碧溪裏，無人秋月明。',48,'全唐诗/poet.tang.20000.json','["夜到碧溪裏，無人秋月明。", "逢幽更移宿，取伴亦探行。", "花下紅泉色，雲西乳鶴聲。", "明朝記歸處，石上自書名。"]'),
('f3e065ca-9346-44be-9ae2-323f9a8e243b','古樹','張籍','唐','唐诗','tang','','[]','古樹枝柯少，枯來復幾春。',48,'全唐诗/poet.tang.20000.json','["古樹枝柯少，枯來復幾春。", "露根堪繫馬，空腹定藏人。", "蠹節莓苔老，燒痕霹靂新。", "若當江浦上，行客祭爲神。"]'),
('66dea4bd-06d8-498b-9c44-baf2170078f3','送徐先生歸蜀','張籍','唐','唐诗','tang','','[]','日暮遠歸處，雲間仙觀鐘。',48,'全唐诗/poet.tang.20000.json','["日暮遠歸處，雲間仙觀鐘。", "唯持青玉牒，獨立碧雞峰。", "陰澗長收乳，寒泉舊養龍。", "幾時因賣藥，得向海邊逢。"]'),
('1d4a4e82-31f1-4e92-810f-a34b82888813','隱者','張籍','唐','唐诗','tang','','[]','先生已得道，市井亦容身。',48,'全唐诗/poet.tang.20000.json','["先生已得道，市井亦容身。", "救病自行藥，得錢多與人。", "問年長不定，傳法又非真。", "每見鄰家說，時聞使鬼神。"]'),
('4ffd476a-aeec-4e83-80e5-53ace51e3042','送友人歸山','張籍','唐','唐诗','tang','','[]','出山成北首，重去結茅廬。',48,'全唐诗/poet.tang.20000.json','["出山成北首，重去結茅廬。", "移石修廢井，埽龕盛舊書。", "開田留杏樹，分洞與僧居。", "長在幽峰裏，樵人見亦疎。"]'),
('fef09002-3a03-415d-8a92-e7e3b297e404','霅溪西亭晚望','張籍','唐','唐诗','tang','','[]','霅水碧悠悠，西亭柳岸頭。',48,'全唐诗/poet.tang.20000.json','["霅水碧悠悠，西亭柳岸頭。", "夕陰生遠岫，斜照逐迴流。", "此地動歸思，逢人方倦遊。", "吳興耆舊盡，空見白蘋州。"]'),
('ff3993de-4db8-46b0-9930-079acb652167','哭山中友人','張籍','唐','唐诗','tang','','[]','入雲遙便哭，山友隔今生。',48,'全唐诗/poet.tang.20000.json','["入雲遙便哭，山友隔今生。", "遶墓招魂魄，鐫巖記姓名。", "犬因無主善，鶴爲見人鳴。", "長說能尸解，多應別路行。"]'),
('856b1f2a-4307-414b-987a-f4735d7f96de','答僧拄杖','張籍','唐','唐诗','tang','','[]','靈籐爲拄杖，白淨色如銀。',48,'全唐诗/poet.tang.20000.json','["靈籐爲拄杖，白淨色如銀。", "得自高僧手，將扶病客身。", "春遊不騎馬，夜會亦呈人。", "持此歸山去，深宜戴角巾。"]'),
('da540ddc-fd16-476b-8fa8-4706310f1759','靈都觀李道士','張籍','唐','唐诗','tang','','[]','仙觀雨來靜，遶房瓊草春。',48,'全唐诗/poet.tang.20000.json','["仙觀雨來靜，遶房瓊草春。", "素書天上字，花洞古時人。", "泥竈煮靈液，埽壇朝玉真。", "幾迴遊閬苑，青節亦隨身。"]'),
('91a0cff0-9b7f-4241-8980-5f0d6ef4b35b','送韋評事歸華陰','張籍','唐','唐诗','tang','','[]','三峰西面住，出見世人稀。',48,'全唐诗/poet.tang.20000.json','["三峰西面住，出見世人稀。", "老大誰相識，恓惶又獨歸。", "埽窗秋菌落，開篋夜蛾飛。", "若向雲中伴，還應着褐衣。"]'),
('e17e8a22-ed6d-40bb-8451-b95a597d7c6f','送閩僧','張籍','唐','唐诗','tang','','[]','幾夏京城住，今朝獨遠歸。',48,'全唐诗/poet.tang.20000.json','["幾夏京城住，今朝獨遠歸。", "修行四分律，護淨七條衣。", "谿寺黃橙熟，沙田紫芋肥。", "九龍潭上路，同去客應稀。"]'),
('039c3d4d-158d-4417-99e5-5ab66b78513d','送海南客歸舊島','張籍','唐','唐诗','tang','','[]','海上去應遠，蠻家雲島孤。',48,'全唐诗/poet.tang.20000.json','["海上去應遠，蠻家雲島孤。", "竹船來桂浦，山市賣魚鬚。", "入國自獻寶，逢人多贈珠。", "却歸春洞口，斬象祭天吳。"]'),
('9cf0aafb-1902-4f56-8c86-1a92ee61158c','登咸陽北寺樓','張籍','唐','唐诗','tang','','[]','高秋原上寺，下馬一登臨。',48,'全唐诗/poet.tang.20000.json','["高秋原上寺，下馬一登臨。", "渭水西來直，秦山南向深。", "舊宮人不住，荒碣路難尋。", "日暮涼風起，蕭條多遠心。"]'),
('7b99f297-4701-4256-91bc-e33a5ac4b67c','送新羅使','張籍','唐','唐诗','tang','','[]','萬里爲朝使，離家今幾年。',48,'全唐诗/poet.tang.20000.json','["萬里爲朝使，離家今幾年。", "應知舊行路，却上遠歸船。", "夜泊避蛟窟，朝炊求島泉。", "悠悠到鄉國，還望海西天。"]'),
('6781ec4f-db7c-4fba-9ee0-ec6fa445733e','宿廣德寺寄從舅','張籍','唐','唐诗','tang','','[]','古寺客堂空，開簾四面風。',48,'全唐诗/poet.tang.20000.json','["古寺客堂空，開簾四面風。", "移牀動棲鶴，停燭聚飛蟲。", "閑臥逐涼處，遠愁生靜中。", "林西微月色，思與甯家同。"]'),
('c05cbcb0-dd20-4466-945d-160774bc39bf','宿邯鄲館寄馬磁州','張籍','唐','唐诗','tang','','[]','孤客到空館，夜寒愁臥遲。',48,'全唐诗/poet.tang.20000.json','["孤客到空館，夜寒愁臥遲。", "雖沽主人酒，不似在家時。", "幾宿得歡笑，如今成別離。", "明朝行更遠，迴望隔山陂。"]'),
('3bf18f08-22d2-4833-8b58-ff141dac39a4','舟行寄李湖州','張籍','唐','唐诗','tang','','[]','客愁無次第，川路重辛勤。',48,'全唐诗/poet.tang.20000.json','["客愁無次第，川路重辛勤。", "藻密行舟澀，灣多轉檝頻。", "薄遊空感惠，失計自憐貧。", "賴有汀洲句，時時慰遠人。"]'),
('2ade1893-a44d-45f0-9f9a-0bc2a7402a44','送閑師歸江南','張籍','唐','唐诗','tang','','[]','徧住江南寺，隨緣到上京。',48,'全唐诗/poet.tang.20000.json','["徧住江南寺，隨緣到上京。", "多生修律業，外學得詩名。", "講殿偏追入，齋家別請行。", "青楓鄉路遠，幾日盡歸程。"]'),
('0a74a799-c767-440f-82d1-182b33e3ddb1','遊襄陽山寺','張籍','唐','唐诗','tang','','[]','秋色江邊路，煙霞若有期。',48,'全唐诗/poet.tang.20000.json','["秋色江邊路，煙霞若有期。", "寺貧無利施，僧老足慈悲。", "薜荔侵禪窟，蝦蟆占浴池。", "閑遊殊未徧，即是下山時。"]'),
('af210310-c5ef-4a03-ba98-783c415bc79e','登城寄王秘書建','張籍','唐','唐诗','tang','','[]','聞君鶴嶺住，西望日依依。',48,'全唐诗/poet.tang.20000.json','["聞君鶴嶺住，西望日依依。", "遠客偏相憶，登城獨不歸。", "十年爲道侶，幾處共柴扉。", "今日煙霞外，人間得見稀。"]'),
('95fd9611-2959-4b07-a810-cd374d48c49b','送從弟戴玄往蘇州','張籍','唐','唐诗','tang','','[]','楊柳閶門路，悠悠水岸斜。',48,'全唐诗/poet.tang.20000.json','["楊柳閶門路，悠悠水岸斜。", "乘舟向山寺，着屐到漁家。", "夜月紅柑樹，秋風白藕花。", "江天詩景好，迴日莫令賒。"]'),
('eea19f4a-cb6d-4d23-8d27-367ed5c9b8f0','送朱慶餘及第歸越','張籍','唐','唐诗','tang','','[]','東南歸路遠，幾日到鄉中。',48,'全唐诗/poet.tang.20000.json','["東南歸路遠，幾日到鄉中。", "有寺山皆遍，無家水不通。", "湖聲蓮葉雨，野氣稻花風。", "州縣知名久，爭邀與客同。"]'),
('e797885d-1d00-48f0-9f55-d45b2365608d','過賈島野居','張籍','唐','唐诗','tang','','[]','青門坊外住，行坐見南山。',48,'全唐诗/poet.tang.20000.json','["青門坊外住，行坐見南山。", "此地去人遠，知君終日閑。", "蛙聲籬落下，草色戶庭間。", "好是經過處，唯愁暮獨還。"]'),
('b05412b6-d656-4086-a022-771c4f0dfad9','酬韓庶子','張籍','唐','唐诗','tang','','[]','西街幽僻處，正與嬾相宜。',48,'全唐诗/poet.tang.20000.json','["西街幽僻處，正與嬾相宜。", "尋寺獨行遠，借書常送遲。", "家貧無易事，身病足閑時。", "寂寞誰相問，祗應君自知。"]'),
('4f315ed4-b73a-4a9e-8799-98871c553726','贈姚合少府','張籍','唐','唐诗','tang','','[]','病來辭赤縣，案上有丹經。',48,'全唐诗/poet.tang.20000.json','["病來辭赤縣，案上有丹經。", "爲客燒茶竈，教兒埽竹亭。", "詩成添舊卷，酒盡臥空缾。", "闕下今遺逸，誰瞻隱士星。"]'),
('db6329f7-80c7-4e65-9ec2-ce7082d05c8c','送僧遊五臺兼謁李司空','張籍','唐','唐诗','tang','','[]','遠去見雙節，因行上五臺。',48,'全唐诗/poet.tang.20000.json','["遠去見雙節，因行上五臺。", "化樓侵曉出，雪路向春開。", "邊寺連峰去，胡兒聽法來。", "定知巡禮後，解夏始應迴。"]'),
('0dda2181-90a1-4622-8881-4aa7f81c1080','送鄭秀才歸寧','張籍','唐','唐诗','tang','','[]','桂檝彩爲衣，行當令節歸。',48,'全唐诗/poet.tang.20000.json','["桂檝彩爲衣，行當令節歸。", "夕潮迷浦遠，晝雨見人稀。", "野芰到時熟，江鷗泊處飛。", "離琴一奏罷，山雨靄餘暉。"]'),
('b8300243-8092-4941-9161-3ed3764e0d0f','送李評事遊越','張籍','唐','唐诗','tang','','[]','未習風塵事，初爲吳越遊。',48,'全唐诗/poet.tang.20000.json','["未習風塵事，初爲吳越遊。", "露沾湖草晚，日照海山秋。", "梅市門何在，蘭亭水尚流。", "西陵待潮處，知汝不勝愁。"]'),
('3e458cb0-2f60-4831-8ccd-049b303ad609','夏日閑居','張籍','唐','唐诗','tang','','[]','無事門多閉，偏知夏日長。',48,'全唐诗/poet.tang.20000.json','["無事門多閉，偏知夏日長。", "早蟬聲寂寞，新竹氣清涼。", "閑對臨書案，看移曬藥牀。", "自憐歸未得，猶寄在班行。"]'),
('53e87e6e-3833-4b4e-9c99-9f25a7aa2185','閑居','張籍','唐','唐诗','tang','','[]','東城南陌塵，紫幰與朱輪。',48,'全唐诗/poet.tang.20000.json','["東城南陌塵，紫幰與朱輪。", "盡說無多事，能閑有幾人。", "唯教推甲子，不信守庚申。", "誰見衡門裏，終朝自在貧。"]'),
('f62bdde6-4814-4e8b-a607-f5a2a9881d0d','寄昭應王中丞','張籍','唐','唐诗','tang','','[]','借得街西宅，開門渭水頭。',48,'全唐诗/poet.tang.20000.json','["借得街西宅，開門渭水頭。", "長貧唯要健，漸老不禁愁。", "獨憑藤書案，空懸竹酒鉤。", "春風石甕寺，作意共君遊。"]'),
('00b5f102-385c-409f-959b-7a8485ea2430','酬孫洛陽','張籍','唐','唐诗','tang','','[]','家貧相遠住，齋館入時稀。',48,'全唐诗/poet.tang.20000.json','["家貧相遠住，齋館入時稀。", "獨坐看書卷，閑行著褐衣。", "早蟬庭笋老，新雨徑莎肥。", "各離爭名地，無人見是非。"]'),
('56f869de-4152-49d1-978d-c9176ae97171','送人任濟陰','張籍','唐','唐诗','tang','','[]','黃綬在腰下，知君非旅行。',48,'全唐诗/poet.tang.20000.json','["黃綬在腰下，知君非旅行。", "將書報舊里，留褐與諸生。", "贈別盡沽酒，惜歡多出城。", "春風濟水上，候吏聽車聲。"]'),
('5051ad05-212b-4755-9439-cb2e4201c39a','晚春過崔駙馬東園','張籍','唐','唐诗','tang','','[]','閑園多好風，不意在街東。',48,'全唐诗/poet.tang.20000.json','["閑園多好風，不意在街東。", "早早詩名遠，長長酒性同。", "竹香新雨後，鶯語落花中。", "莫遣經過少，年光漸覺空。"]'),
('6ca8af28-a319-4e0e-95a3-0e757323ebed','夏日閑居','張籍','唐','唐诗','tang','','[]','多病逢迎少，閑居又一年。',48,'全唐诗/poet.tang.20000.json','["多病逢迎少，閑居又一年。", "藥看辰日合，茶過卯時煎。", "草長晴來地，蟲飛晚後天。", "此時幽夢遠，不覺到山邊。"]'),
('419f06f5-c946-42ea-b277-3ebbca04eaa6','晚秋閑居','張籍','唐','唐诗','tang','','[]','獨坐高秋晚，蕭條足遠思。',48,'全唐诗/poet.tang.20000.json','["獨坐高秋晚，蕭條足遠思。", "家貧常畏客，身老轉憐兒。", "萬種盡閑事，一生能幾時。", "從來疎嬾性，應祗有僧知。"]'),
('e5cade8e-f374-4251-a466-5661d1c7cef9','和陸司業習靜寄所知','張籍','唐','唐诗','tang','','[]','幽室獨焚香，清晨下未央。',48,'全唐诗/poet.tang.20000.json','["幽室獨焚香，清晨下未央。", "山開登竹閣，僧到出茶牀。", "收拾新琴譜，封題舊藥方。", "逍遙無別事，不似在班行。"]'),
('0a1d7258-c61a-484e-a98c-49a7f09f3825','酬韓祭酒雨中見寄','張籍','唐','唐诗','tang','','[]','雨中愁不出，陰黑盡連宵。',48,'全唐诗/poet.tang.20000.json','["雨中愁不出，陰黑盡連宵。", "屋濕唯添漏，泥深未放朝。", "無芻憐馬瘦，少食信兒嬌。", "聞道韓夫子，還同此寂寥。"]'),
('79955b13-4756-4e3b-80e0-c8607d0721d1','和裴僕射移官言志','張籍','唐','唐诗','tang','','[]','身在勤勞地，常思放曠時。',48,'全唐诗/poet.tang.20000.json','["身在勤勞地，常思放曠時。", "功成歸聖主，位重委羣司。", "看壘臺邊石，閑吟篋裏詩。", "蒼生正瞻望，難與故山期。"]'),
('fe3e33eb-4b54-4644-80ee-ebfc7b8f5813','酬白二十二舍人早春曲江見招','張籍','唐','唐诗','tang','','[]','曲江冰欲盡，風日已恬和。',48,'全唐诗/poet.tang.20000.json','["曲江冰欲盡，風日已恬和。", "柳色看猶淺，泉聲覺漸多。", "紫蒲生濕岸，青鴨戲新波。", "仙掖高情客，相招共一過。"]'),
('cd2c2b8d-0040-42ce-84dc-8ae12a14b91f','和裴僕射朝回寄韓吏部','張籍','唐','唐诗','tang','','[]','獨愛南關裏，山晴竹杪風。',48,'全唐诗/poet.tang.20000.json','["獨愛南關裏，山晴竹杪風。", "從容朝早退，蕭灑客常通。", "案曲新亭上，移花遠寺中。", "唯應有吏部，詩酒每相同。"]'),
('bfc477d0-e9ae-44eb-9cd6-0f412289e9fc','春日李舍人宅見兩省諸公唱和因書情即事','張籍','唐','唐诗','tang','','[]','又見帝城裏，東風天氣和。',48,'全唐诗/poet.tang.20000.json','["又見帝城裏，東風天氣和。", "官閑人事少，年長道情多。", "紫掖發章句，青闈更詠歌。", "誰知余寂寞，終日斷經過。"]'),
('dff6637d-5cf1-4765-b063-9f5f7cc7be52','和李僕射秋日病中作','張籍','唐','唐诗','tang','','[]','由來病根淺，易見藥功成。',48,'全唐诗/poet.tang.20000.json','["由來病根淺，易見藥功成。", "曉日杵臼靜，涼風衣服輕。", "猶疑少氣力，漸覺有心情。", "獨倚紅藤杖，時時堦上行。"]'),
('ba68f2e9-87b9-4ba1-84b6-bbe65c46bcd5','早春病中','張籍','唐','唐诗','tang','','[]','羸病及年初，心情不自如。',48,'全唐诗/poet.tang.20000.json','["羸病及年初，心情不自如。", "多申請假牒，祗送賀官書。", "幽徑獨行步，白頭長嬾梳。", "更憐晴日色，漸漸暖貧居。"]'),
('6fe9e9d6-56f0-478d-a667-32f0e01eb0b8','送嚴大夫之桂州','張籍','唐','唐诗','tang','','[]','旌斾過湘潭，幽奇得徧探。',48,'全唐诗/poet.tang.20000.json','["旌斾過湘潭，幽奇得徧探。", "莎城百越北，行路九疑南。", "有地多生桂，無時不養蠶。", "聽歌疑似曲，風俗自相諳。"]'),
('8b4a688f-ba5f-41a3-b9e5-53d51dda5daa','詠懷','張籍','唐','唐诗','tang','','[]','老去多悲事，非唯見二毛。',48,'全唐诗/poet.tang.20000.json','["老去多悲事，非唯見二毛。", "眼昏書字大，耳重覺聲高。", "望月偏增思，尋山易發勞。", "都無作官意，賴得在閑曹。"]'),
('dea6d052-14da-4ae4-ab06-2f7007c0f842','使至藍谿驛寄太常王丞','張籍','唐','唐诗','tang','','[]','獨上七盤去，峰巒轉轉稠。',48,'全唐诗/poet.tang.20000.json','["獨上七盤去，峰巒轉轉稠。", "雲中迷象鼻，雨裏下箏頭。", "水沒荒橋路，鴉啼古驛樓。", "君今在城闕，肯見此中愁。"]'),
('7f2ce9af-aff0-480d-bf2a-86f46bee6362','留別江陵王少府','張籍','唐','唐诗','tang','','[]','迢迢山上路，病客獨行遲。',48,'全唐诗/poet.tang.20000.json','["迢迢山上路，病客獨行遲。", "況此分手處，當君失意時。", "寒林遠路驛，晚燒過荒陂。", "別後空迴首，相逢未有期。"]'),
('fdeadecf-359a-4514-96e5-fe73d31997e1','贈海東僧','張籍','唐','唐诗','tang','','[]','別家行萬里，自說過扶餘。',48,'全唐诗/poet.tang.20000.json','["別家行萬里，自說過扶餘。", "學得中州語，能爲外國書。", "與醫收海藻，持咒取龍魚。", "更問同來伴，天台幾處居。"]'),
('08a4cb9d-55b0-4d4b-912a-88b4d0af6a63','寄漢陽故人','張籍','唐','唐诗','tang','','[]','知君漢陽住，煙樹遠重重。',48,'全唐诗/poet.tang.20000.json','["知君漢陽住，煙樹遠重重。", "歸使雨中發，寄書燈下封。", "同時買江塢，今日別雲松。", "欲問新移處，青蘿最北峰。"]'),
('d7ec4374-24b2-4fd8-8d5d-5b3e9b63f3d4','送安西將','張籍','唐','唐诗','tang','','[]','萬里海西路，茫茫邊草秋。',48,'全唐诗/poet.tang.20000.json','["萬里海西路，茫茫邊草秋。", "計程沙塞口，望伴驛峰頭。", "雪暗非時宿，沙深獨去愁。", "塞鄉人易老，莫住近蕃州。"]'),
('b96f1531-8af5-4481-8e9a-669721f8d5a7','題李山人幽居','張籍','唐','唐诗','tang','','[]','襄陽南郭外，茅屋一書生。',48,'全唐诗/poet.tang.20000.json','["襄陽南郭外，茅屋一書生。", "無事焚香坐，有時尋竹行。", "畫苔藤杖細，踏石笋鞋輕。", "應笑風塵客，區區逐世名。"]'),
('1eee64c5-7701-40ea-abf5-97454c69ab05','早春閑遊','張籍','唐','唐诗','tang','','[]','年長身多病，獨宜作冷官。',48,'全唐诗/poet.tang.20000.json','["年長身多病，獨宜作冷官。", "從來閑坐慣，漸覺出門難。", "樹影新猶薄，池光晚尚寒。", "遙聞有花發，騎馬暫行看。"]'),
('c24ee792-d69e-405f-aa1e-a7e31611ad03','贈太常王建藤杖笋鞋','張籍','唐','唐诗','tang','','[]','蠻藤剪爲杖，楚笋結成鞋。',48,'全唐诗/poet.tang.20000.json','["蠻藤剪爲杖，楚笋結成鞋。", "稱與詩人用，堪隨禮寺齋。", "尋花入幽徑，步日下寒堦。", "以此持相贈，君應愜素懷。"]'),
('c6662459-18b5-4cef-9f1b-e52a3b185b18','和周贊善聞子規','張籍','唐','唐诗','tang','','[]','秦城啼楚鳥，遠思更紛紛。',48,'全唐诗/poet.tang.20000.json','["秦城啼楚鳥，遠思更紛紛。", "況是街西夜，偏當雨裏聞。", "應投最高樹，似隔數重雲。", "此處誰能聽，遙知獨有君。"]'),
('d89890cd-b694-4aaf-bade-5f0491dc3003','送李騎曹靈州歸覲','張籍','唐','唐诗','tang','','[]','翩翩出上京，幾日到邊城。',48,'全唐诗/poet.tang.20000.json','["翩翩出上京，幾日到邊城。", "漸覺風沙起，還將弓箭行。", "席箕侵路暗，野馬見人驚。", "軍府知歸慶，應教數騎迎。"]'),
('8c89ec01-675c-4238-a2a7-881f6636e733','寒食夜寄姚侍郎','張籍','唐','唐诗','tang','','[]','貧官多寂寞，不異野人居。',48,'全唐诗/poet.tang.20000.json','["貧官多寂寞，不異野人居。", "作酒和山藥，教兒寫道書。", "五湖歸去遠，百事病來疎。", "況憶同懷者，寒庭月上初。"]'),
('a4fbbd3e-4001-421f-9a95-b300d522bada','題清徹上人院','張籍','唐','唐诗','tang','','[]','古寺臨壇久，松間別起堂。',48,'全唐诗/poet.tang.20000.json','["古寺臨壇久，松間別起堂。", "看添浴佛水，自合讀經香。", "愛養無家客，多傳得效方。", "過齋長不出，坐臥一繩牀。"]'),
('35bfb080-c773-4bbe-9fe9-b4f1b30d6e4e','寄靈一上人初歸雲門寺','張籍','唐','唐诗','tang','','[]','寒山白雲裏，法侶自招攜。',48,'全唐诗/poet.tang.20000.json','["寒山白雲裏，法侶自招攜。", "竹徑通城下，松門隔水西。", "方同沃洲去，不作武陵迷。", "髣髴遙看處，秋風是會稽。"]'),
('ffb034af-8dc0-47c1-9410-42e15f64b187','和裴司空即事通簡舊僚','張籍','唐','唐诗','tang','','[]','肅肅上台坐，四方皆仰風。',48,'全唐诗/poet.tang.20000.json','["肅肅上台坐，四方皆仰風。", "當朝奉明政，早日立元功。", "獨對赤墀下，密宣黃閣中。", "猶聞動高韻，思與舊僚同。"]'),
('3bd50387-6d28-4394-921b-f30ee9ad37c9','使回留別襄陽李司空','張籍','唐','唐诗','tang','','[]','江亭寒日晚，弦管有離聲。',48,'全唐诗/poet.tang.20000.json','["江亭寒日晚，弦管有離聲。", "從此一筵別，獨爲千里行。", "遲遲戀恩德，役役限公程。", "迴首吟新句，霜雲滿楚城。"]'),
('4260e861-cbbb-4ffd-a284-7ce1ced21787','和戶部令狐尚書喜裴司空見招看雪','張籍','唐','唐诗','tang','','[]','南園新覆雪，上宰曉來看。',48,'全唐诗/poet.tang.20000.json','["南園新覆雪，上宰曉來看。", "誰共登春榭，唯聞有地官。", "色連山遠靜，氣與竹偏寒。", "高韻更相應，寧同謌吹歡。"]'),
('d8d8cce8-9094-4f66-b7ac-dc0079ecaf02','和裴司空以詩請刑部白侍郎雙鶴','張籍','唐','唐诗','tang','','[]','皎皎仙家鶴，遠留閑宅中。',48,'全唐诗/poet.tang.20000.json','["皎皎仙家鶴，遠留閑宅中。", "徘徊幽樹月，嘹唳小亭風。", "丞相西園好，池塘野水通。", "欲將來放此，賞望與賓同。"]'),
('cc340943-4814-45c0-931d-1bb90932e610','同錦州胡郎中清明日對雨西亭宴','張籍','唐','唐诗','tang','','[]','郡內開新火，高齋雨氣清。',48,'全唐诗/poet.tang.20000.json','["郡內開新火，高齋雨氣清。", "惜花邀客賞，勸酒促歌聲。", "共醉移芳席，留歡閉暮城。", "政閑方宴語，琴筑任遙情。"]'),
('064fca51-bb9d-4137-8884-3c22e00f2736','莊陵挽歌詞三首 一','張籍','唐','唐诗','tang','','[]','白日已昭昭，干戈亦漸消。',48,'全唐诗/poet.tang.20000.json','["白日已昭昭，干戈亦漸消。", "迎師親出道，從諫早臨朝。", "佞倖威權薄，忠良寵錫饒。", "丘陵今一變，無復白雲謠。"]'),
('8cd12133-f003-4c64-917c-9b4e79378aea','莊陵挽歌詞三首 二','張籍','唐','唐诗','tang','','[]','觀風欲巡洛，習戰亦開池。',48,'全唐诗/poet.tang.20000.json','["觀風欲巡洛，習戰亦開池。", "始改三年政，旋聞七月期。", "陵分內外使，官具吉凶儀。", "渭北新園路，簫笳遠更悲。"]'),
('739d2637-932f-4ef4-9ce8-63506681e838','莊陵挽歌詞三首 三','張籍','唐','唐诗','tang','','[]','曉日龍車動，秋風閶闔開。',48,'全唐诗/poet.tang.20000.json','["曉日龍車動，秋風閶闔開。", "行帷六宮出，執紼萬方來。", "慘慘郊原暮，遲遲挽唱哀。", "空山煙雨夕，新陌遶陵臺。"]'),
('7786ba76-e740-4805-a0d0-2c6a96c6d787','和左司元郎中秋居十首 一','張籍','唐','唐诗','tang','','[]','選得閑坊住，秋來草樹肥。',48,'全唐诗/poet.tang.20000.json','["選得閑坊住，秋來草樹肥。", "風前卷筒簟，雨裏脫荷衣。", "野客留方去，山童取藥歸。", "非因入朝省，過此出門稀。"]'),
('551395d4-51fe-4705-b567-6374534816d2','和左司元郎中秋居十首 二','張籍','唐','唐诗','tang','','[]','有地唯栽竹，無池亦養鵝。',48,'全唐诗/poet.tang.20000.json','["有地唯栽竹，無池亦養鵝。", "學書求墨跡，釀酒愛朝和。", "古鏡銘文淺，神方謎語多。", "居貧閑自樂，豪客莫相過。"]'),
('c601a045-73d5-4843-a0c9-ed31f7de853a','和左司元郎中秋居十首 三','張籍','唐','唐诗','tang','','[]','閑來松菊地，未省有埃塵。',48,'全唐诗/poet.tang.20000.json','["閑來松菊地，未省有埃塵。", "直去多將藥，朝迴不訪人。", "見僧收酒器，迎客換紗巾。", "更恐登清要，難成自在身。"]'),
('5505d72c-bb20-43c5-afd1-9fda4da75819','和左司元郎中秋居十首 四','張籍','唐','唐诗','tang','','[]','自知清靜好，不要問時豪。',48,'全唐诗/poet.tang.20000.json','["自知清靜好，不要問時豪。", "就石安琴枕，穿松壓酒槽。", "山晴因月甚，詩語入秋高。", "身外無餘事，唯應筆硯勞。"]'),
('6eceba24-f1f3-4729-8e8b-40f146385bf2','和左司元郎中秋居十首 五','張籍','唐','唐诗','tang','','[]','閑堂新埽灑，稱是早秋天。',48,'全唐诗/poet.tang.20000.json','["閑堂新埽灑，稱是早秋天。", "書客多呈帖，琴僧與合弦。", "莎臺乘晚上，竹院就涼眠。", "終日無忙事，還應似得仙。"]'),
('2182dbf8-4ba1-4781-ac36-949a4e5f5056','和左司元郎中秋居十首 六','張籍','唐','唐诗','tang','','[]','醉倚斑藤杖，閑眠癭木牀。',48,'全唐诗/poet.tang.20000.json','["醉倚斑藤杖，閑眠癭木牀。", "案頭行氣訣，爐裏降真香。", "尚儉經營少，居閑意思長。", "秋茶莫夜飲，新自作松漿。"]'),
('1055b759-2c85-4724-917c-d95410153657','和左司元郎中秋居十首 七','張籍','唐','唐诗','tang','','[]','每憶舊山居，新教上墨圖。',48,'全唐诗/poet.tang.20000.json','["每憶舊山居，新教上墨圖。", "晚花迴地種，好酒問人沽。", "夜後開朝簿，申前發省符。", "爲郎凡幾歲，已見白髭鬚。"]'),
('18cce48e-12e5-44d8-80b4-47a6d962accf','和左司元郎中秋居十首 八','張籍','唐','唐诗','tang','','[]','菊地纔通履，茶房不壘階。',48,'全唐诗/poet.tang.20000.json','["菊地纔通履，茶房不壘階。", "憑醫看蜀藥，寄信覓吳鞋。", "盡得仙家法，多隨道客齋。", "本無榮辱意，不是學安排。"]'),
('1f75c67e-70b9-42e7-87e4-ee893aa67d91','和左司元郎中秋居十首 九','張籍','唐','唐诗','tang','','[]','林下無拘束，閑行放性靈。',48,'全唐诗/poet.tang.20000.json','["林下無拘束，閑行放性靈。", "好時開藥竈，高處置琴亭。", "更撰居山記，唯尋相鶴經。", "初當授衣假，無吏挽門鈴。"]'),
('4a6e417b-c863-48ae-8443-1e3447abbc78','和左司元郎中秋居十首 十','張籍','唐','唐诗','tang','','[]','客散高齋晚，東園景象偏。',48,'全唐诗/poet.tang.20000.json','["客散高齋晚，東園景象偏。", "晴明猶有蝶，涼冷漸無蟬。", "藤折霜來子，蝸行雨後涎。", "新詩纔上卷，已得滿城傳。"]'),
('bf94838a-f165-449a-9069-c9564727a8ae','經王處士原居','張籍','唐','唐诗','tang','','[]','舊宅誰相近，唯僧近竹關。',48,'全唐诗/poet.tang.20000.json','["舊宅誰相近，唯僧近竹關。", "庭閑雲滿井，窗曉雪通山。", "來客半留宿，借書多寄還。", "明時未中歲，莫便一生閑。"]'),
('1fce4765-c327-4724-a0a1-807b00cc6ca1','不食仙姑山房','張籍','唐','唐诗','tang','','[]','寂寂花枝裏，草堂唯素琴。',48,'全唐诗/poet.tang.20000.json','["寂寂花枝裏，草堂唯素琴。", "因山曾改眼，見客不言心。", "月出溪路靜，鶴鳴雲樹深。", "丹砂如可學，便欲住幽林。"]'),
('e1b45254-d4b4-44aa-a068-b4027219ccdf','江頭','張籍','唐','唐诗','tang','','[]','晚步隨江遠，來帆過眼頻。',48,'全唐诗/poet.tang.20000.json','["晚步隨江遠，來帆過眼頻。", "試尋新住客，少見故鄉人。", "回首憐歸翼，長吟任此身。", "應同南浦雁，更見嶺頭春。"]'),
('415041a9-5162-4470-b063-74957cf056cb','寄孫沖主簿','張籍','唐','唐诗','tang','','[]','低折滄州簿，無書整兩春。',48,'全唐诗/poet.tang.20000.json','["低折滄州簿，無書整兩春。", "馬從同事借，妻怕罷官貧。", "道僻收閑藥，詩高笑故人。", "仍聞長吏奏，表乞鎖廳頻。"]'),
('e47339f6-9095-40b8-9a43-bbeacbf3d24c','贈任懶','張籍','唐','唐诗','tang','','[]','未肯求科第，深坊且隱居。',48,'全唐诗/poet.tang.20000.json','["未肯求科第，深坊且隱居。", "勝遊尋野客，高臥看兵書。", "點藥醫閑馬，分泉灌遠蔬。", "漢庭無得意，誰擬薦相如。"]'),
('f73675fa-9c67-4e5c-b489-3005c1958483','舊宮人','張籍','唐','唐诗','tang','','[]','謌舞梁州女，歸時白髮生。',48,'全唐诗/poet.tang.20000.json','["謌舞梁州女，歸時白髮生。", "全家沒蕃地，無處問鄉程。", "宮錦不傳樣，御香空記名。", "一身難自說，愁逐路人行。"]'),
('7ca34906-4e7e-482e-9466-22d89a5f87ec','春日留別','張籍','唐','唐诗','tang','','[]','遊人欲別離，半醉對花枝。',48,'全唐诗/poet.tang.20000.json','["遊人欲別離，半醉對花枝。", "看著春又晚，莫輕少年時。", "臨行記分處，廻首是相思。", "各向天涯去，重來未可期。"]'),
('5ccd5188-0e5d-450e-8ec5-d6e661fac4f7','沒蕃故人','張籍','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6000\u4eba", "\u4e94\u8a00\u5f8b\u8bd7"]','前年伐月支，城上沒全師。',48,'全唐诗/poet.tang.20000.json','["前年伐月支，城上沒全師。", "蕃漢斷消息，死生長別離。", "無人收廢帳，歸馬識殘旗。", "欲祭疑君在，天涯哭此時。"]'),
('0d8625bb-d201-45d8-9e5a-56346d0cbea6','贈箕山僧','張籍','唐','唐诗','tang','','[]','久住空林下，長齋耳目清。',48,'全唐诗/poet.tang.20000.json','["久住空林下，長齋耳目清。", "蒲團借客坐，石磹甃人行。", "似鶴難知性，因山強號名。", "時聞衣袖裏，闇掐念珠聲。"]'),
('bf5cb147-b653-4297-8569-0d487601292f','冬夕','張籍','唐','唐诗','tang','','[]','寒蛩獨罷織，湘雁猶能鳴。',48,'全唐诗/poet.tang.20000.json','["寒蛩獨罷織，湘雁猶能鳴。", "月色當窗入，鄉心半夜生。", "不成高枕夢，復作遶堦行。", "迴首嗟淹泊，城頭北斗橫。"]'),
('804932ef-6151-43b7-b6e6-3f961fbe840a','奉和陝州十四翁中丞寄雷州二十二翁司戶之作','張籍','唐','唐诗','tang','','[]','聯飛獨不前，迥落海南天。',48,'全唐诗/poet.tang.20000.json','["聯飛獨不前，迥落海南天。", "賈傅竟行矣，邵公惟泫然。", "瘴開山更遠，路極水無邊。", "沈劣本多感，況聞原上篇。"]'),
('790f454c-649e-4cb3-a7ff-e1bfde4373ba','老將','張籍','唐','唐诗','tang','','[]','鬢衰頭似雪，行步急如風。',48,'全唐诗/poet.tang.20000.json','["鬢衰頭似雪，行步急如風。", "不怕騎生馬，猶能挽硬弓。", "兵書封錦字，手詔滿香筒。", "今日身憔悴，猶誇定遠功。"]'),
('6c65c447-6c02-4b8a-918b-485a35466025','送友生遊峽中','張籍','唐','唐诗','tang','','[]','風靜楊柳垂，看花又別離。',48,'全唐诗/poet.tang.20000.json','["風靜楊柳垂，看花又別離。", "幾年同在此，今日各驅馳。", "峽裏聞猿呌，山頭見月時。", "殷勤一盃酒，珍重歲寒姿。"]'),
('587eaf17-f792-45bd-a6b6-6d843d0da11e','送安法師','張籍','唐','唐诗','tang','','[]','出郭見落日，別君臨古津。',48,'全唐诗/poet.tang.20000.json','["出郭見落日，別君臨古津。", "遠程無野寺，宿處問何人。", "原色不分路，錫聲遙隔塵。", "山陰到家節，猶及蕙蘭春。"]'),
('5b1b4f63-c207-4a11-b6f2-c677e0e4e0d5','水','張籍','唐','唐诗','tang','','[]','蕩漾空沙際，虛明入遠天。',48,'全唐诗/poet.tang.20000.json','["蕩漾空沙際，虛明入遠天。", "秋光照不極，鳥色去無邊。", "勢引長雲闊，波輕片雪連。", "汀洲杳難測，萬古覆蒼煙。"]'),
('8e8b950d-862a-4c8d-9fe5-8327e4d31eb9','岳州晚景','張籍','唐','唐诗','tang','','[]','晚景寒鴉集，秋聲旅雁歸。',48,'全唐诗/poet.tang.20000.json','["晚景寒鴉集，秋聲旅雁歸。", "水光浮日去，霞彩暎江飛。", "洲白蘆花吐，園紅柿葉稀。", "長沙卑濕地，九月未成衣。"]'),
('53f8a86c-d7b9-4272-b028-a5fc16ccee53','寒食後','張籍','唐','唐诗','tang','','["\u5bd2\u98df\u8282"]','田舍清明日，家家出火遲。',48,'全唐诗/poet.tang.20000.json','["田舍清明日，家家出火遲。", "白衫眠古巷，紅索搭高枝。", "紗帶生難結，銅釵重易垂。", "斬新衣著盡，還似去年時。"]'),
('3f170945-6d17-44bc-b6c9-e8311dd8a963','寒食書事二首 一','張籍','唐','唐诗','tang','','[]','今朝一百五，出戶雨初晴。',48,'全唐诗/poet.tang.20000.json','["今朝一百五，出戶雨初晴。", "舞愛雙飛蝶，歌聞數里鶯。", "江深青草岸，花滿白雲城。", "爲政多孱懦，應無酷吏名。"]'),
('186a3ef0-4ea6-4e6d-a87e-e60fd78cb793','寒食書事二首 二','張籍','唐','唐诗','tang','','[]','出城煙火少，況復是今朝。',48,'全唐诗/poet.tang.20000.json','["出城煙火少，況復是今朝。", "閑坐將誰語，臨觴只自謠。", "堦前春蘚徧，衣上落花飄。", "妓樂州人戲，使君心寂寥。"]'),
('4679dd5e-f054-4ed3-8c25-70dc7e43f568','和李僕射雨中寄盧嚴二給事','張籍','唐','唐诗','tang','','[]','郊原飛雨至，城闕濕雲埋。',72,'全唐诗/poet.tang.20000.json','["郊原飛雨至，城闕濕雲埋。", "迸點時穿牖，浮漚欲上堦。", "偏滋解籜竹，併灑落花槐。", "晚潤生琴匣，新涼滿藥齋。", "從容朝務退，放曠掖曹乖。", "盡日無來客，閑吟感此懷。"]'),
('50815b10-6ce9-4de8-8d1d-12321b2ae2e4','酬李僕射晚春見寄','張籍','唐','唐诗','tang','','[]','戟戶洞初晨，鶯聲雨後頻。',72,'全唐诗/poet.tang.20000.json','["戟戶洞初晨，鶯聲雨後頻。", "虛庭清氣在，衆藥濕光新。", "魚動芳池面，苔侵老竹身。", "教鋪嘗酒處，自問探花人。", "獨此長多病，幽居欲過春。", "今朝聽高韻，忽覺離埃塵。"]'),
('c0a4d401-6371-4fcc-ae25-6219c8be047f','和盧常侍寄華山鄭隱者','張籍','唐','唐诗','tang','','[]','獨住三峰下，年深學煉丹。',72,'全唐诗/poet.tang.20000.json','["獨住三峰下，年深學煉丹。", "一間松葉屋，數片石花冠。", "酒待山中飲，琴將洞口彈。", "開門移遠竹，剪草出幽蘭。", "荒壁通泉架，晴崖曬藥壇。", "寄知騎省客，長向白雲閑。"]'),
('2d9f705a-7212-4565-aaac-87ae359f6194','和令狐尚書平泉東莊近居李僕射有寄十韻','張籍','唐','唐诗','tang','','[]','平地有清泉，伊南古寺邊。',120,'全唐诗/poet.tang.20000.json','["平地有清泉，伊南古寺邊。", "漲池閑遶屋，出野徧澆田。", "舊隱離多日，新鄰得幾年。", "探幽皆一絕，選勝又雙全。", "門靜山光別，園深竹影連。", "斜分採藥徑，直過釣魚船。", "雞犬還應識，雲霞頓覺鮮。", "追思應不遠，賞愛諒難偏。", "此處堪長往，遊人早共傳。", "各當恩寄重，歸臥恐無緣。"]'),
('84b870dc-c0f8-486a-b858-5e4ba8ea619f','送鄭尚書出鎮南海','張籍','唐','唐诗','tang','','[]','遠鎮承新命，王程不假催。',72,'全唐诗/poet.tang.20000.json','["遠鎮承新命，王程不假催。", "班行爭路送，恩賜併時來。", "牙斾從城展，兵符到府開。", "蠻聲喧夜市，海色浸潮臺。", "畫角天邊月，寒關嶺上梅。", "共知公望重，多是隔年迴。"]'),
('35100df3-5470-494b-b237-f5a010690ede','徐州試反舌無聲','張籍','唐','唐诗','tang','','[]','夏木多好鳥，偏知反舌名。',72,'全唐诗/poet.tang.20000.json','["夏木多好鳥，偏知反舌名。", "林幽仍共宿，時過即無聲。", "竹外天空曉，谿頭雨自晴。", "居人宜寂寞，深院益淒清。", "入霧暗相失，當風閑易驚。", "來年上林苑，知爾最先鳴。"]'),
('d82ae593-0d36-4453-a086-502a28c34d97','省試行不由徑','張籍','唐','唐诗','tang','','[]','田裏有微徑，賢人不復行。',72,'全唐诗/poet.tang.20000.json','["田裏有微徑，賢人不復行。", "孰知求捷步，又恐異端成。", "從易衆所欲，安邪患亦生。", "誰能達天道，共此競前程。", "子羽有遺跡，孔門傳舊聲。", "今逢大君子，士節自光明。"]'),
('a0be7423-c79f-4ed1-a93c-389dc46e7cef','新城甲仗樓','張籍','唐','唐诗','tang','','[]','謝氏起新樓，西臨城角頭。',120,'全唐诗/poet.tang.20000.json','["謝氏起新樓，西臨城角頭。", "圖功百尺麗，藏器五兵修。", "結締榱甍固，虛明戶檻幽。", "魚龍卷旗幟，霜雪積戈矛。", "暑雨熇烝隔，涼風宴位留。", "地高形出沒，山靜氣清優。", "睥睨斜光徹，闌干宿靄浮。", "芊芊秔稻色，脉脉苑谿流。", "郡化黃丞相，詩成沈隱侯。", "居茲良得景，殊勝峴山遊。"]'),
('b4083322-3d89-4037-83b0-8e445f977b34','贈殷山人','張籍','唐','唐诗','tang','','[]','鬱鬱山中客，知名四十年。',288,'全唐诗/poet.tang.20000.json','["鬱鬱山中客，知名四十年。", "恓惶身獨隱，寂寞性應便。", "世業公侯籍，生涯黍稷田。", "藤懸讀書帳，竹繫網魚船。", "已種千頭橘，新開數脉泉。", "閑遊攜酒遠，幽語向僧偏。", "入洞題松過，看花選石眠。", "避喧長汩沒，逢勝即留連。", "自古多高跡，如君少比肩。", "耕耘此辛苦，章句已流傳。", "昔日交遊盛，當時省閣賢。", "同袍還共弊，連轡每推先。", "講序居重席，羣儒願執鞭。", "滿堂虛左待，衆目望喬遷。", "才異時難用，情高道自全。", "畏人顏慘澹，疎物勢迍邅。", "賢者聞知命，吾生復禮玄。", "深藏報恩劒，久緝養生篇。", "憔悴衆夫笑，經過郡守憐。", "夕陽悲病鶴，霜氣動飢鸇。", "處士誰能薦，窮途世所捐。", "伯鸞甘寄食，元淑苦無錢。", "策蹇秋塵裏，吟詩黃葉前。", "故裘餘白領，廢瑟斷朱弦。"]'),
('d8648474-aede-477f-bbd8-9793db49a9e7','夏日可畏','張籍','唐','唐诗','tang','','[]','赫赫溫風扇，炎炎夏日徂。',72,'全唐诗/poet.tang.20000.json','["赫赫溫風扇，炎炎夏日徂。", "火威馳逈野，畏景鑠遙途。", "勢矯翔陽翰，功分造化罏。", "禁城千品燭，黃道一輪孤。", "落照頻空簟，餘暉卷夕梧。", "如何倦遊子，中路獨踟躕。"]'),
('79f27efe-fb2a-4e22-b7ec-a30d9a0cfd1b','罔象得玄珠','張籍','唐','唐诗','tang','','[]','赤水今何處，遺珠已渺然。',72,'全唐诗/poet.tang.20000.json','["赤水今何處，遺珠已渺然。", "離婁徒肆目，罔象乃通玄。", "皎潔因成性，圓明不在泉。", "暗中看夜色，塵外照晴田。", "無脛真難掬，懷疑實易遷。", "今朝搜擇得，應免媚晴川。"]'),
('247aeaa0-d69a-4c18-a69f-fc6cf9280161','和李僕射西園','張籍','唐','唐诗','tang','','[]','遇午歸閑處，西庭敞四簷。',96,'全唐诗/poet.tang.20000.json','["遇午歸閑處，西庭敞四簷。", "高眠著琴枕，散帖檢書簽。", "印在休通客，山晴好捲簾。", "竹涼蠅少到，藤暗蝶爭潛。", "曉鵲頻驚喜，疎蟬不許拈。", "石苔生紫點，欄藥吐紅尖。", "虛坐詩情遠，幽探道侶兼。", "所營尚勝地，雖儉復誰嫌。"]'),
('781555b7-0c60-4783-9639-1609adb59969','送裴相公赴鎮太原','張籍','唐','唐诗','tang','','[]','盛德雄名遠近知，功高先乞守藩維。',64,'全唐诗/poet.tang.20000.json','["盛德雄名遠近知，功高先乞守藩維。", "銜恩暫遣分龍節，署勅還同在鳳池。", "天子親臨樓上送，朝官齊出道傍辭。", "明年塞北清蕃落，應建生祠請立碑。"]'),
('47a432f9-a8f7-48bd-903d-1fdb90cf3ea1','寄元員外','張籍','唐','唐诗','tang','','[]','外郎直罷無餘事，埽灑書堂試藥爐。',64,'全唐诗/poet.tang.20000.json','["外郎直罷無餘事，埽灑書堂試藥爐。", "門巷不教當要鬧，詩篇轉覺足工夫。", "月明臺上唯僧到，夜靜坊中有酒沽。", "朝省入頻閑日少，可能同作舊遊無。"]'),
('c637d249-8158-48b9-98ee-a2300c0acbde','贈梅處士','張籍','唐','唐诗','tang','','[]','早聞聲價滿京城，頭白江湖放曠情。',64,'全唐诗/poet.tang.20000.json','["早聞聲價滿京城，頭白江湖放曠情。", "講易自傳新註義，題詩不著舊官名。", "近移馬跡山前住，多向牛頭寺裏行。", "天子如今議封禪，應將束帛請先生。"]'),
('05bf7ea8-b98c-4a8c-b488-557dc2ae0db6','贈王秘書','張籍','唐','唐诗','tang','','[]','不曾浪出謁公侯，唯向花間水畔遊。',64,'全唐诗/poet.tang.20000.json','["不曾浪出謁公侯，唯向花間水畔遊。", "每著新衣看藥竈，多收古器在書樓。", "有官祗作山人老，平地能開洞穴幽。", "自領閑司了無事，得來君處喜相留。"]'),
('611a7cbf-4679-427d-bf88-784eb53bcdd2','謝裴司空寄馬','張籍','唐','唐诗','tang','','[]','騄耳新駒駿得名，司空遠自寄書生。',64,'全唐诗/poet.tang.20000.json','["騄耳新駒駿得名，司空遠自寄書生。", "乍離華廐移蹄澀，初到貧家舉眼驚。", "每被閑人來借問，多尋古寺獨騎行。", "長思歲旦沙堤上，得從鳴珂傍火城。"]'),
('9d8abe6e-b38b-4777-9219-083db49583cb','酬祕書王丞見寄','張籍','唐','唐诗','tang','','[]','相看頭白來城闕，却憶漳溪舊往還。',64,'全唐诗/poet.tang.20000.json','["相看頭白來城闕，却憶漳溪舊往還。", "今體詩中偏出格，常參官裏每同班。", "街西借宅多臨水，馬上逢人亦說山。", "芸閣水曹雖最冷，與君長喜得身閑。"]'),
('c9cceace-2c0b-4a98-9532-fbca3d7dd057','送李餘及第後歸蜀','張籍','唐','唐诗','tang','','[]','十年人詠好詩章，今日成名出舉場。',64,'全唐诗/poet.tang.20000.json','["十年人詠好詩章，今日成名出舉場。", "歸去唯將新誥牒，後來爭取舊衣裳。", "山橋曉上芭蕉暗，水店晴看芋草黃。", "鄉里親情相見日，一時攜酒賀高堂。"]'),
('d2cfde83-58d0-4d9e-9783-61f9de80c42d','早朝寄白舍人嚴郎中','張籍','唐','唐诗','tang','','[]','鼓聲初動未聞雞，羸馬街中踏凍泥。',64,'全唐诗/poet.tang.20000.json','["鼓聲初動未聞雞，羸馬街中踏凍泥。", "燭暗有時衝石柱，雪深無處認沙堤。", "常參班裏人猶少，待漏房前月欲西。", "鳳闕星郎離去遠，閤門開日入還齊。"]'),
('df014f30-57b2-4a82-b2be-efa446d5f926','書懷寄元郎中','張籍','唐','唐诗','tang','','[]','轉覺人間無氣味，常因身外省因緣。',64,'全唐诗/poet.tang.20000.json','["轉覺人間無氣味，常因身外省因緣。", "經過獨愛遊山客，計校唯求買藥錢。", "重作學官閑盡日，一離江塢病多年。", "吟君釣客詞中說，便欲南歸榜小船。"]'),
('220398b6-508f-4148-bc38-7287f18faa67','贈道士宜師','張籍','唐','唐诗','tang','','[]','自到王城得幾年，巴童蜀馬共隨緣。',64,'全唐诗/poet.tang.20000.json','["自到王城得幾年，巴童蜀馬共隨緣。", "兩朝侍從當時貴，五字聲名遠處傳。", "舊住紅樓通內院，新承墨詔賜齋錢。", "閑房暫喜居相近，還得陪師坐竹邊。"]'),
('74c637b5-6125-4c59-9d66-1932b721ee82','書懷寄王祕書','張籍','唐','唐诗','tang','','[]','白髮如今欲滿頭，從來百事盡應休。',64,'全唐诗/poet.tang.20000.json','["白髮如今欲滿頭，從來百事盡應休。", "祗於觸目須防病，不擬將心更養愁。", "下藥遠求新熟酒，看山多上最高樓。", "賴君同在京城住，每到花前免獨遊。"]'),
('64cd94af-cc46-46c4-83cd-c2e52706fdbc','題韋郎中新亭','張籍','唐','唐诗','tang','','[]','起得幽亭景復新，碧莎地上更無塵。',64,'全唐诗/poet.tang.20000.json','["起得幽亭景復新，碧莎地上更無塵。", "琴書著盡猶嫌少，松竹栽多亦稱貧。", "藥酒欲開期好客，朝衣暫脫見閑身。", "成名同日官連署，此處經過有幾人。"]'),
('0ef2d670-45a0-4c58-b23f-4fe45fcfb414','送楊州判官','張籍','唐','唐诗','tang','','[]','應得煙霞出俗心，茅山道士共追尋。',64,'全唐诗/poet.tang.20000.json','["應得煙霞出俗心，茅山道士共追尋。", "閑憐鶴貌偏能畫，暗辨桐聲自作琴。", "長嘯每來松下坐，新詩堪向雪中吟。", "征南幕裏多賓客，君獨相知最校深。"]'),
('247c812e-2db0-44ae-95b6-bfcb328016a8','喜王起侍郎放牒','張籍','唐','唐诗','tang','','[]','東風節氣近清明，車馬爭來滿禁城。',64,'全唐诗/poet.tang.20000.json','["東風節氣近清明，車馬爭來滿禁城。", "二十八人初上牒，百千萬里盡傳名。", "誰家不借花園看，在處多將酒器行。", "共賀春司能鑒識，今年定合有公卿。"]'),
('14449c3d-09ec-494f-bd4c-7b5531cd38e4','贈王司馬','張籍','唐','唐诗','tang','','[]','白笏朱衫年少時，久登班列會朝儀。',64,'全唐诗/poet.tang.20000.json','["白笏朱衫年少時，久登班列會朝儀。", "貯財不省關身用，行義唯愁被衆知。", "藏得寶刀求主帶，調成駿馬乞人騎。", "未曾相識多聞說，遙望長如白玉枝。"]'),
('18a94893-e46a-4a0b-a892-934276cd8286','書懷','張籍','唐','唐诗','tang','','[]','自小信成疎嬾性，人間事事總無功。',64,'全唐诗/poet.tang.20000.json','["自小信成疎嬾性，人間事事總無功。", "別從仙客求方法，時到僧家問苦空。", "老大登朝如夢裏，貧窮作活似村中。", "未能即便休官去，慚愧南山採藥翁。"]'),
('ea13a4d6-be49-40a4-bdf2-f82968727c3a','贈令狐博士','張籍','唐','唐诗','tang','','[]','頭白新年六十餘，近聞生計轉空虛。',64,'全唐诗/poet.tang.20000.json','["頭白新年六十餘，近聞生計轉空虛。", "久爲博士誰能識，自到長安賃舍居。", "騎馬出隨尋寺客，呼兒散寫乞錢書。", "古來賢哲皆如此，應是才高與衆疎。"]'),
('9228894a-0c26-451a-8328-110d7fae7f42','送從弟刪東歸','張籍','唐','唐诗','tang','','[]','雲水東南兩月程，貪歸慶節馬蹄輕。',64,'全唐诗/poet.tang.20000.json','["雲水東南兩月程，貪歸慶節馬蹄輕。", "春橋欲醉攀花別，野路閑吟觸雨行。", "詩價已高猶失意，禮司曾賞會成名。", "舊山風月知應好，莫向秋時不到京。"]'),
('d6d0c089-9c15-4895-95f8-0c334edbf3a3','贈王祕書','張籍','唐','唐诗','tang','','[]','早在山東聲價遠，曾將順策佐嫖姚。',64,'全唐诗/poet.tang.20000.json','["早在山東聲價遠，曾將順策佐嫖姚。", "賦來詩句無閑語，老去官班未在朝。", "身屈祗聞詞客說，家貧多見野僧招。", "獨從書閣歸時晚，春水渠邊看柳條。"]'),
('eb81d8cb-2ad6-4b73-878c-cf146a785289','哭丘長史','張籍','唐','唐诗','tang','','[]','曾是先皇殿上臣，丹砂久服不成真。',64,'全唐诗/poet.tang.20000.json','["曾是先皇殿上臣，丹砂久服不成真。", "常騎馬在嘶空櫪，自作書留別故人。", "詩句徧傳天下口，朝衣偏送地中身。", "最悲昨日同遊處，看却春風樹樹新。"]'),
('b3d3d64e-76f0-4c7c-be55-9c9e61d8baac','送枝江劉明府','張籍','唐','唐诗','tang','','[]','老著青衫爲楚宰，平生志業有誰知。',64,'全唐诗/poet.tang.20000.json','["老著青衫爲楚宰，平生志業有誰知。", "家僮從去愁行遠，縣吏迎來怪到遲。", "定訪玉泉幽院宿，應過碧澗早茶時。", "向南漸漸雲山好，一路唯聞唱竹枝。"]'),
('77b0962f-1c31-4ff1-9f4c-2f90d4cd309c','送從弟徹東歸','張籍','唐','唐诗','tang','','[]','緱山領印知公奏，才稱同時盡不如。',64,'全唐诗/poet.tang.20000.json','["緱山領印知公奏，才稱同時盡不如。", "奉使賀成登冊禮，陪班看出降恩書。", "去迴在路秋塵裏，受詔辭歸曉漏初。", "早晚得爲朝署拜，閑坊買宅作鄰居。"]'),
('1d7fc68f-be35-464b-b70a-06725f99238a','哭胡十八遇','張籍','唐','唐诗','tang','','[]','早得聲名年尚少，尋常志氣出風塵。',64,'全唐诗/poet.tang.20000.json','["早得聲名年尚少，尋常志氣出風塵。", "文場繼續成三代，家族輝華在一身。", "幼子見生才滿月，選書知寫未呈人。", "送君帳下衣裳白，數尺墳頭栢樹新。"]'),
('33be17f8-f0b2-4c54-9d97-d4900b2c1f31','贈賈島','張籍','唐','唐诗','tang','','[]','籬落荒涼僮僕飢，樂遊原上住多時。',64,'全唐诗/poet.tang.20000.json','["籬落荒涼僮僕飢，樂遊原上住多時。", "蹇驢放飽騎將出，秋卷裝成寄與誰。", "拄杖傍田尋野菜，封書乞米趂時炊。", "姓名未上登科記，身屈惟應內史知。"]'),
('ef40e90a-5774-4790-951d-06277b45033d','逢王建有贈','張籍','唐','唐诗','tang','','[]','年狀皆齊初有髭，鵲山漳水每追隨。',64,'全唐诗/poet.tang.20000.json','["年狀皆齊初有髭，鵲山漳水每追隨。", "使君座下朝聽易，處士庭中夜會詩。", "新作句成相借問，閑求義盡共尋思。", "經今三十餘年事，却說還同昨日時。"]'),
('5ee04935-b05b-427d-be12-d1015dfabff7','移居靜安坊答元八郎中','張籍','唐','唐诗','tang','','[]','長安寺裏多時住，雖守卑官不苦貧。',64,'全唐诗/poet.tang.20000.json','["長安寺裏多時住，雖守卑官不苦貧。", "作活每常嫌費力，移居祗是貴容身。", "初開井淺偏宜樹，漸覺街閑省踏塵。", "更喜往還相去近，門前減却送書人。"]'),
('7670129d-e5f8-483d-9c00-361f0e425faa','送楊少尹赴鳳翔','張籍','唐','唐诗','tang','','[]','詩名往日動長安，首首人家卷裏看。',64,'全唐诗/poet.tang.20000.json','["詩名往日動長安，首首人家卷裏看。", "西學已行秦博士，南宮新拜漢郎官。", "得錢祗了還書鋪，借宅常時事藥欄。", "今去岐州生計薄，移居偏近隴頭寒。"]'),
('9448354e-2de0-4cad-8a68-dfca162110cf','送韓侍御歸山','張籍','唐','唐诗','tang','','[]','聞君久臥在雲間，爲佐嫖姚未得還。',64,'全唐诗/poet.tang.20000.json','["聞君久臥在雲間，爲佐嫖姚未得還。", "新階茆廬招隱逸，獨騎驄馬入深山。", "九靈洞口行應到，五粒松枝醉亦攀。", "明日珂聲出城去，家僮不復埽柴關。"]'),
('0660e5ee-25b4-41c5-ac79-7994c87f6e3d','新除水曹郎答白舍人見賀','張籍','唐','唐诗','tang','','[]','年過五十到南宮，章句無名荷至公。',64,'全唐诗/poet.tang.20000.json','["年過五十到南宮，章句無名荷至公。", "黃紙開呈相府後，朱衣引入謝班中。", "諸曹縱許爲仙侶，羣吏多嫌是老翁。", "最幸紫薇郎見愛，獨稱官與古人同。"]'),
('38e62a26-9840-48c5-b72f-78c744172661','送楊少尹赴滿城','張籍','唐','唐诗','tang','','[]','官爲本府當身榮，因得還鄉任野情。',64,'全唐诗/poet.tang.20000.json','["官爲本府當身榮，因得還鄉任野情。", "自廢田園今作主，每逢耆老不呼名。", "舊遊寺裏僧應識，新別橋邊樹已成。", "公事況閑詩更好，將隨相逐上山行。"]'),
('52dc13f5-5fd6-4b8c-aa4b-afc699123361','哭元九少府','張籍','唐','唐诗','tang','','[]','平生志業獨相知，早結雲山老去期。',64,'全唐诗/poet.tang.20000.json','["平生志業獨相知，早結雲山老去期。", "初作學官常共宿，晚登朝列暫同時。", "閑來各數經過地，醉後齊吟唱和詩。", "今日春風花滿宅，入門行哭見靈帷。"]'),
('4fea8fb6-44b1-495c-b196-3875715a09d1','送侯判官赴廣州從軍','張籍','唐','唐诗','tang','','[]','年少才高求自展，將身萬里赴軍門。',64,'全唐诗/poet.tang.20000.json','["年少才高求自展，將身萬里赴軍門。", "辟書遠到開呈客，公服新成著謝恩。", "驛舫過江分白堠，戍亭當嶺見紅旛。", "海花蠻草連冬有，行處無家不滿園。"]'),
('28527ad0-4b09-4eca-8a74-79a1ab1aa755','答白杭州郡樓登望畫圖見寄','張籍','唐','唐诗','tang','','[]','畫得江城登望處，寄來今日到長安。',64,'全唐诗/poet.tang.20000.json','["畫得江城登望處，寄來今日到長安。", "乍驚物色從詩出，更想工人下手難。", "將展書堂偏覺好，每來朝客盡求看。", "見君向此閑吟意，肯恨當時作外官。"]'),
('2deab82a-0a07-4848-85e1-f77dc21495d8','贈趙將軍','張籍','唐','唐诗','tang','','[]','當年膽略已縱橫，每見妖星氣不平。',64,'全唐诗/poet.tang.20000.json','["當年膽略已縱橫，每見妖星氣不平。", "身貴早登龍尾道，功高自破鹿頭城。", "尋常得對論邊事，委曲承恩掌內兵。", "會取安西將報國，凌煙閣上大書名。"]'),
('a1a7ff27-a054-41fa-8d37-71901338f6da','送和蕃公主','張籍','唐','唐诗','tang','','[]','塞上如今無戰塵，漢家公主出和親。',64,'全唐诗/poet.tang.20000.json','["塞上如今無戰塵，漢家公主出和親。", "邑司猶屬宗卿寺，冊號還同虜帳人。", "九姓旗旛先引路，一生衣服盡隨身。", "氈城南望無迴日，空見沙蓬水柳春。"]'),
('fa1adb66-7fe0-4b2b-be06-6f56eb01cec5','寒食內宴二首 一','張籍','唐','唐诗','tang','','[]','朝光瑞氣滿宮樓，綵纛魚龍四面稠。',64,'全唐诗/poet.tang.20000.json','["朝光瑞氣滿宮樓，綵纛魚龍四面稠。", "廊下御廚分冷食，殿前香騎逐飛毬。", "千官盡醉猶教坐，百戲皆呈未放休。", "共喜拜恩侵夜出，金吾不敢問行由。"]'),
('2fc0e121-f66f-4368-9c8a-1fe8635e7ad1','寒食內宴二首 二','張籍','唐','唐诗','tang','','[]','城闕沈沈向曉寒，恩當令節賜餘歡。',64,'全唐诗/poet.tang.20000.json','["城闕沈沈向曉寒，恩當令節賜餘歡。", "瑞煙深處開三殿，春雨微時引百官。", "寶樹樓前分繡幕，綵花廊下暎華欄。", "宮筵戲樂年年別，已得三廻對御看。"]'),
('7ef7bc94-3b3f-4224-ba4c-889a39870e38','朝日勅賜百官櫻桃','張籍','唐','唐诗','tang','','[]','仙果人間都未有，今朝忽見下天門。',64,'全唐诗/poet.tang.20000.json','["仙果人間都未有，今朝忽見下天門。", "捧盤小吏初宣勅，當殿羣臣共拜恩。", "日色遙分門下坐，露香才出禁中園。", "每年重此先偏待，願得千春奉至尊。"]'),
('74b9cde0-f297-46e1-a744-dcc9daeb7d92','太白老人','張籍','唐','唐诗','tang','','[]','日觀東峰幽客住，竹巾藤帶亦逢迎。',64,'全唐诗/poet.tang.20000.json','["日觀東峰幽客住，竹巾藤帶亦逢迎。", "暗修黃籙無人見，深種胡麻共犬行。", "洞裏仙家常獨往，壺中靈藥自爲名。", "春泉四面遶茅屋，日日唯聞杵臼聲。"]'),
('68080293-b18f-4260-9564-f5b35c06ad3a','和裴司空酬滿城楊少尹','張籍','唐','唐诗','tang','','[]','聖朝偏重大司空，人詠元和第一功。',64,'全唐诗/poet.tang.20000.json','["聖朝偏重大司空，人詠元和第一功。", "擁節高臨漢水上，題詩遠入舜城中。", "共驚向老多年別，更憶登科舊日同。", "誰不望歸丞相府，江邊楊柳又秋風。"]'),
('4334cf10-8430-42a2-b83d-cb8695f024c0','寄和州劉使君','張籍','唐','唐诗','tang','','[]','別離已久猶爲郡，閑向春風倒酒缾。',64,'全唐诗/poet.tang.20000.json','["別離已久猶爲郡，閑向春風倒酒缾。", "送客特過沙口堰，看花多上水心亭。", "曉來江氣連城白，雨後山光滿郭青。", "到此詩情應更遠，醉中高詠有誰聽。"]'),
('d09f2306-ec02-4e9f-a5d1-d37967e17ab1','贈商州王使君','張籍','唐','唐诗','tang','','[]','銜命南來會郡堂，却思朝裏接班行。',64,'全唐诗/poet.tang.20000.json','["銜命南來會郡堂，却思朝裏接班行。", "才雄猶是山城守，道薄初爲水部郎。", "選勝相留開客館，尋幽更引到僧房。", "明朝從此辭君去，獨出商關路漸長。"]'),
('5383280e-28b4-4df5-8fe0-ee9f651165cd','寄令狐賓客','張籍','唐','唐诗','tang','','[]','勳名盡得國家傳，退狎琴僧與酒仙。',64,'全唐诗/poet.tang.20000.json','["勳名盡得國家傳，退狎琴僧與酒仙。", "還帶郡符經幾處，暫辭台座已三年。", "留司未到龍樓下，拜表長懷玉案前。", "秋日出城伊水好，領誰相逐上閑船。"]'),
('599ee7ca-7e82-4689-b92a-709e51bfce33','寄梅處士','張籍','唐','唐诗','tang','','[]','擾擾人間是與非，官閑自覺省心機。',64,'全唐诗/poet.tang.20000.json','["擾擾人間是與非，官閑自覺省心機。", "六行班裏身常下，九列符中事亦稀。", "市客慣曾賒賤藥，家僮驚見著新衣。", "君今獨得居山樂，應喜多時未辦歸。"]'),
('4c7be068-f8db-44c0-99c3-9f44d95b7d4a','送施肩吾東歸','張籍','唐','唐诗','tang','','[]','知君本是煙霞客，被薦因來城闕間。',64,'全唐诗/poet.tang.20000.json','["知君本是煙霞客，被薦因來城闕間。", "世業偏臨七里瀨，仙遊多在四明山。", "早聞詩句傳人徧，新得科名到處閑。", "惆悵灞亭相送去，雲中琪樹不同攀。"]'),
('f254a77c-17ff-46b4-83e9-623ef57d441c','崑崙兒','張籍','唐','唐诗','tang','','[]','崑崙家住海中州，蠻客將來漢地遊。',64,'全唐诗/poet.tang.20000.json','["崑崙家住海中州，蠻客將來漢地遊。", "言語解教秦吉了，波濤初過鬱林洲。", "金環欲落曾穿耳，螺髻長卷不裹頭。", "自愛肌膚黑如漆，行時半脫木綿裘。"]'),
('01f4e76e-8cee-4b7e-a513-e1221a53300d','贈李杭州','張籍','唐','唐诗','tang','','[]','仙郎白首未歸朝，應爲蒼生領六條。',64,'全唐诗/poet.tang.20000.json','["仙郎白首未歸朝，應爲蒼生領六條。", "惠化州人盡清淨，高情野鶴與逍遙。", "竹間虛館無朝訟，山畔青田長夏苗。", "終日政聲長獨坐，開門長望浙江潮。"]'),
('43966955-c47e-428d-92e8-0803ac8bb4de','送鄭尚書赴廣州','張籍','唐','唐诗','tang','','[]','聖朝選將持符節，內使宣時百辟聽。',64,'全唐诗/poet.tang.20000.json','["聖朝選將持符節，內使宣時百辟聽。", "海北蠻夷來舞蹈，嶺南封管送圖經。", "白鷴飛遶迎官舫，紅槿開當讌客亭。", "此處莫言多瘴癘，天邊看取老人星。"]'),
('4f09773a-fe00-4b09-8c0f-c045fd61f344','賀秘書王丞南郊攝將軍','張籍','唐','唐诗','tang','','[]','正初天子親郊禮，詔攝將軍領衛兵。',64,'全唐诗/poet.tang.20000.json','["正初天子親郊禮，詔攝將軍領衛兵。", "斜帶銀刀入黃道，先隨玉輅到青城。", "壇邊不在千官位，仗外唯聞再拜聲。", "共喜與君逢此日，病中無計得隨行。"]'),
('c90e225a-331a-4f78-9e14-f930489e2cff','送令狐尚書赴東都留守','張籍','唐','唐诗','tang','','[]','朝廷重寄在關東，共說從前選上公。',64,'全唐诗/poet.tang.20000.json','["朝廷重寄在關東，共說從前選上公。", "勳業新城大梁鎮，恩榮更守洛陽宮。", "行香暫出天橋上，巡禮常過禁殿中。", "每領羣臣拜章慶，半開門仗日曈曈。"]'),
('3fee945e-5d15-48c3-9ca1-4115f9ee27cd','拜豐陵','張籍','唐','唐诗','tang','','[]','歲朝園寢遣公卿，學省班中亦攝行。',64,'全唐诗/poet.tang.20000.json','["歲朝園寢遣公卿，學省班中亦攝行。", "身逐陵官齊再拜，手持木鐸叩三聲。", "寒更報點來山殿，曉炬分行照栢城。", "却下龍門看漸遠，金峰高處日微明。"]'),
('68da5949-d64b-4058-85e9-ccdf23dd687c','贈孔尚書','張籍','唐','唐诗','tang','','[]','能將直道歷榮班，事著元和實錄間。',64,'全唐诗/poet.tang.20000.json','["能將直道歷榮班，事著元和實錄間。", "三表自陳辭北闕，一家相送入南山。", "買來侍女教人嫁，賜得朝衣在篋閑。", "宅近青山高靜處，時歸林下暫開關。"]'),
('6d111410-9d0e-411b-af45-e61d4f1e0c7a','酬杭州白使君兼寄浙東元大夫','張籍','唐','唐诗','tang','','[]','相印暫離臨遠鎮，掖垣出守復同時。',64,'全唐诗/poet.tang.20000.json','["相印暫離臨遠鎮，掖垣出守復同時。", "一行已作三年別，兩處空傳七字詩。", "越地江山應共見，秦天風月不相知。", "人間聚散真難料，莫歎平生信所之。"]'),
('d6eff5bf-c858-4b80-8ad2-75f19c022a55','寄蘇州白二十二使君','張籍','唐','唐诗','tang','','[]','三朝出入紫微臣，頭白金章未在身。',64,'全唐诗/poet.tang.20000.json','["三朝出入紫微臣，頭白金章未在身。", "登第早年同座主，題詩今日是州人。", "閶門柳色煙中遠，茂苑鶯聲雨後新。", "此處吟詩向山寺，知君忘却曲江春。"]'),
('12d6d253-6aa8-43ea-98ae-6fbd0bafbbf7','送白賓客分司東都','張籍','唐','唐诗','tang','','[]','赫赫聲名三十春，高情人獨出埃塵。',64,'全唐诗/poet.tang.20000.json','["赫赫聲名三十春，高情人獨出埃塵。", "病辭省闥歸閑地，恩許宮曹作上賓。", "詩裏難同相得伴，酒邊多見自由身。", "老人也擬休官去，便是君家池上人。"]'),
('d3ceb589-d95b-45e5-a962-0c45a0619a1a','贈閻少保','張籍','唐','唐诗','tang','','[]','辭榮戀闕未還鄉，修養年多氣力強。',64,'全唐诗/poet.tang.20000.json','["辭榮戀闕未還鄉，修養年多氣力強。", "半俸歸燒伏火藥，全家解說養生方。", "特承恩詔新開戟，每見公卿不下牀。", "竹樹晴深寒院靜，長懸石磬在虛廊。"]'),
('a8765dbf-31c4-46a6-bd1e-0accbdc6fe95','贈別王侍御赴任陝州司馬','張籍','唐','唐诗','tang','','[]','京城在處閑人少，唯共君行並馬蹄。',64,'全唐诗/poet.tang.20000.json','["京城在處閑人少，唯共君行並馬蹄。", "更和詩篇名最出，時傾杯酒戶常齊。", "同趨闕下聽鐘漏，獨向軍前聞鼓鼙。", "今日春明門外別，更無因得到街西。"]'),
('84169119-3ee7-4a54-b111-0ed05cb569fa','田司空入朝','張籍','唐','唐诗','tang','','[]','西來將相位兼雄，不與諸君覲禮同。',64,'全唐诗/poet.tang.20000.json','["西來將相位兼雄，不與諸君覲禮同。", "早變山東知順命，新收濟上立殊功。", "朝官敘謁趨門外，恩使喧迎滿路中。", "閶闔曉開銅漏靜，身當受冊大明宮。"]'),
('aa36b511-7c7b-4d4f-9595-bd0c6a64646e','送浙西周判官','張籍','唐','唐诗','tang','','[]','由來自是煙霞客，早已聞名詩酒間。',64,'全唐诗/poet.tang.20000.json','["由來自是煙霞客，早已聞名詩酒間。", "天闕因將賀表到，家鄉新著賜衣遠。", "常吟卷裏新酬句，自話湖中舊住山。", "吳越主人偏愛重，多應不肯放君閑。"]'),
('bd4b03d3-5491-4c49-80a4-2514043e5d74','送吳鍊師歸王屋','張籍','唐','唐诗','tang','','[]','玉陽峰下學長生，玉洞仙中已有名。',64,'全唐诗/poet.tang.20000.json','["玉陽峰下學長生，玉洞仙中已有名。", "獨戴熊鬚冠暫出，唯將鶴尾扇同行。", "煉成雲母休炊爨，已得雷公當吏兵。", "却到瑤壇上頭宿，應聞空裏步虛聲。"]'),
('b6706142-79ab-4639-9fbe-9c1e09517c5e','送邵州林使君','張籍','唐','唐诗','tang','','[]','詞客南行寵命新，瀟湘郡入曲江津。',64,'全唐诗/poet.tang.20000.json','["詞客南行寵命新，瀟湘郡入曲江津。", "山幽自足探微處，俗朴應無爭競人。", "郭外相連排殿閣，市中多半用金銀。", "知君不作家私計，遷日還同到日貧。"]'),
('d1ec388a-d5a9-4b2c-a93f-86cb85c8f597','寄王六侍御','張籍','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','漸覺近來筋力少，難堪今日在風塵。',64,'全唐诗/poet.tang.20000.json','["漸覺近來筋力少，難堪今日在風塵。", "誰能借問功名事，祗自扶持老病身。", "貴得藥資將助道，肯嫌家計不如人。", "洞庭已置新居處，歸去安期與作鄰。"]'),
('82da9ec9-f213-4a87-b5e0-f419f984b8dc','送稽亭山寺僧','張籍','唐','唐诗','tang','','[]','師住稽亭高處寺，斜廊曲閣倚雲開。',64,'全唐诗/poet.tang.20000.json','["師住稽亭高處寺，斜廊曲閣倚雲開。", "山門十里松間入，泉澗三重洞裏來。", "名岳尋遊今已徧，家城禮謁便應迴。", "舊房到日閑吟後，林下還登說法臺。"]'),
('109f899b-84f0-4e71-959a-969db7f67755','送汀州源使君','張籍','唐','唐诗','tang','','[]','曾成趙北歸朝計，因拜王門最好官。',64,'全唐诗/poet.tang.20000.json','["曾成趙北歸朝計，因拜王門最好官。", "爲郡暫辭雙鳳闕，全家遠過九龍灘。", "山鄉祗有輸蕉戶，水鎮應多養鴨欄。", "地僻尋常來客少，刺桐花發共誰看。"]'),
('0f26e21c-78b1-4f24-be65-7e27ae0d3be0','寄孫洛陽格','張籍','唐','唐诗','tang','','[]','久持刑憲聲名遠，好是中朝正直臣。',64,'全唐诗/poet.tang.20000.json','["久持刑憲聲名遠，好是中朝正直臣。", "赤縣上來應足事，青山老去未離身。", "常思從省連歸馬，乍覺同班少舊人。", "遙愛南橋秋日晚，雨邊楊柳映天津。"]'),
('e4dc1b33-be39-4b2d-be7f-ef13827e6b21','胡山人歸王屋因有贈','張籍','唐','唐诗','tang','','[]','轉轉無成到白頭，人間舉眼盡堪愁。',64,'全唐诗/poet.tang.20000.json','["轉轉無成到白頭，人間舉眼盡堪愁。", "此生已是蹉跎去，每事應從鹵莽休。", "雖作閑官少拘束，難逢勝景可淹留。", "君歸與訪移家處，若箇峰頭最較幽。"]'),
('d6380ab9-4da5-4392-8dd5-d6b9bc4b23de','寄虔州韓使君','張籍','唐','唐诗','tang','','[]','南康太守負才豪，五十如今未擁旄。',64,'全唐诗/poet.tang.20000.json','["南康太守負才豪，五十如今未擁旄。", "早得一人知姓字，常聞三事說功勞。", "月明渡口漳江靜，雲散城頭贛石高。", "郡政已成秋思遠，閑吟應不問官曹。"]'),
('39545234-b328-4476-9299-df92067de29b','送從弟濛赴饒州','張籍','唐','唐诗','tang','','[]','京城南去鄱陽遠，風月悠悠別思勞。',64,'全唐诗/poet.tang.20000.json','["京城南去鄱陽遠，風月悠悠別思勞。", "三領郡符新寄重，再登科第舊名高。", "去程江上多看堠，迎吏船中亦帶刀。", "到日更行清靜化，春田應不見蓬蒿。"]'),
('bb9157d6-9cc6-42ff-8fb0-b59181af7aba','羅道士','張籍','唐','唐诗','tang','','[]','城裏無人得實年，衣襟常帶臭黃煙。',64,'全唐诗/poet.tang.20000.json','["城裏無人得實年，衣襟常帶臭黃煙。", "樓中賒酒唯留藥，洞裏爭棋不賭錢。", "聞客語聲知貴賤，持花歌詠似狂顛。", "尋常行處皆逢見，世上多疑是謫仙。"]'),
('f917edb7-95ba-446b-afab-cf98986139ba','寄陸渾趙明府','張籍','唐','唐诗','tang','','[]','與君學省同官處，常日相隨說道情。',64,'全唐诗/poet.tang.20000.json','["與君學省同官處，常日相隨說道情。", "新作陸渾山縣長，早知三禮甲科名。", "郭中時有仙人住，城內應多藥草生。", "公事稀疎來客少，無妨著屐獨閑行。"]'),
('8451c1ce-8951-4d77-8948-8be88dc4fbfe','同將作韋二少監贈水部李郎中','張籍','唐','唐诗','tang','','[]','舊年同是水曹郎，各罷魚符自楚鄉。',64,'全唐诗/poet.tang.20000.json','["舊年同是水曹郎，各罷魚符自楚鄉。", "重著青衫承詔命，齊趨紫殿異班行。", "別來同說經過事，老去相傳補養方。", "憶得當時亦連步，如今獨在讀書堂。"]'),
('daa86f6d-98fb-4231-84c3-f0cace4efbf6','贈王侍御','張籍','唐','唐诗','tang','','[]','心同野鶴與塵遠，詩似冰壺見底清。',64,'全唐诗/poet.tang.20000.json','["心同野鶴與塵遠，詩似冰壺見底清。", "府縣同趨昨日事，升沈不改故人情。", "上陽春晚蕭蕭雨，洛水寒來夜夜聲。", "自歎獨爲折腰吏，可憐騘馬路傍行。"]'),
('cf87caa9-9c44-4fed-a46e-f72f5b400811','送金少卿副使歸新羅','張籍','唐','唐诗','tang','','[]','雲島茫茫天畔微，向東萬里一帆飛。',64,'全唐诗/poet.tang.20000.json','["雲島茫茫天畔微，向東萬里一帆飛。", "久爲侍子承恩重，今佐使臣銜命歸。", "通海便應將國信，到家猶自著朝衣。", "從前此去人無數，光彩如君定是稀。"]'),
('b7768076-32f2-47d4-8e1e-18841709b67e','送李司空赴鎮襄陽','張籍','唐','唐诗','tang','','[]','中外兼權社稷臣，千官齊出拜行塵。',64,'全唐诗/poet.tang.20000.json','["中外兼權社稷臣，千官齊出拜行塵。", "再調公鼎勳庸盛，三受兵符寵命新。", "商路雪開旗斾展，楚堤梅發驛亭春。", "襄陽風景由來好，重與江山作主人。"]'),
('bcda6c14-512b-4aa0-ba62-d10f4c4fc50c','送李僕射愬赴鎮鳳翔','張籍','唐','唐诗','tang','','[]','由來勳業屬英雄，兄弟連營列位同。',64,'全唐诗/poet.tang.20000.json','["由來勳業屬英雄，兄弟連營列位同。", "先入賊城擒首惡，盡封筦庫讓元公。", "旌幢獨繼家聲外，竹帛新添國史中。", "天子新收秦隴地，故教移鎮古扶風。"]'),
('1290d4c7-e30b-4007-a0fe-bac3cb9d0f4f','寄白二十二舍人','張籍','唐','唐诗','tang','','[]','早知內詔過先輩，蹭蹬江南百事疎。',64,'全唐诗/poet.tang.20000.json','["早知內詔過先輩，蹭蹬江南百事疎。", "湓浦成中爲上佐，爐峰寺後著幽居。", "偏依仙法多求藥，長共僧遊不讀書。", "三省比來名望重，肯容君去樂樵漁。"]'),
('30a2dd04-afb6-4cf4-97f2-8ddd300ebaef','送友人盧處士遊吳越','張籍','唐','唐诗','tang','','[]','羨君東去見殘梅，惟有王孫獨未回。',64,'全唐诗/poet.tang.20000.json','["羨君東去見殘梅，惟有王孫獨未回。", "吳苑夕陽明古堞，越宮春草上高臺。", "波生野水雁初下，風滿驛樓潮欲來。", "試問漁舟看雪浪，幾多江燕荇花開。"]'),
('3db0db09-2db6-4884-bc07-4dd85d45b67c','蘇州江岸留別樂天','張籍','唐','唐诗','tang','','[]','銀泥裙暎錦障泥，畫舸停橈馬簇蹄。',64,'全唐诗/poet.tang.20000.json','["銀泥裙暎錦障泥，畫舸停橈馬簇蹄。", "清管曲終鸚鵡語，紅旗影動薄寒嘶。", "漸消酒色朱顏淺，欲話離情翠黛低。", "莫忘使君吟詠處，女墳湖北武丘西。"]'),
('9e9f8876-7c0c-4722-b7e7-0eba3f64daa5','寒食看花','張籍','唐','唐诗','tang','','[]','早入公門到夜歸，不因寒食少閑時。',64,'全唐诗/poet.tang.20000.json','["早入公門到夜歸，不因寒食少閑時。", "顛狂遶樹猿離鎖，踴躍緣岡馬斷羈。", "酒汙衣裳從客笑，醉饒言語覓花知。", "老來自喜常無事，仰面西園得詠詩。"]'),
('f4ab13ce-b240-407a-a2fc-1949081758ba','酬浙東元尚書見寄綾素','張籍','唐','唐诗','tang','','[]','越地繒紗紋樣新，遠封來寄學曹人。',64,'全唐诗/poet.tang.20000.json','["越地繒紗紋樣新，遠封來寄學曹人。", "便令裁制爲時服，頓覺光榮上病身。", "應念此官同棄置，獨能相賀更殷勤。", "三千里外無由見，海上東風又一春。"]'),
('a1adfc21-9991-486e-a47a-457753a32af5','贈項斯','張籍','唐','唐诗','tang','','[]','端坐吟詩忘忍飢，萬人中覓似君稀。',64,'全唐诗/poet.tang.20000.json','["端坐吟詩忘忍飢，萬人中覓似君稀。", "門連野水風長到，驢放秋原夜不歸。", "日煖剩收新落葉，天寒更著舊生衣。", "曲江亭上頻頻見，爲愛鸕鷀雨裏飛。"]'),
('3e7e656b-5ca2-4dbc-972f-0369be5046b8','和韋開州盛山十二首 宿雲亭','張籍','唐','唐诗','tang','','[]','清淨當深處，虛明向遠開。',24,'全唐诗/poet.tang.20000.json','["清淨當深處，虛明向遠開。", "卷簾無俗客，應只見雲來。"]'),
('5dc1daca-91ed-4733-a4b4-b20c3243d375','和韋開州盛山十二首 梅溪','張籍','唐','唐诗','tang','','[]','自愛新梅好，行尋一徑斜。',24,'全唐诗/poet.tang.20000.json','["自愛新梅好，行尋一徑斜。", "不教人掃石，恐損落來花。"]'),
('fc8c6420-826a-4025-962d-e5b01a6c76b5','和韋開州盛山十二首 茶嶺','張籍','唐','唐诗','tang','','[]','紫芽連白蘂，初向嶺頭生。',24,'全唐诗/poet.tang.20000.json','["紫芽連白蘂，初向嶺頭生。", "自看家人摘，尋常觸露行。"]'),
('2c498561-27a0-447d-86fc-ad0232f9ee43','和韋開州盛山十二首 流杯渠','張籍','唐','唐诗','tang','','[]','淥酒白螺杯，隨流去復回。',24,'全唐诗/poet.tang.20000.json','["淥酒白螺杯，隨流去復回。", "似知人把處，各向面前來。"]'),
('0ea9fab0-d3c4-4ed6-8234-f78a1ae68cbb','和韋開州盛山十二首 盤石磴','張籍','唐','唐诗','tang','','[]','壘石盤空遠，層層勢不危。',24,'全唐诗/poet.tang.20000.json','["壘石盤空遠，層層勢不危。", "不知行幾匝，得到上頭時。"]'),
('70580fb2-022f-4fea-9944-776f5637d835','和韋開州盛山十二首 桃塢','張籍','唐','唐诗','tang','','[]','春塢桃花發，多將野客遊。',24,'全唐诗/poet.tang.20000.json','["春塢桃花發，多將野客遊。", "日西殊未散，看望酒缸頭。"]'),
('389039e4-0124-42c5-84cf-cf29ebcb31e4','和韋開州盛山十二首 竹巖','張籍','唐','唐诗','tang','','[]','獨入千竿裏，緣巖踏石層。',24,'全唐诗/poet.tang.20000.json','["獨入千竿裏，緣巖踏石層。", "笋頭齊欲出，更不許人登。"]'),
('e28b4e3b-2cd8-4915-9c8f-f9d4a50636ab','和韋開州盛山十二首 琵琶臺','張籍','唐','唐诗','tang','','[]','臺上綠蘿春，閑登不待人。',24,'全唐诗/poet.tang.20000.json','["臺上綠蘿春，閑登不待人。", "每當休暇日，著履戴紗巾。"]'),
('1e9c0991-3551-4acf-8948-8115251f0c66','和韋開州盛山十二首 胡蘆沼','張籍','唐','唐诗','tang','','[]','曲沼春流滿，新蒲映野鵝。',24,'全唐诗/poet.tang.20000.json','["曲沼春流滿，新蒲映野鵝。", "閑齋朝飯後，拄杖遶行多。"]'),
('fb5ee0ca-ad31-409d-bcc7-b95b08ba2165','和韋開州盛山十二首 隱月岫','張籍','唐','唐诗','tang','','[]','月出深峰裏，清涼夜亦寒。',24,'全唐诗/poet.tang.20000.json','["月出深峰裏，清涼夜亦寒。", "每嫌西落疾，不得到明看。"]'),
('ae8591be-54b1-484d-8bde-2ccec2ae987f','和韋開州盛山十二首 繡衣石榻','張籍','唐','唐诗','tang','','[]','山城無別味，藥草兼魚果。',24,'全唐诗/poet.tang.20000.json','["山城無別味，藥草兼魚果。", "時到繡衣人，同來石上坐。"]'),
('5209fed5-6f9b-4e12-9fd9-f2d91d154d90','和韋開州盛山十二首 上士泉缾','張籍','唐','唐诗','tang','','[]','堦上一眼泉，四邊青石甃。',24,'全唐诗/poet.tang.20000.json','["堦上一眼泉，四邊青石甃。", "唯有護淨僧，添缾將盥漱。"]'),
('49ce4f86-6999-48a4-8d85-59851b6f62fd','送遠客','張籍','唐','唐诗','tang','','[]','憔悴遠歸客，殷勤欲別杯。',24,'全唐诗/poet.tang.20000.json','["憔悴遠歸客，殷勤欲別杯。", "九星壇下路，幾日見重來。"]'),
('4c937660-3aa1-4f1a-b39d-c41c717162ef','寄西峰僧','張籍','唐','唐诗','tang','','[]','松暗水涓涓，夜涼人未眠。',24,'全唐诗/poet.tang.20000.json','["松暗水涓涓，夜涼人未眠。", "西峰月猶在，遙憶草堂前。"]'),
('9f27bad0-5a8e-45c1-ae8d-54652a436648','禪師','張籍','唐','唐诗','tang','','[]','獨在西峰頂，年年閉石房。',24,'全唐诗/poet.tang.20000.json','["獨在西峰頂，年年閉石房。", "定中無弟子，人到爲焚香。"]'),
('1aee5e51-52a5-4f6d-9271-a95b47d1db12','惜花','張籍','唐','唐诗','tang','','[]','山中春已晚，處處見花稀。',24,'全唐诗/poet.tang.20000.json','["山中春已晚，處處見花稀。", "明日來應盡，林間宿不歸。"]'),
('afe54c56-6577-4031-9610-361371e02256','題暉師影堂','張籍','唐','唐诗','tang','','[]','日早欲參禪，竟無相識緣。',24,'全唐诗/poet.tang.20000.json','["日早欲參禪，竟無相識緣。", "道場今獨到，惆悵影堂前。"]'),
('12ba6512-5989-4b29-929f-5e1e218eaddd','涇州塞','張籍','唐','唐诗','tang','','[]','行到涇州塞，唯聞羌戍鼙。',24,'全唐诗/poet.tang.20000.json','["行到涇州塞，唯聞羌戍鼙。", "道邊古雙堠，猶記向安西。"]'),
('d25708ee-f6bb-4c12-a41d-5ff44f3d21bc','野田','張籍','唐','唐诗','tang','','[]','漠漠野田草，草中牛羊道。',24,'全唐诗/poet.tang.20000.json','["漠漠野田草，草中牛羊道。", "古墓無子孫，白楊不得老。"]'),
('c914d5f4-9d87-4a75-b774-0c01187b4a97','岸花','張籍','唐','唐诗','tang','','[]','可憐岸邊樹，紅蘂發青條。',24,'全唐诗/poet.tang.20000.json','["可憐岸邊樹，紅蘂發青條。", "東風吹渡水，衝着木蘭橈。"]'),
('9c703f78-d424-4982-b5d0-fcc5c5b219f5','別于鵠','張籍','唐','唐诗','tang','','[]','離燈及晨輝，行人起復思。',24,'全唐诗/poet.tang.20000.json','["離燈及晨輝，行人起復思。", "出門兩相顧，青山路逶迤。"]'),
('b84243ce-8627-4860-9065-f36af42441e8','送蜀客','張籍','唐','唐诗','tang','','[]','蜀客南行祭碧雞，木棉花發錦江西。',32,'全唐诗/poet.tang.20000.json','["蜀客南行祭碧雞，木棉花發錦江西。", "山橋日晚行人少，時見猩猩樹上啼。"]'),
('0d280af5-5168-4daf-9c35-ff414a1c79ad','送元結','張籍','唐','唐诗','tang','','[]','昔日同遊漳水邊，如今重說恨綿綿。',32,'全唐诗/poet.tang.20000.json','["昔日同遊漳水邊，如今重說恨綿綿。", "天涯相見還離別，客路秋風又幾年。"]'),
('ec4bc92d-bd98-4edd-9a32-223db867aebc','宿山祠','張籍','唐','唐诗','tang','','[]','秋草宮人斜裏墓，宮人誰送葬來時。',32,'全唐诗/poet.tang.20000.json','["秋草宮人斜裏墓，宮人誰送葬來時。", "千千萬萬皆如此，家在邊城亦不知。"]');
